  (30, 'dakota-poker-tour-2022-23-baffalo-city-showdown', 'Buffalo City Showdown', 'The DPT returns to Jamestown for the Buffalo City Showdown, a single-day SATURDAY afternoon tournament at the Buff Bar! Last year Brandt Jenner took this event down, cashing $5,120 for first place. See the Live Stream replay here: https://www.youtube.com/live/…', '2023-04-15', '2023-04-15', 15, 'https://dakotapokertour.com/storage/event/medium/DPT-Buffalo-City–FB-REVISED-zUID7aGT.png', '', '{"id":30,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-2022-23-baffalo-city-showdown","description":"The DPT returns to Jamestown for the Buffalo City Showdown, a single-day SATURDAY afternoon tournament at the Buff Bar! Last year Brandt Jenner took this event down, cashing $5,120 for first place. See the Live Stream replay here: https://www.youtube.com/live/…","startDate":"2023-04-15 00:00:00","endDate":"2023-04-15 00:00:00","logo":"DPT-Buffalo-City–FB-REVISED-zUID7aGT.png","bannerImage":null,"imageUrl":"https://dakotapokertour.com/storage/event/medium/DPT-Buffalo-City–FB-REVISED-zUID7aGT.png","bannerUrl":"","venue":{"id":15,"name":"Buff Bar & Lounge","alias":"buff-bar-lounge","city":"Jamestown","state":"ND"}}'::jsonb),
