  (21, 'dakota-poker-tour-2022-23-dead-money-open', 'Dead Money Open', 'The Classic is Back! Join us at the M&J Saloon in West Fargo for the Dead Money Open! Friday Night - Super Satellite Saturday - Dead Money Open (1-day Tourney) (Details coming soon)', '2023-01-27', '2023-01-28', 9, 'https://dakotapokertour.com/storage/event/medium/DPT-Dead-Money-Open-FB-VNDR-CZZuwlfj.jpg', '/media/dpt/event/DPT-Dead-Money-Open-FB-VNDR-CZZuwlfj.jpg', '{"id":21,"name":"Dead Money Open","alias":"dakota-poker-tour-2022-23-dead-money-open","description":"The Classic is Back! Join us at the M&J Saloon in West Fargo for the Dead Money Open! Friday Night - Super Satellite Saturday - Dead Money Open (1-day Tourney) (Details coming soon)","startDate":"2023-01-27 00:00:00","endDate":"2023-01-28 00:00:00","logo":"DPT-Dead-Money-Open-FB-VNDR-CZZuwlfj.jpg","bannerImage":null,"imageUrl":"https://dakotapokertour.com/storage/event/medium/DPT-Dead-Money-Open-FB-VNDR-CZZuwlfj.jpg","bannerUrl":"","venue":{"id":9,"name":"M & J Saloon","alias":"m-j-saloon","city":"West Fargo","state":"ND"}}'::jsonb),
  (22, 'dakota-poker-tour-2022-23-rpt-casino-state-championship', 'RPT Casino State Championship', 'North Dakota''s largest poker event of the year! Roughrider Poker Tour and Spirit Lake Casino host the RPT Casino State Championship! Estimated prize pool $125,000+ Attn: Dakota Poker Tour player! Participation in any/all tournaments in this event will COUNT to…', '2022-12-29', '2023-01-01', 77, 'https://dakotapokertour.com/storage/event/medium/RPT-Casino-State-Championship---wide_B-YLZvp3Mp.png', '/media/dpt/event/RPT-Casino-State-Championship---wide_B-YLZvp3Mp.png', '{"id":22,"name":"RPT Casino State Championship","alias":"dakota-poker-tour-2022-23-rpt-casino-state-championship","description":"North Dakota''s largest poker event of the year! Roughrider Poker Tour and Spirit Lake Casino host the RPT Casino State Championship! Estimated prize pool $125,000+ Attn: Dakota Poker Tour player! Participation in any/all tournaments in this event will COUNT to…","startDate":"2022-12-29 00:00:00","endDate":"2023-01-01 00:00:00","logo":"RPT-Casino-State-Championship---wide_B-YLZvp3Mp.png","bannerImage":null,"imageUrl":"https://dakotapokertour.com/storage/event/medium/RPT-Casino-State-Championship---wide_B-YLZvp3Mp.png","bannerUrl":"","venue":{"id":77,"name":"Spirit Lake Casino & Resort","alias":"spirit-lake-casino-resort","city":"St Michael","state":"ND"}}'::jsonb),
  (19, 'dakota-poker-tour-2022-23-poker-brat-bounty-tournament', 'Poker Brat BOUNTY Tournament', 'This fall the Poker Brat at the Windbreak will feature a 1-day Bounty Tournament starting at Noon! Buy-in is $200 (20,000 chips). One add-on for $100 (10,000 chips) available until registration closes. For each player you take out, you earn a $100 bounty plus…', '2022-12-11', '2022-12-11', 4, 'https://dakotapokertour.com/storage/event/medium/DPT-Poker-Brat-graphics-FB-(1)-0MgtoZkS.jpg', '/media/dpt/event/DPT-Poker-Brat-graphics-FB-(1)-0MgtoZkS.jpg', '{"id":19,"name":"Poker Brat BOUNTY Tournament","alias":"dakota-poker-tour-2022-23-poker-brat-bounty-tournament","description":"This fall the Poker Brat at the Windbreak will feature a 1-day Bounty Tournament starting at Noon! Buy-in is $200 (20,000 chips). One add-on for $100 (10,000 chips) available until registration closes. For each player you take out, you earn a $100 bounty plus…","startDate":"2022-12-11 00:00:00","endDate":"2022-12-11 00:00:00","logo":"DPT-Poker-Brat-graphics-FB-(1)-0MgtoZkS.jpg","bannerImage":null,"imageUrl":"https://dakotapokertour.com/storage/event/medium/DPT-Poker-Brat-graphics-FB-(1)-0MgtoZkS.jpg","bannerUrl":"","venue":{"id":4,"name":"Windbreak","alias":"windbreak","city":"Fargo","state":"ND"}}'::jsonb),
  (15, 'dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack', 'L.i.s.t.e.n. Inc Monster Stack', 'The Monster Stack is BACK! The DPT returns to Grand Forks for a premiere event at the Canad Inn weekend of December 3rd 2022. There will be a super satellite Friday night, followed by a 2-day main event featuring deep stacks and 40 minute levels on day 2. Buy…', '2022-12-02', '2022-12-04', 8, 'https://dakotapokertour.com/storage/event/medium/DPT-Monster-Stack-22-23-FB-r1-BiqYW6Qh.png', '/media/dpt/event/DPT-Monster-Stack-22-23-FB-r1-BiqYW6Qh.png', '{"id":15,"name":"L.i.s.t.e.n. Inc Monster Stack","alias":"dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack","description":"The Monster Stack is BACK! The DPT returns to Grand Forks for a premiere event at the Canad Inn weekend of December 3rd 2022. There will be a super satellite Friday night, followed by a 2-day main event featuring deep stacks and 40 minute levels on day 2. Buy…","startDate":"2022-12-02 00:00:00","endDate":"2022-12-04 00:00:00","logo":"DPT-Monster-Stack-22-23-FB-r1-BiqYW6Qh.png","bannerImage":null,"imageUrl":"https://dakotapokertour.com/storage/event/medium/DPT-Monster-Stack-22-23-FB-r1-BiqYW6Qh.png","bannerUrl":"","venue":{"id":8,"name":"Playmaker''s All American Lounge","alias":"playmaker-s-all-american-lounge","city":"Grand Forks","state":"ND"}}'::jsonb),
