  (16, 'dakota-poker-tour-2022-23-season-2022-2023-kickoff', 'Season 2022-2023 Kickoff', 'We''re getting ready to dust off the gear and get the band back to together for the 2022-2023 New DPT Season! Fancy graphics and posters coming soon.. FRIDAY - Super Satellite Night ($40 buy-in), win entries ranging from $150 to $300 for Saturday''s feature tour…', '2022-09-16', '2022-09-17', 7, 'https://dakotapokertour.com/storage/event/medium/DPT-Season-Kickoff-22-23-FB-r3-niHyA6Wt.png', '/media/dpt/event/DPT-Season-Kickoff-22-23-FB-r3-niHyA6Wt.png', '{"id":16,"name":"Season 2022-2023 Kickoff","alias":"dakota-poker-tour-2022-23-season-2022-2023-kickoff","description":"We''re getting ready to dust off the gear and get the band back to together for the 2022-2023 New DPT Season! Fancy graphics and posters coming soon.. FRIDAY - Super Satellite Night ($40 buy-in), win entries ranging from $150 to $300 for Saturday''s feature tour…","startDate":"2022-09-16 00:00:00","endDate":"2022-09-17 00:00:00","logo":"DPT-Season-Kickoff-22-23-FB-r3-niHyA6Wt.png","bannerImage":null,"imageUrl":"https://dakotapokertour.com/storage/event/medium/DPT-Season-Kickoff-22-23-FB-r3-niHyA6Wt.png","bannerUrl":"","venue":{"id":7,"name":"Hagge''s Bar & Grill","alias":"hagge-s-bar-grill","city":"Mapleton","state":"ND"}}'::jsonb),
