  (3, 'dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021', 'dakota-poker-tour-season-xi-poker-brat-classic', 'Poker Brat Classic', 'This is one othe DPT''s premiere events! Lots of play in this 2-day MEGA stack tournament!', '2021-12-04', '2021-12-05', 4, 180, 120, null, 'https://dakotapokertour.com/storage/tournament/medium/O50d5W7mdHqVaFvhnlYONrdTEHXkWK4gKONaabKd.png', '/media/dpt/tournament/O50d5W7mdHqVaFvhnlYONrdTEHXkWK4gKONaabKd.png', '{"id":3,"name":"Poker Brat Classic","alias":"dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021","shortDescription":"This is one othe DPT''s premiere events! Lots of play in this 2-day MEGA stack tournament!","startDate":"2021-12-04 11:08:00","endDate":"2021-12-05 11:08:00","registrationStartDate":"2021-12-04 11:09:00","minimumBuyIn":180,"maximumBuyIn":300,"totalPrizePool":null,"totalPlayers":120,"logo":"O50d5W7mdHqVaFvhnlYONrdTEHXkWK4gKONaabKd.png","bannerImage":"tournament/iXo5XIqqRmzVTgCnbAg3adifs8WcMvPB85bV0npU.jpg","imageUrl":"https://dakotapokertour.com/storage/tournament/medium/O50d5W7mdHqVaFvhnlYONrdTEHXkWK4gKONaabKd.png","bannerUrl":"https://dakotapokertour.com/storage/tournament/medium/tournament/iXo5XIqqRmzVTgCnbAg3adifs8WcMvPB85bV0npU.jpg","event":{"id":3,"name":"Poker Brat Classic","alias":"dakota-poker-tour-season-xi-poker-brat-classic"},"venue":{"id":4,"name":"Windbreak","alias":"windbreak","city":"Fargo","state":"ND"}}'::jsonb),
  (2, 'dakota-poker-tour-season-xi-pour-decisions-tioga-nd-pour-decisions-11-27-2021', 'dakota-poker-tour-season-xi-pour-decisions-tioga-nd', 'Pour Decisions', 'Saturday: Noon start $150 buy-in, starting chips 20k, with add-ons available up to 50k. Registration closes 5pm.', '2021-11-27', '2021-11-27', 2, 135, 26, null, 'https://dakotapokertour.com/storage/tournament/medium/GpzebFi36DGFjY7Xddn3SSiwQsJzDzGDYe84ECka.png', '/media/dpt/tournament/GpzebFi36DGFjY7Xddn3SSiwQsJzDzGDYe84ECka.png', '{"id":2,"name":"Pour Decisions","alias":"dakota-poker-tour-season-xi-pour-decisions-tioga-nd-pour-decisions-11-27-2021","shortDescription":"Saturday: Noon start $150 buy-in, starting chips 20k, with add-ons available up to 50k. Registration closes 5pm.","startDate":"2021-11-27 22:36:17","endDate":"2021-11-27 22:36:26","registrationStartDate":"2021-11-27 11:00:33","minimumBuyIn":135,"maximumBuyIn":null,"totalPrizePool":null,"totalPlayers":26,"logo":"GpzebFi36DGFjY7Xddn3SSiwQsJzDzGDYe84ECka.png","bannerImage":"tournament/ZgvLWvwI3qHEbgol34GhzQUeEX5EPR0hwvAZ0uKt.jpg","imageUrl":"https://dakotapokertour.com/storage/tournament/medium/GpzebFi36DGFjY7Xddn3SSiwQsJzDzGDYe84ECka.png","bannerUrl":"https://dakotapokertour.com/storage/tournament/medium/tournament/ZgvLWvwI3qHEbgol34GhzQUeEX5EPR0hwvAZ0uKt.jpg","event":{"id":2,"name":"Pour Decisions - Tioga ND","alias":"dakota-poker-tour-season-xi-pour-decisions-tioga-nd"},"venue":{"id":2,"name":"Pour Decisions","alias":"pour-decisions","city":"Tioga","state":"ND"}}'::jsonb),
  (9, 'dakota-poker-tour-season-xi-season-xi-kickoff-tournament-hagge-s-hagge-s-bar-grill-09-26-2021', 'dakota-poker-tour-season-xi-season-xi-kickoff-tournament-hagge-s', 'Hagge''s Bar & Grill', 'Kickoff Tourney', '2021-09-26', '2021-09-26', 7, 135, 38, null, '', '', '{"id":9,"name":"Hagge''s Bar & Grill","alias":"dakota-poker-tour-season-xi-season-xi-kickoff-tournament-hagge-s-hagge-s-bar-grill-09-26-2021","shortDescription":"Kickoff Tourney","startDate":"2021-09-26 12:00:00","endDate":"2021-09-26 18:00:00","registrationStartDate":"2021-09-26 11:00:00","minimumBuyIn":135,"maximumBuyIn":null,"totalPrizePool":null,"totalPlayers":38,"logo":"","bannerImage":"","imageUrl":"","bannerUrl":"","event":{"id":5,"name":"Season XI Kickoff Tournament - Hagge''s","alias":"dakota-poker-tour-season-xi-season-xi-kickoff-tournament-hagge-s"},"venue":{"id":7,"name":"Hagge''s Bar & Grill","alias":"hagge-s-bar-grill","city":"Mapleton","state":"ND"}}'::jsonb)
insert into public.dpt_public_articles (legacy_id, alias, title, excerpt, published_at, event_alias, tournament_alias, image_url, local_image_path, video_url, raw) values
  (451, 'congratulations-to-bob-barker-of-perham-mn-the-black-chip-bounty-champion', '♠️🏆 Congratulations to Bob Barker of Perham MN the Black Chip Bounty Champion🏆♠️', 'What an incredible day of poker at the Black Chip Bounty Tournament! Congratulations to all of our players who battled their way to the final table and cashed in on today’s action. 🥇 Champion – Bob Baker (Perham, MN) 💰 $3,100 (Modified Chop…', '2026-06-07 23:13:00', null, 'dakota-poker-tour-2026-poker-brat-black-chip-bounty-tournament-black-chip-bounty-06-07-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_8038-VKsCKKNP.jpg', '/media/dpt/article/IMG_8038-VKsCKKNP.jpg', null, '{"id":451,"title":"♠️🏆 Congratulations to Bob Barker of Perham MN the Black Chip Bounty Champion🏆♠️","alias":"congratulations-to-bob-barker-of-perham-mn-the-black-chip-bounty-champion","excerpt":"What an incredible day of poker at the Black Chip Bounty Tournament! Congratulations to all of our players who battled their way to the final table and cashed in on today’s action. 🥇 Champion – Bob Baker (Perham, MN) 💰 $3,100 (Modified Chop…","content":"What an incredible day of poker at the Black Chip Bounty Tournament! Congratulations to all of our players who battled their way to the final table and cashed in on today’s action. 🥇 Champion – Bob Baker (Perham, MN) 💰 $3,100 (Modified Chop) 🎯 $600 in Bounties 🏆 Trophy Winner 🥈 Bryan Thompson (Fargo, ND) 💰 $3,800 (Modified Chop) 🎯 $1,100 in Bounties 🥉 Chase Lardy (Fargo, ND) 💰 $2,000 🎯 $400 in Bounties 4️⃣ Lee Cavanagh (Hickson, ND) 💰 $1,300 🎯 $500 in Bounties 5️⃣ Mike Anderson (Detroit Lakes, MN) 💰 $1,100 🎯 $600 in Bounties 6️⃣ Jeremy Holmes (West Fargo, ND) 💰 $860 🎯 $200 in Bounties 7️⃣ John Joseph (Doran, MN) 💰 $660 🎯 $1,000 in Bounties 8️⃣ John Elledge (Fargo, ND) 💰 $500 🎯 $100 in Bounties 9️⃣ Keith Johnson (Moorhead, MN) 💰 $500 🔟 Casey Olson (Jamestown, ND) 💰 $320 🎯 $200 in Bounties 1️⃣1️⃣ T-Mack (Moorhead, MN) 💰 $320 🎯 $300 in Bounties 1️⃣2️⃣ Todd Egerdahl (Fargo, ND) 💰 $320 🎯 $200 in Bounties A huge thank you to everyone who came out to support the event, our volunteer dealers, staff, and all of the players who made this tournament another great success. DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-06-07 23:13:00","featured":true,"logo":"IMG_8038-VKsCKKNP.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_8038-VKsCKKNP.jpg","bannerUrl":"","tournament":{"id":346,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2026-poker-brat-black-chip-bounty-tournament-black-chip-bounty-06-07-2026"}}'::jsonb),
  (450, 'final-table-of-the-black-chip-bounty', 'Final Table of the Black Chip Bounty', '🏆 Congratulations to Our Final Table! 🏆 After an incredible turnout of 97 players, we have officially reached the Final Table! Today’s event generated a total prize pool of $24,480, with $9,700 paid out in bounties and $14,780 awarded to th…', '2026-06-07 20:00:00', null, 'dakota-poker-tour-2026-poker-brat-black-chip-bounty-tournament-black-chip-bounty-06-07-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_8020-qCpPTWiP.jpg', '/media/dpt/article/IMG_8020-qCpPTWiP.jpg', null, '{"id":450,"title":"Final Table of the Black Chip Bounty","alias":"final-table-of-the-black-chip-bounty","excerpt":"🏆 Congratulations to Our Final Table! 🏆 After an incredible turnout of 97 players, we have officially reached the Final Table! Today’s event generated a total prize pool of $24,480, with $9,700 paid out in bounties and $14,780 awarded to th…","content":"🏆 Congratulations to Our Final Table! 🏆 After an incredible turnout of 97 players, we have officially reached the Final Table! Today’s event generated a total prize pool of $24,480, with $9,700 paid out in bounties and $14,780 awarded to the Top 12 finishers. A huge thank you to everyone who came out to support our Charity Partner, PPA, and the Dakota Poker Tour. The support from our players continues to make these events a tremendous success. Good luck to our final table players as they battle for the title and the top prize! ♠️♥️♦️♣️","publishedAt":"2026-06-07 20:00:00","featured":false,"logo":"IMG_8020-qCpPTWiP.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_8020-qCpPTWiP.jpg","bannerUrl":"","tournament":{"id":346,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2026-poker-brat-black-chip-bounty-tournament-black-chip-bounty-06-07-2026"}}'::jsonb),
  (449, 'registration-closed-in-the-black-chip-bounty-with-97-players', 'Registration closed in the black Chip bounty with 97 players', '🚨 REGISTRATION IS CLOSED! 🚨 What an incredible turnout today! We officially closed registration with 97 players, generating a total prize pool of $24,480! 💰 $9,700 will be paid out in bounties 💰 $14,780 will be paid out to the Top 12 finish…', '2026-06-07 18:00:00', null, 'dakota-poker-tour-2026-poker-brat-black-chip-bounty-tournament-black-chip-bounty-06-07-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_8035-ucSyTUCS.png', '/media/dpt/article/IMG_8035-ucSyTUCS.png', null, '{"id":449,"title":"Registration closed in the black Chip bounty with 97 players","alias":"registration-closed-in-the-black-chip-bounty-with-97-players","excerpt":"🚨 REGISTRATION IS CLOSED! 🚨 What an incredible turnout today! We officially closed registration with 97 players, generating a total prize pool of $24,480! 💰 $9,700 will be paid out in bounties 💰 $14,780 will be paid out to the Top 12 finish…","content":"🚨 REGISTRATION IS CLOSED! 🚨 What an incredible turnout today! We officially closed registration with 97 players, generating a total prize pool of $24,480! 💰 $9,700 will be paid out in bounties 💰 $14,780 will be paid out to the Top 12 finishers Thank you to everyone who came out to support our amazing Charity Partner, NPPA, and the Dakota Poker Tour. Your participation helps make these events possible and continues to grow the game we all love. A special thank you to Randy Dinner for providing a delicious lunch for our players and staff today. It was greatly appreciated! And, as always, a huge shoutout to our incredible volunteer dealers. Without your time, dedication, and hard work, events like this simply would not be possible. We can’t thank you enough for everything you do. Good luck to all the remaining players as they battle it out for the title, cash, and bounties! ♠️♥️♦️♣️🏆💰 DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-06-07 18:00:00","featured":false,"logo":"IMG_8035-ucSyTUCS.png","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_8035-ucSyTUCS.png","bannerUrl":"","tournament":{"id":346,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2026-poker-brat-black-chip-bounty-tournament-black-chip-bounty-06-07-2026"}}'::jsonb),
  (448, '8-tables-in-the-windbreak-black-chip-bounty', '8 Tables in the Windbreak Black Chip Bounty', '♠️ CARDS ARE IN THE AIR! ♠️ The Dakota Poker Tour Bounty Tournament is officially underway at the Windbreak! We’ve got 8 tables in action and still plenty of room to grow. If you’re thinking about playing, there’s still time to join us! ⏰ L…', '2026-06-07 13:30:00', null, 'dakota-poker-tour-2026-poker-brat-black-chip-bounty-tournament-black-chip-bounty-06-07-2026', '', '', null, '{"id":448,"title":"8 Tables in the Windbreak Black Chip Bounty","alias":"8-tables-in-the-windbreak-black-chip-bounty","excerpt":"♠️ CARDS ARE IN THE AIR! ♠️ The Dakota Poker Tour Bounty Tournament is officially underway at the Windbreak! We’ve got 8 tables in action and still plenty of room to grow. If you’re thinking about playing, there’s still time to join us! ⏰ L…","content":"♠️ CARDS ARE IN THE AIR! ♠️ The Dakota Poker Tour Bounty Tournament is officially underway at the Windbreak! We’ve got 8 tables in action and still plenty of room to grow. If you’re thinking about playing, there’s still time to join us! ⏰ Late registration remains open until approximately 5:00 PM. 💰 $100 bounty on every player you eliminate 🔥 Great action, great food, and a great atmosphere Get down to the Windbreak and take your shot at the prize pool and those bounties! See you at the tables! ♣️♦️♥️♠️ DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-06-07 13:30:00","featured":false,"logo":null,"banner":null,"videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":346,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2026-poker-brat-black-chip-bounty-tournament-black-chip-bounty-06-07-2026"}}'::jsonb),
  (447, 'dakota-poker-tour-has-arrived-at-the-windbreak', 'Dakota Poker Tour has Arrived at the Windbreak', '♠️♦️ ATTENTION POKER FRIENDS! ♦️♠️ The Dakota Poker Tour has officially arrived and is all set up at the Windbreak! Get ready for an action-packed day of poker with our ONE-DAY BOUNTY TOURNAMENT! 💰🔥 🕚 Registration Opens: 11:00 AM 🃏 Cards in…', '2026-06-07 11:00:00', null, 'dakota-poker-tour-2026-poker-brat-black-chip-bounty-tournament-black-chip-bounty-06-07-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7971-s9VVAjDG.jpg', '/media/dpt/article/IMG_7971-s9VVAjDG.jpg', null, '{"id":447,"title":"Dakota Poker Tour has Arrived at the Windbreak","alias":"dakota-poker-tour-has-arrived-at-the-windbreak","excerpt":"♠️♦️ ATTENTION POKER FRIENDS! ♦️♠️ The Dakota Poker Tour has officially arrived and is all set up at the Windbreak! Get ready for an action-packed day of poker with our ONE-DAY BOUNTY TOURNAMENT! 💰🔥 🕚 Registration Opens: 11:00 AM 🃏 Cards in…","content":"♠️♦️ ATTENTION POKER FRIENDS! ♦️♠️ The Dakota Poker Tour has officially arrived and is all set up at the Windbreak! Get ready for an action-packed day of poker with our ONE-DAY BOUNTY TOURNAMENT! 💰🔥 🕚 Registration Opens: 11:00 AM 🃏 Cards in the Air: NOON 💵 Buy-In: $200 = 20,000 Chips ➕ One-Time Add-On: $100 = 20,000 Chips (Add-on available until registration closes. Must have chips to add on.) 🎯 $100 BOUNTY FOR EVERY PLAYER YOU ELIMINATE! Late registration and add-ons remain open through the dinner break (approximately 5 PM) 👏 Suggested Dealer Appreciation: $20 Tips are appreciated but never required to play. 🍽️ Come hungry! Randy’s Diner will be serving up a delicious Philly Cheesesteak Bar during the dinner break. Bring some cash and treat yourself while battling for bounties and big prizes! Grab your friends, bring your A-game, and we’ll see you at the tables at the Windbreak today! ♠️♥️♣️♦️ #DakotaPokerTour #DPTPoker #BountyTournament #WindbreakPoker #PokerLife #Cards DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-06-07 11:00:00","featured":false,"logo":"IMG_7971-s9VVAjDG.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7971-s9VVAjDG.jpg","bannerUrl":"","tournament":{"id":346,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2026-poker-brat-black-chip-bounty-tournament-black-chip-bounty-06-07-2026"}}'::jsonb),
  (441, 'dakota-poker-tour-spring-championship-winner-eric-kassa-of-wahpeton-north-dakota', 'Dakota Poker Tour Spring Championship winner, Eric Kassa of Wahpeton, North Dakota! 🏆♠️', 'Congratulations to the Dakota Poker Tour Spring Championship winner, Eric Kassa of Wahpeton, North Dakota! 🏆♠️ Eric battled through a tough field to take home $8,000 and the coveted Spring Championship trophy! 🔥 This is another huge accompl…', '2026-05-17 23:00:00', null, 'dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7525-ZDBhjtmQ.jpg', '/media/dpt/article/IMG_7525-ZDBhjtmQ.jpg', null, '{"id":441,"title":"Dakota Poker Tour Spring Championship winner, Eric Kassa of Wahpeton, North Dakota! 🏆♠️","alias":"dakota-poker-tour-spring-championship-winner-eric-kassa-of-wahpeton-north-dakota","excerpt":"Congratulations to the Dakota Poker Tour Spring Championship winner, Eric Kassa of Wahpeton, North Dakota! 🏆♠️ Eric battled through a tough field to take home $8,000 and the coveted Spring Championship trophy! 🔥 This is another huge accompl…","content":"Congratulations to the Dakota Poker Tour Spring Championship winner, Eric Kassa of Wahpeton, North Dakota! 🏆♠️ Eric battled through a tough field to take home $8,000 and the coveted Spring Championship trophy! 🔥 This is another huge accomplishment for Eric, who also captured the High Roller Championship at the Free Poker Network National Championship this past January in Las Vegas! A very special thank you as well to Heidi Roggenkamp, owner of Randy’s Diner, for generously providing breakfast and lunch for our hardworking dealers today. Your support is truly appreciated! ❤️ And of course, thank you to all of our amazing volunteer dealers. Events like this would not be possible without your dedication, long hours, and love for the game. We can’t thank you enough! Huge shoutout as well to our tech team for bringing everyone the live stream feature table experience all weekend long! Jerod, Tony, Brian, and the silky smooth Chris Hanson! 🎥♠️ You guys helped make this event truly special for players and viewers everywhere. Thank you to everyone who came out this weekend to support the Dakota Poker Tour and the West Fargo Rural Fire Department. What an incredible championship weekend! ♦️♣️ DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-05-17 23:00:00","featured":true,"logo":"IMG_7525-ZDBhjtmQ.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7525-ZDBhjtmQ.jpg","bannerUrl":"","tournament":{"id":344,"name":"Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026"}}'::jsonb),
  (445, 'black-chip-bounty-champion-jason-mcclellan-of-perham-minnesota', 'Black Chip Bounty Champion, Jason McClellan of Perham, Minnesota! 🏆♠️', 'Congratulations to our Black Chip Bounty Champion, Jason McClellan of Perham, Minnesota! 🏆♠️ Jason battled through a tough field of 61 players to take home $2,300 for the victory, along with an impressive $700 in bounties! 💰🔥 That officiall…', '2026-05-17 22:00:00', null, 'dakota-poker-tour-2026-spring-championship-black-chip-bounty-05-17-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7529-GfTukNhd.jpg', '/media/dpt/article/IMG_7529-GfTukNhd.jpg', null, '{"id":445,"title":"Black Chip Bounty Champion, Jason McClellan of Perham, Minnesota! 🏆♠️","alias":"black-chip-bounty-champion-jason-mcclellan-of-perham-minnesota","excerpt":"Congratulations to our Black Chip Bounty Champion, Jason McClellan of Perham, Minnesota! 🏆♠️ Jason battled through a tough field of 61 players to take home $2,300 for the victory, along with an impressive $700 in bounties! 💰🔥 That officiall…","content":"Congratulations to our Black Chip Bounty Champion, Jason McClellan of Perham, Minnesota! 🏆♠️ Jason battled through a tough field of 61 players to take home $2,300 for the victory, along with an impressive $700 in bounties! 💰🔥 That officially wraps up an incredible Dakota Poker Tour Spring Championship weekend at the DoubleTree in West Fargo. Thank you to every player, volunteer dealer, staff member, charity partner, and supporter who made this event such a huge success. We appreciate everyone who came out to support the Dakota Poker Tour and the West Fargo Rural Fire Department. From the Friday Night Turbo, to the 100K MEGASTACK, to today’s bounty action — the energy all weekend long was absolutely amazing. We’ll see you all at the next stop on the Dakota Poker Tour! ♠️♦️♣️♥️ DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-05-17 22:00:00","featured":true,"logo":"IMG_7529-GfTukNhd.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7529-GfTukNhd.jpg","bannerUrl":"","tournament":{"id":345,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2026-spring-championship-black-chip-bounty-05-17-2026"}}'::jsonb),
  (443, 'final-table-in-the-black-chip-bounty-tournament', 'FINAL TABLE in the Black Chip Bounty Tournament! 💰♠️🔥', 'We have officially reached the FINAL TABLE in the Black Chip Bounty Tournament! 💰♠️🔥 After an action-packed day with 61 players generating a prize pool of over $15,000, we are now down to the final competitors battling for the title and the…', '2026-05-17 19:00:00', null, 'dakota-poker-tour-2026-spring-championship-black-chip-bounty-05-17-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7523-ir3H5Mcn.jpg', '/media/dpt/article/IMG_7523-ir3H5Mcn.jpg', null, '{"id":443,"title":"FINAL TABLE in the Black Chip Bounty Tournament! 💰♠️🔥","alias":"final-table-in-the-black-chip-bounty-tournament","excerpt":"We have officially reached the FINAL TABLE in the Black Chip Bounty Tournament! 💰♠️🔥 After an action-packed day with 61 players generating a prize pool of over $15,000, we are now down to the final competitors battling for the title and the…","content":"We have officially reached the FINAL TABLE in the Black Chip Bounty Tournament! 💰♠️🔥 After an action-packed day with 61 players generating a prize pool of over $15,000, we are now down to the final competitors battling for the title and the cash! 💵 Payouts have officially begun 🏆 Top 7 players are taking home money today 💥 Bounties are still in play and every knockout matters! Good luck to everyone still fighting for the championship! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour Jeremy Thury Jamestown ND Jason Miller Detroit Lakes MN Brendon Sandy Warroad MN Travis Lynde Lake Park MN Josh Matti Dilworth MN Jason McClellan Perham MN Luke DeWulf Fargo ND","publishedAt":"2026-05-17 19:00:00","featured":false,"logo":"IMG_7523-ir3H5Mcn.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7523-ir3H5Mcn.jpg","bannerUrl":"","tournament":{"id":345,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2026-spring-championship-black-chip-bounty-05-17-2026"}}'::jsonb),
  (442, 'final-table-of-the-spring-championship', 'Final table of the Spring Championship', 'Congratulations to everyone who made the final table of the Dakota Poker Tour Spring Championship! ♠️♦️♣️♥️ Out of an incredible field of 134 players, these final competitors have battled their way down to the last table and are now chasing…', '2026-05-17 18:00:00', null, 'dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7493-IfltMK9U.jpg', '/media/dpt/article/IMG_7493-IfltMK9U.jpg', null, '{"id":442,"title":"Final table of the Spring Championship","alias":"final-table-of-the-spring-championship","excerpt":"Congratulations to everyone who made the final table of the Dakota Poker Tour Spring Championship! ♠️♦️♣️♥️ Out of an incredible field of 134 players, these final competitors have battled their way down to the last table and are now chasing…","content":"Congratulations to everyone who made the final table of the Dakota Poker Tour Spring Championship! ♠️♦️♣️♥️ Out of an incredible field of 134 players, these final competitors have battled their way down to the last table and are now chasing their share of the $32,000 prize pool along with the Spring Championship title! Thank you to all the players who came out this weekend to support the Dakota Poker Tour, the West Fargo Fire Department, and our amazing volunteer dealers who help make these events possible. DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour Phu Truong 1,355,000 Steve Zima 755,000 Josh Lanzdorf 1,925,000 Eric Kassa 2,700,000 Tony Uhlir 650,000 Jackson Skjerseth 2,050,000 Mike Anderson 1,920,000 Brad Magnus 440,000 Steve Belland 1,700,000","publishedAt":"2026-05-17 18:00:00","featured":false,"logo":"IMG_7493-IfltMK9U.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/a