  (444, 'registration-has-officially-closed-in-today-s-black-chip-bounty-tournament', 'Registration has officially CLOSED in today’s Black Chip Bounty Tournament! 💰♠️', 'A huge thank you to the 61 players who came out today, generating a Sunday prize pool of over $15,000! 🔥 The action is heating up as players battle it out for the title, with the top 7 players taking home cash today — plus those bounty payo…', '2026-05-17 17:15:00', null, 'dakota-poker-tour-2026-spring-championship-black-chip-bounty-05-17-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7528-ab6KN4Qh.jpg', '/media/dpt/article/IMG_7528-ab6KN4Qh.jpg', null, '{"id":444,"title":"Registration has officially CLOSED in today’s Black Chip Bounty Tournament! 💰♠️","alias":"registration-has-officially-closed-in-today-s-black-chip-bounty-tournament","excerpt":"A huge thank you to the 61 players who came out today, generating a Sunday prize pool of over $15,000! 🔥 The action is heating up as players battle it out for the title, with the top 7 players taking home cash today — plus those bounty payo…","content":"A huge thank you to the 61 players who came out today, generating a Sunday prize pool of over $15,000! 🔥 The action is heating up as players battle it out for the title, with the top 7 players taking home cash today — plus those bounty payouts adding even more excitement along the way! Good luck to everyone still in the hunt! Cards are in the air and the bounty chips are flying! ♦️","publishedAt":"2026-05-17 17:15:00","featured":false,"logo":"IMG_7528-ab6KN4Qh.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7528-ab6KN4Qh.jpg","bannerUrl":"","tournament":{"id":345,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2026-spring-championship-black-chip-bounty-05-17-2026"}}'::jsonb),
  (446, 'the-black-chip-bounty-tournament-is-officially-underway', '💰 The Black Chip Bounty Tournament is officially underway', '💰 The Black Chip Bounty Tournament is officially underway with 5 tables of action and players still rolling in! 💥♠️ Late registration is open until 5 PM, so there’s still plenty of time to get in the game and start collecting bounties! 🔥 $1…', '2026-05-17 14:00:00', null, 'dakota-poker-tour-2026-spring-championship-black-chip-bounty-05-17-2026', '', '', null, '{"id":446,"title":"💰 The Black Chip Bounty Tournament is officially underway","alias":"the-black-chip-bounty-tournament-is-officially-underway","excerpt":"💰 The Black Chip Bounty Tournament is officially underway with 5 tables of action and players still rolling in! 💥♠️ Late registration is open until 5 PM, so there’s still plenty of time to get in the game and start collecting bounties! 🔥 $1…","content":"💰 The Black Chip Bounty Tournament is officially underway with 5 tables of action and players still rolling in! 💥♠️ Late registration is open until 5 PM, so there’s still plenty of time to get in the game and start collecting bounties! 🔥 $100 bounty for every player you eliminate 🃏 $200 Buy-in – 20,000 starting chips ➕ Optional $100 add-on for 20,000 chips Get down here, grab a seat, and enjoy all the action at the Dakota Poker Tour Spring Championship weekend! Tune into the official live stream to watch the action unfold in the conclusion of the 100k deep-stack! Someone is taking home $8,000! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-05-17 14:00:00","featured":false,"logo":null,"banner":null,"videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":345,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2026-spring-championship-black-chip-bounty-05-17-2026"}}'::jsonb),
  (440, 'chips-are-officially-bagged-for-the-night-at-the-dakota-poker-tour-spring-championship-megastack', '♠️♦️ Chips are officially bagged for the night at the Dakota Poker Tour Spring Championship MEGASTACK! ♦️♠️', 'An incredible 134 players came out today to battle for their share of the massive $32,000 prize pool, and after a long day of action, only 31 players found a bag at the end of the night. With 18 players taking home cash! Play resumes Sunday…', '2026-05-17 01:13:00', null, 'dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026', 'https://dakotapokertour.com/storage/article/thumb/D52AE449-8145-4578-B156-12DAD8CAA542-hZsiZcH6.jpg', '/media/dpt/article/D52AE449-8145-4578-B156-12DAD8CAA542-hZsiZcH6.jpg', null, '{"id":440,"title":"♠️♦️ Chips are officially bagged for the night at the Dakota Poker Tour Spring Championship MEGASTACK! ♦️♠️","alias":"chips-are-officially-bagged-for-the-night-at-the-dakota-poker-tour-spring-championship-megastack","excerpt":"An incredible 134 players came out today to battle for their share of the massive $32,000 prize pool, and after a long day of action, only 31 players found a bag at the end of the night. With 18 players taking home cash! Play resumes Sunday…","content":"An incredible 134 players came out today to battle for their share of the massive $32,000 prize pool, and after a long day of action, only 31 players found a bag at the end of the night. With 18 players taking home cash! Play resumes Sunday at NOON at the DoubleTree in West Fargo as players return to chase the title and the big money! 🔥 End of Night Chip Leaders 🔥 1. Steve Zima – 1,276,000 2. Jackson Skjerseth – 1,084,000 3. Phu Troung – 812,000 4. Mike Anderson – 756,000 5. Bob Sylskar – 708,000 Good luck to everyone returning tomorrow! Complete chip counts and table re-draw Feature Table 1 - Charles Funfar 245,000 2 Dave & Jack Ouelette Dickinson ND 158,000 3 Steve Belland Bagley MN 279,000 4 Cody Krause Sioux Falls SD 147,000 5 Jack Ring 104,000 6 Ron Miller MN 160,000 7 Empty 8 Heidi Roggenkamp Fargo ND 112,000 9 Todd Knain Fargo ND 71,000 Table 9 1 Michael Bedney Grandforks ND 583,000 2 Chase Lardy Fargo ND 357,000 3 Empty 4 Paul Johnson 403,000 5 Bob Sylskar 708,000 6 Miles Barnum 627,000 7 Josh Lanzdorf west fargo ND 380,000 8 Eric Kassa Wahpeton ND 227,000 9 Empty Table 8 1 Chris Grey Fargo ND 527,000 2 Calvin Riggs West Fargo ND 637,000 3 Steve Zima 1,276,000 4 Wade Hendrickson 520,000 5 Duane Anderson 179,000 6 Phu Troung 812,000 7 Empty 8 Tony Uhlir Grandforks ND 583,000 9 Jackson Skjerseth 1,084,000 Table 7 1 Don Drummond 487,000 2 Brad Magnus Bismarck ND 357,000 3 Jeremy Holmes 357,000 4 Mike Anderson Detroit Lakes MN 756,000 5 Austin Christiansen 406,000 6 Dirk Gerds Fargo ND 271,000 7 Empty 8 Sid Jarrett Alexandria MN 156,000 9 Jason Kramer west Fargo ND 202,000","publishedAt":"2026-05-17 01:13:00","featured":true,"logo":"D52AE449-8145-4578-B156-12DAD8CAA542-hZsiZcH6.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/D52AE449-8145-4578-B156-12DAD8CAA542-hZsiZcH6.jpg","bannerUrl":"","tournament":{"id":344,"name":"Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026"}}'::jsonb),
  (438, 'live-stream-is-officially-underway', '♠️ LIVE STREAM IS OFFICIALLY UNDERWAY! ♠️🚨', 'The action is heating up at the Dakota Poker Tour Spring Championship! We are now up to 127 players and climbing with a prize pool already OVER $30,000!!! 💰🔥 Don’t miss your shot — late registration remains open until 9:30 PM with players s…', '2026-05-16 19:30:00', null, 'dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7396-1Hcx3o07.jpg', '/media/dpt/article/IMG_7396-1Hcx3o07.jpg', null, '{"id":438,"title":"♠️ LIVE STREAM IS OFFICIALLY UNDERWAY! ♠️🚨","alias":"live-stream-is-officially-underway","excerpt":"The action is heating up at the Dakota Poker Tour Spring Championship! We are now up to 127 players and climbing with a prize pool already OVER $30,000!!! 💰🔥 Don’t miss your shot — late registration remains open until 9:30 PM with players s…","content":"The action is heating up at the Dakota Poker Tour Spring Championship! We are now up to 127 players and climbing with a prize pool already OVER $30,000!!! 💰🔥 Don’t miss your shot — late registration remains open until 9:30 PM with players still getting a very playable stack! 🎥 Tune in now and catch all the action LIVE! Huge pots, tough decisions, and championship dreams on the line right here at the DoubleTree in West Fargo! Who’s making the final table tomorrow?","publishedAt":"2026-05-16 19:30:00","featured":false,"logo":"IMG_7396-1Hcx3o07.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7396-1Hcx3o07.jpg","bannerUrl":"","tournament":{"id":344,"name":"Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026"}}'::jsonb),
  (437, '109-players-at-the-spring-championship', '109 players at the Spring Championship', '♠️♦️♣️♥️ Poker players… YOU HAVE SHOWN UP AND SHOWN THE LOVE! ♥️♣️♦️♠️ We are up to 109 players and STILL GROWING here at the Dakota Poker Tour Spring Championship! 🔥 💰 Prize pool already over $25,000 🏆 1st place currently over $7,000 🎥 Off…', '2026-05-16 16:30:00', null, 'dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7270-DvcFYBdj.jpg', '/media/dpt/article/IMG_7270-DvcFYBdj.jpg', null, '{"id":437,"title":"109 players at the Spring Championship","alias":"109-players-at-the-spring-championship","excerpt":"♠️♦️♣️♥️ Poker players… YOU HAVE SHOWN UP AND SHOWN THE LOVE! ♥️♣️♦️♠️ We are up to 109 players and STILL GROWING here at the Dakota Poker Tour Spring Championship! 🔥 💰 Prize pool already over $25,000 🏆 1st place currently over $7,000 🎥 Off…","content":"♠️♦️♣️♥️ Poker players… YOU HAVE SHOWN UP AND SHOWN THE LOVE! ♥️♣️♦️♠️ We are up to 109 players and STILL GROWING here at the Dakota Poker Tour Spring Championship! 🔥 💰 Prize pool already over $25,000 🏆 1st place currently over $7,000 🎥 Official LIVE STREAM scheduled to begin after dinner break ⏰ Late registration remains open until 9 PM with 20 BIG BLINDS! Players will bag chips approximately around 11:30 PM tonight and return Sunday at 12 PM NOON to play down to a champion! Thank you to everyone coming out to support the Dakota Poker Tour, the West Fargo Fire Department, and our amazing volunteer dealers. The energy in this room has been incredible! Let’s keep building this. DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-05-16 16:30:00","featured":false,"logo":"IMG_7270-DvcFYBdj.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7270-DvcFYBdj.jpg","bannerUrl":"","tournament":{"id":344,"name":"Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026"}}'::jsonb),
  (436, '8-tables-at-the-spring-championship-registration-still-open', '8 tables at the Spring Championship, Registration still open', '♠️♦️ We are officially underway at the Dakota Poker Tour 100K Spring Championship ! ♦️♠️ Eight tables strong and growing here at the DoubleTree in West Fargo! Players are battling it out with 100,000 starting chips and 40-minute blind level…', '2026-05-16 12:00:00', null, 'dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7275-ChoelQE4.jpg', '/media/dpt/article/IMG_7275-ChoelQE4.jpg', null, '{"id":436,"title":"8 tables at the Spring Championship, Registration still open","alias":"8-tables-at-the-spring-championship-registration-still-open","excerpt":"♠️♦️ We are officially underway at the Dakota Poker Tour 100K Spring Championship ! ♦️♠️ Eight tables strong and growing here at the DoubleTree in West Fargo! Players are battling it out with 100,000 starting chips and 40-minute blind level…","content":"♠️♦️ We are officially underway at the Dakota Poker Tour 100K Spring Championship ! ♦️♠️ Eight tables strong and growing here at the DoubleTree in West Fargo! Players are battling it out with 100,000 starting chips and 40-minute blind levels in one of the biggest events of the spring. Still thinking about coming down? There’s still time! 🔥 Late registration is open until 9 PM tonight with 20 BB Come be part of the action and take your shot at a huge payout and the LIVE STREAM featured table! Good luck to all the players and thank you for supporting the Dakota Poker Tour and the West Fargo Fire Department! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-05-16 12:00:00","featured":false,"logo":"IMG_7275-ChoelQE4.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7275-ChoelQE4.jpg","bannerUrl":"","tournament":{"id":344,"name":"Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2026-spring-championship-spring-championship-megastack-100k-05-16-2026"}}'::jsonb),
  (435, 'mark-alinder-of-fargo-takes-home-3100-friday-night-turbo-champion', 'Mark Alinder of Fargo takes home $3100, Friday Night Turbo Champion', 'Congratulations to Mark Alinder of West Fargo, ND, your Friday Night Turbo Champion at the Dakota Poker Tour Spring Championship! ♠️♦️♣️♥️ Thank you to all the players who came out tonight to support the Dakota Poker Tour and our charity pa…', '2026-05-16 01:00:00', null, 'dakota-poker-tour-2026-spring-championship-friday-night-turbo-05-15-2026', 'https://dakotapokertour.com/storage/article/thumb/5895-2ZFJwJk1.jpg', '/media/dpt/article/5895-2ZFJwJk1.jpg', null, '{"id":435,"title":"Mark Alinder of Fargo takes home $3100, Friday Night Turbo Champion","alias":"mark-alinder-of-fargo-takes-home-3100-friday-night-turbo-champion","excerpt":"Congratulations to Mark Alinder of West Fargo, ND, your Friday Night Turbo Champion at the Dakota Poker Tour Spring Championship! ♠️♦️♣️♥️ Thank you to all the players who came out tonight to support the Dakota Poker Tour and our charity pa…","content":"Congratulations to Mark Alinder of West Fargo, ND, your Friday Night Turbo Champion at the Dakota Poker Tour Spring Championship! ♠️♦️♣️♥️ Thank you to all the players who came out tonight to support the Dakota Poker Tour and our charity partner, the West Fargo Rural Fire Department. The energy in the room was incredible! We also want to give a huge thank you to our volunteer dealers. Without your time, dedication, and hard work, events like this would not be possible. We truly appreciate everything you do for our players and the game. We can’t wait to see everyone back for the 100K MEGASTACK with 40-minute blinds and the OFFICIAL LIVE STREAM EVENT! Cards are back in the air at 11 AM! $3100 Mark Alinder Fargo ND $2100 Travis Lynde Lake Park MN $1400 Wade Hendrickson Cando ND $1200 Wade Schlecht Streeter ND $1000 Ryan Belen Moorhead MN $750 Ademar Moraes Moorhead MN $650 Jacob Amble Bemidji MN $550 Brad Thompson Moorhead MN $450 Robert “Muzz” Anderson Winnipeg MB DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-05-16 01:00:00","featured":true,"logo":"5895-2ZFJwJk1.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/5895-2ZFJwJk1.jpg","bannerUrl":"","tournament":{"id":343,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2026-spring-championship-friday-night-turbo-05-15-2026"}}'::jsonb),
  (434, 'registration-closed-for-the-friday-night-turbo-with-58-players', 'Registration Closed for the Friday Night Turbo with 58 Players', 'Registration is officially CLOSED for tonight’s Friday Night Turbo at the Dakota Poker Tour Spring Championship! ♠️♦️♣️♥️ 58 players came out tonight, generating an $11,200 prize pool! Thank you to everyone who came out to support the Dakot…', '2026-05-15 21:00:00', null, 'dakota-poker-tour-2026-spring-championship-friday-night-turbo-05-15-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7264-0vhRdalH.jpg', '/media/dpt/article/IMG_7264-0vhRdalH.jpg', null, '{"id":434,"title":"Registration Closed for the Friday Night Turbo with 58 Players","alias":"registration-closed-for-the-friday-night-turbo-with-58-players","excerpt":"Registration is officially CLOSED for tonight’s Friday Night Turbo at the Dakota Poker Tour Spring Championship! ♠️♦️♣️♥️ 58 players came out tonight, generating an $11,200 prize pool! Thank you to everyone who came out to support the Dakot…","content":"Registration is officially CLOSED for tonight’s Friday Night Turbo at the Dakota Poker Tour Spring Championship! ♠️♦️♣️♥️ 58 players came out tonight, generating an $11,200 prize pool! Thank you to everyone who came out to support the Dakota Poker Tour and the West Fargo Rural Fire Department. We appreciate all of the players, staff, and volunteer dealers who help make these events possible. We can’t wait to see everyone back tomorrow for the DPT Spring Championship MEGASTACK (100K) — our OFFICIAL LIVE STREAM EVENT! Saturday – May 16, 2026 🕥 Registration Opens: 10:30 AM 🃏 Cards in the Air: 11 AM • $300 Buy-in – 100,000 starting chips • 40-minute blind levels • Dinner Break: 6PM – 7PM • Late Registration open until 9:30 PM with 20bb Players will bag chips at the end of Level 15 and return Sunday at NOON. Suggested dealer appreciation is $30. Tips are appreciated but never required. See you tomorrow for a huge day of poker DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-05-15 21:00:00","featured":false,"logo":"IMG_7264-0vhRdalH.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7264-0vhRdalH.jpg","bannerUrl":"","tournament":{"id":343,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2026-spring-championship-friday-night-turbo-05-15-2026"}}'::jsonb),
  (433, 'friday-night-turbo-is-underway', 'Friday Night Turbo is Underway', '🚨 SIX TABLES RUNNING and the room is PACKED at the DoubleTree in West Fargo! ♠️♦️♣️♥️ The Dakota Poker Tour has officially taken over for an epic weekend of poker action and players are rolling in fast! 🔥 Friday Night Turbo is underway ⏰ La…', '2026-05-15 19:00:00', null, 'dakota-poker-tour-2026-spring-championship-friday-night-turbo-05-15-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_7228-FrqJt7uW.jpg', '/media/dpt/article/IMG_7228-FrqJt7uW.jpg', null, '{"id":433,"title":"Friday Night Turbo is Underway","alias":"friday-night-turbo-is-underway","excerpt":"🚨 SIX TABLES RUNNING and the room is PACKED at the DoubleTree in West Fargo! ♠️♦️♣️♥️ The Dakota Poker Tour has officially taken over for an epic weekend of poker action and players are rolling in fast! 🔥 Friday Night Turbo is underway ⏰ La…","content":"🚨 SIX TABLES RUNNING and the room is PACKED at the DoubleTree in West Fargo! ♠️♦️♣️♥️ The Dakota Poker Tour has officially taken over for an epic weekend of poker action and players are rolling in fast! 🔥 Friday Night Turbo is underway ⏰ Late Registration & Rebuys/Add-Ons available until 8:15 PM 💰 $100 buy-in = 15,000 chips ⏱️ 20-minute levels 💵 $100 rebuys/add-ons for 15,000 chips 💥 Max buy-in: $300 If you’re thinking about coming out, NOW is the time. Plenty of action, big stacks flying, and an awesome crowd already in the room. Get down here and take your shot! Suggested dealer appreciation is $20 — tips appreciated but never required. DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapoker","publishedAt":"2026-05-15 19:00:00","featured":false,"logo":"IMG_7228-FrqJt7uW.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7228-FrqJt7uW.jpg","bannerUrl":"","tournament":{"id":343,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2026-spring-championship-friday-night-turbo-05-15-2026"}}'::jsonb),
  (432, 'congratulations-to-clint-otto-of-jamestown-nd-casselton-vets-champion', 'Congratulations to Clint Otto of Jamestown ND Casselton Vets Champion', 'Congratulations to Clint Otto of Jamestown ND on taking down the Casselton Vets Deep Stack and earning $5,300 after a modified chop! 👏 What an incredible turnout. 80 players packed the room, building a $18,960 prize pool and raising an amaz…', '2026-04-19 00:17:00', null, 'dakota-poker-tour-2026-casselton-vets-deep-stack-04-18-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_6806-ZhJShTta.jpg', '/media/dpt/article/IMG_6806-ZhJShTta.jpg', null, '{"id":432,"title":"Congratulations to Clint Otto of Jamestown ND Casselton Vets Champion","alias":"congratulations-to-clint-otto-of-jamestown-nd-casselton-vets-champion","excerpt":"Congratulations to Clint Otto of Jamestown ND on taking down the Casselton Vets Deep Stack and earning $5,300 after a modified chop! 👏 What an incredible turnout. 80 players packed the room, building a $18,960 prize pool and raising an amaz…","content":"Congratulations to Clint Otto of Jamestown ND on taking down the Casselton Vets Deep Stack and earning $5,300 after a modified chop! 👏 What an incredible turnout. 80 players packed the room, building a $18,960 prize pool and raising an amazing $4,700 for the Casselton Vets Club. This is what it’s all about… great poker, great people, and giving back. 🇺🇸 Huge thank you to all the players who came out to support, and to our volunteer dealers, we truly couldn’t do this without you. Special shoutout to Heidi S Roggenkamp owner of Randy’s Diner and a longtime supporter, for generously providing dinner for all the dealers. And to the Vets Club for taking care of our veterans with dinner, class all the way. ❤️ 📅 Save the Date: DPT Spring Championship – May 15–17 $300 Buy-in | 100K Starting Stack | 40-Minute Levels 🎥 Official LIVE STREAM Final Table 🏆 Final Results: 1st – $5,300 Clint Otto Jamestown, ND 2nd – $3,760 Michael Headland Jamestown ND 3rd – $2,760 Holden Kastet Jamestown, ND 4th – $1,900 Dirk Gerdes West Fargo, ND 5th – $1,520 Wade Kyser Erie, ND 6th – $1,280 Kim Rasmussen Forman, ND 7th – $1,040 Adam Landerth Grand Forks, ND 8th – $800 Marcy Schultz Grand Forks, ND 9th – $600 Scott Vance Casselton, ND Who’s ready to run it back in May? ♠️♦️♣️♥️ DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-04-19 00:17:00","featured":true,"logo":"IMG_6806-ZhJShTta.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_6806-ZhJShTta.jpg","bannerUrl":"","tournament":{"id":342,"name":"Deep Stack","alias":"dakota-poker-tour-2026-casselton-vets-deep-stack-04-18-2026"}}'::jsonb),
  (430, 'casselton-deep-stack-big-field-big-money', 'Casselton Deep Stack — Big Field, Big Money ♠️💰', 'Registration is CLOSED for tonight’s Deep Stack at the Casselton Vets Club with a strong turnout of 80 players generating a 💰 $18,960 prize pool! Even better… YOU helped raise 🇺🇸 $4,700 for the Vets Club — absolutely incredible support! 👏 🙏…', '2026-04-18 19:46:00', null, 'dakota-poker-tour-2026-casselton-vets-deep-stack-04-18-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_6799-FMb1Z73v.jpg', '/media/dpt/article/IMG_6799-FMb1Z73v.jpg', null, '{"id":430,"title":"Casselton Deep Stack — Big Field, Big Money ♠️💰","alias":"casselton-deep-stack-big-field-big-money","excerpt":"Registration is CLOSED for tonight’s Deep Stack at the Casselton Vets Club with a strong turnout of 80 players generating a 💰 $18,960 prize pool! Even better… YOU helped raise 🇺🇸 $4,700 for the Vets Club — absolutely incredible support! 👏 🙏…","content":"Registration is CLOSED for tonight’s Deep Stack at the Casselton Vets Club with a strong turnout of 80 players generating a 💰 $18,960 prize pool! Even better… YOU helped raise 🇺🇸 $4,700 for the Vets Club — absolutely incredible support! 👏 🙏 Huge thank you to all the players who came out and battled, and to our volunteer dealers — we truly couldn’t run these events without you! 🍽️ Special shoutout to Heidi Roggenkamp, owner of Randy’s Diner and longtime supporter, for treating all of our dealers to dinner tonight — above and beyond! 🇺🇸 And thank you to the Casselton Vets Club for providing dinner for all veterans — an amazing gesture! ♠️ Now it’s down to business… 🏆 Tonight’s Champion will take home $5,600 CASH 💵 Who’s making the run?! 👀🔥 DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour #DPTPoker #CasseltonVets #DeepStack #PokerLife #SupportOurVets ♠️♦️♣️♥️","publishedAt":"2026-04-18 19:46:00","featured":false,"logo":"IMG_6799-FMb1Z73v.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_6799-FMb1Z73v.jpg","bannerUrl":"","tournament":{"id":342,"name":"Deep Stack","alias":"dakota-poker-tour-2026-casselton-vets-deep-stack-04-18-2026"}}'::jsonb),
  (431, 'it-s-a-full-house-at-the-castleton-vets-club', 'It’s a Full House at the Castleton Vets Club', 'Hey poker players — it’s a full house at the Casselton Vets Club! We’ve got 8 tables going with room to grow, and we’re playing upstairs in the main bar! The lighting is good and the play is questionable. 😎♠️ We’re only an hour in, and late…', '2026-04-18 13:15:00', null, 'dakota-poker-tour-2026-casselton-vets-deep-stack-04-18-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_6798-M1iYZhia.jpg', '/media/dpt/article/IMG_6798-M1iYZhia.jpg', null, '{"id":431,"title":"It’s a Full House at the Castleton Vets Club","alias":"it-s-a-full-house-at-the-castleton-vets-club","excerpt":"Hey poker players — it’s a full house at the Casselton Vets Club! We’ve got 8 tables going with room to grow, and we’re playing upstairs in the main bar! The lighting is good and the play is questionable. 😎♠️ We’re only an hour in, and late…","content":"Hey poker players — it’s a full house at the Casselton Vets Club! We’ve got 8 tables going with room to grow, and we’re playing upstairs in the main bar! The lighting is good and the play is questionable. 😎♠️ We’re only an hour in, and late registration is open until 5 PM! It’s DEEP STACK DAY at the Casselton Vets Club! Bigger stacks, more play, and plenty of time to make a run at the cash. If you missed last night or want another shot, get here and get in the action. 🔥💰 🕛 Cards in the Air: NOON ⏰ Late Registration: Open until 5 PM 🏆 SATURDAY SINGLE DAY EVENT – 4/18/2026 🏆 • $150 buy-in – 20,000 chips • 30-minute levels • $50 add-ons for 10K (up to 3x, max $300) • Add-ons anytime, even at the start and for re-entry • Late reg/re-entry open through dinner break (~5 PM) 🍝 SATURDAY DINNER BREAK SPECIAL 🍝 Spaghetti, bread, and side salad for just $8 Gluten-free available 🇺🇸 Vets eat FREE – thank you for your service! 💵 $20 suggested dealer appreciation – optional but always appreciated Big stacks. Big plays. Big payouts. Who’s making a run today? 👀♠️♦️♣️♥️ DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube: https://youtube.com/@dakota","publishedAt":"2026-04-18 13:15:00","featured":false,"logo":"IMG_6798-M1iYZhia.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_6798-M1iYZhia.jpg","bannerUrl":"","tournament":{"id":342,"name":"Deep Stack","alias":"dakota-poker-tour-2026-casselton-vets-deep-stack-04-18-2026"}}'::jsonb),
  (429, 'deep-stack-day-at-the-casselton-vets-club', 'DEEP STACK DAY at the Casselton Vets Club! 🔥', '♠️♦️ CALLING ALL POKER PLAYERS ♦️♣️ The chips are stacked and the cards are ready… it’s DEEP STACK DAY at the Casselton Vets Club! 🔥 🕛 Cards in the Air at NOON ⏰ Late Registration open until 5 PM If you missed last night or want another sho…', '2026-04-18 10:35:00', null, 'dakota-poker-tour-2026-casselton-vets-deep-stack-04-18-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_6690-fJB6BS1U.jpg', '/media/dpt/article/IMG_6690-fJB6BS1U.jpg', null, '{"id":429,"title":"DEEP STACK DAY at the Casselton Vets Club! 🔥","alias":"deep-stack-day-at-the-casselton-vets-club","excerpt":"♠️♦️ CALLING ALL POKER PLAYERS ♦️♣️ The chips are stacked and the cards are ready… it’s DEEP STACK DAY at the Casselton Vets Club! 🔥 🕛 Cards in the Air at NOON ⏰ Late Registration open until 5 PM If you missed last night or want another sho…","content":"♠️♦️ CALLING ALL POKER PLAYERS ♦️♣️ The chips are stacked and the cards are ready… it’s DEEP STACK DAY at the Casselton Vets Club! 🔥 🕛 Cards in the Air at NOON ⏰ Late Registration open until 5 PM If you missed last night or want another shot at a big run—this is your tournament. More chips, more play, more chances to build a stack and make a run at the cash! 💰 🍝 SATURDAY DINNER BREAK SPECIAL 🍝 Spaghetti, bread & side salad just $8 (gluten-free available) 🇺🇸 VETS EAT FREE – thank you for your service! 🏆 SATURDAY SINGLE DAY EVENT – 4/18/2026 🏆 • $150 buy-in – 20,000 chips • 30-minute levels • $50 add-ons for 10K (up to 3x, max $300) • Add-ons anytime (even at the start & for re-entry) • Late reg/re-entry open through dinner break (~5 PM) 💵 $20 suggested dealer appreciation – optional but always appreciated Big stacks. Big plays. Big payouts. Don’t miss your seat at the table. Who’s making a run today? 👀♠️♦️♣️♥️ DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube: https://yo