  (394, 'dakota-poker-tour-has-arrived-at-m-j-saloon-in-west-fargo', 'Dakota Poker Tour has arrived at M&J Saloon in West Fargo', 'Dakota Poker Tour has arrived at M&J Saloon in West Fargo, North Dakota for the Dead Money Open! ♠️ Come out and join us for a Friday Night Turbo: • Registration opens at 5:00 PM • Cards in the air at 6:00 PM • 20-minute blinds • Late regis…', '2026-01-30 12:00:00', null, 'dakota-poker-tour-2026-dead-money-open-friday-night-turbo-01-30-2026', 'https://dakotapokertour.com/storage/article/thumb/625345834_1557684043025335_6356642423505752983_n-xdasf0Pk.jpg', '/media/dpt/article/625345834_1557684043025335_6356642423505752983_n-xdasf0Pk.jpg', null, '{"id":394,"title":"Dakota Poker Tour has arrived at M&J Saloon in West Fargo","alias":"dakota-poker-tour-has-arrived-at-m-j-saloon-in-west-fargo","excerpt":"Dakota Poker Tour has arrived at M&J Saloon in West Fargo, North Dakota for the Dead Money Open! ♠️ Come out and join us for a Friday Night Turbo: • Registration opens at 5:00 PM • Cards in the air at 6:00 PM • 20-minute blinds • Late regis…","content":"Dakota Poker Tour has arrived at M&J Saloon in West Fargo, North Dakota for the Dead Money Open! ♠️ Come out and join us for a Friday Night Turbo: • Registration opens at 5:00 PM • Cards in the air at 6:00 PM • 20-minute blinds • Late registration until 8:20PM Buy-in details: • $100 buy-in for 15,000 tournament chips • $100 re-buys/add-on for 15,000 chips (available until registration closes at 8:20PM) Max buyin $300 • Suggested dealer appreciation $20 • Tips are appreciated but not required to play Come out for a fun Friday night, play some great poker, and support West Fargo Hockey! 🏒","publishedAt":"2026-01-30 12:00:00","featured":false,"logo":"625345834_1557684043025335_6356642423505752983_n-xdasf0Pk.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/625345834_1557684043025335_6356642423505752983_n-xdasf0Pk.jpg","bannerUrl":"","tournament":{"id":332,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2026-dead-money-open-friday-night-turbo-01-30-2026"}}'::jsonb),
  (393, 'wade-kyser-of-erie-nd-is-your-eagle-eye-champion', 'Wade Kyser of Erie, ND is your Eagle Eye Champion! 🏆♠️', 'Wade Kyser of Erie, ND is your Eagle Eye Champion! 🏆♠️ Wade is a long-time supporter of the Dakota Poker Tour, and tonight he claimed victory in a big way, battling through 63 players and taking down one stacked final table! This final tabl…', '2026-01-25 01:55:00', null, 'dakota-poker-tour-2026-eagle-eye-eagle-eye-01-24-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_4925-0FuMa0U1.jpg', '/media/dpt/article/IMG_4925-0FuMa0U1.jpg', null, '{"id":393,"title":"Wade Kyser of Erie, ND is your Eagle Eye Champion! 🏆♠️","alias":"wade-kyser-of-erie-nd-is-your-eagle-eye-champion","excerpt":"Wade Kyser of Erie, ND is your Eagle Eye Champion! 🏆♠️ Wade is a long-time supporter of the Dakota Poker Tour, and tonight he claimed victory in a big way, battling through 63 players and taking down one stacked final table! This final tabl…","content":"Wade Kyser of Erie, ND is your Eagle Eye Champion! 🏆♠️ Wade is a long-time supporter of the Dakota Poker Tour, and tonight he claimed victory in a big way, battling through 63 players and taking down one stacked final table! This final table was truly a who’s who of championship titles, and when the last chips fell, Wade walked away with $4,700 and the first trophy of the 2026 season! 🔥 Final Table Payouts: 2nd – $2,960 Jamie Meidinger (Jamestown, ND) 3rd – $2,340 Kent Gronlie (Valley City, ND) 4th – $1,780 Basim Habib (Cottage Grove, WI) 5th – $1,360 Lindsey Hanson (Fargo, ND) 6th – $1,100 Travis Severson (Sanborn, ND) 7th – $900 Niles Short (Minnewauken, ND) 8th – $700 Joel Smith (Henning MN) 9th – $180 Tim Scott (Bubble) Thank you again to everyone who came out to support the Dakota Poker Tour and the Valley City Eagles Club — we appreciate each and every one of you! ❤️ Next Stop: Dead Money Open West Fargo, North Dakota We’ll see you next weekend! 🔥♠️ DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-01-25 01:55:00","featured":true,"logo":"IMG_4925-0FuMa0U1.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_4925-0FuMa0U1.jpg","bannerUrl":"","tournament":{"id":331,"name":"Eagle Eye","alias":"dakota-poker-tour-2026-eagle-eye-eagle-eye-01-24-2026"}}'::jsonb),
  (392, 'eagle-eye-final-table', 'Eagle Eye Final Table', 'Congratulations to your final table at the Eagle Eye Poker Tournament! ♠️🦅 A total of 63 players braved the freezing temperatures to battle it out for a $4,700 first-place prize at the Valley City Eagles Club, and the action did not disappo…', '2026-01-24 22:38:00', null, 'dakota-poker-tour-2026-eagle-eye-eagle-eye-01-24-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_4904-4f1Sggzo.jpg', '/media/dpt/article/IMG_4904-4f1Sggzo.jpg', null, '{"id":392,"title":"Eagle Eye Final Table","alias":"eagle-eye-final-table","excerpt":"Congratulations to your final table at the Eagle Eye Poker Tournament! ♠️🦅 A total of 63 players braved the freezing temperatures to battle it out for a $4,700 first-place prize at the Valley City Eagles Club, and the action did not disappo…","content":"Congratulations to your final table at the Eagle Eye Poker Tournament! ♠️🦅 A total of 63 players braved the freezing temperatures to battle it out for a $4,700 first-place prize at the Valley City Eagles Club, and the action did not disappoint! Here are your final table payouts: 1st – $4,700 2nd – $2,960 3rd – $2,340 4th – $1,780 5th – $1,360 6th – $1,100 7th – $900 8th – $700 Thank you again to everyone who came out to support the Dakota Poker Tour and the Valley City Eagles Club, we appreciate every one of you! 📍 Next Stop: Dead Money Open West Fargo, North Dakota We’ll see you next weekend! 🔥♠️","publishedAt":"2026-01-24 22:38:00","featured":false,"logo":"IMG_4904-4f1Sggzo.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_4904-4f1Sggzo.jpg","bannerUrl":"","tournament":{"id":331,"name":"Eagle Eye","alias":"dakota-poker-tour-2026-eagle-eye-eagle-eye-01-24-2026"}}'::jsonb),
  (391, 'registration-is-officially-closed-for-tonight-at-the-valley-city-eagles', 'Registration is officially CLOSED for tonight at the Valley City Eagles 🦅♠️', 'The Eagle Eye Tournament drew 63 players and generated a total prize pool of nearly $16,000! THANK YOU to everyone who came out to support the Valley City Eagles and the Dakota Poker Tour — we truly appreciate you all! 🙌🔥 🏆 1st Place Champi…', '2026-01-24 18:15:00', null, 'dakota-poker-tour-2026-eagle-eye-eagle-eye-01-24-2026', 'https://dakotapokertour.com/storage/article/thumb/IMG_4861-JyLeeWtJ.png', '/media/dpt/article/IMG_4861-JyLeeWtJ.png', null, '{"id":391,"title":"Registration is officially CLOSED for tonight at the Valley City Eagles 🦅♠️","alias":"registration-is-officially-closed-for-tonight-at-the-valley-city-eagles","excerpt":"The Eagle Eye Tournament drew 63 players and generated a total prize pool of nearly $16,000! THANK YOU to everyone who came out to support the Valley City Eagles and the Dakota Poker Tour — we truly appreciate you all! 🙌🔥 🏆 1st Place Champi…","content":"The Eagle Eye Tournament drew 63 players and generated a total prize pool of nearly $16,000! THANK YOU to everyone who came out to support the Valley City Eagles and the Dakota Poker Tour — we truly appreciate you all! 🙌🔥 🏆 1st Place Champion will be taking home $4,700 💰 What a way to kick things off — the 2026 season is off to a GREAT start! 🚀🎉 📍 Up Next: Next weekend we’re headed to M&J Saloon in Fargo, North Dakota! ♠️ Friday Night Turbo — $100 buy-in ♠️ Saturday Main Event Can’t wait to see you all there! 🔥♠️💙 📊 DPT Leaderboard: dakotapokertour.com/leaderboard 📅 DPT Calendar: dakotapokertour.com/calendar 🎥 DPT YouTube Channel: youtube.com/@dakotapokertour","publishedAt":"2026-01-24 18:15:00","featured":false,"logo":"IMG_4861-JyLeeWtJ.png","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_4861-JyLeeWtJ.png","bannerUrl":"","tournament":{"id":331,"name":"Eagle Eye","alias":"dako