  (389, 'update-from-valley-city-eagles-club', '♠️🔥 Update from Valley City Eagles Club!', '🔥♠️ We’re up to 60 players and still plenty of room to grow! 🙌 Registration is OPEN until 5:00 PM, so it’s not too late to jump in and make your run! 💰 Buy-In Details: ✅ $150 = 20,000 tournament chips ➕ Every additional $50 = +10,000 chips…', '2026-01-24 15:25:00', null, 'dakota-poker-tour-2026-eagle-eye-eagle-eye-01-24-2026', 'https://dakotapokertour.com/storage/article/thumb/vc2-5n79Fhra.jpg', '/media/dpt/article/vc2-5n79Fhra.jpg', null, '{"id":389,"title":"♠️🔥 Update from Valley City Eagles Club!","alias":"update-from-valley-city-eagles-club","excerpt":"🔥♠️ We’re up to 60 players and still plenty of room to grow! 🙌 Registration is OPEN until 5:00 PM, so it’s not too late to jump in and make your run! 💰 Buy-In Details: ✅ $150 = 20,000 tournament chips ➕ Every additional $50 = +10,000 chips…","content":"🔥♠️ We’re up to 60 players and still plenty of room to grow! 🙌 Registration is OPEN until 5:00 PM, so it’s not too late to jump in and make your run! 💰 Buy-In Details: ✅ $150 = 20,000 tournament chips ➕ Every additional $50 = +10,000 chips 🎯 Max buy-in $300 = 50,000 tournament chips ⏱️ 30-minute blind levels DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2026-01-24 15:25:00","featured":false,"logo":"vc2-5n79Fhra.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/vc2-5n79Fhra.jpg","bannerUrl":"","tournament":{"id":331,"name":"Eagle Eye","alias":"dakota-poker-tour-2026-eagle-eye-eagle-eye-01-24-2026"}}'::jsonb),
  (388, 'jackson-your-operation-red-white-bluff-champion', 'Jackson Your Operation Red, White & Bluff Champion! 🇺🇸♠️', '🎉 Congratulations Jackson — Your Operation Red, White & Bluff Champion! 🇺🇸♠️ What. A. Finish. 🔥 After an absolutely epic heads-up battle between Jackson and Kim Rasmussen, the chips finally swung Jackson’s way — and he closed it out like a…', '2025-11-15 23:59:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3983-uOZp5eya.jpg', '/media/dpt/article/IMG_3983-uOZp5eya.jpg', null, '{"id":388,"title":"Jackson Your Operation Red, White & Bluff Champion! 🇺🇸♠️","alias":"jackson-your-operation-red-white-bluff-champion","excerpt":"🎉 Congratulations Jackson — Your Operation Red, White & Bluff Champion! 🇺🇸♠️ What. A. Finish. 🔥 After an absolutely epic heads-up battle between Jackson and Kim Rasmussen, the chips finally swung Jackson’s way — and he closed it out like a…","content":"🎉 Congratulations Jackson — Your Operation Red, White & Bluff Champion! 🇺🇸♠️ What. A. Finish. 🔥 After an absolutely epic heads-up battle between Jackson and Kim Rasmussen, the chips finally swung Jackson’s way — and he closed it out like a true champ! 💪🃏 Jackson is officially your Operation Red, White & Bluff Champion, taking home a well-earned $4,000 in cash… and marking his SECOND championship win here at the Casselton Vets Club! 👑💵 Kim Rasmussen put up an incredible fight and made the final duel one to remember — hats off to both players for a fantastic finish. ⚡️ Thank you to everyone who came out to support the Casselton Vets Club and the Dakota Poker Tour. 1st $4000 Jackson Sjkerseth Fargo ND 2nd $2400 Kim Rasmussen Forman ND 3rd $1900 Katy Fredrickson Carrington ND 4th $ 1500 Wade Kyser Erie ND 5th $1200 Joshua Jordan West Fargo 6th $1000Joel Klipping red Lake Falls, MN 7th $800Jon Wurden Fisher MN 8th $600 Julie Wadena Mahnomen, Mn DPT Leaderboard: dakotapokertour.com/leaderboard DPT Calendar: dakotapokertour.com/calendar DPT YouTube Channel:youtube.com/@dakotapokertour #DakotaPokerTour #OperationPoker #RedWhiteAndBluff #Casselton #VeteransDay #PokerEvent #NorthDakotaPoker #HonoringHeroes","publishedAt":"2025-11-15 23:59:00","featured":true,"logo":"IMG_3983-uOZp5eya.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3983-uOZp5eya.jpg","bannerUrl":"","tournament":{"id":330,"name":"Operation Red White & Bluff","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025"}}'::jsonb),
  (387, 'operation-red-white-bluff-final-table', '🏆 Operation Red White & Bluff — Final Table!', 'Congratulations to the Final Table at the Casselton Vets Club! 🇺🇸♠️ Operation Red White & Bluff has been an incredible event, and we’re down to the final table! Congratulations to the players who battled through a 58-player field to earn th…', '2025-11-15 20:25:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3978-7AtznfoY.jpg', '/media/dpt/article/IMG_3978-7AtznfoY.jpg', null, '{"id":387,"title":"🏆 Operation Red White & Bluff — Final Table!","alias":"operation-red-white-bluff-final-table","excerpt":"Congratulations to the Final Table at the Casselton Vets Club! 🇺🇸♠️ Operation Red White & Bluff has been an incredible event, and we’re down to the final table! Congratulations to the players who battled through a 58-player field to earn th…","content":"Congratulations to the Final Table at the Casselton Vets Club! 🇺🇸♠️ Operation Red White & Bluff has been an incredible event, and we’re down to the final table! Congratulations to the players who battled through a 58-player field to earn their spot under the lights tonight. Thank you to everyone who came out to support the Casselton Vets Club and the Dakota Poker Tour — what an amazing turnout and energy all day long! Good luck to the finalists… time to play for the big money! 💰🔥 ♣️♥️♠️♦️ Jon Wurden Fisher MN Joel Klipping Red Lake Falls MN Andrew Ryan Fargo ND Kim Rasmussen, Forman, ND Joshua Jordan West Fargo, ND￼ Julie Wadena Mahnomen MN Jackson Skjerseth Fargo ND Wade Kyser Erie ND Kathy Fredrickson 📊 DPT Leaderboard: dakotapokertour.com/leaderboard 📅 DPT Calendar: dakotapokertour.com/calendar 🎥 DPT YouTube Channel: youtube.com/@dakotapokertour #DakotaPokerTour #OperationPoker #RedWhiteAndBluff #Casselton #VeteransDay #PokerEvent #NorthDakotaPoker #HonoringHeroes","publishedAt":"2025-11-15 20:25:00","featured":false,"logo":"IMG_3978-7AtznfoY.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3978-7AtznfoY.jpg","bannerUrl":"","tournament":{"id":330,"name":"Operation Red White & Bluff","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025"}}'::jsonb),
  (386, 'kim-rasmussen-your-chip-leader-as-registration-closes', 'Kim Rasmussen, Your Chip leader  as Registration Closes', 'Registration is officially closed tonight at the Casselton Vets Club! 🇺🇸♠️ We had an awesome turnout with 58 players, building a $13,400 prize pool! Tonight’s winner will be taking home a $4,000 cash payout. 💰🔥 Your chip leader after the di…', '2025-11-15 17:45:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3973-5TekJ52d.jpg', '/media/dpt/article/IMG_3973-5TekJ52d.jpg', null, '{"id":386,"title":"Kim Rasmussen, Your Chip leader  as Registration Closes","alias":"kim-rasmussen-your-chip-leader-as-registration-closes","excerpt":"Registration is officially closed tonight at the Casselton Vets Club! 🇺🇸♠️ We had an awesome turnout with 58 players, building a $13,400 prize pool! Tonight’s winner will be taking home a $4,000 cash payout. 💰🔥 Your chip leader after the di…","content":"Registration is officially closed tonight at the Casselton Vets Club! 🇺🇸♠️ We had an awesome turnout with 58 players, building a $13,400 prize pool! Tonight’s winner will be taking home a $4,000 cash payout. 💰🔥 Your chip leader after the dinner break is Kim Rasmussen, sitting on over 300,000 chips! 🏆💥 A huge thank-you to everyone who came out to support the Casselton Vets Club and the Dakota Poker Tour. Good luck to the players still in the hunt! ♣️♥️♠️♦️ 📊 DPT Leaderboard: dakotapokertour.com/leaderboard 📅 DPT Calendar: dakotapokertour.com/calendar 🎥 DPT YouTube Channel: youtube.com/@dakotapokertour #DakotaPokerTour #OperationPoker #RedWhiteAndBluff #Casselton #VeteransDay #PokerEvent #NorthDakotaPoker #HonoringHeroes","publishedAt":"2025-11-15 17:45:00","featured":false,"logo":"IMG_3973-5TekJ52d.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3973-5TekJ52d.jpg","bannerUrl":"","tournament":{"id":330,"name":"Operation Red White & Bluff","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025"}}'::jsonb),
  (385, 'operation-red-white-bluff-today', '🇺🇸 OPERATION RED WHITE & BLUFF – TODAY!', 'Cards are in the air at the Casselton Vets Club! 🇺🇸♠️ Operation Red White & Bluff is underway as we honor our veterans today. We’ve already got six tables going strong, and there’s plenty of room for more players. Come out, play some poker,…', '2025-11-15 12:57:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3938-gaMq9iwa.jpg', '/media/dpt/article/IMG_3938-gaMq9iwa.jpg', null, '{"id":385,"title":"🇺🇸 OPERATION RED WHITE & BLUFF – TODAY!","alias":"operation-red-white-bluff-today","excerpt":"Cards are in the air at the Casselton Vets Club! 🇺🇸♠️ Operation Red White & Bluff is underway as we honor our veterans today. We’ve already got six tables going strong, and there’s plenty of room for more players. Come out, play some poker,…","content":"Cards are in the air at the Casselton Vets Club! 🇺🇸♠️ Operation Red White & Bluff is underway as we honor our veterans today. We’ve already got six tables going strong, and there’s plenty of room for more players. Come out, play some poker, and support the Casselton Vets Club! 🕚 Registration Opens: 11AM 🃏 Cards in the Air: NOON 💰 $150 Buy-In = 20K Chips | 30-Minute Levels ➕ $50 Add-On = 10K Chips (up to 3 times, max buy-in $300) 🍽️ Late Reg, Re-Entry & Add-Ons open through dinner break (~5PM) 💵 Suggested Dealer Appreciation: $20 (tips appreciated but not required) Come join the action! 🇺🇸♣️♥️♠️♦️ 📊 DPT Leaderboard: dakotapokertour.com/leaderboard 📅 DPT Calendar: dakotapokertour.com/calendar 🎥 DPT YouTube Channel: youtube.com/@dakotapokertour #DakotaPokerTour #OperationPoker #RedWhiteAndBluff #Casselton #VeteransDay #PokerEvent #NorthDakotaPoker #HonoringHeroes","publishedAt":"2025-11-15 12:57:00","featured":false,"logo":"IMG_3938-gaMq9iwa.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3938-gaMq9iwa.jpg","bannerUrl":"","tournament":{"id":330,"name":"Operation Red White & Bluff","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025"}}'::jsonb),
  (384, 'congratulations-bruce-wheeler', '🎉 Congratulations Bruce Wheeler! 🎉', 'What a night at the Casselton Vets Club Friday Night Turbo! A huge shoutout to Bruce Wheeler of Casselton, ND, who battled through a field of 47 players and came out on top, taking home a well-earned $2,500! We’d also like to extend a heart…', '2025-11-15 01:15:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-14-2025', 'https://dakotapokertour.com/storage/article/thumb/bruce-wheeler-cXvssJJx.jpg', '/media/dpt/article/bruce-wheeler-cXvssJJx.jpg', null, '{"id":384,"title":"🎉 Congratulations Bruce Wheeler! 🎉","alias":"congratulations-bruce-wheeler","excerpt":"What a night at the Casselton Vets Club Friday Night Turbo! A huge shoutout to Bruce Wheeler of Casselton, ND, who battled through a field of 47 players and came out on top, taking home a well-earned $2,500! We’d also like to extend a heart…","content":"What a night at the Casselton Vets Club Friday Night Turbo! A huge shoutout to Bruce Wheeler of Casselton, ND, who battled through a field of 47 players and came out on top, taking home a well-earned $2,500! We’d also like to extend a heartfelt thank you to Bruce for his service as a retired veteran. Your dedication to our country and your support of the Casselton Vets Club mean so much to all of us. Thank you to everyone who came out tonight to support the Casselton Vets Club and the Dakota Poker Tour. And we’re not done yet… Join us tomorrow for Operation Red White & Bluff!","publishedAt":"2025-11-15 01:15:00","featured":true,"logo":"bruce-wheeler-cXvssJJx.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/bruce-wheeler-cXvssJJx.jpg","bannerUrl":"","tournament":{"id":329,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-14-2025"}}'::jsonb),
  (383, 'big-night-in-casselton-8-400-prize-pool', 'Big Night in Casselton: $8,400 Prize Pool!', 'Registration is now closed for tonight’s Friday Night Turbo at the Casselton Vets Club! We drew a strong field of 47 players, building an impressive $8,400 prize pool. Tonight’s champion will walk away with $2,500 — not bad for a Friday nig…', '2025-11-14 22:08:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-14-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3932-3f4CTESp.jpg', '/media/dpt/article/IMG_3932-3f4CTESp.jpg', null, '{"id":383,"title":"Big Night in Casselton: $8,400 Prize Pool!","alias":"big-night-in-casselton-8-400-prize-pool","excerpt":"Registration is now closed for tonight’s Friday Night Turbo at the Casselton Vets Club! We drew a strong field of 47 players, building an impressive $8,400 prize pool. Tonight’s champion will walk away with $2,500 — not bad for a Friday nig…","content":"Registration is now closed for tonight’s Friday Night Turbo at the Casselton Vets Club! We drew a strong field of 47 players, building an impressive $8,400 prize pool. Tonight’s champion will walk away with $2,500 — not bad for a Friday night’s work! The top 7 players will all be taking home cash, so good luck to everyone still in the hunt. See you tomorrow for the Main event! Operation Red White & Bluff. 🕚 Registration Opens: 11AM | 🃏 Cards in the Air: NOON 💰 $150 Buy-In = 20K Chips | 30-Minute Levels ➕ $50 Add-On = 10K Chips (up to 3 times, max buy-in $300) 🍽️ Late Reg, Re-Entry & Add-Ons open through Dinner Break (~5PM) 💵 Suggested Dealer Appreciation: $20 (tips appreciated but not mandatory) Thank you to everyone who came out to support the Casselton Vets Club and play some great poker! ♠️♥️♦️♣️ 📊 DPT Leaderboard: dakotapokertour.com/leaderboard 📅 DPT Calendar: dakotapokertour.com/calendar 🎥 DPT YouTube Channel: youtube.com/@dakotapokertour #DakotaPokerTour #OperationPoker #RedWhiteAndBluff #Casselton #VeteransDay #PokerEvent #NorthDakotaPoker #HonoringHeroes","publishedAt":"2025-11-14 22:08:00","featured":false,"logo":"IMG_3932-3f4CTESp.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3932-3f4CTESp.jpg","bannerUrl":"","tournament":{"id":329,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-14-2025"}}'::jsonb),
  (380, 'castleton-vets-club-friday-night-turbo', 'Castleton Vets Club Friday Night Turbo', 'Cards are in the air tonight at the Casselton Vets Club for the Friday Night Turbo! ♠️ We’ve got 5 tables set and room for more — registration is open until 8:15 PM. Come play some poker and support the local Casselton Vets Club! Friday Nig…', '2025-11-14 18:46:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-14-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3912-tJdpGWFr.jpg', '/media/dpt/article/IMG_3912-tJdpGWFr.jpg', null, '{"id":380,"title":"Castleton Vets Club Friday Night Turbo","alias":"castleton-vets-club-friday-night-turbo","excerpt":"Cards are in the air tonight at the Casselton Vets Club for the Friday Night Turbo! ♠️ We’ve got 5 tables set and room for more — registration is open until 8:15 PM. Come play some poker and support the local Casselton Vets Club! Friday Nig…","content":"Cards are in the air tonight at the Casselton Vets Club for the Friday Night Turbo! ♠️ We’ve got 5 tables set and room for more — registration is open until 8:15 PM. Come play some poker and support the local Casselton Vets Club! Friday Night Turbo – November 14, 2025 🕔 Registration: 5:00 PM 🃏 Cards in the Air: 6:00 PM ⏱️ 20-Minute Blinds ⏳ Late Registration: until 8:00 PM 💰 $100 Buy-In = 15K Chips ♻️ $100 Rebuys/Add-On = 15K Chips (until 8PM) 💵 Suggested Dealer Appreciation: $20 (tips appreciated, never required) Come out, play some cards, and help support the Vets club! ♠️♥️♦️♣️ 📊 DPT Leaderboard: dakotapokertour.com/leaderboard 📅 DPT Calendar: dakotapokertour.com/calendar 🎥 DPT YouTube Channel: youtube.com/@dakotapokertour #DakotaPokerTour #OperationPoker #RedWhiteAndBluff #Casselton #VeteransDay #PokerEvent #NorthDakotaPoker #HonoringHeroes","publishedAt":"2025-11-14 18:46:00","featured":false,"logo":"IMG_3912-tJdpGWFr.jpg","banner":null,"videoUrl":null,"imageUrl":"https:/