  (379, 'congratulations-to-sara-weishaar-from-fargo-nd', '💥 Congratulations to Sara Weishaar from Fargo, ND! 💥', 'What an incredible debut! In her first-ever Dakota Poker Tour event , Sara made a statement — taking down the L.I.S.T.E.N. Inc. Monster Stack and walking away with $6,000 and the trophy! 🏆💵 She battled through a tough field of 80 players an…', '2025-11-01 23:40:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025', 'https://dakotapokertour.com/storage/article/thumb/sara-U9IRo3Xq.jpg', '/media/dpt/article/sara-U9IRo3Xq.jpg', null, '{"id":379,"title":"💥 Congratulations to Sara Weishaar from Fargo, ND! 💥","alias":"congratulations-to-sara-weishaar-from-fargo-nd","excerpt":"What an incredible debut! In her first-ever Dakota Poker Tour event , Sara made a statement — taking down the L.I.S.T.E.N. Inc. Monster Stack and walking away with $6,000 and the trophy! 🏆💵 She battled through a tough field of 80 players an…","content":"What an incredible debut! In her first-ever Dakota Poker Tour event , Sara made a statement — taking down the L.I.S.T.E.N. Inc. Monster Stack and walking away with $6,000 and the trophy! 🏆💵 She battled through a tough field of 80 players and showed the boys how it’s done! 👏🔥 A huge thank you to everyone who came out to support the Dakota Poker Tour and our charity partner L.I.S.T.E.N. Inc. Another great night of poker, competition, and community! Check out the latest results and upcoming events below: DPT Leaderboard: dakotapokertour.com/leaderboard DPT Calendar: dakotapokertour.com/calendar DPT YouTube Channel: youtube.com/@dakotapokertour","publishedAt":"2025-11-01 23:40:00","featured":true,"logo":"sara-U9IRo3Xq.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/sara-U9IRo3Xq.jpg","bannerUrl":"","tournament":{"id":328,"name":"LISTEN INC MONSTER STACK","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025"}}'::jsonb),
  (378, 'congratulations-to-the-final-table-of-the-l-i-s-t-e-n-inc-monster-stack', '🏆 Congratulations to the Final Table of the L.I.S.T.E.N. INC. MONSTER STACK! 🏆', 'What a night! A huge thank you to all 80 players who came out to support the Dakota Poker Tour and our charity partner L.I.S.T.E.N. Inc. Together, we generated an incredible $20,400 prize pool! 💰 It was a stacked final table filled with tal…', '2025-11-01 21:24:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025', 'https://dakotapokertour.com/storage/article/thumb/Screenshot-2025-11-01-212559-phVO0lkq.jpg', '/media/dpt/article/Screenshot-2025-11-01-212559-phVO0lkq.jpg', null, '{"id":378,"title":"🏆 Congratulations to the Final Table of the L.I.S.T.E.N. INC. MONSTER STACK! 🏆","alias":"congratulations-to-the-final-table-of-the-l-i-s-t-e-n-inc-monster-stack","excerpt":"What a night! A huge thank you to all 80 players who came out to support the Dakota Poker Tour and our charity partner L.I.S.T.E.N. Inc. Together, we generated an incredible $20,400 prize pool! 💰 It was a stacked final table filled with tal…","content":"What a night! A huge thank you to all 80 players who came out to support the Dakota Poker Tour and our charity partner L.I.S.T.E.N. Inc. Together, we generated an incredible $20,400 prize pool! 💰 It was a stacked final table filled with talent, competition, and great poker energy all night long: Paul Johnson – Fargo, ND David Vig – Fargo, ND Anthony Uhlir – Grand Forks, ND Sara Weiskar – Fargo, ND James Petriella – Grand Forks, ND Zach Braaten – West Fargo, ND Matt Jore – Grand Forks, ND Joel Klipping – Red Lake Falls, MN Ricky Kadlec – Grand Forks, ND And the stakes couldn’t be higher — tonight’s champion will take home $6,000 and the trophy! 🏆💵 Congratulations to everyone who made it deep — and thank you again for making this event such a success. 🙌 Check out the latest results and upcoming events below: DPT Leaderboard: dakotapokertour.com/leaderboard DPT Calendar: dakotapokertour.com/calendar DPT YouTube Channel: youtube.com/@dakotapokertour","publishedAt":"2025-11-01 21:24:00","featured":false,"logo":"Screenshot-2025-11-01-212559-phVO0lkq.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Screenshot-2025-11-01-212559-phVO0lkq.jpg","bannerUrl":"","tournament":{"id":328,"name":"LISTEN INC MONSTER STACK","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025"}}'::jsonb),
  (377, 'cards-are-in-the-air-for-the-l-i-s-t-e-n-inc-monster-stack', '♠️ Cards are in the air for the L.I.S.T.E.N. INC. MONSTER STACK! ♠️', 'We have 6 tables going strong and growing! With plenty of room to jump in! Get down here and join the action! 💰 $300 Buy-In | Freezeout Format 💵 100K Starting Stack ⏱️ 30-Min Levels 🕕 Late Registration Open Until 6PM One shot. One stack. On…', '2025-11-01 11:50:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025', 'https://dakotapokertour.com/storage/article/thumb/playmakers2-c3Z8EGTy.jpg', '/media/dpt/article/playmakers2-c3Z8EGTy.jpg', null, '{"id":377,"title":"♠️ Cards are in the air for the L.I.S.T.E.N. INC. MONSTER STACK! ♠️","alias":"cards-are-in-the-air-for-the-l-i-s-t-e-n-inc-monster-stack","excerpt":"We have 6 tables going strong and growing! With plenty of room to jump in! Get down here and join the action! 💰 $300 Buy-In | Freezeout Format 💵 100K Starting Stack ⏱️ 30-Min Levels 🕕 Late Registration Open Until 6PM One shot. One stack. On…","content":"We have 6 tables going strong and growing! With plenty of room to jump in! Get down here and join the action! 💰 $300 Buy-In | Freezeout Format 💵 100K Starting Stack ⏱️ 30-Min Levels 🕕 Late Registration Open Until 6PM One shot. One stack. One dream. Come claim victory, cash, and the trophy! Last year’s champion, Eric Thompson of East Grand Forks, ND, took home $6,000! Who will rise to the top this year? 🏆 Don’t miss your chance to make poker history with the Dakota Poker Tour and our charity partner, L.I.S.T.E.N. Inc. DPT Leaderboard: [dakotapokertour.com/leaderboard](https://dakotapokertour.com/leaderboard) DPT Calendar: [dakotapokertour.com/calendar](https://dakotapokertour.com/calendar) DPT YouTube Channel: [youtube.com/@dakotapokertour](https://youtube.com/@dakotapokertour) #DakotaPokerTour #GrandForks #PokerEvent #MonsterStack #LISTENInc","publishedAt":"2025-11-01 11:50:00","featured":false,"logo":"playmakers2-c3Z8EGTy.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/playmakers2-c3Z8EGTy.jpg","bannerUrl":"","tournament":{"id":328,"name":"LISTEN INC MONSTER STACK","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025"}}'::jsonb),
  (376, 'get-ready-for-the-l-i-s-t-e-n-inc-monster-stack', '🔥 Get Ready for the L.I.S.T.E.N. INC. MONSTER STACK! 🔥', 'It’s one of the biggest events of the season – and it’s happening **TODAY!!** A full day of deep stacks, big blinds, and serious poker action awaits. 🗓️ Saturday, November 1, 2025 🕚 New Start Time: 11AM 💰 $300 Buy-In | One-Day Monster Stack…', '2025-11-01 11:00:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025', 'https://dakotapokertour.com/storage/article/thumb/dpt2-EexLyMqt.jpg', '/media/dpt/article/dpt2-EexLyMqt.jpg', null, '{"id":376,"title":"🔥 Get Ready for the L.I.S.T.E.N. INC. MONSTER STACK! 🔥","alias":"get-ready-for-the-l-i-s-t-e-n-inc-monster-stack","excerpt":"It’s one of the biggest events of the season – and it’s happening **TODAY!!** A full day of deep stacks, big blinds, and serious poker action awaits. 🗓️ Saturday, November 1, 2025 🕚 New Start Time: 11AM 💰 $300 Buy-In | One-Day Monster Stack…","content":"It’s one of the biggest events of the season – and it’s happening **TODAY!!** A full day of deep stacks, big blinds, and serious poker action awaits. 🗓️ Saturday, November 1, 2025 🕚 New Start Time: 11AM 💰 $300 Buy-In | One-Day Monster Stack Event 💵 100K Starting Stack | 30-Min Levels 🕕 Late Registration available until 6PM (after Dinner Break) Last year’s champion, **Eric Thompson of East Grand Forks, ND**, took home **$6,000** in the Monster Stack. Who will claim the title — and the big prize — this year? 🏆 Don’t miss your shot to join one of the most exciting poker events of the year! Click below for all the details and to register: DPT Leaderboard: [dakotapokertour.com/leaderboard](https://dakotapokertour.com/leaderboard) DPT Calendar: [dakotapokertour.com/calendar](https://dakotapokertour.com/calendar) DPT YouTube Channel: [youtube.com/@dakotapokertour](https://youtube.com/@dakotapokertour)","publishedAt":"2025-11-01 11:00:00","featured":false,"logo":"dpt2-EexLyMqt.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/dpt2-EexLyMqt.jpg","bannerUrl":"","tournament":{"id":328,"name":"LISTEN INC MONSTER STACK","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025"}}'::jsonb),
  (375, 'congratulations-joel-klipping', '🏆 Congratulations, Joel Klipping! 🏆', '🏆 Congratulations, Joel Klipping! 🏆 Joel Klipping from Red Lake Falls, MN is making his presence known and kicking off the weekend in style! Back in March 2025, he claimed 2nd place, and in 2024, Joel was crowned the L.I.S.T.E.N. Inc. Champ…', '2025-10-31 23:24:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-friday-night-turbo-10-31-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3691-cHgm8b3i.jpg', '/media/dpt/article/IMG_3691-cHgm8b3i.jpg', null, '{"id":375,"title":"🏆 Congratulations, Joel Klipping! 🏆","alias":"congratulations-joel-klipping","excerpt":"🏆 Congratulations, Joel Klipping! 🏆 Joel Klipping from Red Lake Falls, MN is making his presence known and kicking off the weekend in style! Back in March 2025, he claimed 2nd place, and in 2024, Joel was crowned the L.I.S.T.E.N. Inc. Champ…","content":"🏆 Congratulations, Joel Klipping! 🏆 Joel Klipping from Red Lake Falls, MN is making his presence known and kicking off the weekend in style! Back in March 2025, he claimed 2nd place, and in 2024, Joel was crowned the L.I.S.T.E.N. Inc. Champion, taking home $7,400. Tonight, Joel conquered the Friday Night Turbo, defeating 21 players to earn $1,500 and another 1st Place Victory! Final Results: 1st – Joel Klipping (Red Lake Falls, MN) – $1,500 2nd – Jason Senger (Devils Lake, ND) – $1,060 3rd – Jeremiah Alonge (Jamestown, ND) – $720 4th – Mike Marek (East Grand Forks, MN) – $540 Joel has been a longtime supporter and friend of the Dakota Poker Tour, and we’re thrilled to see his continued success at the tables. Thank you to everyone who came out to support the Dakota Poker Tour and our charity partner, L.I.S.T.E.N. Inc. Join us tomorrow for the SATURDAY – MONSTER STACK! November 1, 2025 New Start Time: 11AM $300 Buy-In | One-Day Monster Stack Event 100K Starting Stack | 30-Min Levels Late Registration available until 6PM (after Dinner Break) Don’t miss this monster day of poker action and your chance to grab a big stack and a bigger payout! DPT Leaderboard: dakotapokertour.com/leaderboard DPT Calendar: dakotapokertour.com/calendar DPT YouTube Channel: youtube.com/@dakotapokertour","publishedAt":"2025-10-31 23:24:00","featured":false,"logo":"IMG_3691-cHgm8b3i.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3691-cHgm8b3i.jpg","bannerUrl":"","tournament":{"id":327,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-friday-night-turbo-10-31-2025"}}'::jsonb),
  (374, 'the-cards-are-in-the-air', '♠️ The Cards Are in the Air! ♠️', 'Plenty of time to get down here for the Friday Night Turbo at Playmakers Lounge - Canad Inn, Grand Forks, ND! Just $100 gets you 15K in chips and a shot at glory. Tournament Details: 💰 $100 Buy-In = 15K Starting Chips ⏱️ 20-Min Blind Levels…', '2025-10-31 19:07:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-friday-night-turbo-10-31-2025', 'https://dakotapokertour.com/storage/article/thumb/dpt1-LlABN4Vn.jpg', '/media/dpt/article/dpt1-LlABN4Vn.jpg', null, '{"id":374,"title":"♠️ The Cards Are in the Air! ♠️","alias":"the-cards-are-in-the-air","excerpt":"Plenty of time to get down here for the Friday Night Turbo at Playmakers Lounge - Canad Inn, Grand Forks, ND! Just $100 gets you 15K in chips and a shot at glory. Tournament Details: 💰 $100 Buy-In = 15K Starting Chips ⏱️ 20-Min Blind Levels…","content":"Plenty of time to get down here for the Friday Night Turbo at Playmakers Lounge - Canad Inn, Grand Forks, ND! Just $100 gets you 15K in chips and a shot at glory. Tournament Details: 💰 $100 Buy-In = 15K Starting Chips ⏱️ 20-Min Blind Levels 🕘 Late Registration until 9PM ♻️ $100 Rebuys / Add-On (Double Add-On if no Rebuy) We’ve got 3 tables running to start — don’t miss your seat in the action! 👉 DPT Leaderboard: dakotapokertour.com/leaderboard 📅 DPT Calendar: dakotapokertour.com/calendar 🎥 DPT YouTube Channel: youtube.com/@dakotapokertour","publishedAt":"2025-10-31 19:07:00","featured":false,"logo":"dpt1-LlABN4Vn.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/dpt1-LlABN4Vn.jpg","bannerUrl":"","tournament":{"id":327,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-friday-night-turbo-10-31-2025"}}'::jsonb),
  (373, 'dakota-poker-tour-is-has-arrived-in-grand-forks', 'Dakota Poker Tour is has arrived in Grand Forks!', 'Get ready for the L.I.S.T.E.N INC. Monster Stack – a poker event you won’t want to miss! Last year’s winner, Champion Eric Thompson, East Grand Forks, ND, took home $6,000 in the Monster Stack, and Jim Paskett, Grand Forks ND $3200 in the F…', '2025-10-31 16:00:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-friday-night-turbo-10-31-2025', 'https://dakotapokertour.com/storage/article/thumb/dpt1-CZv1V5DE.jpg', '/media/dpt/article/dpt1-CZv1V5DE.jpg', null, '{"id":373,"title":"Dakota Poker Tour is has arrived in Grand Forks!","alias":"dakota-poker-tour-is-has-arrived-in-grand-forks","excerpt":"Get ready for the L.I.S.T.E.N INC. Monster Stack – a poker event you won’t want to miss! Last year’s winner, Champion Eric Thompson, East Grand Forks, ND, took home $6,000 in the Monster Stack, and Jim Paskett, Grand Forks ND $3200 in the F…","content":"Get ready for the L.I.S.T.E.N INC. Monster Stack – a poker event you won’t want to miss! Last year’s winner, Champion Eric Thompson, East Grand Forks, ND, took home $6,000 in the Monster Stack, and Jim Paskett, Grand Forks ND $3200 in the Friday night Turbo– who will take home the big prize this time? Here’s the schedule: • Friday Night Turbo: Starts at 6 PM • Saturday Monster 100K Stack: Kicks off at 11 AM, with late registration until 6 PM. Who will claim the new trophy and the cash prize? Only time will tell! Click below for all the details and to register! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour #DakotaPokerTour #GrandForks #PokerEvent #MonsterS","publishedAt":"2025-10-31 16:00:00","featured":false,"logo":"dpt1-CZv1V5DE.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/dpt1-CZv1V5DE.jpg","bannerUrl":"","tournament":{"id":327,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-friday-night-turbo-10-31-2025"}}'::jsonb),
  (372, 'mike-hlebechuk-poker-brat-champion-at-the-windbreak', 'Mike Hlebechuk Poker Brat Champion at The Windbreak', 'Congratulations to Mike Hlebechuk of Fargo, ND, our Poker Brat Black Chip Bounty Champion at The Windbreak! Mike battled his way through a talented 46-player field to take home $2,100 plus $800 in bounties, defeating Tony Waltz heads-up in…', '2025-10-19 23:32:00', null, 'dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-19-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3509-JV1vUWAS.jpg', '/media/dpt/article/IMG_3509-JV1vUWAS.jpg', null, '{"id":372,"title":"Mike Hlebechuk Poker Brat Champion at The Windbreak","alias":"mike-hlebechuk-poker-brat-champion-at-the-windbreak","excerpt":"Congratulations to Mike Hlebechuk of Fargo, ND, our Poker Brat Black Chip Bounty Champion at The Windbreak! Mike battled his way through a talented 46-player field to take home $2,100 plus $800 in bounties, defeating Tony Waltz heads-up in…","content":"Congratulations to Mike Hlebechuk of Fargo, ND, our Poker Brat Black Chip Bounty Champion at The Windbreak! Mike battled his way through a talented 46-player field to take home $2,100 plus $800 in bounties, defeating Tony Waltz heads-up in a bittersweet finish, fittingly, the very friend who first introduced him to poker! A longtime supporter and friend of the Dakota Poker Tour, Mike’s win tonight is a well-deserved triumph and another great moment in DPT history. Thank you to everyone who came out to support the Dakota Poker Tour and our charity partner, NPPA. It was incredible to see so many familiar faces and meet new players — we appreciate each and every one of you! This event brought together 46 players, generating an $11,700 prize pool and a great night of poker, sportsmanship, and community. 1st $2100 Mike Hlebechuk Fargo ND +$800 Bounty’s 2nd $1300 Tony Walz Fargo ND + $400 Bounty’s 3rd $100 Todd Egerdahl Fargo ND +$200 bounty’s 4th $800 Gary Ewald Park River ND + $800 bounty’s 5th $700 Matt Wolff Spicer MN + $400 bounty’s 6th $600 Alan Perry Aberdeen SD +$500 Bounty’s 7th $500 Jon Christian Casselton ND $100 bounty’s 8th Tim Walsh Dark Rapids MN 9th Josh Lanzdorf West Fargo ND $300 bounty’s","publishedAt":"2025-10-19 23:32:00","featured":true,"logo":"IMG_3509-JV1vUWAS.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3509-JV1vUWAS.jpg","bannerUrl":"","tournament":{"id":326,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-19-2025"}}'::jsonb),
  (371, 'registration-closed-at', 'Registration closed at', 'Registration is closed here at The Windbreak for the Black Chip Bounty Tournament. 46 players came out to support the NPPA charity and battle it out on the felt. Today’s champion will take home $2,100, the championship trophy, and plenty of…', '2025-10-19 19:14:00', null, 'dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-19-2025', 'https://dakotapokertour.com/storage/article/thumb/payouts-cpmIZO51.jpg', '/media/dpt/article/payouts-cpmIZO51.jpg', null, '{"id":371,"title":"Registration closed at","alias":"registration-closed-at","excerpt":"Registration is closed here at The Windbreak for the Black Chip Bounty Tournament. 46 players came out to support the NPPA charity and battle it out on the felt. Today’s champion will take home $2,100, the championship trophy, and plenty of…","content":"Registration is closed here at The Windbreak for the Black Chip Bounty Tournament. 46 players came out to support the NPPA charity and battle it out on the felt. Today’s champion will take home $2,100, the championship trophy, and plenty of bounties along the way!","publishedAt":"2025-10-19 19:14:00","featured":false,"logo":"payouts-cpmIZO51.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/payouts-cpmIZO51.jpg","bannerUrl":"","tournament":{"id":326,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-19-2025"}}'::jsonb),
  (370, 'cards-are-in-the-air-at-the-windbreak', 'Cards are in the air at the Windbreak', 'Cards are in the air here at The Windbreak! The Dakota Poker Tour has rolled into Fargo for today’s Poker Brat Black Chip Bounty Tournament! Cards fly at 12:00 PM Registration opens at 11:00 AM Late registration available until 5:00 PM — pl…', '2025-10-19 14:55:00', null, 'dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-19-2025', 'https://dakotapokertour.com/storage/article/thumb/wind-2-n2E9Udxs.jpg', '/media/dpt/article/wind-2-n2E9Udxs.jpg', null, '{"id":370,"title":"Cards are in the air at the Windbreak","alias":"cards-are-in-the-air-at-the-windbreak","excerpt":"Cards are in the air here at The Windbreak! The Dakota Poker Tour has rolled into Fargo for today’s Poker Brat Black Chip Bounty Tournament! Cards fly at 12:00 PM Registration opens at 11:00 AM Late registration available until 5:00 PM — pl…","content":"Cards are in the air here at The Windbreak! The Dakota Poker Tour has rolled into Fargo for today’s Poker Brat Black Chip Bounty Tournament! Cards fly at 12:00 PM Registration opens at 11:00 AM Late registration available until 5:00 PM — plenty of time to jump in and join the action! Buy-In: $200 = 20K starting stack Add-On: $100 for an extra 20K (must have chips in play to qualify) Blinds: 30 minutes — giving you time to play your best game Bounties: Knock someone out and earn $100 cash instantly!","publishedAt":"2025-10-19 14:55:00","featured":false,"logo":"wind-2-n2E9Udxs.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/wind-2-n2E9Udxs.jpg","bannerUrl":"","tournament":{"id":326,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-19-2025"}}'::jsonb),
  (369, 'windbreak-black-chip-bounty', 'Poker Brat Black Chip Bounty at The Windbreak', 'The Dakota Poker Tour has rolled into The Windbreak for today’s Poker Brat Black Chip Bounty Tournament! Cards are in the air at 12:00 PM, with registration opening at 11:00 AM and late registration available until 5:00 PM — plenty of time…', '2025-10-19 14:43:00', null, 'dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-19-2025', 'https://dakotapokertour.com/storage/article/thumb/wind-0sqfY9Eu.jpg', '/media/dpt/article/wind-0sqfY9Eu.jpg', null, '{"id":369,"title":"Poker Brat Black Chip Bounty at The Windbreak","alias":"windbreak-black-chip-bounty","excerpt":"The Dakota Poker Tour has rolled into The Windbreak for today’s Poker Brat Black Chip Bounty Tournament! Cards are in the air at 12:00 PM, with registration opening at 11:00 AM and late registration available until 5:00 PM — plenty of time…","content":"The Dakota Poker Tour has rolled into The Windbreak for today’s Poker Brat Black Chip Bounty Tournament! Cards are in the air at 12:00 PM, with registration opening at 11:00 AM and late registration available until 5:00 PM — plenty of time to jump in and join the action! $200 Buy-In gets you 20K in starting chips, with a $100 add-on available for another 20K (must have chips in play to qualify). Blinds are 30 minutes, giving you room to play your best game. A quick reminder — our dealers are volunteers who make these events possible and are paid only through your generosity. A suggested $20 dealer appreciation helps show your support and keeps the cards flying all day long. And don’t forget — eliminate a player and earn $100 cash instantly! Come join the fun, grab some bounties, and see your name climb the DPT Leaderboard!","publishedAt":"2025-10-19 14:43:00","featured":false,"logo":"wind-0sqfY9Eu.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/wind-0sqfY9Eu.jpg","bannerUrl":"","tournament":{"id":326,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-19-2025"}}'::jsonb),
  (368, 'ali-novin-claims-victory-at-dakota-magic', 'Ali Novin Claims Victory at Dakota Magic', 'Tri-State Poker Championship: Ali Novin Wins Second Chance Event at Dakota Magic! The action was electric once again at Dakota Magic Casino & Hotel in Hankinson, ND, as the Dakota Poker Tour (DPT) and Roughrider Poker Tour (RPT) teamed up t…', '2025-10-06 14:32:00', null, 'dakota-poker-tour-2025-the-tri-state-poker-championship-sunday-second-chance-10-05-2025', 'https://dakotapokertour.com/storage/article/thumb/ALI-lR0p9Bjn.jpg', '/media/dpt/article/ALI-lR0p9Bjn.jpg', null, '{"id":368,"title":"Ali Novin Claims Victory at Dakota Magic","alias":"ali-novin-claims-victory-at-dakota-magic","excerpt":"Tri-State Poker Championship: Ali Novin Wins Second Chance Event at Dakota Magic! The action was electric once again at Dakota Magic Casino & Hotel in Hankinson, ND, as the Dakota Poker Tour (DPT) and Roughrider Poker Tour (RPT) teamed up t…","content":"Tri-State Poker Championship: Ali Novin Wins Second Chance Event at Dakota Magic! The action was electric once again at Dakota Magic Casino & Hotel in Hankinson, ND, as the Dakota Poker Tour (DPT) and Roughrider Poker Tour (RPT) teamed up to present Event #47C — the Tri-State Poker Championship Second Chance Tournament on October 5, 2025. The $250 buy-in event drew 67 entries, building a $13,400 prize pool and capping off an incredible weekend of championship poker. In his first-ever appearance, Ali Novin made it one to remember, battling through a tough field and securing his first RPT/DPT title along with a $4,000 payday! Here’s how the final table finished: Ali Novin – $4,000 Cordell Schroeder – $2,700 Robert “Muzz” Anderson – $2,000 Carl Wallin – $1,400 Lindsey Hansen – $1,000 David Highley – $710 Patrick Wingard – $620 Natalia Zinn – $520 Jon Wurden – $450 The DPT x RPT Tri-State Poker Championship weekend was a massive success, featuring three days of high-level play, strong turnouts, and unforgettable finishes. Congratulations to all the players who made the trip and helped make this debut stop one to remember!","publishedAt":"2025-10-06 14:32:00","featured":false,"logo":"ALI-lR0p9Bjn.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/ALI-lR0p9Bjn.jpg","bannerUrl":"","tournament":{"id":325,"name":"Sunday Second Chance","alias":"dakota-poker-tour-2025-the-tri-state-poker-championship-sunday-second-chance-10-05-2025"}}'::jsonb),
  (367, 'congratulations-tri-state-poker-championship-winner-bridget-johnson', 'Congratulations Tri-State Poker Championship Winner Bridget Johnson', 'Tri-State Poker Championship has officially crowned its champion, Bridget Johnson of Dickinson, ND outlasted a talented field of 351 entries to capture her career-best payday of $35,000, the custom trophy, and a coveted $1,000 Dream Chaser…', '2025-10-06 00:38:00', null, 'dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-2025-10-03-2025', 'https://dakotapokertour.com/storage/article/thumb/Screenshot-2025-10-06-003746-CuFtCdok.jpg', '/media/dpt/article/Screenshot-2025-10-06-003746-CuFtCdok.jpg', null, '{"id":367,"title":"Congratulations Tri-State Poker Championship Winner Bridget Johnson","alias":"congratulations-tri-state-poker-championship-winner-bridget-johnson","excerpt":"Tri-State Poker Championship has officially crowned its champion, Bridget Johnson of Dickinson, ND outlasted a talented field of 351 entries to capture her career-best payday of $35,000, the custom trophy, and a coveted $1,000 Dream Chaser…","content":"Tri-State Poker Championship has officially crowned its champion, Bridget Johnson of Dickinson, ND outlasted a talented field of 351 entries to capture her career-best payday of $35,000, the custom trophy, and a coveted $1,000 Dream Chaser V Main Event seat. The $650 buy-in event, co-hosted by the Roughrider Poker Tour (RPT) and the Dakota Poker Tour (DPT), generated a massive $189,540 prize pool and showcased some of the best poker talent in the region. Johnson sealed the deal after a quick heads-up battle with Mark Fink, who finished runner-up for $20,000. Here’s how the Final Table finished: Bridget Johnson – Dickinson, ND – $35,000 Mark Fink – Sioux Falls, SD – $20,000 Keith Kemper – Casselton, ND – $15,000 Paul Johnson – Fargo, ND – $10,700 Kim Rasmussen – Forman, ND – $9,000 Cody Slusher – Kindred, ND – $7,700 Chad Knoblauch – Grand Forks, ND – $6,600 James Girouard – Sioux Falls, SD – $5,500 Dustin Benda – Wahpeton, ND – $4,400 A huge thank you to everyone who came out to play, to FPN Gaming for powering the live stream, and to Jerod and Goose for their incredible production work. And of course, a big shoutout to our dealers and staff for keeping the action running smoothly all weekend long. Check out the pokernews article & interview with our inaugural Tri-State Poker CHAMPION, Bridget Johnson!","publishedAt":"2025-10-06 00:38:00","featured":true,"logo":"Screenshot-2025-10-06-003746-CuFtCdok.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Screenshot-2025-10-06-003746-CuFtCdok.jpg","bannerUrl":"","tournament":{"id":322,"name":"The Tri-State Poker Championship 2025","alias":"dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-2025-10-03-2025"}}'::jsonb),
  (366, 'congratulations-to-the-52-finalists-advancing-to-championship-sunday', '🎉 Congratulations to the 52 Finalists Advancing to Championship Sunday! 🎉', 'After two exciting starting flights and a total of 351 entries, the field has been narrowed to just 52 players who will return for Day 2 of the RPT Tri-State Poker Championship at Dakota Magic Hotel & Casino! Each of these players has alrea…', '2025-10-05 01:41:00', null, 'dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-2025-10-03-2025', '', '', null, '{"id":366,"title":"🎉 Congratulations to the 52 Finalists Advancing to Championship Sunday! 🎉","alias":"congratulations-to-the-52-finalists-advancing-to-championship-sunday","excerpt":"After two exciting starting flights and a total of 351 entries, the field has been narrowed to just 52 players who will return for Day 2 of the RPT Tri-State Poker Championship at Dakota Magic Hotel & Casino! Each of these players has alrea…","content":"After two exciting starting flights and a total of 351 entries, the field has been narrowed to just 52 players who will return for Day 2 of the RPT Tri-State Poker Championship at Dakota Magic Hotel & Casino! Each of these players has already secured a payout, but the big goal remains, capturing the $35,000 first-place prize, the trophy, and the title of Tri-State Poker Champion! The stage is set for an unforgettable Championship Sunday. Leading the way is Jamie Meidinger with a commanding 1,427,000 in chips, followed by Eric Hanson with 1,260,000, and Heidi Roggenkamp close behind at 1,126,000. The rest of the field is stacked with talent and determination — it’s anyone’s game! A huge thank you from the Dakota Poker Tour (DPT) and Roughrider Poker Tour (RPT) to everyone for their continued support! Special thanks to FPN Gaming for providing the Live Stream, and to Jerod and Goose for their awesome production work behind the scenes. 🎥 And of course, a big shoutout to our dealers and staff — your hard work and dedication make these championship events possible! 🙌 Best of luck to all 52 returning players as they battle it out for glory on Championship Sunday! 🏆 Prize Pool Overview – 1st – $35,000 2nd – $20,000 3rd – $15,000 4th – $10,700 5th – $9,000 6th – $7,700 7th – $6,600 8th – $5,500 9th – $4,400 10th – $3,315 …and payouts continuing through 52nd place! Jamie Meidinger – 1,427,000 Eric Hanson – 1,260,000 Heidi Roggenkamp – 1,126,000 Mark Fink – 928,000 Craig Pohlmann – 797,000 Keith Kemper – 769,000 Kim Rasmussen – 758,000 Corey Littlewolf – 727,000 Gary Ewald – 724,000 Arlie Brandvold – 645,000 Joshua Matti – 613,000 Anthony Uhlir – 602,000 Samuel Johnson – 587,000 Chad Knoblauch – 561,000 Cody Billadeau – 553,000 Tyler Kolness – 523,000 Bridget Johnson – 475,000 Robert Urbatsch – 474,000 Jeremy Thury – 461,000 Samuel Faleide – 409,000 Jon Wurden – 383,000 Skyler Sand – 361,000 Ernest Trzpuc – 344,000 Josh Unruh – 316,000 Steve Belland – 311,000 Chad Ransom – 280,000 Eric Hjelmstad – 279,000 Jason Kramer – 277,000 Matthew Wetsch – 265,000 James Girouard – 258,000 Dustin Benda – 254,000 Weston Wells – 238,000 Daniel Tennefos – 225,000 Chastity Askvig – 221,000 Cody Slusher – 195,000 Paul Johnson – 193,000 Chad Fowler – 192,000 Eli Egli – 154,000 Justin Carlson – 152,000 Hahn Kupfer – 147,000 David Chaput – 134,000 Timothy Arens – 129,000 Robert Anderson – 122,000 Les Haagenson – 116,000 Jeremy Holmes – 110,000 Timothy Scott – 106,000 Cary Long – 100,000 Cody Krause – 100,000 Erik Nordeng – 56,000 Timothy Scott – 40,000 Reid Johnson – 17,000","publishedAt":"2025-10-05 01:41:00","featured":false,"logo":null,"banner":null,"videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":322,"name":"The Tri-State Poker Championship 2025","alias":"dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-2025-10-03-2025"}}'::jsonb),
  (365, 'flight-b-wraps-at-the-rpt-tri-state-poker-championship', 'Flight B Wraps at the RPT Tri-State Poker Championship!', 'Action has come to an end for Flight B of the RPT Tri-State Poker Championship at Dakota Magic Hotel & Casino , following 16 intense levels of play. From a field of 188 entries , just 27 players survived the night, each already in the money…', '2025-10-05 00:15:00', null, 'dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-flight-b-09-06-2025', 'https://dakotapokertour.com/storage/article/thumb/Screenshot-2025-10-05-012853-VOxq04gl.jpg', '/media/dpt/article/Screenshot-2025-10-05-012853-VOxq04gl.jpg', null, '{"id":365,"title":"Flight B Wraps at the RPT Tri-State Poker Championship!","alias":"flight-b-wraps-at-the-rpt-tri-state-poker-championship","excerpt":"Action has come to an end for Flight B of the RPT Tri-State Poker Championship at Dakota Magic Hotel & Casino , following 16 intense levels of play. From a field of 188 entries , just 27 players survived the night, each already in the money…","content":"Action has come to an end for Flight B of the RPT Tri-State Poker Championship at Dakota Magic Hotel & Casino , following 16 intense levels of play. From a field of 188 entries , just 27 players survived the night, each already in the money and locked into Sunday’s Championship Day . They’ll be joining the 25 qualifiers from Day 1A , bringing the total field returning Sunday to 52 players — all eyeing the trophy, the title, and the $35,000 top prize ! 💰 Leading the charge is Jamie Meidinger , who dominated play from start to finish, bagging a massive 1,427,000 to take the overall chip lead into Championship Day. The North Dakota standout continues a stellar run, fresh off his victory at the RPT South Dakota State Poker Championship , where he earned over $90,000 earlier this year. 💵 Payout Breakdown 🏆 Top Payouts: 1st – $35,000 2nd – $20,000 3rd – $15,000 4th – $10,700 5th – $9,000 6th – $7,700 7th – $6,600 8th – $5,500 9th – $4,400 10th – $3,315 💰 Additional Cashes: 11th–12th – $2,800 13th–15th – $2,500 16th–18th – $2,200 19th–21st – $2,050 22nd–24th – $1,925 25th–27th – $1,800 28th–36th – $1,500 37th–45th – $1,200 46th–52nd – $1,000 🔥 The stage is set for an action-packed Championship Sunday , where the final 52 contenders will battle for glory, prestige, and their share of the prize pool!","publishedAt":"2025-10-05 00:15:00","featured":false,"logo":"Screenshot-2025-10-05-012853-VOxq04gl.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Screenshot-2025-10-05-012853-VOxq04gl.jpg","bannerUrl":"","tournament":{"id":324,"name":"The Tri-State Poker Championship Flight B","alias":"dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-flight-b-09-06-2025"}}'::jsonb),
  (364, 'day-1b-is-underway-at-the-tri-state-poker-championship', '🔥 Day 1B is Underway at the Tri-State Poker Championship! 🔥', 'The tables are packed, chips are flying, and the excitement is electric as Day 1B kicks off in full force! DPT and RPT have teamed up once again to host this epic event, a $650 buy-in tournament boasting an estimated $200,000 prize pool . 💰…', '2025-10-04 14:00:00', null, 'dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-flight-b-09-06-2025', 'https://dakotapokertour.com/storage/article/thumb/Screenshot-2025-10-05-012533-A2njZnOF.jpg', '/media/dpt/article/Screenshot-2025-10-05-012533-A2njZnOF.jpg', null, '{"id":364,"title":"🔥 Day 1B is Underway at the Tri-State Poker Championship! 🔥","alias":"day-1b-is-underway-at-the-tri-state-poker-championship","excerpt":"The tables are packed, chips are flying, and the excitement is electric as Day 1B kicks off in full force! DPT and RPT have teamed up once again to host this epic event, a $650 buy-in tournament boasting an estimated $200,000 prize pool . 💰…","content":"The tables are packed, chips are flying, and the excitement is electric as Day 1B kicks off in full force! DPT and RPT have teamed up once again to host this epic event, a $650 buy-in tournament boasting an estimated $200,000 prize pool . 💰 Players are locking in their stacks and chasing a coveted Day 2 bag. 🎥 Tune in to the live broadcast (20-minute delay) featuring Keith and Jerry breaking down the action in the booth, with Goose and Jerod delivering a top-tier production. You can catch it all on the DPT YouTube channel and RPT Facebook page . 📰 Official PokerNews coverage is in full swing, bringing you live updates, chip counts, and highlights straight from the floor. 📅 Day 1B runs today, and all advancing players will return Sunday to compete for the title, the trophy, and their share of the payday. ⏰ There’s still time to get in — late registration is open until 9 PM! Don’t miss your shot to join the action and make your mark on the championship stage.","publishedAt":"2025-10-04 14:00:00","featured":false,"logo":"Screenshot-2025-10-05-012533-A2njZnOF.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Screenshot-2025-10-05-012533-A2njZnOF.jpg","bannerUrl":"","tournament":{"id":324,"name":"The Tri-State Poker Championship Flight B","alias":"dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-flight-b-09-06-2025"}}'::jsonb),
  (363, '25-players-advance-to-day-2-of-the-tri-state-poker-championship', '25 Players Advance to Day 2 of the Tri-State Poker Championship', 'Eric Hanson from dominated the opening flight, bagging a towering stack of 1,260,000. He built momentum throughout the session and seized control of the leaderboard in the closing stretch. Hanson stands alone as the only player to top the m…', '2025-10-04 12:09:00', null, 'dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-flight-a-09-05-2025', 'https://dakotapokertour.com/storage/article/thumb/erichanson-ijosQJo2.jpg', '/media/dpt/article/erichanson-ijosQJo2.jpg', null, '{"id":363,"title":"25 Players Advance to Day 2 of the Tri-State Poker Championship","alias":"25-players-advance-to-day-2-of-the-tri-state-poker-championship","excerpt":"Eric Hanson from dominated the opening flight, bagging a towering stack of 1,260,000. He built momentum throughout the session and seized control of the leaderboard in the closing stretch. Hanson stands alone as the only player to top the m…","content":"Eric Hanson from dominated the opening flight, bagging a towering stack of 1,260,000. He built momentum throughout the session and seized control of the leaderboard in the closing stretch. Hanson stands alone as the only player to top the million mark and will head into Championship Sunday armed with more than 100 big blinds. In second position is Craig Pohlmann (797,000), who vaulted up the counts after a dramatic bubble hand. Pohlmann connected with the stone-cold nuts against Carl Derry’s flopped set, a clash that sent Derry tumbling to the short stack before bowing out as the bubble finisher. Not far behind sits Gary Ewald (724,000). Ewald surged late in the evening, winning a critical race when his pocket jacks prevailed over Joseph Osterbauer Sr.’s ace-king. From there, he held steady to secure a top-three stack heading into Day 2. Day 1 final Chip Counts: Eric Hanson 1,260,000 Craig Pohlmann 797,000 Gary Ewald 724,000 Arlie Brandvold 645,000 Anthony Uhlir 602,000 Samuel Johnson 587,000 Chad Knoblauch 561,000 Robert Urbatsch 474,000 Jeremy Thury 461,000 Samuel Faleide 409,000 Jon Wurden 383,000 Skyler Sand 361,000 Ernest Trzpuc 344,000 Chad Ransom 280,000 Jason Kramer 277,000 Matthew Wetsch 265,000 James Girouard 258,000 Weston Wells 238,000 Cody Slusher 195,000 Paul Johnson 193,000 Eli Egli 154,000 Les Haagenson 116,000 Jeremy Holmes 110,000 Cody Billadeau 75,000 Mark Dufner 63,000","publishedAt":"2025-10-04 12:09:00","featured":true,"logo":"erichanson-ijosQJo2.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/erichanson-ijosQJo2.jpg","bannerUrl":"","tournament":{"id":323,"name":"The Tri-State Poker Championship  Flight A","alias":"dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-flight-a-09-05-2025"}}'::jsonb),
  (362, 'the-action-is-officially-underway-at-the-tri-state-poker-championship', '🎉 The action is officially underway at the Tri-State Poker Championship! 🎉', 'DPT and RPT have joined forces to bring you this premier event – a $650 buy-in with an estimated $200,000 prize pool on the line! 💰 8 tables strong, and the energy is already buzzing in the room. The live stream is now live with Keith and J…', '2025-10-03 13:24:00', null, 'dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-flight-a-09-05-2025', '', '', 'https://www.youtube.com/live/TUj5rdgBHZQ?si=KLGLoMnUDqrRP-ck', '{"id":362,"title":"🎉 The action is officially underway at the Tri-State Poker Championship! 🎉","alias":"the-action-is-officially-underway-at-the-tri-state-poker-championship","excerpt":"DPT and RPT have joined forces to bring you this premier event – a $650 buy-in with an estimated $200,000 prize pool on the line! 💰 8 tables strong, and the energy is already buzzing in the room. The live stream is now live with Keith and J…","content":"DPT and RPT have joined forces to bring you this premier event – a $650 buy-in with an estimated $200,000 prize pool on the line! 💰 8 tables strong, and the energy is already buzzing in the room. The live stream is now live with Keith and Jerry calling the action from the booth, while Goose and Jerod are running the top-notch production. 🎥🎙️ Live strean is on a 20 min delay. Catch all the action on the DPT YouTube channel (linked below) and the RPT Facebook page. 📰 Plus – enjoy official event reporting powered by PokerNews, bringing you chip counts, updates, and more throughout the championship! 📅 Day 1A kicks off today, Day 1B runs tomorrow, and players who bag will return on Sunday to battle for the title. ⏰ Don’t forget – late registration is open until 9 PM tonight. Still time to grab your seat in this championship event! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2025-10-03 13:24:00","featured":true,"logo":null,"banner":null,"videoUrl":"https://www.youtube.com/live/TUj5rdgBHZQ?si=KLGLoMnUDqrRP-ck","imageUrl":"","bannerUrl":"","tournament":{"id":323,"name":"The Tri-State Poker Championship  Flight A","alias":"dakota-poker-tour-2025-the-tri-state-poker-championship-the-tri-state-poker-championship-flight-a-09-05-2025"}}'::jsonb),
  (361, 'sunday-funday-fall-championship-winner-josh-dahlstrom-of-west-fargo-nd', 'Sunday Funday Fall Championship Winner – Josh Dahlstrom of West Fargo, ND', '🏆 Congratulations to our Sunday Funday Fall Championship Winner – Josh Dahlstrom of West Fargo, ND! 🏆 Josh battled his way through the field to take home $1,050 and the top spot! 🔥 💰 Final Payouts – $2,700 Prize Pool 🥇 $1,050 – Josh Dahlstr…', '2025-09-28 19:36:00', null, 'dakota-poker-tour-2025-hagge-s-fall-classic-sunday-fun-day-turbo-09-28-2025', 'https://dakotapokertour.com/storage/article/thumb/josh-q5mehR7Y.jpg', '/media/dpt/article/josh-q5mehR7Y.jpg', null, '{"id":361,"title":"Sunday Funday Fall Championship Winner – Josh Dahlstrom of West Fargo, ND","alias":"sunday-funday-fall-championship-winner-josh-dahlstrom-of-west-fargo-nd","excerpt":"🏆 Congratulations to our Sunday Funday Fall Championship Winner – Josh Dahlstrom of West Fargo, ND! 🏆 Josh battled his way through the field to take home $1,050 and the top spot! 🔥 💰 Final Payouts – $2,700 Prize Pool 🥇 $1,050 – Josh Dahlstr…","content":"🏆 Congratulations to our Sunday Funday Fall Championship Winner – Josh Dahlstrom of West Fargo, ND! 🏆 Josh battled his way through the field to take home $1,050 and the top spot! 🔥 💰 Final Payouts – $2,700 Prize Pool 🥇 $1,050 – Josh Dahlstrom -West Fargo, ND 🥈 $750 – Carl Derry - Ortonville, MN 🥉 $500 – Justin Smith -West FargoND 🎖️ $400 – Matthew Klemetson -Ulen, MN A huge thank you to everyone who came out to support the Dakota Poker Tour and the West Fargo Rural Fire Department. 🙌 Stay in the action: 📊 Leaderboard: https://dakotapokertour.com/leaderboard 📅 Calendar: https://dakotapokertour.com/calendar ▶️ YouTube: https://youtube.com/@dakotapokertour","publishedAt":"2025-09-28 19:36:00","featured":true,"logo":"josh-q5mehR7Y.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/josh-q5mehR7Y.jpg","bannerUrl":"","tournament":{"id":321,"name":"Sunday Fun-Day Turbo","alias":"dakota-poker-tour-2025-hagge-s-fall-classic-sunday-fun-day-turbo-09-28-2025"}}'::jsonb),
  (360, 'robert-sylskar-mayville-nd-the-hagge-s-fall-championship-winner', 'Robert Sylskar – Mayville, ND the Hagge’s Fall Championship Winner!', '🏆 Congratulations to the Hagge’s Fall Championship Winner! 🏆 Robert Sylskar – Mayville, ND Taking home $4,700, the DPT Championship Trophy, and claiming his first-ever DPT title! 🎉 🔥 60 players battled it out at Hagge’s Bar, building a $16,…', '2025-09-28 19:29:00', null, 'dakota-poker-tour-2025-hagge-s-fall-classic-fall-classic-megastack-100k-09-27-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3239-4Y76okTH.jpg', '/media/dpt/article/IMG_3239-4Y76okTH.jpg', null, '{"id":360,"title":"Robert Sylskar – Mayville, ND the Hagge’s Fall Championship Winner!","alias":"robert-sylskar-mayville-nd-the-hagge-s-fall-championship-winner","excerpt":"🏆 Congratulations to the Hagge’s Fall Championship Winner! 🏆 Robert Sylskar – Mayville, ND Taking home $4,700, the DPT Championship Trophy, and claiming his first-ever DPT title! 🎉 🔥 60 players battled it out at Hagge’s Bar, building a $16,…","content":"🏆 Congratulations to the Hagge’s Fall Championship Winner! 🏆 Robert Sylskar – Mayville, ND Taking home $4,700, the DPT Championship Trophy, and claiming his first-ever DPT title! 🎉 🔥 60 players battled it out at Hagge’s Bar, building a $16,200 prize pool in the Fall Championship Mega Stack! After two days of action, it all came down to the wire… and Robert stood tall as Champion. Final Table Results: 💰 2nd – $2,800 | Todd Egerdahl – Fargo, ND 💰 3rd – $2,200 | Jeremy Holmes – West Fargo, ND 💰 4th – $1,650 | Jon Wurden – Fisher, MN 💰 5th – $1,350 | Matthew Olsen – West Fargo, ND 💰 6th – $1,160 | Marcy Schultz – Grand Forks, ND 💰 7th – $950 | Adam Laskey – Mapleton, ND 💰 8th – $750 | James Odegaard – Fargo, ND 💰 9th – $650 | Vu Troung – Fargo, ND 🙌 A huge THANK YOU to everyone who came out to support the Dakota Poker Tour and the West Fargo Rural Fire Department! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT YouTube: https://youtube.com/@dakotapokertour","publishedAt":"2025-09-28 19:29:00","featured":true,"logo":"IMG_3239-4Y76okTH.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3239-4Y76okTH.jpg","bannerUrl":"","tournament":{"id":320,"name":"Fall Classic  MEGASTACK (100K)","alias":"dakota-poker-tour-2025-hagge-s-fall-classic-fall-classic-megastack-100k-09-27-2025"}}'::jsonb),
  (359, 'final-table-action', '🔥 Final Table Action! 🔥', 'We are down to the last 9 players in the Hagge’s Fall Championship $100K Mega Stack! 60 players battled it out, building a $16,200 prize pool — and now it’s down to the wire. Who will claim the coveted championship trophy and the $4,200 top…', '2025-09-28 13:44:00', null, 'dakota-poker-tour-2025-hagge-s-fall-classic-fall-classic-megastack-100k-09-27-2025', 'https://dakotapokertour.com/storage/article/thumb/555748659_1448476947279379_729359170473683877_n-lxnos1wS.jpg', '/media/dpt/article/555748659_1448476947279379_729359170473683877_n-lxnos1wS.jpg', null, '{"id":359,"title":"🔥 Final Table Action! 🔥","alias":"final-table-action","excerpt":"We are down to the last 9 players in the Hagge’s Fall Championship $100K Mega Stack! 60 players battled it out, building a $16,200 prize pool — and now it’s down to the wire. Who will claim the coveted championship trophy and the $4,200 top…","content":"We are down to the last 9 players in the Hagge’s Fall Championship $100K Mega Stack! 60 players battled it out, building a $16,200 prize pool — and now it’s down to the wire. Who will claim the coveted championship trophy and the $4,200 top prize? 🏆💰 Here’s your Final Table lineup: • Marcy Schultz – Grand Forks, ND • James Odegaard – Fargo, ND • Todd Egerdahl – Fargo, ND • Jon Warden – Fisher, MN • Matthew Olsen – West Fargo, ND • Adam Laskey – Mapleton, ND • Jeremy Holmes – West Fargo, ND • Bob Skylskar – Mayville, ND • Vu Troung – Texas / Fargo, ND","publishedAt":"2025-09-28 13:44:00","featured":false,"logo":"555748659_1448476947279379_729359170473683877_n-lxnos1wS.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/555748659_1448476947279379_729359170473683877_n-lxnos1wS.jpg","bannerUrl":"","tournament":{"id":320,"name":"Fall Classic  MEGASTACK (100K)","alias":"dakota-poker-tour-2025-hagge-s-fall-classic-fall-classic-megastack-100k-09-27-2025"}}'::jsonb),
  (358, 'sunday-funday-turbo', 'Sunday Funday Turbo', 'The cards are in the air! Plenty of time to get down here for the Sunday Funday Turbo — just $100 gets you 15K in chips with late reg open until Hagge’s Bar – Mapleton, ND $100 Buy-In = 15K starting chips 20-min blind levels Late Reg until…', '2025-09-28 13:40:00', null, 'dakota-poker-tour-2025-hagge-s-fall-classic-sunday-fun-day-turbo-09-28-2025', 'https://dakotapokertour.com/storage/article/thumb/557545431_1448650893928651_4618658126212488191_n-UdCWcrox.jpg', '/media/dpt/article/557545431_1448650893928651_4618658126212488191_n-UdCWcrox.jpg', null, '{"id":358,"title":"Sunday Funday Turbo","alias":"sunday-funday-turbo","excerpt":"The cards are in the air! Plenty of time to get down here for the Sunday Funday Turbo — just $100 gets you 15K in chips with late reg open until Hagge’s Bar – Mapleton, ND $100 Buy-In = 15K starting chips 20-min blind levels Late Reg until…","content":"The cards are in the air! Plenty of time to get down here for the Sunday Funday Turbo — just $100 gets you 15K in chips with late reg open until Hagge’s Bar – Mapleton, ND $100 Buy-In = 15K starting chips 20-min blind levels Late Reg until 5PM $100 Rebuys / Add-On (Double Add-On if no re-buy) DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2025-09-28 13:40:00","featured":false,"logo":"557545431_1448650893928651_4618658126212488191_n-UdCWcrox.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/557545431_1448650893928651_4618658126212488191_n-UdCWcrox.jpg","bannerUrl":"","tournament":{"id":321,"name":"Sunday Fun-Day Turbo","alias":"dakota-poker-tour-2025-hagge-s-fall-classic-sunday-fun-day-turbo-09-28-2025"}}'::jsonb),
  (357, 'day-1-of-the-100k-fall-championship-mega-stack-is-in-the-books', 'Day 1 of the $100K Fall Championship Mega Stack is in the books!', 'We had 60 entries, building a $16,200 prize pool, and just 15 players remain. Leading the charge into Day 2 is James Odegaard (Fargo, ND) with a massive 915,000 chip stack! The average stack sits at 400K, so everyone’s still in the hunt for…', '2025-09-27 23:39:00', null, 'dakota-poker-tour-2025-hagge-s-fall-classic-fall-classic-megastack-100k-09-27-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3200-fUQQskKM.jpg', '/media/dpt/article/IMG_3200-fUQQskKM.jpg', null, '{"id":357,"title":"Day 1 of the $100K Fall Championship Mega Stack is in the books!","alias":"day-1-of-the-100k-fall-championship-mega-stack-is-in-the-books","excerpt":"We had 60 entries, building a $16,200 prize pool, and just 15 players remain. Leading the charge into Day 2 is James Odegaard (Fargo, ND) with a massive 915,000 chip stack! The average stack sits at 400K, so everyone’s still in the hunt for…","content":"We had 60 entries, building a $16,200 prize pool, and just 15 players remain. Leading the charge into Day 2 is James Odegaard (Fargo, ND) with a massive 915,000 chip stack! The average stack sits at 400K, so everyone’s still in the hunt for the title. Players return tomorrow at 12PM to battle for the coveted DPT Championship Trophy and the $4,700 top prize! A huge thank you to everyone who came out to support the Dakota Poker Tour and the West Fargo Rural Fire Department. ♠️♦️ And don’t forget — the action doesn’t stop there! ♦️♠️ The Sunday Funday Turbo kicks off tomorrow at 1PM at Hagge’s Bar – Mapleton, ND • $100 Buy-In = 15K starting chips • 20-Min Blinds | Late Reg until 5PM • $100 Rebuys/Add-On (Double Add-On if no re-buy) Table 2 1 Marcy Schultz- Grandforks Forks ND 435k 2 EMPTY 3 Justin Cole - Mapleton ND 126k 4 Jeremy Holmes West Fargo ND 154k 5 Bob Skylskar Mayville ND 479k 6 Eric Kassa- Whapeton ND 134k 7 Vu Troung - Texas/Fargo ND 382k 8 Jackson Skjerserth Fargo ND 236k 9 Chase Lardy -Fargo ND 270k Table 3 1 Jon Wurden- Fisher MN 504k 2 Craig Thompson -Fargo ND 377k 3 James Odegaard Fargo ND 915k 4 Adam Lasky -Mapleton ND 447k 5 Matthew Olsen - West Fargo ND 759k 6 Empty 7 Todd Egerdahl- Fargo ND 643k 8 Carl Derry - Ortonville MN 153k 9 Empty","publishedAt":"2025-09-27 23:39:00","featured":true,"logo":"IMG_3200-fUQQskKM.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3200-fUQQskKM.jpg","bannerUrl":"","tournament":{"id":320,"name":"Fall Classic  MEGASTACK (100K)","alias":"dakota-poker-tour-2025-hagge-s-fall-classic-fall-classic-megastack-100k-09-27-2025"}}'::jsonb),
  (356, 'registration-is-still-open-for-the-100k-fall-championship-mega-stack', 'Registration is STILL OPEN for the $100K Fall Championship Mega Stack!', 'You’ve got 2 hours left to jump in—plenty of time to get down here and take your shot. The prize pool is already over $15,000 and climbing! Starting stacks are 100K chips with blinds will only be at 3k/6k/6k (at 9pm)—tons of play and big bl…', '2025-09-27 19:14:00', null, 'dakota-poker-tour-2025-hagge-s-fall-classic-fall-classic-megastack-100k-09-27-2025', 'https://dakotapokertour.com/storage/article/thumb/hagge''s-fhxCpYzj.jpg', '/media/dpt/article/hagge-s-fhxCpYzj.jpg', null, '{"id":356,"title":"Registration is STILL OPEN for the $100K Fall Championship Mega Stack!","alias":"registration-is-still-open-for-the-100k-fall-championship-mega-stack","excerpt":"You’ve got 2 hours left to jump in—plenty of time to get down here and take your shot. The prize pool is already over $15,000 and climbing! Starting stacks are 100K chips with blinds will only be at 3k/6k/6k (at 9pm)—tons of play and big bl…","content":"You’ve got 2 hours left to jump in—plenty of time to get down here and take your shot. The prize pool is already over $15,000 and climbing! Starting stacks are 100K chips with blinds will only be at 3k/6k/6k (at 9pm)—tons of play and big blinds to make moves. Current Average Chip Stack Is 151K Hagge’s Bar – Mapleton, ND Saturday 9/27 | Reg 11AM | Cards in Air Noon 40-min blind levels Late reg until 9PM Day 2 restarts Sunday at 12PM We’re raising money for the West Fargo Rural Fire Dept. (state min 10% withheld, max payouts back to players). Five tables are already battling it out—who’s coming for the Championship trophy? Track the action: Leaderboard: https://dakotapokertour.com/leaderboard Calendar: https://dakotapokertour.com/calendar YouTube: https://youtube.com/@dakotapokertour","publishedAt":"2025-09-27 19:14:00","featured":false,"logo":"hagge''s-fhxCpYzj.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/hagge''s-fhxCpYzj.jpg","bannerUrl":"","tournament":{"id":320,"name":"Fall Classic  MEGASTACK (100K)","alias":"dakota-poker-tour-2025-hagge-s-fall-classic-fall-classic-megastack-100k-09-27-2025"}}'::jsonb),
  (355, 'the-100k-fall-championship-mega-stack-is-officially-underway', 'The $100K Fall Championship Mega Stack is officially underway!', 'Cards are in the air and we’ve got 5 tables battling it out already! Hagge’s Bar – Mapleton, ND Saturday 9/27 | Reg 11AM | Shuffle Up & Deal at Noon 40-min blind levels Late reg until 9PM Day 2 restarts Sunday at 12PM This weekend we’re pla…', '2025-09-27 13:51:00', null, 'dakota-poker-tour-2025-hagge-s-fall-classic-fall-classic-megastack-100k-09-27-2025', 'https://dakotapokertour.com/storage/article/thumb/hagges-ZU6VHIq8.jpg', '/media/dpt/article/hagges-ZU6VHIq8.jpg', null, '{"id":355,"title":"The $100K Fall Championship Mega Stack is officially underway!","alias":"the-100k-fall-championship-mega-stack-is-officially-underway","excerpt":"Cards are in the air and we’ve got 5 tables battling it out already! Hagge’s Bar – Mapleton, ND Saturday 9/27 | Reg 11AM | Shuffle Up & Deal at Noon 40-min blind levels Late reg until 9PM Day 2 restarts Sunday at 12PM This weekend we’re pla…","content":"Cards are in the air and we’ve got 5 tables battling it out already! Hagge’s Bar – Mapleton, ND Saturday 9/27 | Reg 11AM | Shuffle Up & Deal at Noon 40-min blind levels Late reg until 9PM Day 2 restarts Sunday at 12PM This weekend we’re playing for huge prizes while raising money for the West Fargo Rural Fire Dept. (state min 10% withheld, max payouts back to players). Who’s taking down the Championship trophy? Track the action: Leaderboard: https://dakotapokertour.com/leaderboard Calendar: https://dakotapokertour.com/calendar YouTube: https://youtube.com/@dakotapokertour","publishedAt":"2025-09-27 13:51:00","featured":false,"logo":"hagges-ZU6VHIq8.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/hagges-ZU6VHIq8.jpg","bannerUrl":"","tournament":{"id":320,"name":"Fall Classic  MEGASTACK (100K)","alias":"dakota-poker-tour-2025-hagge-s-fall-classic-fall-classic-megastack-100k-09-27-2025"}}'::jsonb),
  (354, 'congratulations-to-the-city-brew-champion-mike-columbus', 'Congratulations to the City Brew Champion Mike Columbus', 'Mike Columbus of Red Lake Falls, MN takes home $4,000 and DPT Trophy, triumphing over Josh Matti Dillworth, MN in a fierce heads-up battle! Thank you to everyone who came out to support the Dakota Poker Tour and our charity partner, the Hea…', '2025-09-22 15:15:00', null, 'dakota-poker-tour-2025-city-brew-hall-deep-stack-09-20-2025', 'https://dakotapokertour.com/storage/article/thumb/mike-QOSNZ4VZ.jpg', '/media/dpt/article/mike-QOSNZ4VZ.jpg', null, '{"id":354,"title":"Congratulations to the City Brew Champion Mike Columbus","alias":"congratulations-to-the-city-brew-champion-mike-columbus","excerpt":"Mike Columbus of Red Lake Falls, MN takes home $4,000 and DPT Trophy, triumphing over Josh Matti Dillworth, MN in a fierce heads-up battle! Thank you to everyone who came out to support the Dakota Poker Tour and our charity partner, the Hea…","content":"Mike Columbus of Red Lake Falls, MN takes home $4,000 and DPT Trophy, triumphing over Josh Matti Dillworth, MN in a fierce heads-up battle! Thank you to everyone who came out to support the Dakota Poker Tour and our charity partner, the Head of the Red Youth Activities. It was amazing to see familiar faces and to welcome new friends to the tables—we truly appreciate each and every one of you! Next up: Join us at Haggie’s in Mapleton, ND, next weekend for the 100K Monster Stack! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour 1st $4000 Mike Columbus Red Lake Falls, MN 2nd $2700 Josh Matti Dilworth, MN 3rd $2100 Joel Klipping Red Lake Falls MN 4th $1600 Sam Johnson Wahpeton ND 5th $1200 Craig Evenson Argsville ND 6th $1000 Tony Uhlir Grand Forks ND 7th $830 Steve Belland Bemidji MN 8th $700 Brian Watson Wahpeton ND","publishedAt":"2025-09-22 15:15:00","featured":true,"logo":"mike-QOSNZ4VZ.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/mike-QOSNZ4VZ.jpg","bannerUrl":"","tournament":{"id":319,"name":"Deep Stack","alias":"dakota-poker-tour-2025-city-brew-hall-deep-stack-09-20-2025"}}'::jsonb),
  (353, 'thank-you-players-registration-closed-at-the-city-brew-hall', 'Thank you, players, registration closed at the City Brew Hall', 'A huge thank you to everyone who came out today to support the Dakota Poker Tour and our charity partner, the Head of the Red Youth Activities! 📝 Registration closed with 54 players and 153 add-ons/rebuys, building an incredible $15,700 pri…', '2025-09-20 17:44:00', null, 'dakota-poker-tour-2025-city-brew-hall-deep-stack-09-20-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3064-TpZCcdxQ.png', '/media/dpt/article/IMG_3064-TpZCcdxQ.png', null, '{"id":353,"title":"Thank you, players, registration closed at the City Brew Hall","alias":"thank-you-players-registration-closed-at-the-city-brew-hall","excerpt":"A huge thank you to everyone who came out today to support the Dakota Poker Tour and our charity partner, the Head of the Red Youth Activities! 📝 Registration closed with 54 players and 153 add-ons/rebuys, building an incredible $15,700 pri…","content":"A huge thank you to everyone who came out today to support the Dakota Poker Tour and our charity partner, the Head of the Red Youth Activities! 📝 Registration closed with 54 players and 153 add-ons/rebuys, building an incredible $15,700 prize pool! 💵 🏆 Tonight, 8 players will be taking home cash—good luck to everyone still in the hunt! 👏 Special thanks to the familiar faces who continue to support us and a warm welcome to the new players who joined the action today—we’re glad to have you as part of the DPT family! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2025-09-20 17:44:00","featured":true,"logo":"IMG_3064-TpZCcdxQ.png","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3064-TpZCcdxQ.png","bannerUrl":"","tournament":{"id":319,"name":"Deep Stack","alias":"dakota-poker-tour-2025-city-brew-hall-deep-stack-09-20-2025"}}'::jsonb),
  (352, 'wahpeton-poker-event-5-tables-running-registration-open-till-5pm', 'Wahpeton Poker Event – 5 Tables Running, Registration Open Till 5PM!', 'Cards are in the air now at City Brew Hall in Wahpeton, ND! We’re starting with 5 tables of action, and late registration is open until 5 PM. Buy-in: $150 = 20K in chips Add 10K more for every extra $50 (up to a $300 max buy-in for a 50K st…', '2025-09-20 13:34:00', null, 'dakota-poker-tour-2025-city-brew-hall-deep-stack-09-20-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3026-L51Xu126.jpg', '/media/dpt/article/IMG_3026-L51Xu126.jpg', null, '{"id":352,"title":"Wahpeton Poker Event – 5 Tables Running, Registration Open Till 5PM!","alias":"wahpeton-poker-event-5-tables-running-registration-open-till-5pm","excerpt":"Cards are in the air now at City Brew Hall in Wahpeton, ND! We’re starting with 5 tables of action, and late registration is open until 5 PM. Buy-in: $150 = 20K in chips Add 10K more for every extra $50 (up to a $300 max buy-in for a 50K st…","content":"Cards are in the air now at City Brew Hall in Wahpeton, ND! We’re starting with 5 tables of action, and late registration is open until 5 PM. Buy-in: $150 = 20K in chips Add 10K more for every extra $50 (up to a $300 max buy-in for a 50K starting stack) Dinner break special: Taco Bar for just $10 Watch some college ball, stay dry from the rainy weather, and hang out with your friends while playing great poker! Last year we had 91 players—let’s beat that record today! We’re proud to support the Head of the Red Youth Activities Foundation, keeping the state minimum 10% and giving maximum prize pool back to our players! Don’t miss out—plenty of action still ahead!","publishedAt":"2025-09-20 13:34:00","featured":true,"logo":"IMG_3026-L51Xu126.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3026-L51Xu126.jpg","bannerUrl":"","tournament":{"id":319,"name":"Deep Stack","alias":"dakota-poker-tour-2025-city-brew-hall-deep-stack-09-20-2025"}}'::jsonb),
  (351, 'city-brew-hall-hosts-one-day-poker-event', 'City Brew Hall Hosts One-Day Poker Event', 'Who’s joining us today at City Brew Hall in Wahpeton, ND for this one-day event? 🃏 Cards in the air: 12:00 PM ⏱️ Blinds: 30 minutes 💵 Buy-in: $150 = 20K in chips ➕ Add 10K more for every extra $50 (up to a $300 max buy-in for a 50K starting…', '2025-09-20 11:51:00', null, 'dakota-poker-tour-2025-city-brew-hall-deep-stack-09-20-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3003-euKmr5JA.jpg', '/media/dpt/article/IMG_3003-euKmr5JA.jpg', null, '{"id":351,"title":"City Brew Hall Hosts One-Day Poker Event","alias":"city-brew-hall-hosts-one-day-poker-event","excerpt":"Who’s joining us today at City Brew Hall in Wahpeton, ND for this one-day event? 🃏 Cards in the air: 12:00 PM ⏱️ Blinds: 30 minutes 💵 Buy-in: $150 = 20K in chips ➕ Add 10K more for every extra $50 (up to a $300 max buy-in for a 50K starting…","content":"Who’s joining us today at City Brew Hall in Wahpeton, ND for this one-day event? 🃏 Cards in the air: 12:00 PM ⏱️ Blinds: 30 minutes 💵 Buy-in: $150 = 20K in chips ➕ Add 10K more for every extra $50 (up to a $300 max buy-in for a 50K starting stack) 🕓 Late registration: open until 5 PM 🌮 Dinner break special: Taco Bar for just $10 🏈 Watch the Bison game, stay dry from the rainy weather, and hang out with your friends while playing some great poker! Last year we had 91 players—let’s beat that record today! 🔥 We’re proud to support the Head of the Red Youth Activities Foundation, keeping the state minimum 10% and giving maximum prize pool back to our players! Don’t miss it—see you on the felt! 🃏","publishedAt":"2025-09-20 11:51:00","featured":true,"logo":"IMG_3003-euKmr5JA.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3003-euKmr5JA.jpg","bannerUrl":"","tournament":{"id":319,"name":"Deep Stack","alias":"dakota-poker-tour-2025-city-brew-hall-deep-stack-09-20-2025"}}'::jsonb),
  (350, 'donald-drummond-does-it-again', 'Donald Drummond does it again!', 'Donald claimed victory tonight and took home $2,150! With 28 players in the field, we generated a $6,200 prize pool. A huge thank you to everyone who came out and to our charity partner, Head of the Red Youth Association, for keeping the st…', '2025-09-20 00:34:00', null, 'dakota-poker-tour-2025-city-brew-hall-friday-night-turbo-09-19-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3020-xBRUT7TM.jpg', '/media/dpt/article/IMG_3020-xBRUT7TM.jpg', null, '{"id":350,"title":"Donald Drummond does it again!","alias":"donald-drummond-does-it-again","excerpt":"Donald claimed victory tonight and took home $2,150! With 28 players in the field, we generated a $6,200 prize pool. A huge thank you to everyone who came out and to our charity partner, Head of the Red Youth Association, for keeping the st…","content":"Donald claimed victory tonight and took home $2,150! With 28 players in the field, we generated a $6,200 prize pool. A huge thank you to everyone who came out and to our charity partner, Head of the Red Youth Association, for keeping the state minimum 10%—which means more money back to our players! 📊 DPT Leaderboard: https://dakotapokertour.com/leaderboard 📅 DPT Calendar: https://dakotapokertour.com/calendar ▶️ DPT YouTube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2025-09-20 00:34:00","featured":false,"logo":"IMG_3020-xBRUT7TM.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3020-xBRUT7TM.jpg","bannerUrl":"","tournament":{"id":318,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-city-brew-hall-friday-night-turbo-09-19-2025"}}'::jsonb),
  (348, 'jackson-skjerseth-is-your-poker-brat-black-chip-bounty-champion', 'Jackson Skjerseth  is your Poker Brat Black Chip Bounty Champion', 'Jackson Skjerseth is your Poker Brat Black Chip Bounty Champion….taking home $3,600 plus $1300 bounty’s. Jackson outlasted 92 players to claim victory. Jackson is on fire, he has made 3 final tables and won them all!!! Thank you to everyone…', '2025-06-08 23:13:00', null, 'dakota-poker-tour-2025-the-poker-brat-at-the-windbreak-black-chip-bounty-06-08-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_1242-qQ8kixoK.jpg', '/media/dpt/article/IMG_1242-qQ8kixoK.jpg', null, '{"id":348,"title":"Jackson Skjerseth  is your Poker Brat Black Chip Bounty Champion","alias":"jackson-skjerseth-is-your-poker-brat-black-chip-bounty-champion","excerpt":"Jackson Skjerseth is your Poker Brat Black Chip Bounty Champion….taking home $3,600 plus $1300 bounty’s. Jackson outlasted 92 players to claim victory. Jackson is on fire, he has made 3 final tables and won them all!!! Thank you to everyone…","content":"Jackson Skjerseth is your Poker Brat Black Chip Bounty Champion….taking home $3,600 plus $1300 bounty’s. Jackson outlasted 92 players to claim victory. Jackson is on fire, he has made 3 final tables and won them all!!! Thank you to everyone who came out to support the NPPA Charity and the Dakota Poker Tour. 1st $3600 1st $3600 Jackson Skjerseth Fargo ND $1300 Bountys 2nd $3000 Bradly Craig Casselton ND $600 Bounty’s 3rd $1900 James Whitten Santa Fe $200 Bounty’s 4th $1400 Cole Vatnsdal West Fargo ND $300 Bounty’s 5th $1000 Wade Kyser Erie ND $600 6th $800 Jon Warden Fisher MN $400 in Bounty’s 7th $600 Tim Scott Fargo ND $100 Bounty’s 8th $500 Bob Sylskar Mayville MN $200 bounty’s 9th $400 Jerome Getz Alexandria MN $100 bounty’s 10th $300 Duane Anderson Bemidji MN $400 Bounty’s 11th $300 Bryan Strand West Fargo ND $100 Bounty 12th $300 Ademar Moraes Moorhead MN $200 Bounty’s DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2025-06-08 23:13:00","featured":true,"logo":"IMG_1242-qQ8kixoK.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_1242-qQ8kixoK.jpg","bannerUrl":"","tournament":{"id":317,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2025-the-poker-brat-at-the-windbreak-black-chip-bounty-06-08-2025"}}'::jsonb),
  (349, 'final-table-at-the-poker-brat-black-chip-bounty', 'Final Table at the Poker Brat  Black Chip Bounty', 'Congratulations to the final table at the Poker Brat Black Chip Bounty event! Someone will be taking home $4,000 plus bounty’s. 92 players came out today to generate a prize pool of $23,300. Thank you to everyone who came out to support the…', '2025-06-08 21:30:00', null, 'dakota-poker-tour-2025-the-poker-brat-at-the-windbreak-black-chip-bounty-06-08-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_1234-aBdPq7jm.jpg', '/media/dpt/article/IMG_1234-aBdPq7jm.jpg', null, '{"id":349,"title":"Final Table at the Poker Brat  Black Chip Bounty","alias":"final-table-at-the-poker-brat-black-chip-bounty","excerpt":"Congratulations to the final table at the Poker Brat Black Chip Bounty event! Someone will be taking home $4,000 plus bounty’s. 92 players came out today to generate a prize pool of $23,300. Thank you to everyone who came out to support the…","content":"Congratulations to the final table at the Poker Brat Black Chip Bounty event! Someone will be taking home $4,000 plus bounty’s. 92 players came out today to generate a prize pool of $23,300. Thank you to everyone who came out to support the NPPA clCharity and the Dakota Poker Tour. DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2025-06-08 21:30:00","featured":false,"logo":"IMG_1234-aBdPq7jm.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_1234-aBdPq7jm.jpg","bannerUrl":"","tournament":{"id":317,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2025-the-poker-brat-at-the-windbreak-black-chip-bounty-06-08-2025"}}'::jsonb),
  (347, 'parts-are-in-the-air-at-the-poker-black', 'Cards are in the air at the Poker Brat Black Chip Bounty', 'Cards are in the air at The Poker Brat at the Windbreak Black Chip Bounty Tournament?! 7 tables with late registration available until 5pm. $200 Buy-In gets you a 20K starting stack $100 Add-On available for an extra 20K chips (must have ch…', '2025-06-08 12:43:00', null, 'dakota-poker-tour-2025-the-poker-brat-at-the-windbreak-black-chip-bounty-06-08-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_1168-21bDds7k.jpg', '/media/dpt/article/IMG_1168-21bDds7k.jpg', null, '{"id":347,"title":"Cards are in the air at the Poker Brat Black Chip Bounty","alias":"parts-are-in-the-air-at-the-poker-black","excerpt":"Cards are in the air at The Poker Brat at the Windbreak Black Chip Bounty Tournament?! 7 tables with late registration available until 5pm. $200 Buy-In gets you a 20K starting stack $100 Add-On available for an extra 20K chips (must have ch…","content":"Cards are in the air at The Poker Brat at the Windbreak Black Chip Bounty Tournament?! 7 tables with late registration available until 5pm. $200 Buy-In gets you a 20K starting stack $100 Add-On available for an extra 20K chips (must have chips in play to be eligible) 30-minute blind levels Suggested Dealer Appreciation: $20 ELIMINATE a player, EARN $100! Lunch available from Randy''s Diner, Too “Taco in a Bag” – Chicken or Beef Gluten-friendly options. Tag your crew, bring your A-game, and let’s see who’s got what it takes to be the last one standing! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour #PokerBratBounty #FargoPoker #WindbreakFargo #DakotaPokerTour #BlackChipBounty","publishedAt":"2025-06-08 12:43:00","featured":true,"logo":"IMG_1168-21bDds7k.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_1168-21bDds7k.jpg","bannerUrl":"","tournament":{"id":317,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2025-the-poker-brat-at-the-windbreak-black-chip-bounty-06-08-2025"}}'::jsonb),
  (346, 'urbatsch-goes-all-in-and-takes-it-down', 'Urbatsch Goes All In and Takes It Down!', 'Congratulations to Robert Urbatsch for taking down the Casselton Vets Deep Stack Event ! Robert played like a true champion, outlasting a tough field of 44 players to claim $3,000 in cash , the championship trophy , and of course — ultimate…', '2025-05-10 23:35:00', null, 'dakota-poker-tour-2025-casselton-vets-deep-stack-05-03-2025', 'https://dakotapokertour.com/storage/article/thumb/rob-urb-AJakMiSv.jpg', '/media/dpt/article/rob-urb-AJakMiSv.jpg', null, '{"id":346,"title":"Urbatsch Goes All In and Takes It Down!","alias":"urbatsch-goes-all-in-and-takes-it-down","excerpt":"Congratulations to Robert Urbatsch for taking down the Casselton Vets Deep Stack Event ! Robert played like a true champion, outlasting a tough field of 44 players to claim $3,000 in cash , the championship trophy , and of course — ultimate…","content":"Congratulations to Robert Urbatsch for taking down the Casselton Vets Deep Stack Event ! Robert played like a true champion, outlasting a tough field of 44 players to claim $3,000 in cash , the championship trophy , and of course — ultimate bragging rights ! A big THANK YOU to all the players who came out to support not only the Dakota Poker Tour , but also today''s incredible charity — the Casselton Vets Club . Your continued support means the world, and we’re proud to keep the cards flying for great causes. 2nd $1900 Calvin Riggs West Fargo ND 3rd $1500 Eugene Smith Litchville ND 4th $1200 Donald Drummond Fargo ND 5th $900 Nick Boyum Mahnomen MN 6th $800 Anthony Uhlir Grand Forks ND 7th$700 Jason Kramer West Fargo ND","publishedAt":"2025-05-10 23:35:00","featured":true,"logo":"rob-urb-AJakMiSv.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/rob-urb-AJakMiSv.jpg","bannerUrl":"","tournament":{"id":315,"name":"Deep Stack","alias":"dakota-poker-tour-2025-casselton-vets-deep-stack-05-03-2025"}}'::jsonb),
  (345, 'jackson-skjerseth-claims-victory-in-the-friday-night-turbo', 'Jackson Skjerseth Claims victory in the Friday night Turbo', 'Last night’s turbo at The Casselton Vets Club ended with Jackson Skjerseth defeating 36 players taking home $2200. 2nd $1500 Gaige Reep 3rd $1100 Brad Pausch 4th $850 Steve Belland 5th $600 Carl Wallen 6th $550 Erik Kassa', '2025-05-03 10:36:00', null, 'dakota-poker-tour-2025-casselton-vets-friday-night-turbo-05-02-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_5916-yVB7S6pr.jpg', '/media/dpt/article/IMG_5916-yVB7S6pr.jpg', null, '{"id":345,"title":"Jackson Skjerseth Claims victory in the Friday night Turbo","alias":"jackson-skjerseth-claims-victory-in-the-friday-night-turbo","excerpt":"Last night’s turbo at The Casselton Vets Club ended with Jackson Skjerseth defeating 36 players taking home $2200. 2nd $1500 Gaige Reep 3rd $1100 Brad Pausch 4th $850 Steve Belland 5th $600 Carl Wallen 6th $550 Erik Kassa","content":"Last night’s turbo at The Casselton Vets Club ended with Jackson Skjerseth defeating 36 players taking home $2200. 2nd $1500 Gaige Reep 3rd $1100 Brad Pausch 4th $850 Steve Belland 5th $600 Carl Wallen 6th $550 Erik Kassa","publishedAt":"2025-05-03 10:36:00","featured":false,"logo":"IMG_5916-yVB7S6pr.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_5916-yVB7S6pr.jpg","bannerUrl":"","tournament":{"id":314,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-casselton-vets-friday-night-turbo-05-02-2025"}}'::jsonb),
  (344, 'dpt-spring-champion-nathan-rettke-fargo-nd', 'DPT Spring Champion Nathan Rettke Fargo ND', 'Congratulations Nathan Rettke Your Dakota Poker Tout Spring Champion, taking home the trophy and $6300 cash. Nathan defeated 85 players to claim his first Championship title. Thank you to everyone that came out to support the Dakota Poker T…', '2025-04-27 20:02:00', null, 'dakota-poker-tour-2025-dakota-poker-tour-spring-championship-dpt-spring-championship-megastack-100k-04-26-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_0405-LkQxJ5Ck.jpg', '/media/dpt/article/IMG_0405-LkQxJ5Ck.jpg', null, '{"id":344,"title":"DPT Spring Champion Nathan Rettke Fargo ND","alias":"dpt-spring-champion-nathan-rettke-fargo-nd","excerpt":"Congratulations Nathan Rettke Your Dakota Poker Tout Spring Champion, taking home the trophy and $6300 cash. Nathan defeated 85 players to claim his first Championship title. Thank you to everyone that came out to support the Dakota Poker T…","content":"Congratulations Nathan Rettke Your Dakota Poker Tout Spring Champion, taking home the trophy and $6300 cash. Nathan defeated 85 players to claim his first Championship title. Thank you to everyone that came out to support the Dakota Poker Tour and West Fargo Rule Fire department. Join us next weekend for Casselton Vets Club for an action packed weekend of poker","publishedAt":"2025-04-27 20:02:00","featured":true,"logo":"IMG_0405-LkQxJ5Ck.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_0405-LkQxJ5Ck.jpg","bannerUrl":"","tournament":{"id":312,"name":"DPT Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2025-dakota-poker-tour-spring-championship-dpt-spring-championship-megastack-100k-04-26-2025"}}'::jsonb),
  (343, 'day-one-of-the-spring-championship-has-been-completed', 'Day One of the Spring Championship has been completed', '21 players have bagged chips and are headed into Day Two tomorrow, all with their eyes on that sweet $6,300 first-place cash and the Championship Trophy Cards in the air at 12 PM Blinds: 6k/12k/12k Average stack: 387k The top 10 players mak…', '2025-04-26 23:41:00', null, 'dakota-poker-tour-2025-dakota-poker-tour-spring-championship-dpt-spring-championship-megastack-100k-04-26-2025', 'https://dakotapokertour.com/storage/article/thumb/dpt56-AmyR2V86.jpg', '/media/dpt/article/dpt56-AmyR2V86.jpg', null, '{"id":343,"title":"Day One of the Spring Championship has been completed","alias":"day-one-of-the-spring-championship-has-been-completed","excerpt":"21 players have bagged chips and are headed into Day Two tomorrow, all with their eyes on that sweet $6,300 first-place cash and the Championship Trophy Cards in the air at 12 PM Blinds: 6k/12k/12k Average stack: 387k The top 10 players mak…","content":"21 players have bagged chips and are headed into Day Two tomorrow, all with their eyes on that sweet $6,300 first-place cash and the Championship Trophy Cards in the air at 12 PM Blinds: 6k/12k/12k Average stack: 387k The top 10 players make the money Catch all the action on the live stream from the feature table – it’s going to be a showdown you don’t want to miss! And don’t forget... Sunday Funday Turbo kicks off at 1PM! $100 buy-in = 15k starting stack Late reg open ''til 5PM Thank you again to West Fargo Rural Fire for giving maximum back to the player, keeping the state minimum 10% Table and Seat Assignments Table 1 1.Cindy Schroeder 250K 2. Empty 3.Jon Christensen 148k 4. Miles Barnum 626k 5, Max Beckdol 385k 6.Wade Kyser 397k 7. Empty 8. Jerrod Strod 735k 9. Mike Schultz 226k Table 4 1 Todd Egerdahl 354k 2 Empty 3. Jerome Getz 230k 4.Jason Anderson 141k 5. Craig Thompson 133k 6.Empty 7.Dylan Hanson 770k 8. Skyler Sand 528k 9. Jackson Skyersth 241k Table 5 1.Tony Uhlir 151k 2.Michael Denen 967k 3 Nathan Rettke 487k 4. EMpty 5Empty 6. Brian Twete 319k 7. Chase Lardy 669k 8.Erik Kimble 422k 9 Steve Belland 371k","publishedAt":"2025-04-26 23:41:00","featured":false,"logo":"dpt56-AmyR2V86.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/dpt56-AmyR2V86.jpg","bannerUrl":"","tournament":{"id":312,"name":"DPT Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2025-dakota-poker-tour-spring-championship-dpt-spring-championship-megastack-100k-04-26-2025"}}'::jsonb),
  (342, '20k-prize-pool-and-climbing', '$20K prize pool and climbing!', 'What’s that?! A $20K prize pool and climbing! Plenty of time to join the action — late registration open until 9:30 PM! Bag chips 11:30 PM and come back on Day Two: Sunday at 12 PM. $300 buy-in gets you a 100K starting stack with 40-minute…', '2025-04-26 17:00:00', null, 'dakota-poker-tour-2025-dakota-poker-tour-spring-championship-dpt-spring-championship-megastack-100k-04-26-2025', 'https://dakotapokertour.com/storage/article/thumb/structure-9xv6mwkS.jpg', '/media/dpt/article/structure-9xv6mwkS.jpg', null, '{"id":342,"title":"$20K prize pool and climbing!","alias":"20k-prize-pool-and-climbing","excerpt":"What’s that?! A $20K prize pool and climbing! Plenty of time to join the action — late registration open until 9:30 PM! Bag chips 11:30 PM and come back on Day Two: Sunday at 12 PM. $300 buy-in gets you a 100K starting stack with 40-minute…","content":"What’s that?! A $20K prize pool and climbing! Plenty of time to join the action — late registration open until 9:30 PM! Bag chips 11:30 PM and come back on Day Two: Sunday at 12 PM. $300 buy-in gets you a 100K starting stack with 40-minute blinds Huge shoutout to West Fargo Rule Fire Department — holding the state 10% minimum, giving maximum love back to the poker community. Don’t miss the official livestream — catch all the action starting at 7 PM on YouTube!","publishedAt":"2025-04-26 17:00:00","featured":false,"logo":"structure-9xv6mwkS.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/structure-9xv6mwkS.jpg","bannerUrl":"","tournament":{"id":312,"name":"DPT Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2025-dakota-poker-tour-spring-championship-dpt-spring-championship-megastack-100k-04-26-2025"}}'::jsonb),
  (341, 'cards-are-in-the-air-and-chips-are-flying-at-hagge-s-in-mapelton-nd', 'Cards are in the air and chips are flying at Hagge’s in Mapelton ND.', 'We’ve got 8 tables packed with poker faces (and a few questionable bluffs), and we’ve got room for more— Late registration open ‘til 9:30PM. $300 buy-in gets you 100K in chips and 40-minute blinds. It’s all for a great cause: the West Fargo…', '2025-04-26 14:56:00', null, 'dakota-poker-tour-2025-dakota-poker-tour-spring-championship-dpt-spring-championship-megastack-100k-04-26-2025', 'https://dakotapokertour.com/storage/article/thumb/dpt56-Gvd4OKgw.jpg', '/media/dpt/article/dpt56-Gvd4OKgw.jpg', null, '{"id":341,"title":"Cards are in the air and chips are flying at Hagge’s in Mapelton ND.","alias":"cards-are-in-the-air-and-chips-are-flying-at-hagge-s-in-mapelton-nd","excerpt":"We’ve got 8 tables packed with poker faces (and a few questionable bluffs), and we’ve got room for more— Late registration open ‘til 9:30PM. $300 buy-in gets you 100K in chips and 40-minute blinds. It’s all for a great cause: the West Fargo…","content":"We’ve got 8 tables packed with poker faces (and a few questionable bluffs), and we’ve got room for more— Late registration open ‘til 9:30PM. $300 buy-in gets you 100K in chips and 40-minute blinds. It’s all for a great cause: the West Fargo Rural Fire Department is keeping the state minimum 10% and giving the MAXIMUM back to the prize pool. So your bad beat just might help buy a fire hose. This is an official live stream event, you can find all the action after 7pm on YouTube/@dakotapokertour","publishedAt":"2025-04-26 14:56:00","featured":false,"logo":"dpt56-Gvd4OKgw.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/dpt56-Gvd4OKgw.jpg","bannerUrl":"","tournament":{"id":312,"name":"DPT Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2025-dakota-poker-tour-spring-championship-dpt-spring-championship-megastack-100k-04-26-2025"}}'::jsonb),
  (340, 'the-dakota-poker-tour-has-officially-arrived-at-hagge-s-bar-in-mapelton-north-dakota', 'The Dakota Poker Tour has officially arrived at Hagge’s Bar in Mapelton North Dakota', 'It’s time to shuffle up and deal, the Spring Championship is HERE The only thing hotter than the action at Hagge’s today is someone slow-rolling with pocket aces. Cards are in the air at 12PM. Late registration open until 9:30PM. $300 buy-i…', '2025-04-26 14:46:00', null, 'dakota-poker-tour-2025-dakota-poker-tour-spring-championship-dpt-spring-championship-megastack-100k-04-26-2025', 'https://dakotapokertour.com/storage/article/thumb/dpt12-sGgNrT3V.jpg', '/media/dpt/article/dpt12-sGgNrT3V.jpg', null, '{"id":340,"title":"The Dakota Poker Tour has officially arrived at Hagge’s Bar in Mapelton North Dakota","alias":"the-dakota-poker-tour-has-officially-arrived-at-hagge-s-bar-in-mapelton-north-dakota","excerpt":"It’s time to shuffle up and deal, the Spring Championship is HERE The only thing hotter than the action at Hagge’s today is someone slow-rolling with pocket aces. Cards are in the air at 12PM. Late registration open until 9:30PM. $300 buy-i…","content":"It’s time to shuffle up and deal, the Spring Championship is HERE The only thing hotter than the action at Hagge’s today is someone slow-rolling with pocket aces. Cards are in the air at 12PM. Late registration open until 9:30PM. $300 buy-in, 100k stack, 40-minute blinds — it’s like they want you to play like a legend. That’s right, folks—this is a freezeout. One shot. One stack. One dream. OFFICIAL LIVE STREAM EVENT!— yes, your questionable all-ins can now be judged in real time on YouTube by the internet and your grandma. Every bluff deserves an audience.— come for the poker, stay for the chaos.","publishedAt":"2025-04-26 14:46:00","featured":false,"logo":"dpt12-sGgNrT3V.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/dpt12-sGgNrT3V.jpg","bannerUrl":"","tournament":{"id":312,"name":"DPT Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2025-dakota-poker-tour-spring-championship-dpt-spring-championship-megastack-100k-04-26-2025"}}'::jsonb),
  (339, 'cards-are-in-the-air-at-the-cactus-jack-s-open-here-in-fargo-nd', 'Cards are in the air at the Cactus Jack’s Open here in Fargo, ND!', 'Cards are in the air at the Cactus Jack’s Open here in Fargo, ND! We’ve got 5 tables running and room to grow—late registration is open until 8:20 PM tonight! Buy-in is just $100 for 15K in tournament chips, with rebuys and add-ons availabl…', '2025-04-11 19:09:00', null, 'dakota-poker-tour-2025-cactus-jacks-open-cactus-jacks-open-friday-night-turbo-04-11-2025', 'https://dakotapokertour.com/storage/article/thumb/cactus-pgo-OfoEHRg5.jpg', '/media/dpt/article/cactus-pgo-OfoEHRg5.jpg', null, '{"id":339,"title":"Cards are in the air at the Cactus Jack’s Open here in Fargo, ND!","alias":"cards-are-in-the-air-at-the-cactus-jack-s-open-here-in-fargo-nd","excerpt":"Cards are in the air at the Cactus Jack’s Open here in Fargo, ND! We’ve got 5 tables running and room to grow—late registration is open until 8:20 PM tonight! Buy-in is just $100 for 15K in tournament chips, with rebuys and add-ons availabl…","content":"Cards are in the air at the Cactus Jack’s Open here in Fargo, ND! We’ve got 5 tables running and room to grow—late registration is open until 8:20 PM tonight! Buy-in is just $100 for 15K in tournament chips, with rebuys and add-ons available to keep the action going. Thank you to our host, Plains Art Museum, who’s keeping it real with the state minimum 10%—which means more money back to our players! Don’t miss the feature table, which will be live-streamed tomorrow—come out, play some cards, and be part of the action!","publishedAt":"2025-04-11 19:09:00","featured":false,"logo":"cactus-pgo-OfoEHRg5.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/cactus-pgo-OfoEHRg5.jpg","bannerUrl":"","tournament":{"id":310,"name":"Cactus Jacks Open Friday Night Turbo","alias":"dakota-poker-tour-2025-cactus-jacks-open-cactus-jacks-open-friday-night-turbo-04-11-2025"}}'::jsonb),
  (338, 'cactus-jacks-open-live-stream-feature-event', 'Cactus Jacks Open - Live Stream Feature Event!', 'The Dakota Poker Tour is coming to Cactus Jacks in Fargo with a Feature Table Live Stream production! Join us for two tournaments at Cactus Jacks, starting with a $100 buy-in Friday Night special, followed by a $150 buy-in Deepstack tournam…', '2025-04-06 08:56:00', null, 'dakota-poker-tour-2025-cactus-jacks-open-cactus-jacks-open-main-event-04-12-2025', 'https://dakotapokertour.com/storage/article/thumb/Screenshot-2025-04-06-085749-eYBf2vJ8.png', '/media/dpt/article/Screenshot-2025-04-06-085749-eYBf2vJ8.png', 'https://youtu.be/UJvMmjhOXFc', '{"id":338,"title":"Cactus Jacks Open - Live Stream Feature Event!","alias":"cactus-jacks-open-live-stream-feature-event","excerpt":"The Dakota Poker Tour is coming to Cactus Jacks in Fargo with a Feature Table Live Stream production! Join us for two tournaments at Cactus Jacks, starting with a $100 buy-in Friday Night special, followed by a $150 buy-in Deepstack tournam…","content":"The Dakota Poker Tour is coming to Cactus Jacks in Fargo with a Feature Table Live Stream production! Join us for two tournaments at Cactus Jacks, starting with a $100 buy-in Friday Night special, followed by a $150 buy-in Deepstack tournament on Saturday. Don''t miss this opportunity to cash in big!","publishedAt":"2025-04-06 08:56:00","featured":true,"logo":"Screenshot-2025-04-06-085749-eYBf2vJ8.png","banner":null,"videoUrl":"https://youtu.be/UJvMmjhOXFc","imageUrl":"https://dakotapokertour.com/storage/article/thumb/Screenshot-2025-04-06-085749-eYBf2vJ8.png","bannerUrl":"","tournament":{"id":311,"name":"Cactus Jacks Open Main Event","alias":"dakota-poker-tour-2025-cactus-jacks-open-cactus-jacks-open-main-event-04-12-2025"}}'::jsonb),
  (337, 'final-table-at-the-buckskin-shootout', 'Final Table at The Buckskin Shootout', 'Congratulations to the final table at the Buckskin Shootout. Tonight’s champion will be taking home $4,600! Thank you for everyone who came out tonight to support the Buckskin Saloon, the Ezra Barrows American Legion and the Dakota poker to…', '2025-04-05 23:04:00', null, 'dakota-poker-tour-2025-buckskin-shootout-buckskin-deep-stack-04-05-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_9835-XAhBidrJ.jpg', '/media/dpt/article/IMG_9835-XAhBidrJ.jpg', null, '{"id":337,"title":"Final Table at The Buckskin Shootout","alias":"final-table-at-the-buckskin-shootout","excerpt":"Congratulations to the final table at the Buckskin Shootout. Tonight’s champion will be taking home $4,600! Thank you for everyone who came out tonight to support the Buckskin Saloon, the Ezra Barrows American Legion and the Dakota poker to…","content":"Congratulations to the final table at the Buckskin Shootout. Tonight’s champion will be taking home $4,600! Thank you for everyone who came out tonight to support the Buckskin Saloon, the Ezra Barrows American Legion and the Dakota poker tour. Thank you again to the Ezra Barrows American Legion who will again be taking the state minimum 10%, giving the maximum back to the players!","publishedAt":"2025-04-05 23:04:00","featured":false,"logo":"IMG_9835-XAhBidrJ.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_9835-XAhBidrJ.jpg","bannerUrl":"","tournament":{"id":308,"name":"Buckskin Deep Stack","alias":"dakota-poker-tour-2025-buckskin-shootout-buckskin-deep-stack-04-05-2025"}}'::jsonb),
  (336, 'registration-closed-at-the-buckskin-shootout', 'Registration Closed at the Buckskin Shootout.', 'Registration closed tonight With 65 players creating a $16,000 prize pool. Tonight’s champion will be taking home $4,600! Thank you for everyone who came out tonight to support the Buckskin Saloon, the Ezra Barrows American Legion and the D…', '2025-04-05 21:00:00', null, 'dakota-poker-tour-2025-buckskin-shootout-buckskin-deep-stack-04-05-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_9829-7IFPAGJm.png', '/media/dpt/article/IMG_9829-7IFPAGJm.png', null, '{"id":336,"title":"Registration Closed at the Buckskin Shootout.","alias":"registration-closed-at-the-buckskin-shootout","excerpt":"Registration closed tonight With 65 players creating a $16,000 prize pool. Tonight’s champion will be taking home $4,600! Thank you for everyone who came out tonight to support the Buckskin Saloon, the Ezra Barrows American Legion and the D…","content":"Registration closed tonight With 65 players creating a $16,000 prize pool. Tonight’s champion will be taking home $4,600! Thank you for everyone who came out tonight to support the Buckskin Saloon, the Ezra Barrows American Legion and the Dakota poker tour. Thank you again to the Ezra Barrows American Legion who will again be taking the state minimum 10%, giving the maximum back to the players!","publishedAt":"2025-04-05 21:00:00","featured":false,"logo":"IMG_9829-7IFPAGJm.png","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_9829-7IFPAGJm.png","bannerUrl":"","tournament":{"id":308,"name":"Buckskin Deep Stack","alias":"dakota-poker-tour-2025-buckskin-shootout-buckskin-deep-stack-04-05-2025"}}'::jsonb),
  (335, 'it-s-a-full-house-here-at-the-buckskin-in-killdeer-nd', 'It’s a full house here at the Buckskin in Killdeer, ND', 'It’s a full house here at the Buckskin in Killdeer, ND! With 7 full tables, the prize pool is already up to $12,000 and still climbing! Late registration is open until 5pm, so there’s still time to get in on the action. Come for the best fo…', '2025-04-05 14:56:00', null, 'dakota-poker-tour-2025-buckskin-shootout-buckskin-deep-stack-04-05-2025', 'https://dakotapokertour.com/storage/article/thumb/killdeer5-FC9d1Aio.jpg', '/media/dpt/article/killdeer5-FC9d1Aio.jpg', null, '{"id":335,"title":"It’s a full house here at the Buckskin in Killdeer, ND","alias":"it-s-a-full-house-here-at-the-buckskin-in-killdeer-nd","excerpt":"It’s a full house here at the Buckskin in Killdeer, ND! With 7 full tables, the prize pool is already up to $12,000 and still climbing! Late registration is open until 5pm, so there’s still time to get in on the action. Come for the best fo…","content":"It’s a full house here at the Buckskin in Killdeer, ND! With 7 full tables, the prize pool is already up to $12,000 and still climbing! Late registration is open until 5pm, so there’s still time to get in on the action. Come for the best food in town, stay for the chance to win some serious cash, and maybe even take home this awesome trophy! Thank you again to the Ezra Barrows Post 46 American Legion who will again be taking the state minimum 10%, giving the maximum back to the players!","publishedAt":"2025-04-05 14:56:00","featured":true,"logo":"killdeer5-FC9d1Aio.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/killdeer5-FC9d1Aio.jpg","bannerUrl":"","tournament":{"id":308,"name":"Buckskin Deep Stack","alias":"dakota-poker-tour-2025-buckskin-shootout-buckskin-deep-stack-04-05-2025"}}'::jsonb),
  (334, 'registration-closed-at-the-buckskin-shootout-friday-night-turbo', 'Registration Closed at the Buckskin Shootout Friday Night Turbo!', 'Thank you to the 34 players who joined us for Friday night turbo! Someone is walking away with a grand prize of $2200 in CASH tonight! Tomorrow, don’t miss out on the Single Day Deep Stack event! Cards go in the air at 12pm MST, with late r…', '2025-04-04 22:17:00', null, 'dakota-poker-tour-2025-buckskin-shootout-buckskin-friday-night-turbo-04-04-2025', 'https://dakotapokertour.com/storage/article/thumb/trophie-killdeet-ebrDf6kp.jpg', '/media/dpt/article/trophie-killdeet-ebrDf6kp.jpg', null, '{"id":334,"title":"Registration Closed at the Buckskin Shootout Friday Night Turbo!","alias":"registration-closed-at-the-buckskin-shootout-friday-night-turbo","excerpt":"Thank you to the 34 players who joined us for Friday night turbo! Someone is walking away with a grand prize of $2200 in CASH tonight! Tomorrow, don’t miss out on the Single Day Deep Stack event! Cards go in the air at 12pm MST, with late r…","content":"Thank you to the 34 players who joined us for Friday night turbo! Someone is walking away with a grand prize of $2200 in CASH tonight! Tomorrow, don’t miss out on the Single Day Deep Stack event! Cards go in the air at 12pm MST, with late registration available until 5pm. Thank you again to the Ezra Barrows Post 46 American Legion who will again be taking the state minimum 10%, giving the maximum back to the players! play some poker win some cash!","publishedAt":"2025-04-04 22:17:00","featured":false,"logo":"trophie-killdeet-ebrDf6kp.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/trophie-killdeet-ebrDf6kp.jpg","bannerUrl":"","tournament":{"id":307,"name":"Buckskin Friday Night Turbo","alias":"dakota-poker-tour-2025-buckskin-shootout-buckskin-friday-night-turbo-04-04-2025"}}'::jsonb),
  (333, 'cards-in-the-air-for-the-buckskin-shootout-friday-night-turbo', 'Cards in the air for the Buckskin Shootout Friday Night Turbo', 'The Buckskin Shootout is underway with 4 tables in play. Late registration remains open until 8:00 PM—there’s still time to get in on the action A big thanks to the Ezra Barrows Post 46 American Legion for hosting this great event. And the…', '2025-04-04 22:09:00', null, 'dakota-poker-tour-2025-buckskin-shootout-buckskin-friday-night-turbo-04-04-2025', 'https://dakotapokertour.com/storage/article/thumb/killdeer-880ZlH0Y.jpg', '/media/dpt/article/killdeer-880ZlH0Y.jpg', null, '{"id":333,"title":"Cards in the air for the Buckskin Shootout Friday Night Turbo","alias":"cards-in-the-air-for-the-buckskin-shootout-friday-night-turbo","excerpt":"The Buckskin Shootout is underway with 4 tables in play. Late registration remains open until 8:00 PM—there’s still time to get in on the action A big thanks to the Ezra Barrows Post 46 American Legion for hosting this great event. And the…","content":"The Buckskin Shootout is underway with 4 tables in play. Late registration remains open until 8:00 PM—there’s still time to get in on the action A big thanks to the Ezra Barrows Post 46 American Legion for hosting this great event. And the best part? The charity is only taking the state minimum 10%, giving the maximum back to the players! Come for the poker, stay for the food! The Bucksin Saloon has the best food around — grab some dinner, play some poker win some cash!","publishedAt":"2025-04-04 22:09:00","featured":false,"logo":"killdeer-880ZlH0Y.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/killdeer-880ZlH0Y.jpg","bannerUrl":"","tournament":{"id":307,"name":"Buckskin Friday Night Turbo","alias":"dakota-poker-tour-2025-buckskin-shootout-buckskin-friday-night-turbo-04-04-2025"}}'::jsonb),
  (332, 'your-pour-decisions-champion-david-hilley-from-dillingham-ak', 'Your Pour Decisions Champion David Hilley from Dillingham AK', 'Your Pour Decisions Champion David Hilley from Dillingham AK taking home $3000 and the coveted trophy! David came out victorious after a back and forth heads up battle with Mark Ihringer of Williston ND. Thank you again everyone who came ou…', '2025-03-29 22:14:00', null, 'dakota-poker-tour-2025-pour-decisions-pour-decisions-deep-stack-03-29-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_9651-QhQEiGPd.jpg', '/media/dpt/article/IMG_9651-QhQEiGPd.jpg', null, '{"id":332,"title":"Your Pour Decisions Champion David Hilley from Dillingham AK","alias":"your-pour-decisions-champion-david-hilley-from-dillingham-ak","excerpt":"Your Pour Decisions Champion David Hilley from Dillingham AK taking home $3000 and the coveted trophy! David came out victorious after a back and forth heads up battle with Mark Ihringer of Williston ND. Thank you again everyone who came ou…","content":"Your Pour Decisions Champion David Hilley from Dillingham AK taking home $3000 and the coveted trophy! David came out victorious after a back and forth heads up battle with Mark Ihringer of Williston ND. Thank you again everyone who came out and showed their support for Prarie Public Broadcasting, Pour Decisions Steakhouse, and The Dakota Poker Tour. Next weekend, we’re headed to Killdeer, ND for more action packed Friday and Saturday at the Buckskin Saloon","publishedAt":"2025-03-29 22:14:00","featured":true,"logo":"IMG_9651-QhQEiGPd.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_9651-QhQEiGPd.jpg","bannerUrl":"","tournament":{"id":306,"name":"Pour Decisions Deep Stack","alias":"dakota-poker-tour-2025-pour-decisions-pour-decisions-deep-stack-03-29-2025"}}'::jsonb),
  (331, 'registration-is-closed-at-poor-decisions-in-tioga', 'Registration is closed at Poor Decisions in Tioga!', 'Registration is closed at Poor Decisions in Tioga! We had 37 players join the action, generating a prize pool of $8,585! Top 5 players will be taking home cash, and one lucky champion will walk away with $3,000 AND the coveted Pour Decision…', '2025-03-29 17:52:00', null, 'dakota-poker-tour-2025-pour-decisions-pour-decisions-deep-stack-03-29-2025', 'https://dakotapokertour.com/storage/article/thumb/tioga-pUmFQpQb.jpg', '/media/dpt/article/tioga-pUmFQpQb.jpg', null, '{"id":331,"title":"Registration is closed at Poor Decisions in Tioga!","alias":"registration-is-closed-at-poor-decisions-in-tioga","excerpt":"Registration is closed at Poor Decisions in Tioga! We had 37 players join the action, generating a prize pool of $8,585! Top 5 players will be taking home cash, and one lucky champion will walk away with $3,000 AND the coveted Pour Decision…","content":"Registration is closed at Poor Decisions in Tioga! We had 37 players join the action, generating a prize pool of $8,585! Top 5 players will be taking home cash, and one lucky champion will walk away with $3,000 AND the coveted Pour Decisions trophy! Big thanks to everyone who participated and came out to support Prairie Public Broadcasting and the Dakota Poker Tour. Next weekend, we’re headed to Killdeer, ND for more action at the Buckskin Saloon • Friday night Turbo • Saturday Deep Stack","publishedAt":"2025-03-29 17:52:00","featured":false,"logo":"tioga-pUmFQpQb.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/tioga-pUmFQpQb.jpg","bannerUrl":"","tournament":{"id":306,"name":"Pour Decisions Deep Stack","alias":"dakota-poker-tour-2025-pour-decisions-pour-decisions-deep-stack-03-29-2025"}}'::jsonb),
  (330, 'cards-are-in-the-air-at-pour-decisions-in-tioga-nd', 'Cards are in the air at Pour Decisions in Tioga, ND', 'Cards are in the air at Pour Decisions in Tioga, ND! There’s still plenty of time to join the action with late registration open until 5 PM. $150 gets you a 20k starting stack and 4 tables are already in play! Come down, take a shot at this…', '2025-03-29 13:56:00', null, 'dakota-poker-tour-2025-pour-decisions-pour-decisions-deep-stack-03-29-2025', 'https://dakotapokertour.com/storage/article/thumb/pour-decisions06-FfqfxmW0.jpg', '/media/dpt/article/pour-decisions06-FfqfxmW0.jpg', null, '{"id":330,"title":"Cards are in the air at Pour Decisions in Tioga, ND","alias":"cards-are-in-the-air-at-pour-decisions-in-tioga-nd","excerpt":"Cards are in the air at Pour Decisions in Tioga, ND! There’s still plenty of time to join the action with late registration open until 5 PM. $150 gets you a 20k starting stack and 4 tables are already in play! Come down, take a shot at this…","content":"Cards are in the air at Pour Decisions in Tioga, ND! There’s still plenty of time to join the action with late registration open until 5 PM. $150 gets you a 20k starting stack and 4 tables are already in play! Come down, take a shot at this awesome trophy, and grab your share of the cash. Let’s make some POUR DECISIONS!","publishedAt":"2025-03-29 13:56:00","featured":false,"logo":"pour-decisions06-FfqfxmW0.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/pour-decisions06-FfqfxmW0.jpg","bannerUrl":"","tournament":{"id":306,"name":"Pour Decisions Deep Stack","alias":"dakota-poker-tour-2025-pour-decisions-pour-decisions-deep-stack-03-29-2025"}}'::jsonb),
  (329, 'congratulations-to-eric-thompson-2025-listen-inc-monster-stack-champion', 'Congratulations to Eric Thompson – 2025 LISTEN INC Monster Stack Champion', 'Congratulations Eric Thompson of East Grand Forks, ND, who triumphed over the defending champion, Joel Kippling, in an intense heads-up battle to take home the 2025 LISTEN INC Monster Stack title! Eric earned a well-deserved $6,000 and the…', '2025-03-23 01:45:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-saturday-monster-stack-03-22-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_9528-jUL2mjUe.jpg', '/media/dpt/article/IMG_9528-jUL2mjUe.jpg', null, '{"id":329,"title":"Congratulations to Eric Thompson – 2025 LISTEN INC Monster Stack Champion","alias":"congratulations-to-eric-thompson-2025-listen-inc-monster-stack-champion","excerpt":"Congratulations Eric Thompson of East Grand Forks, ND, who triumphed over the defending champion, Joel Kippling, in an intense heads-up battle to take home the 2025 LISTEN INC Monster Stack title! Eric earned a well-deserved $6,000 and the…","content":"Congratulations Eric Thompson of East Grand Forks, ND, who triumphed over the defending champion, Joel Kippling, in an intense heads-up battle to take home the 2025 LISTEN INC Monster Stack title! Eric earned a well-deserved $6,000 and the coveted trophy. A big thank you to everyone who came out to support LISTEN INC and the Dakota Poker Tour – We appreciate all the players and fans for making this such a successful tournament! Champion $6000 Eric Thompson East Grand Forks ND 2nd $3800 Joel Klipping Red Lake Falls MN 3rd $2700 Rob Urbatsch Fargo ND 4th $2000 Henry Anderson Little Saskatchewan MB 5th $1600 Jesse Haddeland Fargo ND 6th $1300 Alex Mollberg Hawley MN 7th $1100 Satya Vegi Fargo ND 8th $800 Marcie Schultz Grand Forks ND 9th $600 Jim Bohlman Rugby ND","publishedAt":"2025-03-23 01:45:00","featured":true,"logo":"IMG_9528-jUL2mjUe.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/