  (327, 'registration-closed-tonight-for-the-listen-inc-monster-stack-event', 'Registration Closed Tonight for the LISTEN INC Monster Stack Event', 'Thank you to everyone who participated in tonight’s LISTEN INC Monster Stack event! With 78 players and a prize pool of $19,900. One lucky player will walk away with $6,000 in cash and the coveted trophy. We appreciate your continued suppor…', '2025-03-22 18:49:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-saturday-monster-stack-03-22-2025', 'https://dakotapokertour.com/storage/article/thumb/prize-pool11-LOOG1vMj.jpg', '/media/dpt/article/prize-pool11-LOOG1vMj.jpg', null, '{"id":327,"title":"Registration Closed Tonight for the LISTEN INC Monster Stack Event","alias":"registration-closed-tonight-for-the-listen-inc-monster-stack-event","excerpt":"Thank you to everyone who participated in tonight’s LISTEN INC Monster Stack event! With 78 players and a prize pool of $19,900. One lucky player will walk away with $6,000 in cash and the coveted trophy. We appreciate your continued suppor…","content":"Thank you to everyone who participated in tonight’s LISTEN INC Monster Stack event! With 78 players and a prize pool of $19,900. One lucky player will walk away with $6,000 in cash and the coveted trophy. We appreciate your continued support for the Dakota Poker Tour and the LISTEN INC charity. Best of luck to all the players still in the game!","publishedAt":"2025-03-22 18:49:00","featured":false,"logo":"prize-pool11-LOOG1vMj.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/prize-pool11-LOOG1vMj.jpg","bannerUrl":"","tournament":{"id":288,"name":"L.i.s.t.e.n. Inc Monster Stack","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-saturday-monster-stack-03-22-2025"}}'::jsonb),
  (326, 'cards-are-in-the-air-for-the-listen-inc-charity-monster-stack-event', 'Cards Are in the Air for the LISTEN INC Charity Monster Stack Event!', 'The LISTEN INC Charity Monster Stack Event kicks off today at thee Canad Inn! With a massive 100k starting chip stack for $300. We’ve already got 5 tables filled and counting, and late registration is open until 6pm, so there’s still time t…', '2025-03-22 11:43:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-saturday-monster-stack-03-22-2025', 'https://dakotapokertour.com/storage/article/thumb/dakota-trophy-yv9zsXaE.jpg', '/media/dpt/article/dakota-trophy-yv9zsXaE.jpg', null, '{"id":326,"title":"Cards Are in the Air for the LISTEN INC Charity Monster Stack Event!","alias":"cards-are-in-the-air-for-the-listen-inc-charity-monster-stack-event","excerpt":"The LISTEN INC Charity Monster Stack Event kicks off today at thee Canad Inn! With a massive 100k starting chip stack for $300. We’ve already got 5 tables filled and counting, and late registration is open until 6pm, so there’s still time t…","content":"The LISTEN INC Charity Monster Stack Event kicks off today at thee Canad Inn! With a massive 100k starting chip stack for $300. We’ve already got 5 tables filled and counting, and late registration is open until 6pm, so there’s still time to get in on the action. Last year’s winner walked away with over $7,000, and this year’s champion will take home both a brand-new trophy and a hefty cash prize.","publishedAt":"2025-03-22 11:43:00","featured":false,"logo":"dakota-trophy-yv9zsXaE.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/dakota-trophy-yv9zsXaE.jpg","bannerUrl":"","tournament":{"id":288,"name":"L.i.s.t.e.n. Inc Monster Stack","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-saturday-monster-stack-03-22-2025"}}'::jsonb),
  (325, 'congratulations-jim-paskett-of-grand-forks-nd', 'Congratulations Jim Paskett of Grand Forks ND', 'Congratulations to Jim Paskett for taking home the first-place prize of $3,200! A big thank you to all 51 players who came out tonight for the Friday Night Turbo at Canad Inn in Grand Forks. Your support for the LISTEN INC Charity and the D…', '2025-03-22 01:16:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-friday-night-turbo-03-21-2025', 'https://dakotapokertour.com/storage/article/thumb/jim-paskett-0UoFWfWV.jpg', '/media/dpt/article/jim-paskett-0UoFWfWV.jpg', null, '{"id":325,"title":"Congratulations Jim Paskett of Grand Forks ND","alias":"congratulations-jim-paskett-of-grand-forks-nd","excerpt":"Congratulations to Jim Paskett for taking home the first-place prize of $3,200! A big thank you to all 51 players who came out tonight for the Friday Night Turbo at Canad Inn in Grand Forks. Your support for the LISTEN INC Charity and the D…","content":"Congratulations to Jim Paskett for taking home the first-place prize of $3,200! A big thank you to all 51 players who came out tonight for the Friday Night Turbo at Canad Inn in Grand Forks. Your support for the LISTEN INC Charity and the Dakota Poker Tour is greatly appreciated! We’ll see you tomorrow for the Monster Stack Event, starting at 11 AM, with late registration available until 6 PM. 1st $3200 Jim Paskett Grand Forks ND 2nd $2100 Karsen Johnson Grand Forks ND 3rd $1600 Steve Belland Bagley MN 4th $1300 Jeff Steer Warren MN 5th $1000 Santos Reyes Grafton ND 6th $800 Brad Carlson Menahga MN 7th $620 Larry Britton Circle Pines MN","publishedAt":"2025-03-22 01:16:00","featured":true,"logo":"jim-paskett-0UoFWfWV.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/jim-paskett-0UoFWfWV.jpg","bannerUrl":"","tournament":{"id":287,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-friday-night-turbo-03-21-2025"}}'::jsonb),
  (324, 'final-table-in-the-friday-night-turbo', 'Final Table in The Friday Night Turbo', 'Congrats to the 7 remaining players taking home cash tonight in the LISTEN INC Friday Night Turbo. Who’s walking away with the 1st place prize of $3200?! 51 players came out tonight, creating a prize pool of $10,620.', '2025-03-22 00:01:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-friday-night-turbo-03-21-2025', 'https://dakotapokertour.com/storage/article/thumb/final-table-2-1xmd5lI8.jpg', '/media/dpt/article/final-table-2-1xmd5lI8.jpg', null, '{"id":324,"title":"Final Table in The Friday Night Turbo","alias":"final-table-in-the-friday-night-turbo","excerpt":"Congrats to the 7 remaining players taking home cash tonight in the LISTEN INC Friday Night Turbo. Who’s walking away with the 1st place prize of $3200?! 51 players came out tonight, creating a prize pool of $10,620.","content":"Congrats to the 7 remaining players taking home cash tonight in the LISTEN INC Friday Night Turbo. Who’s walking away with the 1st place prize of $3200?! 51 players came out tonight, creating a prize pool of $10,620.","publishedAt":"2025-03-22 00:01:00","featured":false,"logo":"final-table-2-1xmd5lI8.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/final-table-2-1xmd5lI8.jpg","bannerUrl":"","tournament":{"id":287,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-friday-night-turbo-03-21-2025"}}'::jsonb),
