  (306, 'we-ve-got-a-full-house-here-at-the-angry-beaver-in-oaks', 'Full House at Angry Beaver', 'We’ve got a full house here at the Angry Beaver in Oakes with nine (9) tables in play! There’s still time to buy in with late registration open until 5 PM today. Buy-ins are $150 for a 20k starting stack or $300 for a 50k starting stack. It…', '2025-03-01 13:25:00', null, 'dakota-poker-tour-2025-hole-in-one-deepstack-angry-beaver-deep-stack-03-01-2025', '', '', null, '{"id":306,"title":"Full House at Angry Beaver","alias":"we-ve-got-a-full-house-here-at-the-angry-beaver-in-oaks","excerpt":"We’ve got a full house here at the Angry Beaver in Oakes with nine (9) tables in play! There’s still time to buy in with late registration open until 5 PM today. Buy-ins are $150 for a 20k starting stack or $300 for a 50k starting stack. It…","content":"We’ve got a full house here at the Angry Beaver in Oakes with nine (9) tables in play! There’s still time to buy in with late registration open until 5 PM today. Buy-ins are $150 for a 20k starting stack or $300 for a 50k starting stack. It’s a great chance to play some poker while supporting the Hole in One Foundation. The winner will earn the Trophy, hat, and CASH — last year’s champ took home $6,800 and it looks like we will beat that today!","publishedAt":"2025-03-01 13:25:00","featured":false,"logo":"","banner":null,"videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":302,"name":"Angry Beaver Deep Stack","alias":"dakota-poker-tour-2025-hole-in-one-deepstack-angry-beaver-deep-stack-03-01-2025"}}'::jsonb),
  (305, 'hole-in-one-foundation-poker-tournament-oakes-north-dakota', 'Today''s Tournament Kicks Off at NOON', 'We are kicking off the Hole in one tournament in Oaks ND. Late registration until 5pm. $150 get 20k in starting chips. Last years winner took home $6800. Lunch will be a Burger bar for $15 lots of time to get here and support The Hole in On…', '2025-03-01 12:01:00', null, 'dakota-poker-tour-2025-hole-in-one-deepstack-angry-beaver-deep-stack-03-01-2025', '', '', null, '{"id":305,"title":"Today''s Tournament Kicks Off at NOON","alias":"hole-in-one-foundation-poker-tournament-oakes-north-dakota","excerpt":"We are kicking off the Hole in one tournament in Oaks ND. Late registration until 5pm. $150 get 20k in starting chips. Last years winner took home $6800. Lunch will be a Burger bar for $15 lots of time to get here and support The Hole in On…","content":"We are kicking off the Hole in one tournament in Oaks ND. Late registration until 5pm. $150 get 20k in starting chips. Last years winner took home $6800. Lunch will be a Burger bar for $15 lots of time to get here and support The Hole in One Foundation . Today’s winner will be taking home the custom hat trophy and cash.","publishedAt":"2025-03-01 12:01:00","featured":false,"logo":"","banner":null,"videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":302,"name":"Angry Beaver Deep Stack","alias":"dakota-poker-tour-2025-hole-in-one-deepstack-angry-beaver-deep-stack-03-01-2025"}}'::jsonb),
  (302, 'congratulations-bradley-craig', 'Bradley Craig Captures Dead Money Open', 'Bradley Craig came out on top at the Dead Money Open - taking home $6200 cash. Thank you everyone that came out to support West Fargo Hockey and The Dakota Poker Tour. Next up: Hole in One Event in Oakes ND March 1st. 1st $6200 Bradley Crai…', '2025-02-02 00:41:00', null, 'dakota-poker-tour-2025-dead-money-open-deep-stack-02-01-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_8575-amRfLPht.jpg', '/media/dpt/article/IMG_8575-amRfLPht.jpg', null, '{"id":302,"title":"Bradley Craig Captures Dead Money Open","alias":"congratulations-bradley-craig","excerpt":"Bradley Craig came out on top at the Dead Money Open - taking home $6200 cash. Thank you everyone that came out to support West Fargo Hockey and The Dakota Poker Tour. Next up: Hole in One Event in Oakes ND March 1st. 1st $6200 Bradley Crai…","content":"Bradley Craig came out on top at the Dead Money Open - taking home $6200 cash. Thank you everyone that came out to support West Fargo Hockey and The Dakota Poker Tour. Next up: Hole in One Event in Oakes ND March 1st. 1st $6200 Bradley Craig Casselton ND 2nd $4000 Austyn Christiansen Fargo ND 3rd $3000 Brad Pausch Wahpeton ND 4th $2000 Tanner Carlson Hankenson ND 5th $1500 Jeremy Danielson Fargo ND 6th $1300 Jon Christensen Casselton ND 7th $1100 Steve Belland Bemidji MN 8th $900 Mark Duffner Crookston MN 9th $700 Darrin Tougas Moorehead MN 10th $500 Randall Smith - MN DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2025-02-02 00:41:00","featured":true,"logo":"IMG_8575-amRfLPht.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_8575-amRfLPht.jpg","bannerUrl":"","tournament":{"id":297,"name":"Deep Stack","alias":"dakota-poker-tour-2025-dead-money-open-deep-stack-02-01-2025"}}'::jsonb),
