  (299, 'cards-in-the-air-at-the-dead-money-open-2', 'Cards in the Air at The Dead Money Open', 'Cards are in the air at the Dead Money Open. 6 Tables to start. Lots of time to get down here, late registration until 5pm. $150 gets you 20k in chips for an additional $50 you get another 10k max buyin $300. Last year’s winner took home $8…', '2025-02-01 13:00:00', null, 'dakota-poker-tour-2025-dead-money-open-deep-stack-02-01-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_8550-cMaAaV99.jpg', '/media/dpt/article/IMG_8550-cMaAaV99.jpg', null, '{"id":299,"title":"Cards in the Air at The Dead Money Open","alias":"cards-in-the-air-at-the-dead-money-open-2","excerpt":"Cards are in the air at the Dead Money Open. 6 Tables to start. Lots of time to get down here, late registration until 5pm. $150 gets you 20k in chips for an additional $50 you get another 10k max buyin $300. Last year’s winner took home $8…","content":"Cards are in the air at the Dead Money Open. 6 Tables to start. Lots of time to get down here, late registration until 5pm. $150 gets you 20k in chips for an additional $50 you get another 10k max buyin $300. Last year’s winner took home $8100. Food specials today from Maria’s Mexican, catered in! Food available until 9pm. DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2025-02-01 13:00:00","featured":false,"logo":"IMG_8550-cMaAaV99.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_8550-cMaAaV99.jpg","bannerUrl":"","tournament":{"id":297,"name":"Deep Stack","alias":"dakota-poker-tour-2025-dead-money-open-deep-stack-02-01-2025"}}'::jsonb),
