  (294, 'registration-closed-in-the-friday-night-turbo-with-55-players-2', 'Registration closed in the Friday night turbo with 55 players', 'Registration closed tonight in the Dead Money Open Friday night turbo, with 55 players generating an impressive prize pool of $9,860! The winner tonight will walk away with $3,000! Dont forget, tomorrow''s s action kicks off at 12pm with the…', '2025-01-31 21:21:00', null, 'dakota-poker-tour-2025-dead-money-open-friday-night-turbo-01-31-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_8501-7JcDN2T8.png', '/media/dpt/article/IMG_8501-7JcDN2T8.png', null, '{"id":294,"title":"Registration closed in the Friday night turbo with 55 players","alias":"registration-closed-in-the-friday-night-turbo-with-55-players-2","excerpt":"Registration closed tonight in the Dead Money Open Friday night turbo, with 55 players generating an impressive prize pool of $9,860! The winner tonight will walk away with $3,000! Dont forget, tomorrow''s s action kicks off at 12pm with the…","content":"Registration closed tonight in the Dead Money Open Friday night turbo, with 55 players generating an impressive prize pool of $9,860! The winner tonight will walk away with $3,000! Dont forget, tomorrow''s s action kicks off at 12pm with the Single Day Deep Stack tournament. DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2025-01-31 21:21:00","featured":false,"logo":"IMG_8501-7JcDN2T8.png","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_8501-7JcDN2T8.png","bannerUrl":"","tournament":{"id":296,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-dead-money-open-friday-night-turbo-01-31-2025"}}'::jsonb),
  (292, 'registration-open-at-the-m-j', 'Registration open at the M&J', '7 tables and room for more!! Get down here registration open till 8:15 PM . $100 gets you 15k in chips. Good food from Maria’s Mexican here until 9pm tonight and tomorrow!', '2025-01-31 18:34:00', null, 'dakota-poker-tour-2025-dead-money-open-friday-night-turbo-01-31-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_8499-beiT072R.jpg', '/media/dpt/article/IMG_8499-beiT072R.jpg', null, '{"id":292,"title":"Registration open at the M&J","alias":"registration-open-at-the-m-j","excerpt":"7 tables and room for more!! Get down here registration open till 8:15 PM . $100 gets you 15k in chips. Good food from Maria’s Mexican here until 9pm tonight and tomorrow!","content":"7 tables and room for more!! Get down here registration open till 8:15 PM . $100 gets you 15k in chips. Good food from Maria’s Mexican here until 9pm tonight and tomorrow!","publishedAt":"2025-01-31 18:34:00","featured":false,"logo":"IMG_8499-beiT072R.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_8499-beiT072R.jpg","bannerUrl":"","tournament":{"id":296,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-dead-money-open-friday-night-turbo-01-31-2025"}}'::jsonb),
  (291, 'dead-money-open-2025-hype-video', 'Dead Money Open 2025 - *HYPE VIDEO*', 'Hey guys, mark your calendars! DPT kicks off the 2025 season at the M&J Saloon in West Fargo on Friday, January 31st and Saturday, February 1st. Friday night features a Turbo even t starting at 6 PM . Saturday ''s single-day deep stack start…', '2025-01-22 14:14:00', null, null, 'https://dakotapokertour.com/storage/article/thumb/DPT-2025-Dead-Money-Open-d2s3jssM-xxPnWuZa.png', '/media/dpt/article/DPT-2025-Dead-Money-Open-d2s3jssM-xxPnWuZa.png', 'https://youtu.be/VL0aZtNiJnw', '{"id":291,"title":"Dead Money Open 2025 - *HYPE VIDEO*","alias":"dead-money-open-2025-hype-video","excerpt":"Hey guys, mark your calendars! DPT kicks off the 2025 season at the M&J Saloon in West Fargo on Friday, January 31st and Saturday, February 1st. Friday night features a Turbo even t starting at 6 PM . Saturday ''s single-day deep stack start…","content":"Hey guys, mark your calendars! DPT kicks off the 2025 season at the M&J Saloon in West Fargo on Friday, January 31st and Saturday, February 1st. Friday night features a Turbo even t starting at 6 PM . Saturday ''s single-day deep stack starts at 12 PM . Last year’s winner took home $8,100 !","publishedAt":"2025-01-22 14:14:00","featured":true,"logo":"DPT-2025-Dead-Money-Open-d2s3jssM-xxPnWuZa.png","banner":null,"videoUrl":"https://youtu.be/VL0aZtNiJnw","imageUrl":"https://dakotapokertour.com/storage/article/thumb/DPT-2025-Dead-Money-Open-d2s3jssM-xxPnWuZa.png","bannerUrl":"","tournament":{"id":null,"name":null,"alias":null}}'::jsonb),
  (290, 'dream-chaser-iii-champion-35-000-caden-coleman', 'Dream Chaser III CHAMPION $35,000 Caden Coleman', 'Caden Coleman does it again! Just over 24 hours removed from his championship performance in the $375 Monster Stack for a $13,000 win, Caden Coleman pulls off the ultimate SUN RUN! Caden started the Dream Chaser III final table as massive c…', '2024-11-25 12:51:00', null, 'dakota-poker-tour-2023-24-dakota-jim-dandy-poker-festival-2-dream-chaser-11-23-2024', 'https://dakotapokertour.com/storage/article/thumb/winner-CgeFEWOG.jpg', '/media/dpt/article/winner-CgeFEWOG.jpg', null, '{"id":290,"title":"Dream Chaser III CHAMPION $35,000 Caden Coleman","alias":"dream-chaser-iii-champion-35-000-caden-coleman","excerpt":"Caden Coleman does it again! Just over 24 hours removed from his championship performance in the $375 Monster Stack for a $13,000 win, Caden Coleman pulls off the ultimate SUN RUN! Caden started the Dream Chaser III final table as massive c…","content":"Caden Coleman does it again! Just over 24 hours removed from his championship performance in the $375 Monster Stack for a $13,000 win, Caden Coleman pulls off the ultimate SUN RUN! Caden started the Dream Chaser III final table as massive chip leader and goes coast to coast, setting himself a new high score of $35,000! Incredible weekend, Caden! Caden also locks up the $5,000 Player of the Series BONUS to cap off one of the most impressive weekends in RPT tour history! Huge thanks to everybody who came out this weekend as we absolutely CRUSHED another Dream Chaser event at Spirit Lake Casino, with 160 entries and a total prize pool of $140,000","publishedAt":"2024-11-25 12:51:00","featured":true,"logo":"winner-CgeFEWOG.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/winner-CgeFEWOG.jpg","bannerUrl":"","tournament":{"id":286,"name":"Dream Chaser","alias":"dakota-poker-tour-2023-24-dakota-jim-dandy-poker-festival-2-dream-chaser-11-23-2024"}}'::jsonb),
  (289, 'dream-chaser-final-table', 'Dream Chaser Final Table', 'We have reached your $1,000 Dream Chaser III FINAL TABLE! From 160 entries down to 9, $35,000 and the 🏆 up for grabs with a star studded cast of RPT players in the mix!', '2024-11-24 17:14:00', null, 'dakota-poker-tour-2023-24-dakota-jim-dandy-poker-festival-2-dream-chaser-11-23-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_7446-4VTy7mgx.jpg', '/media/dpt/article/IMG_7446-4VTy7mgx.jpg', null, '{"id":289,"title":"Dream Chaser Final Table","alias":"dream-chaser-final-table","excerpt":"We have reached your $1,000 Dream Chaser III FINAL TABLE! From 160 entries down to 9, $35,000 and the 🏆 up for grabs with a star studded cast of RPT players in the mix!","content":"We have reached your $1,000 Dream Chaser III FINAL TABLE! From 160 entries down to 9, $35,000 and the 🏆 up for grabs with a star studded cast of RPT players in the mix!","publishedAt":"2024-11-24 17:14:00","featured":false,"logo":"IMG_7446-4VTy7mgx.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7446-4VTy7mgx.jpg","bannerUrl":"","tournament":{"id":286,"name":"Dream Chaser","alias":"dakota-poker-tour-2023-24-dakota-jim-dandy-poker-festival-2-dream-chaser-11-23-2024"}}'::jsonb),
  (288, 'registration-open-until-1-am', 'Registration open until 1 AM', 'Dream Chaser III is off to a hot start with 94 total entries as we are about to head on our 75 minute dinner break from 7:15-8:30. Late registration & re-entry still open through 12 levels of play, all the way until 1:00am.', '2024-11-23 22:24:00', null, 'dakota-poker-tour-2023-24-dakota-jim-dandy-poker-festival-2-dream-chaser-11-23-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_7432-MNdx2QUP.jpg', '/media/dpt/article/IMG_7432-MNdx2QUP.jpg', null, '{"id":288,"title":"Registration open until 1 AM","alias":"registration-open-until-1-am","excerpt":"Dream Chaser III is off to a hot start with 94 total entries as we are about to head on our 75 minute dinner break from 7:15-8:30. Late registration & re-entry still open through 12 levels of play, all the way until 1:00am.","content":"Dream Chaser III is off to a hot start with 94 total entries as we are about to head on our 75 minute dinner break from 7:15-8:30. Late registration & re-entry still open through 12 levels of play, all the way until 1:00am.","publishedAt":"2024-11-23 22:24:00","featured":false,"logo":"IMG_7432-MNdx2QUP.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7432-MNdx2QUP.jpg","bannerUrl":"","tournament":{"id":286,"name":"Dream Chaser","alias":"dakota-poker-tour-2023-24-dakota-jim-dandy-poker-festival-2-dream-chaser-11-23-2024"}}'::jsonb),
  (287, 'dream-chaser-iii-registration-is-now-open', 'Dream Chaser III registration is now open', 'ND''s ONLY $1,000 Buy-in tournament kicks off today at 3:00pm. 100,000 Starting Stack, 40-minute levels. Late registration is open until 1:00am. Last year''s 1st place prize was $40,000.', '2024-11-23 11:26:00', null, 'dakota-poker-tour-2023-24-dakota-jim-dandy-poker-festival-2-dream-chaser-11-23-2024', 'https://dakotapokertour.com/storage/article/thumb/DPTPIC-nT4BTE7N.jpg', '/media/dpt/article/DPTPIC-nT4BTE7N.jpg', null, '{"id":287,"title":"Dream Chaser III registration is now open","alias":"dream-chaser-iii-registration-is-now-open","excerpt":"ND''s ONLY $1,000 Buy-in tournament kicks off today at 3:00pm. 100,000 Starting Stack, 40-minute levels. Late registration is open until 1:00am. Last year''s 1st place prize was $40,000.","content":"ND''s ONLY $1,000 Buy-in tournament kicks off today at 3:00pm. 100,000 Starting Stack, 40-minute levels. Late registration is open until 1:00am. Last year''s 1st place prize was $40,000.","publishedAt":"2024-11-23 11:26:00","featured":true,"logo":"DPTPIC-nT4BTE7N.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/DPTPIC-nT4BTE7N.jpg","bannerUrl":"","tournament":{"id":286,"name":"Dream Chaser","alias":"dakota-poker-tour-2023-24-dakota-jim-dandy-poker-festival-2-dream-chaser-11-23-2024"}}'::jsonb),
  (286, 'mike-schultz-operation-red-white-and-bluff-champion', 'Mike Schultz Operation Red White and Bluff Champion', 'Congratulations Mike Schultz! The Operation Poker: Red White and Bluff - Honoring Heroes for Veterans Day at the Casselton Vets Club Inc. Tournament Champion! It couldn’t be more fitting that Mike, a veteran himself, took home the win at th…', '2024-11-18 10:31:00', null, 'dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-single-day-deep-stack-11-16-2024', 'https://dakotapokertour.com/storage/article/thumb/mike--s-win-Enn0D7h2.jpg', '/media/dpt/article/mike--s-win-Enn0D7h2.jpg', null, '{"id":286,"title":"Mike Schultz Operation Red White and Bluff Champion","alias":"mike-schultz-operation-red-white-and-bluff-champion","excerpt":"Congratulations Mike Schultz! The Operation Poker: Red White and Bluff - Honoring Heroes for Veterans Day at the Casselton Vets Club Inc. Tournament Champion! It couldn’t be more fitting that Mike, a veteran himself, took home the win at th…","content":"Congratulations Mike Schultz! The Operation Poker: Red White and Bluff - Honoring Heroes for Veterans Day at the Casselton Vets Club Inc. Tournament Champion! It couldn’t be more fitting that Mike, a veteran himself, took home the win at this special event! 🇺🇸 It was amazing to see so many veterans come out and support the cause— We cant thank you enough for your service and sacrifice. At the final table, Mike and Wade were heads-up, each with an even stack of chips. They made a deal for the prize money but still battled it out for another 45 minutes for the trophy and the coveted seat in the Tournament of Champions. A huge thank you to everyone who came out to support the Casselton Vets Club and the Dakota Poker Tour! Your presence truly made this event a success, and we couldn’t be more grateful for your ongoing support of our veterans and their families. 2nd $3850 Wade Kyser Erie ND 3rd $2100 Jeremy Heinze Lisbon ND 4th $1600 Becky Hanson Lisbon ND 5th $1300 Bruce Kulseth 6th $1100 Mike Columbus Red Lake Falls MN 7th $900 Bruce Wheeler Casselton ND 8th $700 Tanner Larson Fargo ND 9th $600 Craig Thompson West Fargo ND","publishedAt":"2024-11-18 10:31:00","featured":true,"logo":"mike--s-win-Enn0D7h2.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/mike--s-win-Enn0D7h2.jpg","bannerUrl":"","tournament":{"id":284,"name":"Deepstack","alias":"dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-single-day-deep-stack-11-16-2024"}}'::jsonb),
  (285, 'congratulations-to-the-final-table-2', ' Congratulations to the Final Table', 'We have reached the final table at Operation Poker: Red, White, and Bluff! With 69 players, we generated an incredible $16,000 prize pool. Tonight’s Champion will take home $4,700! Thank you to everyone who came out to support the Casselton…', '2024-11-16 21:45:00', null, 'dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-single-day-deep-stack-11-16-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_7340-Ge6KhIMz.jpg', '/media/dpt/article/IMG_7340-Ge6KhIMz.jpg', null, '{"id":285,"title":" Congratulations to the Final Table","alias":"congratulations-to-the-final-table-2","excerpt":"We have reached the final table at Operation Poker: Red, White, and Bluff! With 69 players, we generated an incredible $16,000 prize pool. Tonight’s Champion will take home $4,700! Thank you to everyone who came out to support the Casselton…","content":"We have reached the final table at Operation Poker: Red, White, and Bluff! With 69 players, we generated an incredible $16,000 prize pool. Tonight’s Champion will take home $4,700! Thank you to everyone who came out to support the Casselton Vets Club and make this event a success. We appreciate your continued support.","publishedAt":"2024-11-16 21:45:00","featured":false,"logo":"IMG_7340-Ge6KhIMz.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7340-Ge6KhIMz.jpg","bannerUrl":"","tournament":{"id":284,"name":"Deepstack","alias":"dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-single-day-deep-stack-11-16-2024"}}'::jsonb),
  (284, 'thank-you-for-supporting-the-casselton-vets-club', 'Thank You for Supporting the Casselton Vets Club', 'A big thank you to everyone who came out today to make this event a success! Registration closed with 69 players, creating an impressive $16,000 prize pool! Top 9 taking home cash. Your support means so much to the Casselton Vets Club and t…', '2024-11-16 19:08:00', null, 'dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-single-day-deep-stack-11-16-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_7338-zCGGifD0.png', '/media/dpt/article/IMG_7338-zCGGifD0.png', null, '{"id":284,"title":"Thank You for Supporting the Casselton Vets Club","alias":"thank-you-for-supporting-the-casselton-vets-club","excerpt":"A big thank you to everyone who came out today to make this event a success! Registration closed with 69 players, creating an impressive $16,000 prize pool! Top 9 taking home cash. Your support means so much to the Casselton Vets Club and t…","content":"A big thank you to everyone who came out today to make this event a success! Registration closed with 69 players, creating an impressive $16,000 prize pool! Top 9 taking home cash. Your support means so much to the Casselton Vets Club and the Dakota Poker Tour. 🎉 See you next weekend for the joint DPT/RPT Dream Chaser event in Devils Lake!","publishedAt":"2024-11-16 19:08:00","featured":false,"logo":"IMG_7338-zCGGifD0.png","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7338-zCGGifD0.png","bannerUrl":"","tournament":{"id":284,"name":"Deepstack","alias":"dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-single-day-deep-stack-11-16-2024"}}'::jsonb),
  (283, 'cards-are-in-the-air-at-the-casselton-vets-club', 'Cards Are in the Air at the Casselton Vets Club', 'Starting with five tables.Late registration is open until 5:00 PM, get down here! Today’s Lunch Special: Pulled Pork Plate – only $10! we will be watching the Bison game while enjoying great food and poker. Buy-In Options: * $150 for 20k in…', '2024-11-16 13:00:00', null, 'dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-single-day-deep-stack-11-16-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_7301-577Swccj.jpg', '/media/dpt/article/IMG_7301-577Swccj.jpg', null, '{"id":283,"title":"Cards Are in the Air at the Casselton Vets Club","alias":"cards-are-in-the-air-at-the-casselton-vets-club","excerpt":"Starting with five tables.Late registration is open until 5:00 PM, get down here! Today’s Lunch Special: Pulled Pork Plate – only $10! we will be watching the Bison game while enjoying great food and poker. Buy-In Options: * $150 for 20k in…","content":"Starting with five tables.Late registration is open until 5:00 PM, get down here! Today’s Lunch Special: Pulled Pork Plate – only $10! we will be watching the Bison game while enjoying great food and poker. Buy-In Options: * $150 for 20k in chips * $300 for 50k in chips 30 min blinds. Come support the Casselton Vets Club and enjoy an exciting day with the Dakota Poker Tour!","publishedAt":"2024-11-16 13:00:00","featured":false,"logo":"IMG_7301-577Swccj.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7301-577Swccj.jpg","bannerUrl":"","tournament":{"id":284,"name":"Deepstack","alias":"dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-single-day-deep-stack-11-16-2024"}}'::jsonb),
  (282, 'congratulations-to-the-final-table', '🎉 Congratulations to the Final Table! 🎉', 'Congratulations to the Final Table! The top 5 players of Operation Poker: Red, White, and Bluff, will take home cash prizes tonight! 🏆 💰 1st: $2,320 💰 2nd: $1,660 💰 3rd: $1,200 💰 4th: $860 💰 5th: $600 Thank you to everyone who came out to s…', '2024-11-15 23:34:00', null, 'dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-15-2024', 'https://dakotapokertour.com/storage/article/thumb/final-table-qo2G7bER.jpg', '/media/dpt/article/final-table-qo2G7bER.jpg', null, '{"id":282,"title":"🎉 Congratulations to the Final Table! 🎉","alias":"congratulations-to-the-final-table","excerpt":"Congratulations to the Final Table! The top 5 players of Operation Poker: Red, White, and Bluff, will take home cash prizes tonight! 🏆 💰 1st: $2,320 💰 2nd: $1,660 💰 3rd: $1,200 💰 4th: $860 💰 5th: $600 Thank you to everyone who came out to s…","content":"Congratulations to the Final Table! The top 5 players of Operation Poker: Red, White, and Bluff, will take home cash prizes tonight! 🏆 💰 1st: $2,320 💰 2nd: $1,660 💰 3rd: $1,200 💰 4th: $860 💰 5th: $600 Thank you to everyone who came out to support the Casselton Vets Club and the Dakota Poker Tour. We’ll see you all tomorrow for more poker action and the Bison game!","publishedAt":"2024-11-15 23:34:00","featured":false,"logo":"final-table-qo2G7bER.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/final-table-qo2G7bER.jpg","bannerUrl":"","tournament":{"id":283,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-15-2024"}}'::jsonb),
  (281, 'registration-closed-tonight-s-winner-takes-home-2-320', 'Registration Closed – Tonight’s Winner Takes Home $2,320', 'Registration closed tonight with 39 players and 49 add-ons, creating an impressive prize pool of $6,640! A big congratulations to tonight’s winner, taking home $2,320! Thank you to everyone who came out to support the Casselton Vets Club an…', '2024-11-15 21:33:00', null, 'dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-15-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_7254-q895A5fv.png', '/media/dpt/article/IMG_7254-q895A5fv.png', null, '{"id":281,"title":"Registration Closed – Tonight’s Winner Takes Home $2,320","alias":"registration-closed-tonight-s-winner-takes-home-2-320","excerpt":"Registration closed tonight with 39 players and 49 add-ons, creating an impressive prize pool of $6,640! A big congratulations to tonight’s winner, taking home $2,320! Thank you to everyone who came out to support the Casselton Vets Club an…","content":"Registration closed tonight with 39 players and 49 add-ons, creating an impressive prize pool of $6,640! A big congratulations to tonight’s winner, taking home $2,320! Thank you to everyone who came out to support the Casselton Vets Club and the Dakota Poker Tour. Your participation makes these events possible! If you missed out tonight, don’t worry—we’ve got more action tomorrow! Join us for a Single Day Deep Stack: Cards in the air at 12 PM, 30 min blinds $150 buy-in for a 20k starting stack (add-on available for up to 50k stack) Plus, we’ll be watching the Bison game while the action unfolds! 🦬🏈 We hope to see you there for another exciting day of poker!","publishedAt":"2024-11-15 21:33:00","featured":false,"logo":"IMG_7254-q895A5fv.png","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7254-q895A5fv.png","bannerUrl":"","tournament":{"id":283,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-15-2024"}}'::jsonb),
  (280, 'cards-in-the-air-17', 'Cards in the air', 'Cards are in the air!! Come join us for poker and the Tyson fight! $100 buyin. 15k chips late registration until 8:30pm.', '2024-11-15 18:21:00', null, 'dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-15-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_7246-GordlWzU.jpg', '/media/dpt/article/IMG_7246-GordlWzU.jpg', null, '{"id":280,"title":"Cards in the air","alias":"cards-in-the-air-17","excerpt":"Cards are in the air!! Come join us for poker and the Tyson fight! $100 buyin. 15k chips late registration until 8:30pm.","content":"Cards are in the air!! Come join us for poker and the Tyson fight! $100 buyin. 15k chips late registration until 8:30pm.","publishedAt":"2024-11-15 18:21:00","featured":false,"logo":"IMG_7246-GordlWzU.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7246-GordlWzU.jpg","bannerUrl":"","tournament":{"id":283,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2023-24-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-15-2024"}}'::jsonb),
  (279, 'final-table-at-poker-brat', 'Final Table at Poker Brat', 'Congratulations to your final table here at the Poker Brat. Today’s champion will be taking home $4000 plus Bounty’s! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Ch…', '2024-11-03 21:07:00', null, 'dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-13-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_7062-hil8QwGF.jpg', '/media/dpt/article/IMG_7062-hil8QwGF.jpg', null, '{"id":279,"title":"Final Table at Poker Brat","alias":"final-table-at-poker-brat","excerpt":"Congratulations to your final table here at the Poker Brat. Today’s champion will be taking home $4000 plus Bounty’s! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Ch…","content":"Congratulations to your final table here at the Poker Brat. Today’s champion will be taking home $4000 plus Bounty’s! DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2024-11-03 21:07:00","featured":false,"logo":"IMG_7062-hil8QwGF.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7062-hil8QwGF.jpg","bannerUrl":"","tournament":{"id":282,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-13-2024"}}'::jsonb),
  (278, 'registration-closed-at-the-poker-brat-with-88-players', 'Registration closed at The  Poker Brat  with 88 players', 'Registration closed at The Poker Brat with 88 players and 86 add-ons generating a prize pool of $22270. $8800 will be paid in bounty’s and the remaining $13470 in the prize pool. Thank you everyone who came out to support the Dakota Poker T…', '2024-11-03 18:13:00', null, 'dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-13-2024', 'https://dakotapokertour.com/storage/article/thumb/75237054611__C4EACB72-9A21-4100-9119-A6BEEBBA735E-v9QBe0df.jpg', '/media/dpt/article/75237054611__C4EACB72-9A21-4100-9119-A6BEEBBA735E-v9QBe0df.jpg', null, '{"id":278,"title":"Registration closed at The  Poker Brat  with 88 players","alias":"registration-closed-at-the-poker-brat-with-88-players","excerpt":"Registration closed at The Poker Brat with 88 players and 86 add-ons generating a prize pool of $22270. $8800 will be paid in bounty’s and the remaining $13470 in the prize pool. Thank you everyone who came out to support the Dakota Poker T…","content":"Registration closed at The Poker Brat with 88 players and 86 add-ons generating a prize pool of $22270. $8800 will be paid in bounty’s and the remaining $13470 in the prize pool. Thank you everyone who came out to support the Dakota Poker Tour, and Team Makers, we greatly appreciate your continued support. Thank you The Windbreak for hosting and Randy''s Diner, Too for catering the delicious lunch! Today’s champion will be taking home $4000 plus Bounty’s! Definitely not a bad day. DPT Leaderboard: https://dakotapokertour.com/leaderboard DPT Calendar: https://dakotapokertour.com/calendar DPT Youtube Channel: https://youtube.com/@dakotapokertour","publishedAt":"2024-11-03 18:13:00","featured":false,"logo":"75237054611__C4EACB72-9A21-4100-9119-A6BEEBBA735E-v9QBe0df.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/75237054611__C4EACB72