  (277, 'it-s-already-a-full-house-at-the-windbreak', 'It’s Already a Full-house at The Windbreak', '9 Tables and counting! Late registration until 5:00pm. Full buy-in gets you 40k in chips 30min blinds. $100 for every player you knock out.', '2024-11-03 12:26:00', null, 'dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-13-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_7019-4HMrmiMh.jpg', '/media/dpt/article/IMG_7019-4HMrmiMh.jpg', null, '{"id":277,"title":"It’s Already a Full-house at The Windbreak","alias":"it-s-already-a-full-house-at-the-windbreak","excerpt":"9 Tables and counting! Late registration until 5:00pm. Full buy-in gets you 40k in chips 30min blinds. $100 for every player you knock out.","content":"9 Tables and counting! Late registration until 5:00pm. Full buy-in gets you 40k in chips 30min blinds. $100 for every player you knock out.","publishedAt":"2024-11-03 12:26:00","featured":false,"logo":"IMG_7019-4HMrmiMh.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7019-4HMrmiMh.jpg","bannerUrl":"","tournament":{"id":282,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2023-24-poker-brat-black-chip-bounty-tournament-black-chip-bounty-10-13-2024"}}'::jsonb),
  (276, 'dwayne-anderson-wins-hagie-s-fall-poker-classic', 'Duane Anderson Wins Hagge‘s Fall Poker Classic', 'Congratulations Duane Anderson, tonights Hagge’s Fall Poker Classic Champion taking home $8,300 and a Seat in the DPT Tournament of Champions Freeroll. With tonight''s win, Duane takes over 1st place on the current season leaderboard with 23…', '2024-09-29 00:15:00', null, 'dakota-poker-tour-2023-24-hagge-s-main-event-hagge-s-main-event-09-28-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_6475-WOGPxHvy.jpg', '/media/dpt/article/IMG_6475-WOGPxHvy.jpg', null, '{"id":276,"title":"Duane Anderson Wins Hagge‘s Fall Poker Classic","alias":"dwayne-anderson-wins-hagie-s-fall-poker-classic","excerpt":"Congratulations Duane Anderson, tonights Hagge’s Fall Poker Classic Champion taking home $8,300 and a Seat in the DPT Tournament of Champions Freeroll. With tonight''s win, Duane takes over 1st place on the current season leaderboard with 23…","content":"Congratulations Duane Anderson, tonights Hagge’s Fall Poker Classic Champion taking home $8,300 and a Seat in the DPT Tournament of Champions Freeroll. With tonight''s win, Duane takes over 1st place on the current season leaderboard with 23,500 points with Brad Pausch right on his heels at 21,217 for Player of the Season. Thank you to everyone who came out to support DPT, RPT, and WFRFD. 1st $8300 Duane Anderson Wilton MN 2nd $5280 Josh Hall Mapelton ND 3rd $3500 James Wilson Wahpeton ND 4th $2600 Joel Smith Henning MN 5th $1800 Niles Short Minnewaukan ND 6th $1500 Derek Warkenthien Fargo ND 7th $1200 Charles Paukert Grand Forks ND 8th $1000 Heidi Roggenkamp Fargo ND 9th $800 Chad Knoblauch Grandforks ND 10th $700 Brian Twete Northwood ND 11th $700 Keith Kemper Hawaii 12th $700 Gage Thompson Valley City ND 13th $600 Craig Thompson Fargo ND 14th $600 Mark Alinder Fargo ND 15th $600 Eric Parvey Mapelton MN","publishedAt":"2024-09-29 00:15:00","featured":true,"logo":"IMG_6475-WOGPxHvy.jpg","banner":null,"vid