  (272, 'congratulations-jackson-taking-down-the-friday-night-turbo', 'Jackson Skjerseth Takes Down Friday Night Turbo at Hagge''s', 'Congratulations Jackson Skjerseth who recently celebrated his 21st birthday, claims his first victory with the Dakota Poker Tour. Jackson defeated 57 players taking home $3800. Registration closed for the Friday night turbo with 57 players…', '2024-09-28 00:50:00', null, 'dakota-poker-tour-2023-24-hagge-s-main-event-hagge-s-friday-night-turbo-09-27-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_6384-1XR875wY.jpg', '/media/dpt/article/IMG_6384-1XR875wY.jpg', null, '{"id":272,"title":"Jackson Skjerseth Takes Down Friday Night Turbo at Hagge''s","alias":"congratulations-jackson-taking-down-the-friday-night-turbo","excerpt":"Congratulations Jackson Skjerseth who recently celebrated his 21st birthday, claims his first victory with the Dakota Poker Tour. Jackson defeated 57 players taking home $3800. Registration closed for the Friday night turbo with 57 players…","content":"Congratulations Jackson Skjerseth who recently celebrated his 21st birthday, claims his first victory with the Dakota Poker Tour. Jackson defeated 57 players taking home $3800. Registration closed for the Friday night turbo with 57 players and 86 re-buys/addons. Total prize pool $12870. 1st $3800 Jackson Skjerserh Fargo ND 2nd $2500 Dave Dirkman Dalton MN 3rd $1800 Craig Evenson Argusville MN 4th $1270 Daniel Tennefos Fargo ND 5th $1000 Rob Urbatsch Grand Forks, ND 6th 850 Donald Drummond Fargo ND 7th $700 Bill Madison Fergus Falls MN 8th $550 Phu Troung Moorhead MN 9th $400 Austyn Christiansen Fargo ND","publishedAt":"2024-09-28 00:50:00","featured":true,"logo":"IMG_6384-1XR875wY.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_6384-1XR875wY.jpg","bannerUrl":"","tournament":{"id":280,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2023-24-hagge-s-main-event-hagge-s-friday-night-turbo-09-27-2024"}