  (271, 'congratulations-final-table-3', 'Congratulations final table', 'Congratulations to your final table tonight in the Friday night turbo one of these guys will be taking home $3800. Don’t forget tomorrow Deepstack starting at Noon with a 20k starting stack and optional addon for up to a 50k starting stack.…', '2024-09-27 23:48:00', null, 'dakota-poker-tour-2023-24-hagge-s-main-event-hagge-s-friday-night-turbo-09-27-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_6381-xiw1YzrZ.jpg', '/media/dpt/article/IMG_6381-xiw1YzrZ.jpg', null, '{"id":271,"title":"Congratulations final table","alias":"congratulations-final-table-3","excerpt":"Congratulations to your final table tonight in the Friday night turbo one of these guys will be taking home $3800. Don’t forget tomorrow Deepstack starting at Noon with a 20k starting stack and optional addon for up to a 50k starting stack.…","content":"Congratulations to your final table tonight in the Friday night turbo one of these guys will be taking home $3800. Don’t forget tomorrow Deepstack starting at Noon with a 20k starting stack and optional addon for up to a 50k starting stack. Phu Trong Moorhead MN Donald Drummond Fargo ND Daniel Tennefos Fargo ND Rob Urbatsch Fargo ND Austyn Christiansen - Fargo ND Craig Evenson - Argusville ND Jackson Skjerserh Fargo ND Bill Madison Fergus Falls MN Dave Dirkman Dalton MN","publishedAt":"2024-09-27 23:48:00","featured":false,"logo":"IMG_6381-xiw1YzrZ.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_6381-xiw1YzrZ.jpg","bannerUrl":"","tournament":{"id":280,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2023-24-hagge-s-main-event-hagge-s-friday-night-turbo-09-27-2024"}}'::jsonb),
