  (263, 'dpt-and-rpt-team-up-for-the-hagge-s-fall-classic', 'Hagge''s Fall Classic Kicks off Fall Schedule', 'The 2023-2024 poker season is heating up as the Dakota Poker Tour (DPT) teams up with the Roughrider Poker Tour (RPT) for Hagges Fall Classic this weekend in Mapleton, ND. This event has generated a $7,000+ 1st place cash the last 2 years,…', '2024-09-25 15:39:00', null, 'dakota-poker-tour-2023-24-hagge-s-main-event-hagge-s-main-event-09-28-2024', 'https://dakotapokertour.com/storage/article/thumb/DPT-Hagge''s-Fall-Classic-23-24-digital-r3-orRYWI8X.png', '/media/dpt/article/DPT-Hagge-s-Fall-Classic-23-24-digital-r3-orRYWI8X.png', 'https://youtu.be/zwNv7xZIK6k?si=EosjwfjujpqzF4h-', '{"id":263,"title":"Hagge''s Fall Classic Kicks off Fall Schedule","alias":"dpt-and-rpt-team-up-for-the-hagge-s-fall-classic","excerpt":"The 2023-2024 poker season is heating up as the Dakota Poker Tour (DPT) teams up with the Roughrider Poker Tour (RPT) for Hagges Fall Classic this weekend in Mapleton, ND. This event has generated a $7,000+ 1st place cash the last 2 years,…","content":"The 2023-2024 poker season is heating up as the Dakota Poker Tour (DPT) teams up with the Roughrider Poker Tour (RPT) for Hagges Fall Classic this weekend in Mapleton, ND. This event has generated a $7,000+ 1st place cash the last 2 years, and we expect that to climb with the charity taking the state-minimum 10% from the prize pool. Thank you WFRFD :) DPT current season points leader is Brad Pausch from Wahpeton, ND, with Duane Anderson and Joel Klipping on his heels. This event will count for points on both the Dakota Poker Tour and Roughrider Poker Tour leaderboards. Expect to see lots of familiar faces and some new faces too! DPT Current Leaderboard Standings: Brad Pausch- 20617 points Duane Anderson - 14900 points Joel Klipping - 11750 points Brett Leben - 11547 points Anthoney Uhlir 11438 points Rough Rider Current Leaderboard standings: Arlie Brandvold 961.9 Points Zach Byers 681.3 Points Robert Urbatsch 654.2 Greg Passa 644.35 Richard Perkerewicz 500.82","publishedAt":"2024-09-25 15:39:00","featured":true,"logo":"DPT-Hagge''s-Fall-Classic-23-24-digital-r3-orRYWI8X.png","banner":null,"videoUrl":"https://youtu.be/zwNv7xZIK6k?si=EosjwfjujpqzF4h-","imageUrl":"https://dakotapokertour.com/storage/article/thumb/DPT-Hagge''s-Fall-Classic-23-24-digital-r3-orRYWI8X.png","bannerUrl":"","tournament":{"id":281,"name":"Hagge''s Fall Classic - Deepstack","alias":"dakota-poker-tour-2023-24-hagge-s-main-event-hagge-s-main-event-09-28-2024"}}'::jsonb),
