  (256, 'tony-uhlir-wins-dpt-spring-championship-main-event-7-700', 'Tony Uhlir Wins DPT Spring Championship Main Event $7,700', 'Tony Uhlir came out on top of the DPT Spring Championship Main Event 2-day event over a field of 100 players, scoring the Trophy and $7,700. Duane Anderson was the Runner Up for $5,000. Full results: https://dakotapokertour.com/tournament/d…', '2024-04-21 17:26:00', null, 'dakota-poker-tour-2023-24-dpt-championship-weekend-dpt-spring-championship-megastack-100k-04-20-2024', 'https://dakotapokertour.com/storage/article/thumb/Image_20240421_144118_177-8BxqiXS0.jpg', '/media/dpt/article/Image_20240421_144118_177-8BxqiXS0.jpg', 'https://www.youtube.com/live/TSy_UPxrvu4?si=XJxJ81VaOkjWxJUC', '{"id":256,"title":"Tony Uhlir Wins DPT Spring Championship Main Event $7,700","alias":"tony-uhlir-wins-dpt-spring-championship-main-event-7-700","excerpt":"Tony Uhlir came out on top of the DPT Spring Championship Main Event 2-day event over a field of 100 players, scoring the Trophy and $7,700. Duane Anderson was the Runner Up for $5,000. Full results: https://dakotapokertour.com/tournament/d…","content":"Tony Uhlir came out on top of the DPT Spring Championship Main Event 2-day event over a field of 100 players, scoring the Trophy and $7,700. Duane Anderson was the Runner Up for $5,000. Full results: https://dakotapokertour.com/tournament/dakota-poker-tour-2023-24-dpt-championship-weekend-dpt-spring-championship-megastack-100k-04-20-2024 Thanks everyone for your support for this event, and a big shout out to the West Fargo Rural Fire Department for giving us a great opportunity to play poker at the Red River Valley Fairgrounds!","publishedAt":"2024-04-21 17:26:00","featured":true,"logo":"Image_20240421_144118_177-8BxqiXS0.jpg","banner":null,"videoUrl":"https://www.youtube.com/live/TSy_UPxrvu4?si=XJxJ81VaOkjWxJUC","imageUrl":"https://dakotapokertour.com/storage/article/thumb/Image_20240421_144118_177-8BxqiXS0.jpg","bannerUrl":"","tournament":{"id":277,"n