  (253, '80-players-in-the-100k-deep-stack', '80 players in the 100k deep stack.', 'Late registration available until 6pm. 80 players so far. Prize pool already over $22,000. Join us at the Red-river Valley fairgrounds (west fargo) Hartl building. Also don’t miss your opportunity at $12k get yourself a $20 raffle ticket (d…', '2024-04-20 14:30:00', null, 'dakota-poker-tour-2023-24-dpt-championship-weekend-dpt-spring-championship-megastack-100k-04-20-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_2928-OZv3IO5I.jpg', '/media/dpt/article/IMG_2928-OZv3IO5I.jpg', null, '{"id":253,"title":"80 players in the 100k deep stack.","alias":"80-players-in-the-100k-deep-stack","excerpt":"Late registration available until 6pm. 80 players so far. Prize pool already over $22,000. Join us at the Red-river Valley fairgrounds (west fargo) Hartl building. Also don’t miss your opportunity at $12k get yourself a $20 raffle ticket (d…","content":"Late registration available until 6pm. 80 players so far. Prize pool already over $22,000. Join us at the Red-river Valley fairgrounds (west fargo) Hartl building. Also don’t miss your opportunity at $12k get yourself a $20 raffle ticket (don’t have to be present to win) 18 total prizes.","publishedAt":"2024-04-20 14:30:00","featured":false,"logo":"IMG_2928-OZv3IO5I.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_2928-OZv3IO5I.jpg","bannerUrl":"","tournament":{"id":277,"name":"DPT Spring Championship MEGASTACK (100K)","alias":"dakota-poker-tour-2023-24-dpt-championship-weekend-dpt-spring-championship-megastack-100k-04-20-2024"}}'::jsonb),
  (252, 'raffle-for-12-000-poker-package', 'Raffle for $12,000 Poker Package', 'WHO WANTS TO WIN A $12,000 MAIN EVENT POKER PACKAGE?!! West Fargo Rural Fire Department-Gaming is selling raffle tickets this weekend at the DPT Spring Championship - don''t miss out on this awesome opportunity! Grand Prize - (1) $12,000 Mai…', '2024-04-20 09:46:00', null, null, 'https://dakotapokertour.com/storage/article/thumb/Image_20240420_092024_402-wHdepxrB.jpg', '/media/dpt/article/Image_20240420_092024_402-wHdepxrB.jpg', null, '{"id":252,"title":"Raffle for $12,000 Poker Package","alias":"raffle-for-12-000-poker-package","excerpt":"WHO WANTS TO WIN A $12,000 MAIN EVENT POKER PACKAGE?!! West Fargo Rural Fire Department-Gaming is selling raffle tickets this weekend at the DPT Spring Championship - don''t miss out on this awesome opportunity! Grand Prize - (1) $12,000 Mai…","content":"WHO WANTS TO WIN A $12,000 MAIN EVENT POKER PACKAGE?!! West Fargo Rural Fire Department-Gaming is selling raffle tickets this weekend at the DPT Spring Championship - don''t miss out on this awesome opportunity! Grand Prize - (1) $12,000 Main Event Package (Cash) $1000 Cash (1) $500 Cash (4) $200 Cash (12) Tickets - $20 each There are a couple hundred tickets remaining! Purchase raffle tickets at registration during DPT Champinoship weekend at Red River Fairgrounds in West Fargo, ND April 19-21st. If the raffle sells out the drawing will be held Sunday during the Black Chip Bounty tournament. DON''T MISS OUT!!!","publishedAt":"2024-04-20 09:46:00","featured":true,"logo":"Image_20240420_092024_402-wHdepxrB.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Image_20240420_092024_402-wHdepxrB.jpg","bannerUrl":"","tournament":{"id":null,"name":null,"alias":null}}'::jsonb),
