  (223, 'dpt-has-rolled-into-tioga', 'DPT has rolled into Tioga', 'DPT has officially rolled into Tioga. Join us Saturday 3/9/2024 at Pour Decisions for POKER!!! Cards in the air at NOON', '2024-03-08 22:20:00', null, 'dakota-poker-tour-2023-24-pour-decisions-pour-decisions-03-09-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_1457-Q66CmoWo.jpg', '/media/dpt/article/IMG_1457-Q66CmoWo.jpg', null, '{"id":223,"title":"DPT has rolled into Tioga","alias":"dpt-has-rolled-into-tioga","excerpt":"DPT has officially rolled into Tioga. Join us Saturday 3/9/2024 at Pour Decisions for POKER!!! Cards in the air at NOON","content":"DPT has officially rolled into Tioga. Join us Saturday 3/9/2024 at Pour Decisions for POKER!!! Cards in the air at NOON","publishedAt":"2024-03-08 22:20:00","featured":true,"logo":"IMG_1457-Q66CmoWo.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_1457-Q66CmoWo.jpg","bannerUrl":"","tournament":{"id":274,"name":"Pour Decisions","alias":"dakota-poker-tour-2023-24-pour-decisions-pour-decisions-03-09-2024"}}'::jsonb),
  (222, 'james-wilson-wins-in-oakes-6-750', 'James Wilson Wins in Oakes $6,750', 'Congrats to James Wilson from Wahpeton ND for capturing the Hole In One Foundation tournament in Oakes, ND for $6,750. It was a fun final table that had plenty of big hand drama. Steve Belland was runner up for $4,000 and Cody Slusher took…', '2024-03-03 08:35:00', null, 'dakota-poker-tour-2023-24-hole-in-one-main-event-hole-in-one-main-event-03-02-2024', 'https://dakotapokertour.com/storage/article/thumb/1000009645-DQhgVS71.jpg', '/media/dpt/article/1000009645-DQhgVS71.jpg', null, '{"id":222,"title":"James Wilson Wins in Oakes $6,750","alias":"james-wilson-wins-in-oakes-6-750","excerpt":"Congrats to James Wilson from Wahpeton ND for capturing the Hole In One Foundation tournament in Oakes, ND for $6,750. It was a fun final table that had plenty of big hand drama. Steve Belland was runner up for $4,000 and Cody Slusher took…","content":"Congrats to James Wilson from Wahpeton ND for capturing the Hole In One Foundation tournament in Oakes, ND for $6,750. It was a fun final table that had plenty of big hand drama. Steve Belland was runner up for $4,000 and Cody Slusher took 3rd for $3,000. Here are the players who cashed: 1st $6750 James Wilson Wahpeton ND 2nd $4000 Steve Belland Bagley MN 3rd $3000 Cody Slusher Oakes ND 4th $2000 Shawn Pettigrew Grand Forks N 5th $1700 Robin Green Groton SD 6th $1400 Cody Nash Oakes ND 7th $1100 Grayson Roney Oakes ND 8th $ 900 Jason Miller Detroit Lakes MN 9th $700 Bob Miller Oakes ND 10th $600 John Waliser Lisbon ND Click here for complete results . Big thanks to everyone for coming out, next up is Pour Decisions in Tioga Saturday March 9th.","publishedAt":"2024-03-03 08:35:00","featured":true,"logo":"1000009645-DQhgVS71.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/1000009645-DQhgVS71.jpg","bannerUrl":"","tournament":{"id":266,"name":"Hole in One Main Event","alias":"dakota-poker-tour-2023-24-hole-in-one-main-event-hole-in-one-main-event-03-02-2024"}}'::jsonb),
  (221, '9-tables-registration-open-until-5pm', '9 Tables , registration open until 5pm', '9 Tables! Still time to get down here! Registration open until 5pm. Prize pool already over $17000 join us at AngryBeaver Lodge for the Hole in One Main . Come play on the Live stream and it’s a great opportunity to play some poker for a go…', '2024-03-02 12:25:00', null, 'dakota-poker-tour-2023-24-hole-in-one-main-event-hole-in-one-main-event-03-02-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_1334-ovQhsWKU.jpg', '/media/dpt/article/IMG_1334-ovQhsWKU.jpg', null, '{"id":221,"title":"9 Tables , registration open until 5pm","alias":"9-tables-registration-open-until-5pm","excerpt":"9 Tables! Still time to get down here! Registration open until 5pm. Prize pool already over $17000 join us at AngryBeaver Lodge for the Hole in One Main . Come play on the Live stream and it’s a great opportunity to play some poker for a go…","content":"9 Tables! Still time to get down here! Registration open until 5pm. Prize pool already over $17000 join us at AngryBeaver Lodge for the Hole in One Main . Come play on the Live stream and it’s a great opportunity to play some poker for a good cause supporting our local small town communities and people in need.","publishedAt":"2024-03-02 12:25:00","featured":true,"logo":"IMG_1334-ovQhsWKU.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_1334-ovQhsWKU.jpg","bannerUrl":"","tournament":{"id":266,"name":"Hole in One Main Event","alias":"dakota-poker-tour-2023-24-hole-in-one-main-event-hole-in-one-main-event-03-02-2024"}}'::jsonb),
