  (218, 'registration-open-the-line-is-out-the-door', 'Registration Open, the line is out the DOOR!', 'We are OUT HERE! With a line out the door early on, the busy RPT/DPT co-op weekend continues at the Phat Fish in Dickinson today at NOON! Late entry, re-entry and add-ons all available through dinner break at 5:30 pm! Come play poker!', '2024-02-25 12:15:00', null, 'dakota-poker-tour-2023-24-phat-stacks-at-the-phat-fish-phat-fish-main-event-02-25-2024', 'https://dakotapokertour.com/storage/article/thumb/phat-1-bxFN9Lln.jpg', '/media/dpt/article/phat-1-bxFN9Lln.jpg', null, '{"id":218,"title":"Registration Open, the line is out the DOOR!","alias":"registration-open-the-line-is-out-the-door","excerpt":"We are OUT HERE! With a line out the door early on, the busy RPT/DPT co-op weekend continues at the Phat Fish in Dickinson today at NOON! Late entry, re-entry and add-ons all available through dinner break at 5:30 pm! Come play poker!","content":"We are OUT HERE! With a line out the door early on, the busy RPT/DPT co-op weekend continues at the Phat Fish in Dickinson today at NOON! Late entry, re-entry and add-ons all available through dinner break at 5:30 pm! Come play poker!","publishedAt":"2024-02-25 12:15:00","featured":false,"logo":"phat-1-bxFN9Lln.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/phat-1-bxFN9Lln.jpg","bannerUrl":"","tournament":{"id":275,"name":"Phat Fish Main Event","alias":"dakota-poker-tour-2023-24-phat-stacks-at-the-phat-fish-phat-fish-main-event-02-25-2024"}}'::jsonb),
  (216, 'arlie-brandvold-watford-city-eagles-champion', 'Arlie Brandvold Watford City Eagles Champion', 'Event 10 02-24-2024 Watford City Eagles Club, Watford City ND WINNER $6,500 Arlie Brandvold! After the dust settled on a record shattering day in Wild Wild Watford, we finished with 105 unique players, 201 total entries, and a massive prize…', '2024-02-24 23:30:00', null, 'dakota-poker-tour-2023-24-watford-city-eagles-club-monster-stack-watford-city-eagles-club-monster-stack-02-24-2024', 'https://dakotapokertour.com/storage/article/thumb/whatfor-eagles-wvL78m9G.jpg', '/media/dpt/article/whatfor-eagles-wvL78m9G.jpg', null, '{"id":216,"title":"Arlie Brandvold Watford City Eagles Champion","alias":"arlie-brandvold-watford-city-eagles-champion","excerpt":"Event 10 02-24-2024 Watford City Eagles Club, Watford City ND WINNER $6,500 Arlie Brandvold! After the dust settled on a record shattering day in Wild Wild Watford, we finished with 105 unique players, 201 total entries, and a massive prize…","content":"Event 10 02-24-2024 Watford City Eagles Club, Watford City ND WINNER $6,500 Arlie Brandvold! After the dust settled on a record shattering day in Wild Wild Watford, we finished with 105 unique players, 201 total entries, and a massive prize pool of $24,120! Current Player of the Year points leader and 2022 RPT Player of the Year, Arlie Brandvold plays it to perfection as he becomes the first of 2 DPT/RPT trophy winning players on this epic weekend! See you Sunday at Phat Fish Brewing in Dickinson at NOON! Late entry, re-entry and add-ons available until 5:30 pm. 201 entries $24,120 prize pool 1st Arlie Brandvold $6,500 2nd Garrick Baatrup $4,100 3rd Mike Salveson $3,150 4th Kostner Benz-Weber $2,220 5th Vanessa Christensen $1,700 6th Jeremy Hausauer $1,100 7th Dave Ouellette $970 8th Seth Hilleren $850 9th Nick Hammarstrom $710 10th Greg Johnson $600 11th Lori Hausauer $600 12th Shae Johnson $540 13th Ray Frank $540 14th Carol Bohlman $540","publishedAt":"2024-02-24 23:30:00","featured":true,"logo":"whatfor-eagles-wvL78m9G.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/whatfor-eagles-wvL78m9G.jpg","bannerUrl":"","tournament":{"id":273,"name":"Watford City Eagles Club Monster Stack","alias":"dakota-poker-tour-2023-24-watford-city-eagles-club-monster-stack-watford-city-eagles-club-monster-stack-02-24-2024"}}'::jsonb),
