  (214, 'final-table-at-the-buckskin-shootout-main-event-2', 'Final Table at the Buckskin Shootout Main Event', 'Final Table for the Buckskin Shootout Main Event. 56 Players Came out today generating a 14k prize pool. Congratulations players. Justin Young Bird Daniel Vallevik Wendell Vigen Rod Zalesky Lorry Sirios Marcos Sotelo Kevin Krohn Jeff Gab', '2024-02-10 21:39:00', null, 'dakota-poker-tour-2023-24-buckskin-shootout-buckskin-shootout-main-event-02-10-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_0963-vR4kZbei.jpg', '/media/dpt/article/IMG_0963-vR4kZbei.jpg', null, '{"id":214,"title":"Final Table at the Buckskin Shootout Main Event","alias":"final-table-at-the-buckskin-shootout-main-event-2","excerpt":"Final Table for the Buckskin Shootout Main Event. 56 Players Came out today generating a 14k prize pool. Congratulations players. Justin Young Bird Daniel Vallevik Wendell Vigen Rod Zalesky Lorry Sirios Marcos Sotelo Kevin Krohn Jeff Gab","content":"Final Table for the Buckskin Shootout Main Event. 56 Players Came out today generating a 14k prize pool. Congratulations players. Justin Young Bird Daniel Vallevik Wendell Vigen Rod Zalesky Lorry Sirios Marcos Sotelo Kevin Krohn Jeff Gab","publishedAt":"2024-02-10 21:39:00","featured":false,"logo":"IMG_0963-vR4kZbei.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_0963-vR4kZbei.jpg","bannerUrl":"","tournament":{"id":272,"name":"Buckskin Shootout Main Event","alias":"dakota-poker-tour-2023-24-buckskin-shootout-buckskin-shootout-main-event-02-10-2024"}}'::jsonb),
  (212, 'registration-closed-at-the-buckskin-shootout-main-event', 'Registration Closed at the Buckskin Shootout Main Event', 'Registration closed at the Buckskin Shootout Main Event with 56 players generating over $14000 in the prize pool. First place taking home $4200 and a seat in the Dakota Poker Tour Tournament of Champions. Thank you Players for your continue…', '2024-02-10 18:38:00', null, 'dakota-poker-tour-2023-24-buckskin-shootout-buckskin-shootout-main-event-02-10-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_0932-XSVVzMyu.png', '/media/dpt/article/IMG_0932-XSVVzMyu.png', null, '{"id":212,"title":"Registration Closed at the Buckskin Shootout Main Event","alias":"registration-closed-at-the-buckskin-shootout-main-event","excerpt":"Registration closed at the Buckskin Shootout Main Event with 56 players generating over $14000 in the prize pool. First place taking home $4200 and a seat in the Dakota Poker Tour Tournament of Champions. Thank you Players for your continue…","content":"Registration closed at the Buckskin Shootout Main Event with 56 players generating over $14000 in the prize pool. First place taking home $4200 and a seat in the Dakota Poker Tour Tournament of Champions. Thank you Players for your continued support of the Dakota Poker Tour, Ezra Barrows Post 46 American Legion and The Buckskin.","publishedAt":"2024-02-10 18:38:00","featured":false,"logo":"IMG_0932-XSVVzMyu.png","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_0932-XSVVzMyu.png","bannerUrl":"","tournament":{"id":272,"name":"Buckskin Shootout Main Event","alias":"dakota-poker-tour-2023-24-buckskin-shootout-buckskin-shootout-main-event-02-10-2024"}}'::jsonb),
  (211, 'cards-are-in-the-air-5', 'Cards are in the air!!', 'Cards are in the air at the Buckskin Shootout Main Event. Late registration availability until dinner break (approximately 5pm MT time) We already have 6 Tables. $150+ (Dealer appreciation ) gets you 20k in chips! Thank you again to Ezra Ba…', '2024-02-10 13:44:00', null, 'dakota-poker-tour-2023-24-buckskin-shootout-buckskin-shootout-main-event-02-10-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_0928-yHQ2kczN.jpg', '/media/dpt/article/IMG_0928-yHQ2kczN.jpg', null, '{"id":211,"title":"Cards are in the air!!","alias":"cards-are-in-the-air-5","excerpt":"Cards are in the air at the Buckskin Shootout Main Event. Late registration availability until dinner break (approximately 5pm MT time) We already have 6 Tables. $150+ (Dealer appreciation ) gets you 20k in chips! Thank you again to Ezra Ba…","content":"Cards are in the air at the Buckskin Shootout Main Event. Late registration availability until dinner break (approximately 5pm MT time) We already have 6 Tables. $150+ (Dealer appreciation ) gets you 20k in chips! Thank you again to Ezra Barrows Post 46 American Legion who’s has bought every player their first drink today, and will only be keeping 10% of the prize pool, Meaning 90% is being paid back to our players!!","publishedAt":"2024-02-10 13:44:00","featured":false,"logo":"IMG_0928-yHQ2kczN.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_0928-yHQ2kczN.jpg","bannerUrl":"","tournament":{"id":272,"name":"Buckskin Shootout Main Event","alias":"dakota-poker-tour-2023-24-buckskin-shootout-buckskin-shootout-main-event-02-10-2024"}}'::jsonb),
  (210, 'cards-fly-at-12pm-mt-time', 'Cards Fly at 12pm Mt time', 'The Buckskin Shootout Main Event starts at 12pm Local time (MT) $150 + (dealer appreciation) gets you 20k chips. Thank you to our host Buckskin, with delicious food and drinks the Steak sliders are 🤤 Thank you to the charity Ezra Barrows Po…', '2024-02-10 10:25:00', null, 'dakota-poker-tour-2023-24-buckskin-shootout-buckskin-shootout-main-event-02-10-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_0926-Fsgvfp52.jpg', '/media/dpt/article/IMG_0926-Fsgvfp52.jpg', null, '{"id":210,"title":"Cards Fly at 12pm Mt time","alias":"cards-fly-at-12pm-mt-time","excerpt":"The Buckskin Shootout Main Event starts at 12pm Local time (MT) $150 + (dealer appreciation) gets you 20k chips. Thank you to our host Buckskin, with delicious food and drinks the Steak sliders are 🤤 Thank you to the charity Ezra Barrows Po…","content":"The Buckskin Shootout Main Event starts at 12pm Local time (MT) $150 + (dealer appreciation) gets you 20k chips. Thank you to our host Buckskin, with delicious food and drinks the Steak sliders are 🤤 Thank you to the charity Ezra Barrows Post 46 American Legion who again for today’s event is only accepting the state min 10%! Thats means 90% is going to the prize pool!! They have also said they will be sponsoring some drink give aways today","publishedAt":"2024-02-10 10:25:00","featured":false,"logo":"IMG_0926-Fsgvfp52.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_0926-Fsgvfp52.jpg","bannerUrl":"","tournament":{"id":272,"name":"Buckskin Shootout Main Event","alias":"dakota-poker-tour-2023-24-buckskin-shootout-buckskin-shootout-main-event-02-10-2024"}}'::jsonb),
  (208, 'congratulations-jeremy-hausauer-buckskin-shootout-turbo-champion', 'Congratulations Jeremy Hausauer Buckskin Shootout Turbo Champion', 'Congratulations Jeremy Hausaur your Buckskin Friday Night Turbo Winner. Jeremy defeated 34 players including sending his wife Lori home in 3rd place winning $2100! Join us tomorrow at 12pm for Buckskin Shootout Main Event Thank you to our H…', '2024-02-10 01:59:00', null, 'dakota-poker-tour-2023-24-buckskin-shootout-buckskin-friday-turbo-02-09-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_0921-wCNDV59H.jpg', '/media/dpt/article/IMG_0921-wCNDV59H.jpg', null, '{"id":208,"title":"Congratulations Jeremy Hausauer Buckskin Shootout Turbo Champion","alias":"congratulations-jeremy-hausauer-buckskin-shootout-turbo-champion","excerpt":"Congratulations Jeremy Hausaur your Buckskin Friday Night Turbo Winner. Jeremy defeated 34 players including sending his wife Lori home in 3rd place winning $2100! Join us tomorrow at 12pm for Buckskin Shootout Main Event Thank you to our H…","content":"Congratulations Jeremy Hausaur your Buckskin Friday Night Turbo Winner. Jeremy defeated 34 players including sending his wife Lori home in 3rd place winning $2100! Join us tomorrow at 12pm for Buckskin Shootout Main Event Thank you to our Host Buckskin Bar & Grill and Ezra Barrows Post 46 American Legion who is taking the state minimum 10% of prize pool to generously give 90% back to the players! Thank you again for supporting the Dakota Poker Tour. 1st $2100 Jeremy Hausauer Halliday, ND 2nd $1320 Duglas Sirios Williston, ND 3rd $1000 Lori Hausauer Halliday, ND 4th $700 Kyle Hall Killdeer, ND 5th $560 John Truchan Killdeer, ND 6th $480 Mark Ries Dickinson, ND 7th $390 John Linseth Killdeer, ND 8th $300 Placido Sotel Dunn Center, ND 9th $260 Nanette Klingback Killdeer, ND","publishedAt":"2024-02-10 01:59:00","featured":true,"logo":"IMG_0921-wCNDV59H.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article