  (207, 'final-table-7', 'Final Table', 'Congratulations to the final table at the Buckskin Shootout Friday Night Turbo! 34 players generated a $7110 prize pool. All players taking home cash tonight!! John Linseth Nanette Edmondson Placido Sotelo Kyle Hall John Truchan Dug Sirius…', '2024-02-10 00:24:00', null, 'dakota-poker-tour-2023-24-buckskin-shootout-buckskin-friday-turbo-02-09-2024', 'https://dakotapokertour.com/storage/article/thumb/IMG_0918-s3MyNSSZ.jpg', '/media/dpt/article/IMG_0918-s3MyNSSZ.jpg', null, '{"id":207,"title":"Final Table","alias":"final-table-7","excerpt":"Congratulations to the final table at the Buckskin Shootout Friday Night Turbo! 34 players generated a $7110 prize pool. All players taking home cash tonight!! John Linseth Nanette Edmondson Placido Sotelo Kyle Hall John Truchan Dug Sirius…","content":"Congratulations to the final table at the Buckskin Shootout Friday Night Turbo! 34 players generated a $7110 prize pool. All players taking home cash tonight!! John Linseth Nanette Edmondson Placido Sotelo Kyle Hall John Truchan Dug Sirius Jeremy Hausauer Lori Hausauer Mark Ries","publishedAt":"2024-02-10 00:24:00","featured":false,"logo":"IMG_0918-s3MyNSSZ.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_0918-s3MyNSSZ.jpg","bannerUrl":"","tournament":{"id":271,"name":"Buckskin Friday Turbo","alias":"dakota-poker-tour-2023-24-buckskin-shootout-buckskin-friday-turbo-02-09-2024"}}'::jsonb),
