  (198, 'dpt-is-back-for-the-dead-money-open', 'DPT is Back for the Dead Money Open!', 'It''s that time of year for the DPT Classic Dead Money Open at the M&J Saloon in West Fargo! C''mon out and blast chips into the pot all day for a shot at making the final table and a nice chunk of CASH. Cards in the air at Noon!', '2024-02-03 07:28:00', null, 'dakota-poker-tour-season-xi-dead-money-open-dead-money-open-02-12-2022', 'https://dakotapokertour.com/storage/article/thumb/Screenshot-2024-02-03-073147-mGnYQeDa.png', '/media/dpt/article/Screenshot-2024-02-03-073147-mGnYQeDa.png', 'https://youtu.be/Tkz92keHTTw?si=hU8s4hJXwUFTH0cr', '{"id":198,"title":"DPT is Back for the Dead Money Open!","alias":"dpt-is-back-for-the-dead-money-open","excerpt":"It''s that time of year for the DPT Classic Dead Money Open at the M&J Saloon in West Fargo! C''mon out and blast chips into the pot all day for a shot at making the final table and a nice chunk of CASH. Cards in the air at Noon!","content":"It''s that time of year for the DPT Classic Dead Money Open at the M&J Saloon in West Fargo! C''mon out and blast chips into the pot all day for a shot at making the final table and a nice chunk of CASH. Cards in the air at Noon!","publishedAt":"2024-02-03 07:28:00","featured":true,"logo":"Screenshot-2024-02-03-073147-mGnYQeDa.png","banner":null,"videoUrl":"https://youtu.be/Tkz92keHTTw?si=hU8s4hJXwUFTH0cr","imageUrl":"https://dakotapokertour.com/storage/article/thumb/Screenshot-2024-02-03-073147-mGnYQeDa.png","bannerUrl":"","tournament":{"id":12,"name":"Dead Money Open","alias":"dakota-poker-tour-season-xi-dead-money-open-dead-money-open-02-12-2022"}}'::jsonb),
