  (167, 'congratulations', 'Congratulations', 'Congratulations to the final table at tonight’s Satellite Night. 31 players came out tonight. 8 players won a seat into tomorrows Main Event. Last years Hagge’s champion won over 7k Wade Kyser Craig Thompson Erik Nordeng Allen Peyerl Royal…', '2023-09-16 00:07:00', null, 'dakota-poker-tour-2023-24-hagge-s-deep-stack-hagge-s-super-satellite-09-15-2023', 'https://dakotapokertour.com/storage/article/thumb/IMG_7187-WDProPK2.jpg', '/media/dpt/article/IMG_7187-WDProPK2.jpg', null, '{"id":167,"title":"Congratulations","alias":"congratulations","excerpt":"Congratulations to the final table at tonight’s Satellite Night. 31 players came out tonight. 8 players won a seat into tomorrows Main Event. Last years Hagge’s champion won over 7k Wade Kyser Craig Thompson Erik Nordeng Allen Peyerl Royal…","content":"Congratulations to the final table at tonight’s Satellite Night. 31 players came out tonight. 8 players won a seat into tomorrows Main Event. Last years Hagge’s champion won over 7k Wade Kyser Craig Thompson Erik Nordeng Allen Peyerl Royal Merkel James Gienger Randy Villalon Frank Jirik","publishedAt":"2023-09-16 00:07:00","featured":false,"logo":"IMG_7187-WDProPK2.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7187-WDProPK2.jpg","bannerUrl":"","tournament":{"id":239,"name":"Hagge''s - Super Satellite","alias":"dakota-poker-tour-2023-24-hagge-s-deep-stack-hagge-s-super-satellite-09-15-2023"}}'::jsonb),
  (166, 'registration-still-open-9pm', 'Registration still open! 9pm', 'At Hagge''s Bar & Grill — Satellite Night! Come win a cheap seat into tomorrows main event! $40 gets you 10k in tournament chips. 4 tables, Late registration until 9pm.', '2023-09-15 20:19:00', null, 'dakota-poker-tour-2023-24-hagge-s-deep-stack-hagge-s-super-satellite-09-15-2023', 'https://dakotapokertour.com/storage/article/thumb/IMG_7168-UWr5H2gZ.jpg', '/media/dpt/article/IMG_7168-UWr5H2gZ.jpg', null, '{"id":166,"title":"Registration still open! 9pm","alias":"registration-still-open-9pm","excerpt":"At Hagge''s Bar & Grill — Satellite Night! Come win a cheap seat into tomorrows main event! $40 gets you 10k in tournament chips. 4 tables, Late registration until 9pm.","content":"At Hagge''s Bar & Grill — Satellite Night! Come win a cheap seat into tomorrows main event! $40 gets you 10k in tournament chips. 4 tables, Late registration until 9pm.","publishedAt":"2023-09-15 20:19:00","featured":false,"logo":"IMG_7168-UWr5H2gZ.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_7168-UWr5H2gZ.jpg","bannerUrl":"","tournament":{"id":239,"name":"Hagge''s - Super Satellite","alias":"dakota-poker-tour-2023-24-hagge-s-deep-stack-hagge-s-super-satellite-09-15-2023"}}'::jsonb),
  (165, 'new-season-begins-soon', 'New Season Begins Soon!', 'The summer break for the DPT is coming to end soon! We''re looking forward the official kickoff of the DPT 2023-2024 Season with the RPT Summer Main event with the Roughrider Poker Tour at the Bismarck Hotel Aug 25-27th. Stay tuned for updat…', '2023-08-08 08:02:00', null, null, 'https://dakotapokertour.com/storage/article/thumb/DPT-General-Banner-Aug-2023-Fu1CU5ey.png', '/media/dpt/article/DPT-General-Banner-Aug-2023-Fu1CU5ey.png', null, '{"id":165,"title":"New Season Begins Soon!","alias":"new-season-begins-soon","excerpt":"The summer break for the DPT is coming to end soon! We''re looking forward the official kickoff of the DPT 2023-2024 Season with the RPT Summer Main event with the Roughrider Poker Tour at the Bismarck Hotel Aug 25-27th. Stay tuned for updat…","content":"The summer break for the DPT is coming to end soon! We''re looking forward the official kickoff of the DPT 2023-2024 Season with the RPT Summer Main event with the Roughrider Poker Tour at the Bismarck Hotel Aug 25-27th. Stay tuned for updates in the near future as we finalize the Fall schedule, including some exciting new events! Aug 25-27th RPT Summer Main Event - Bismarck Hotel Sept 16th Hagge''s Deep Stack Oct 8th Mandan Eagles Club Mega Stack Oct 15th Poker Brat Bounty Tournament - Windbreak","publishedAt":"2023-08-08 08:02:00","featured":true,"logo":"DPT-General-Banner-Aug-2023-Fu1CU5ey.png","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/DPT-General-Banner-Aug-2023-Fu1CU5ey.png","bannerUrl":"","tournament":{"id":null,"name":null,"alias":null}}'::jsonb),
  (164, 'champion-joel-klipping', 'Champion Joel Klipping', 'Congratulations Joel Klipping !!! 10 players came out to compete in the Tournament of Champions, after a heads up battle with Brad Pausch, Joel is your Champion. Joel won a $1,500 Tournament Prize package and a seat into the FPN Vegas 100k…', '2023-05-07 22:26:00', null, 'dakota-poker-tour-2022-23-end-of-season-championship-bonus-freerolls-dpt-season-2022-23-tournament-of-champions-05-07-2023', 'https://dakotapokertour.com/storage/article/thumb/IMG_4332-iqPensM5.jpg', '/media/dpt/article/IMG_4332-iqPensM5.jpg', null, '{"id":164,"title":"Champion Joel Klipping","alias":"champion-joel-klipping","excerpt":"Congratulations Joel Klipping !!! 10 players came out to compete in the Tournament of Champions, after a heads up battle with Brad Pausch, Joel is your Champion. Joel won a $1,500 Tournament Prize package and a seat into the FPN Vegas 100k…","content":"Congratulations Joel Klipping !!! 10 players came out to compete in the Tournament of Champions, after a heads up battle with Brad Pausch, Joel is your Champion. Joel won a $1,500 Tournament Prize package and a seat into the FPN Vegas 100k World Championship. With Joel’s win he and Brad have a tight race for player of the year!","publishedAt":"2023-05-07 22:26:00","featured":false,"logo":"IMG_4332-iqPensM5.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_4332-iqPensM5.jpg","bannerUrl":"","tournament":{"id":229,"name":"DPT Season 2022-23 Tournament of Champions","alias":"dakota-poker-tour-2022-23-end-of-season-championship-bonus-freerolls-dpt-season-2022-23-tournament-of-champions-05-07-2023"}}'::jsonb),
  (163, 'nikki-smith-champion', 'Nikki Smith CHAMPION!!!', 'Congratulations to Nikki Smith!!! Your Player Appreciation Champion winning a $1,500 tournament prize package and a seat into the FPN Vegas 100k World Championship. 2nd $300 DPT Certificate Phu Truong 3rd $150 DPT Certificate Alpha Adkins 4…', '2023-05-07 20:56:00', null, 'dakota-poker-tour-season-2022-23-player-appreciation-freeroll', 'https://dakotapokertour.com/storage/article/thumb/IMG_4371-uJPyfRSw.jpg', '/media/dpt/article/IMG_4371-uJPyfRSw.jpg', null, '{"id":163,"title":"Nikki Smith CHAMPION!!!","alias":"nikki-smith-champion","excerpt":"Congratulations to Nikki Smith!!! Your Player Appreciation Champion winning a $1,500 tournament prize package and a seat into the FPN Vegas 100k World Championship. 2nd $300 DPT Certificate Phu Truong 3rd $150 DPT Certificate Alpha Adkins 4…","content":"Congratulations to Nikki Smith!!! Your Player Appreciation Champion winning a $1,500 tournament prize package and a seat into the FPN Vegas 100k World Championship. 2nd $300 DPT Certificate Phu Truong 3rd $150 DPT Certificate Alpha Adkins 4th $150 DTP Certificate Jeremy Heinze 5th $150 DPT Certificate Karl Johnson 6th Dinner at Randy’s Chase Lardy! Other prizes Randy’s Dinner Gift Cards: Chase Lardy (2X) Ryan Bellen, Jon Christianson 10-7 Drink round from Rough Rider table 4! $150 DPT Certificate for high hand Lilyann sponsored by Hole In one And (10) Large One topping pizzas and (6) $25 gift cards donated by Deeks Pizza","publishedAt":"2023-05-07 20:56:00","featured":false,"logo":"IMG_4371-uJPyfRSw.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_4371-uJPyfRSw.jpg","bannerUrl":"","tournament":{"id":228,"name":"DPT Season 2022-23 Player Appreciation Freeroll","alias":"dakota-poker-tour-season-2022-23-player-appreciation-freeroll"}}'::jsonb),
  (162, 'final-table-4', 'Final table!', 'Congratulations to the final table at the Player Appreciation Freeroll. DPT Season 2022-2023 Bonus Freerolls 1st place taking home that $1,500 tournament prize package and seat into the FPN Vegas 100k Championship. 2nd $300 DPT Certificate…', '2023-05-07 19:46:00', null, 'dakota-poker-tour-season-2022-23-player-appreciation-freeroll', 'https://dakotapokertour.com/storage/article/thumb/IMG_4354-DLzPJcvO.jpg', '/media/dpt/article/IMG_4354-DLzPJcvO.jpg', null, '{"id":162,"title":"Final table!","alias":"final-table-4","excerpt":"Congratulations to the final table at the Player Appreciation Freeroll. DPT Season 2022-2023 Bonus Freerolls 1st place taking home that $1,500 tournament prize package and seat into the FPN Vegas 100k Championship. 2nd $300 DPT Certificate…","content":"Congratulations to the final table at the Player Appreciation Freeroll. DPT Season 2022-2023 Bonus Freerolls 1st place taking home that $1,500 tournament prize package and seat into the FPN Vegas 100k Championship. 2nd $300 DPT Certificate 3-5 $150 DPT Certificate 6th Dinner at Randy''s University Diner !","publishedAt":"2023-05-07 19:46:00","featured":true,"logo":"IMG_4354-DLzPJcvO.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_4354-DLzPJcvO.jpg","bannerUrl":"","tournament":{"id":228,"name":"DPT Season 2022-23 Player Appreciation Freeroll","alias":"dakota-poker-tour-season-2022-23-player-appreciation-freeroll"}}'::jsonb),
  (161, '3-players-remain', '3 players remain', 'Tournament of Champions down to 3 players. Joel Klipping is your chip leader. It’s a tight race for Player or the Year!!', '2023-05-07 15:55:00', null, 'dakota-poker-tour-2022-23-end-of-season-championship-bonus-freerolls-dpt-season-2022-23-tournament-of-champions-05-07-2023', 'https://dakotapokertour.com/storage/article/thumb/IMG_4309-mugjvzuM.jpg', '/media/dpt/article/IMG_4309-mugjvzuM.jpg', null, '{"id":161,"title":"3 players remain","alias":"3-players-remain","excerpt":"Tournament of Champions down to 3 players. Joel Klipping is your chip leader. It’s a tight race for Player or the Year!!","content":"Tournament of Champions down to 3 players. Joel Klipping is your chip leader. It’s a tight race for Player or the Year!!","publishedAt":"2023-05-07 15:55:00","featured":true,"logo":"IMG_4309-mugjvzuM.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_4309-mugjvzuM.jpg","bannerUrl":"","tournament":{"id":229,"name":"DPT Season 2022-23 Tournament of Champions","alias":"dakota-poker-tour-2022-23-end-of-season-championship-bonus-freerolls-dpt-season-2022-23-tournament-of-champions-05-07-2023"}}'::jsonb),
  (160, 'late-registration-until-5pm', 'Late Registration until 5pm!!', 'What?!!! 9 Tables! Get down here Speedway Steakhouse & Event Center late registration until 5PM 2 time FPN National Champion Joel Smith makes an early exit. Joel''s pocket KK cracked by 7-2 and yes there was a raise and re-raise pre flop! Fi…', '2023-05-07 15:47:00', null, 'dakota-poker-tour-season-2022-23-player-appreciation-freeroll', 'https://dakotapokertour.com/storage/article/thumb/IMG_4306-jEThguJG.jpg', '/media/dpt/article/IMG_4306-jEThguJG.jpg', null, '{"id":160,"title":"Late Registration until 5pm!!","alias":"late-registration-until-5pm","excerpt":"What?!!! 9 Tables! Get down here Speedway Steakhouse & Event Center late registration until 5PM 2 time FPN National Champion Joel Smith makes an early exit. Joel''s pocket KK cracked by 7-2 and yes there was a raise and re-raise pre flop! Fi…","content":"What?!!! 9 Tables! Get down here Speedway Steakhouse & Event Center late registration until 5PM 2 time FPN National Champion Joel Smith makes an early exit. Joel''s pocket KK cracked by 7-2 and yes there was a raise and re-raise pre flop! First out prize Jon Christensen recieved a gift card courtesy of Randy''s University Diner and a Medallion. Table 4 won the 7-10 drink round prize, thank you Roughrider Poker Tour. Current high hand quad Aces for the $150 DPT certificate thank you to Hole-In-One Foundation","publishedAt":"2023-05-07 15:47:00","featured":false,"logo":"IMG_4306-jEThguJG.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_4306-jEThguJG.jpg","bannerUrl":"","tournament":{"id":228,"name":"DPT Season 2022-23 Player Appreciation Freeroll","alias":"dakota-poker-tour-season-2022-23-player-appreciation-freeroll"}}'::jsonb),
  (159, '2-30pm-cards-in-the-air', '2:30pm Cards in the Air', 'Join us 2:30pm for our Player Appreciation Freeroll at the Speedway Steakhouse & Event Center. 1st place is a $1,500 Tournament Prize Package and a seat into the FPN Vegas 100k World Championship. 2nd $300 DPT Certificate 3rd-5th $150 DPT C…', '2023-05-07 13:33:00', null, 'dakota-poker-tour-season-2022-23-player-appreciation-freeroll', 'https://dakotapokertour.com/storage/article/thumb/IMG_4304-mWoootnY.jpg', '/media/dpt/article/IMG_4304-mWoootnY.jpg', null, '{"id":159,"title":"2:30pm Cards in the Air","alias":"2-30pm-cards-in-the-air","excerpt":"Join us 2:30pm for our Player Appreciation Freeroll at the Speedway Steakhouse & Event Center. 1st place is a $1,500 Tournament Prize Package and a seat into the FPN Vegas 100k World Championship. 2nd $300 DPT Certificate 3rd-5th $150 DPT C…","content":"Join us 2:30pm for our Player Appreciation Freeroll at the Speedway Steakhouse & Event Center. 1st place is a $1,500 Tournament Prize Package and a seat into the FPN Vegas 100k World Championship. 2nd $300 DPT Certificate 3rd-5th $150 DPT Certificate Todays event is a 2X multiplier for the points race for player of the year! Also give away from our friends!! Randy’s Dinner gift cards, Deeks pizza gift cards, a drink round from Roughrider Poker Tour for 10-7, Hole-In-One Foundation sponsored a $150 DPT Certificate for high hand.","publishedAt":"2023-05-07 13:33:00","featured":true,"logo":"IMG_4304-mWoootnY.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_4304-mWoootnY.jpg","bannerUrl":"","tournament":{"id":228,"name":"DPT Season 2022-23 Player Appreciation Freeroll","alias":"dakota-poker-tour-season-2022-23-player-appreciation-freeroll"}}'::jsonb),
  (158, 'over-5-500-in-prizes-up-for-grabs-today', 'Over $5,500 in prizes up for grabs today!', 'Today! Over $5,500 in prizes are up for grabs in our Season ending BONUS FREEROLLS! Plus seats in FPN''s Vegas 100K World Championship Main Event at the Golden Nugget in Las Vegas Jan 4-7th 2024. TOURNAMENT OF CHAMPIONS (TOC) - Noon 1st Plac…', '2023-05-07 11:12:00', null, 'dakota-poker-tour-season-2022-23-player-appreciation-freeroll', 'https://dakotapokertour.com/storage/article/thumb/DPT-Championship-22-23-jkrRaXmO.png', '/media/dpt/article/DPT-Championship-22-23-jkrRaXmO.png', null, '{"id":158,"title":"Over $5,500 in prizes up for grabs today!","alias":"over-5-500-in-prizes-up-for-grabs-today","excerpt":"Today! Over $5,500 in prizes are up for grabs in our Season ending BONUS FREEROLLS! Plus seats in FPN''s Vegas 100K World Championship Main Event at the Golden Nugget in Las Vegas Jan 4-7th 2024. TOURNAMENT OF CHAMPIONS (TOC) - Noon 1st Plac…","content":"Today! Over $5,500 in prizes are up for grabs in our Season ending BONUS FREEROLLS! Plus seats in FPN''s Vegas 100K World Championship Main Event at the Golden Nugget in Las Vegas Jan 4-7th 2024. TOURNAMENT OF CHAMPIONS (TOC) - Noon 1st Place - $1,500 Poker Package + FPN 100k Seat 2nd Place - $300 DPT Certificate 3rd Place - $150 DPT Certificate Starting Chips 100k Individual Champions from Season 2022-2023 are invited to this event. Points: 2x Prizes plus participation (100) PLAYER APPRECIATION FREEROLL (PAF) - 230pm 1st Place - $1,500 Poker Package + FPN 100k Seat 2nd Place - $300 DPT Certificate 3rd Place - $150 DPT Certificate Starting Chips 10k/15k/20k (based on POY rank) All players who participated in at least one (1) Dakota Poker Tour event in Season 2022-2023 are invited to today''s Player Appreciation Freeroll. Points: 2x Points (FPN Points System + Value of Prize) plus participation (100) PLAYER OF THE YEAR (POY) 1st Place - $1,500 Poker Package + FPN 100k Seat Based on final POY ranking after today''s events and official review Pre-Register for today''s tournaments: https://dakotapokertour.com Current Leaderboard: https://dakotapokertour.com/leaderboard Can Brad Pausch hang on to lock in Player of the Year status?! BIG THANKS to everyone who participated this season in DPT and RPT events this year!","publishedAt":"2023-05-07 11:12:00","featured":true,"logo":"DPT-Championship-22-23-jkrRaXmO.png","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/DPT-Championship-22-23-jkrRaXmO.png","bannerUrl":"","tournament":{"id":228,"name":"DPT Season 2022-23 Player Appreciation Freeroll","alias":"dakota-poker-tour-season-2022-23-player-appreciation-freeroll"}}'::jsonb),
  (157, 'dick-gerdes-bounty-champ-5-580', 'Dick Gerdes Bounty Champ $5,580', 'Dick Gerdes took down Sunday''s Black-Chip Bounty Tournament over DPT Championship weekend, earning $4,380 for first place in addition to $1,200 in bounty knockouts for a total win of $5,580. Congratulations to Donald Drummond for placing ru…', '2023-04-23 23:45:00', null, 'dakota-poker-tour-2022-23-dpt-championship-black-chip-bounty-04-23-2023', 'https://dakotapokertour.com/storage/article/thumb/Image_20230424_085027_778-IEw28A0s.jpg', '/media/dpt/article/Image_20230424_085027_778-IEw28A0s.jpg', 'https://www.youtube.com/live/RlVGZpvubTg?feature=share', '{"id":157,"title":"Dick Gerdes Bounty Champ $5,580","alias":"dick-gerdes-bounty-champ-5-580","excerpt":"Dick Gerdes took down Sunday''s Black-Chip Bounty Tournament over DPT Championship weekend, earning $4,380 for first place in addition to $1,200 in bounty knockouts for a total win of $5,580. Congratulations to Donald Drummond for placing ru…","content":"Dick Gerdes took down Sunday''s Black-Chip Bounty Tournament over DPT Championship weekend, earning $4,380 for first place in addition to $1,200 in bounty knockouts for a total win of $5,580. Congratulations to Donald Drummond for placing runner up and the rest of the final table players that cashed. Dirk Gerdes $5,580 Donald Drummond $3,270 Rob Urbatsch $2,460 Michael Hlehechuk $1,770 Nick Boyum $1,400 Arlie Brandvold $1,380 Basim Habib $1,400 Weston Wells $1,020 David Beadle $880 DPT Championship weekend was a huge success with over $72,000 in cash prizes paid out, big thanks to Rough Rider Poker Tour for teaming up on this event. Also, big thank you to the West Fargo Volunteer Fire Dept and the Speedway Event Center for hosting this event. We look forward to the Season ending Bonus Freerolls on Sunday May 7th for the final opportunity for players to earn points towards Player of the Year status. Brad Pausch leads the way wtih Awesome Basim, Mark Dufner, Joel Klipping, and Rob Urbatsch rounding out the Top 5 currently.","publishedAt":"2023-04-23 23:45:00","featured":true,"logo":"Image_20230424_085027_778-IEw28A0s.jpg","banner":null,"videoUrl":"https://www.youtube.com/live/RlVGZpvubTg?feature=share","imageUrl":"https://dakotapokertour.com/storage/article/thumb/Image_20230424_085027_778-IEw28A0s.jpg","bannerUrl":"","tournament":{"id":223,"name":"Black Chip Bounty","alias":"dakota-poker-tour-2022-23-dpt-championship-black-chip-bounty-04-23-2023"}}'::jsonb),
  (156, 'brad-pausch-wins-dpt-championship-main-event-10-145', 'Brad Pausch Wins DPT Championship Main Event $10,145', 'Congratulations to Brad Pausch from Wahpeton DPT Championship main event winner 1st Place-$10,145. This big win puts Brad at the top of the Player of the Year season standings and a seat in the Tournament of Champions. Thank you to everyone…', '2023-04-22 23:45:00', null, 'dakota-poker-tour-2022-23-dpt-championship-speedway-main-event-04-22-2023', 'https://dakotapokertour.com/storage/article/thumb/FB_IMG_1682273703083-E7LfSMfw.jpg', '/media/dpt/article/FB_IMG_1682273703083-E7LfSMfw.jpg', null, '{"id":156,"title":"Brad Pausch Wins DPT Championship Main Event $10,145","alias":"brad-pausch-wins-dpt-championship-main-event-10-145","excerpt":"Congratulations to Brad Pausch from Wahpeton DPT Championship main event winner 1st Place-$10,145. This big win puts Brad at the top of the Player of the Year season standings and a seat in the Tournament of Champions. Thank you to everyone…","content":"Congratulations to Brad Pausch from Wahpeton DPT Championship main event winner 1st Place-$10,145. This big win puts Brad at the top of the Player of the Year season standings and a seat in the Tournament of Champions. Thank you to everyone that came out to support the Dakota Poker Tour and Roughrider Poker Tour!! 1. 10,145 Brad Pausch Wahpeton,ND 2. 6,640 Niles Short, Minnowakan,ND 3. 4,280 Dave Berger, Grand Forks, ND 4. 3,300 Donald Drummond, Fargo ND 5. 2,450 Cody Slusher, Oaks ND 6. 1,950 Chad Hegeberg, Lisbon, ND 7. 1,560 Brandon Schmidt, Fargo ND 8. 1,220 David Beadle, Mobridge, SD 9. 975 Titus Wipf, Fargo, ND 10. 850 Taylor Collins, Moorhead, MN 11. 850 James Meagher, Mekinock, ND 12. 850 Mark Alinder, Fargo, ND 13. 700 David Keena, Frazee, MN 14. 700 Dennis Seeb, Fargo, ND 15. 700 Mark Ihninger, Williston, ND 16. 600 Bryan Thompson, Fargo, ND 17. 600 Ernest Trzpac, Kathryn, ND 18. 600 Sam Saville, West Fargo,ND","publishedAt":"2023-04-22 23:45:00","featured":true,"logo":"FB_IMG_1682273703083-E7LfSMfw.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/FB_IMG_1682273703083-E7LfSMfw.jpg","bannerUrl":"","tournament":{"id":224,"name":"Speedway Main Event","alias":"dakota-poker-tour-2022-23-dpt-championship-speedway-main-event-04-22-2023"}}'::jsonb),
  (154, 'dpt-championship-main-event-underway', 'DPT Championship Main Event Underway', 'We have a stacked field for today''s feature tournament with 120 players+ registered before the first break. Current DPT Player of The Year points leader Mark Duffner is in the field looking to add to his points lead. Also, at least 4 of the…', '2023-04-22 13:20:00', null, 'dakota-poker-tour-2022-23-dpt-championship-speedway-main-event-04-22-2023', 'https://dakotapokertour.com/storage/article/thumb/20230422121058_IMG_6802-q6dUvCYX.jpg', '/media/dpt/article/20230422121058_IMG_6802-q6dUvCYX.jpg', null, '{"id":154,"title":"DPT Championship Main Event Underway","alias":"dpt-championship-main-event-underway","excerpt":"We have a stacked field for today''s feature tournament with 120 players+ registered before the first break. Current DPT Player of The Year points leader Mark Duffner is in the field looking to add to his points lead. Also, at least 4 of the…","content":"We have a stacked field for today''s feature tournament with 120 players+ registered before the first break. Current DPT Player of The Year points leader Mark Duffner is in the field looking to add to his points lead. Also, at least 4 of the Top 10 points leaders on the Rough Rider Poker Tour are also in today''s field, includiing Weston Wells, Zach Byers, David Delaplane, and Jim Bohlman.","publishedAt":"2023-04-22 13:20:00","featured":true,"logo":"20230422121058_IMG_6802-q6dUvCYX.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20230422121058_IMG_6802-q6dUvCYX.jpg","bannerUrl":"","tournament":{"id":224,"name":"Speedway Main Event","alias":"dakota-poker-tour-2022-23-dpt-championship-speedway-main-event-04-22-2023"}}'::jsonb),
  (155, 'mike-estes-wins-friday-night-special-4-270', 'Mike Estes Wins Friday Night Special $4,270', 'Congratulations to our winner Mike Estes taking home $4270! It was a great start to our Championship weekend with Roughrider Poker Tour, at the Speedway Steakhouse & Event Center. Mike Estes Will join us for our tournament of champions and…', '2023-04-22 08:15:00', null, 'dakota-poker-tour-2022-23-dpt-championship-friday-night-turbo-04-21-2023', 'https://dakotapokertour.com/storage/article/thumb/FB_IMG_1682273650880-Ak1s40LV.jpg', '/media/dpt/article/FB_IMG_1682273650880-Ak1s40LV.jpg', null, '{"id":155,"title":"Mike Estes Wins Friday Night Special $4,270","alias":"mike-estes-wins-friday-night-special-4-270","excerpt":"Congratulations to our winner Mike Estes taking home $4270! It was a great start to our Championship weekend with Roughrider Poker Tour, at the Speedway Steakhouse & Event Center. Mike Estes Will join us for our tournament of champions and…","content":"Congratulations to our winner Mike Estes taking home $4270! It was a great start to our Championship weekend with Roughrider Poker Tour, at the Speedway Steakhouse & Event Center. Mike Estes Will join us for our tournament of champions and is in the race for player of the year.￼￼ 1st $4270 Mike Estes Coralville IA 2nd $2750 Dave Ouellette Dickinson ND 3rd $2000 Chris Gray Fargo ND 4th $1440 Eric Erbe Aberdeen SD 5th $1150 Mike Hlebechuk Fargo ND 6th $980 Steven Obregon Fargo ND 7th $800 Phu Truong Moorhead MN 8th $600 Jaclyn Hollands Mapelton ND 9th $500 Kevin Selby Bismarck ND","publishedAt":"2023-04-22 08:15:00","featured":true,"logo":"FB_IMG_1682273650880-Ak1s40LV.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/FB_IMG_1682273650880-Ak1s40LV.jpg","bannerUrl":"","tournament":{"id":225,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2022-23-dpt-championship-friday-night-turbo-04-21-2023"}}'::jsonb),
  (153, 'congratulations-mike-estes', 'Congratulations Mike Estes', 'Congratulations to our winner Mike Estes taking home $4270! It was a great start to our Championship weekend with Roughrider Poker Tour, at the Speedway Steakhouse & Event Center. Mike Estes Will join us for our tournament of champions and…', '2023-04-22 02:36:00', null, 'dakota-poker-tour-2022-23-dpt-championship-friday-night-turbo-04-21-2023', 'https://dakotapokertour.com/storage/article/thumb/B56ED09D-6D8D-4410-B9FA-7A7F1F91F0BE-KbxQNNDC.jpg', '/media/dpt/article/B56ED09D-6D8D-4410-B9FA-7A7F1F91F0BE-KbxQNNDC.jpg', null, '{"id":153,"title":"Congratulations Mike Estes","alias":"congratulations-mike-estes","excerpt":"Congratulations to our winner Mike Estes taking home $4270! It was a great start to our Championship weekend with Roughrider Poker Tour, at the Speedway Steakhouse & Event Center. Mike Estes Will join us for our tournament of champions and…","content":"Congratulations to our winner Mike Estes taking home $4270! It was a great start to our Championship weekend with Roughrider Poker Tour, at the Speedway Steakhouse & Event Center. Mike Estes Will join us for our tournament of champions and is in the race for player of the year.￼￼ 1st $4270 Mike Estes Coralville IA 2nd $2750 Dave Ouellette Dickinson ND 3rd $2000 Chris Gray Fargo ND 4th $1440 Eric Erbe Aberdeen SD 5th $1150 Mike Hlebechuk Fargo ND 6th $980 Steven Obregon Fargo ND 7th $800 Phu Truong Moorehead MN 8th $600 Jaclyn Hollands Mapelton ND 9th $500 Kevin Selby Bismarck ND","publishedAt":"2023-04-22 02:36:00","featured":true,"logo":"B56ED09D-6D8D-4410-B9FA-7A7F1F91F0BE-KbxQNNDC.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/B56ED09D-6D8D-4410-B9FA-7A7F1F91F0BE-KbxQNNDC.jpg","bannerUrl":"","tournament":{"id":225,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2022-23-dpt-championship-friday-night-turbo-04-21-2023"}}'::jsonb),
  (152, 'final-table-3', 'Friday Night Special-Final Table', 'Congratulations to our final table at the DPT Championship Friday night Turbo 94 Players joined us tonight. 66 rebuys generating $14490. Thank you to Roughrider Poker Tour for helping make this a successful event. Thank you to all our playe…', '2023-04-22 00:37:00', null, 'dakota-poker-tour-2022-23-dpt-championship-friday-night-turbo-04-21-2023', 'https://dakotapokertour.com/storage/article/thumb/02F5E6EA-87AE-4A14-8986-CE8DFA03F852-38tNPuVp.jpg', '/media/dpt/article/02F5E6EA-87AE-4A14-8986-CE8DFA03F852-38tNPuVp.jpg', null, '{"id":152,"title":"Friday Night Special-Final Table","alias":"final-table-3","excerpt":"Congratulations to our final table at the DPT Championship Friday night Turbo 94 Players joined us tonight. 66 rebuys generating $14490. Thank you to Roughrider Poker Tour for helping make this a successful event. Thank you to all our playe…","content":"Congratulations to our final table at the DPT Championship Friday night Turbo 94 Players joined us tonight. 66 rebuys generating $14490. Thank you to Roughrider Poker Tour for helping make this a successful event. Thank you to all our players for your continued support","publishedAt":"2023-04-22 00:37:00","featured":true,"logo":"02F5E6EA-87AE-4A14-8986-CE8DFA03F852-38tNPuVp.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/02F5E6EA-87AE-4A14-8986-CE8DFA03F852-38tNPuVp.jpg","bannerUrl":"","tournament":{"id":225,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2022-23-dpt-championship-friday-night-turbo-04-21-2023"}}'::jsonb),
  (151, 'cordell-schroeder-from-carrington-wins-buffalo-city-showdown-4-220', 'Cordell Schroeder from Carrington Wins Buffalo City Showdown $4,220', 'Congratulations Cordell Schroeder from Carrington! Cordell takes home the Trophy and $4,220 for 1st Place in the Buffalo City Showdown at the Buff Bar in Jamestown. Cordell also earns a seat in the Tournament of Champions Bonus $1500 WSOP P…', '2023-04-16 09:35:00', null, 'dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023', 'https://dakotapokertour.com/storage/article/thumb/342033586_1291800025019776_2711776892739173459_n-grWi3Jfw.jpg', '/media/dpt/article/342033586_1291800025019776_2711776892739173459_n-grWi3Jfw.jpg', null, '{"id":151,"title":"Cordell Schroeder from Carrington Wins Buffalo City Showdown $4,220","alias":"cordell-schroeder-from-carrington-wins-buffalo-city-showdown-4-220","excerpt":"Congratulations Cordell Schroeder from Carrington! Cordell takes home the Trophy and $4,220 for 1st Place in the Buffalo City Showdown at the Buff Bar in Jamestown. Cordell also earns a seat in the Tournament of Champions Bonus $1500 WSOP P…","content":"Congratulations Cordell Schroeder from Carrington! Cordell takes home the Trophy and $4,220 for 1st Place in the Buffalo City Showdown at the Buff Bar in Jamestown. Cordell also earns a seat in the Tournament of Champions Bonus $1500 WSOP Package Freeroll coming up Sunday May 7th in West Fargo. The 2022-2023 Season of the Dakota Poker Tour wraps up next weekend with 3 BIG events at the Speedway Event Center in West Fargo. Player of the Year race is heating up! Here is the updated leaderboard: https://dakotapokertour.com/leaderboard Congratulations to the players that cashed today. Thank you to all the players that came out, and for your continued support! $4220 Cordell Schroeder Carrington, ND $2680 Myles Torgerson Jamestown, ND $2000 Shawn Lambertz Webster, SD $1430 Robby Grajczyk Eureka, SD $1150 Aaron Knudson Adrian, ND $980 Larry Loose Jamestown, ND $780 Skyler Sand Cando, ND $665 Michael Headland Jamestown, ND $545 Roddy Gentzkow Jamestown, ND","publishedAt":"2023-04-16 09:35:00","featured":true,"logo":"342033586_1291800025019776_2711776892739173459_n-grWi3Jfw.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/342033586_1291800025019776_2711776892739173459_n-grWi3Jfw.jpg","bannerUrl":"","tournament":{"id":203,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023"}}'::jsonb),
  (150, 'congratulations-cordell', 'Congratulations  Cordell', 'Welcome Cordell to our Season 2022-2023 Champions! Cordell took home $4220 and a seat into our Tournament of Champions on May 7, 2023. 63 players came out today. Congratulations to the players that cashed today. Thank you to all the players…', '2023-04-15 22:38:00', null, 'dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023', 'https://dakotapokertour.com/storage/article/thumb/E000D067-AAAB-4816-A95B-6692F5D2A527-QsavZmCQ.jpg', '/media/dpt/article/E000D067-AAAB-4816-A95B-6692F5D2A527-QsavZmCQ.jpg', null, '{"id":150,"title":"Congratulations  Cordell","alias":"congratulations-cordell","excerpt":"Welcome Cordell to our Season 2022-2023 Champions! Cordell took home $4220 and a seat into our Tournament of Champions on May 7, 2023. 63 players came out today. Congratulations to the players that cashed today. Thank you to all the players…","content":"Welcome Cordell to our Season 2022-2023 Champions! Cordell took home $4220 and a seat into our Tournament of Champions on May 7, 2023. 63 players came out today. Congratulations to the players that cashed today. Thank you to all the players that came out, and for your continued support! $4220 Cordell Schroeder Carrington, ND $2680 Myles Torgerson Jamestown, ND $2000 Shawn Lambertz Webster, SD $1430 Robby Grajczyk Eureka, SD $1150 Aaron Knudson Adrian, ND $980 Larry Loose Jamestown, ND $780 Skyler Sand Cando, ND $665 Michael Headland Jamestown, ND $545 Roddy Gentzkow Jamestown, ND","publishedAt":"2023-04-15 22:38:00","featured":false,"logo":"E000D067-AAAB-4816-A95B-6692F5D2A527-QsavZmCQ.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/E000D067-AAAB-4816-A95B-6692F5D2A527-QsavZmCQ.jpg","bannerUrl":"","tournament":{"id":203,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023"}}'::jsonb),
  (149, 'final-table-2', 'Final Table', 'We are down to the FINAL 9! Congratulations to those taking home winnings. As always, thank you to all the players who made it out today and supporting the Dakota Poker Tour. Today we generated a prize pool of $14,450!!!', '2023-04-15 20:43:00', null, 'dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023', 'https://dakotapokertour.com/storage/article/thumb/8987D85A-9878-463E-A23E-94F659685680-Cjn6TE6R.jpg', '/media/dpt/article/8987D85A-9878-463E-A23E-94F659685680-Cjn6TE6R.jpg', null, '{"id":149,"title":"Final Table","alias":"final-table-2","excerpt":"We are down to the FINAL 9! Congratulations to those taking home winnings. As always, thank you to all the players who made it out today and supporting the Dakota Poker Tour. Today we generated a prize pool of $14,450!!!","content":"We are down to the FINAL 9! Congratulations to those taking home winnings. As always, thank you to all the players who made it out today and supporting the Dakota Poker Tour. Today we generated a prize pool of $14,450!!!","publishedAt":"2023-04-15 20:43:00","featured":false,"logo":"8987D85A-9878-463E-A23E-94F659685680-Cjn6TE6R.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/8987D85A-9878-463E-A23E-94F659685680-Cjn6TE6R.jpg","bannerUrl":"","tournament":{"id":203,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023"}}'::jsonb),
  (148, 'registration-closed', 'Registration Closed', 'Registration now closed! 63 players started the day. Only 4 tables remain after dinner break. Unfortunately, the sharks sent Martin Short to the rail. The battle will continue for player of the year at the DPT Championship event at Speedway…', '2023-04-15 20:41:00', null, 'dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023', 'https://dakotapokertour.com/storage/article/thumb/AD8936BD-1C25-4AC2-B34E-79BA962E3F59-0QTvbO9d.jpg', '/media/dpt/article/AD8936BD-1C25-4AC2-B34E-79BA962E3F59-0QTvbO9d.jpg', null, '{"id":148,"title":"Registration Closed","alias":"registration-closed","excerpt":"Registration now closed! 63 players started the day. Only 4 tables remain after dinner break. Unfortunately, the sharks sent Martin Short to the rail. The battle will continue for player of the year at the DPT Championship event at Speedway…","content":"Registration now closed! 63 players started the day. Only 4 tables remain after dinner break. Unfortunately, the sharks sent Martin Short to the rail. The battle will continue for player of the year at the DPT Championship event at Speedway Event Center in Fargo with the Roughrider Poker Tour. April 21st - 23rd (Fri-Sun)","publishedAt":"2023-04-15 20:41:00","featured":false,"logo":"AD8936BD-1C25-4AC2-B34E-79BA962E3F59-0QTvbO9d.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/AD8936BD-1C25-4AC2-B34E-79BA962E3F59-0QTvbO9d.jpg","bannerUrl":"","tournament":{"id":203,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023"}}'::jsonb),
  (147, 'martin-short-trying-to-take-the-lead', 'Martin Short trying to take the lead', 'It''s a close race for player of the year with Mark Dufner, Awesome Basim, and Martin Short in attendance today... Going into dinner break...the last one standing is Martin Short', '2023-04-15 16:33:00', null, 'dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023', 'https://dakotapokertour.com/storage/article/thumb/1288B9D9-277C-4648-AA14-A928DCCCF1B6-29pTVY6F.jpg', '/media/dpt/article/1288B9D9-277C-4648-AA14-A928DCCCF1B6-29pTVY6F.jpg', null, '{"id":147,"title":"Martin Short trying to take the lead","alias":"martin-short-trying-to-take-the-lead","excerpt":"It''s a close race for player of the year with Mark Dufner, Awesome Basim, and Martin Short in attendance today... Going into dinner break...the last one standing is Martin Short","content":"It''s a close race for player of the year with Mark Dufner, Awesome Basim, and Martin Short in attendance today... Going into dinner break...the last one standing is Martin Short","publishedAt":"2023-04-15 16:33:00","featured":false,"logo":"1288B9D9-277C-4648-AA14-A928DCCCF1B6-29pTVY6F.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/1288B9D9-277C-4648-AA14-A928DCCCF1B6-29pTVY6F.jpg","bannerUrl":"","tournament":{"id":203,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023"}}'::jsonb),
  (146, 'pocket-kings-fold-preflop-yes-he-showed', 'Pocket Kings fold preflop, yes he showed!', 'We have two all in pre flop with Aaron to make a decision he states he has kings?! ￼￼ He shows the kings and folds! He is correct he was up against pocket aces and pocket queens. ￼￼ The boards run out and aces win! Patti scoops the pot! ￼', '2023-04-15 15:27:00', null, 'dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023', 'https://dakotapokertour.com/storage/article/thumb/908FF7FE-2E51-4853-A104-D9AB2EC37C20-ABkZfl8W.jpg', '/media/dpt/article/908FF7FE-2E51-4853-A104-D9AB2EC37C20-ABkZfl8W.jpg', null, '{"id":146,"title":"Pocket Kings fold preflop, yes he showed!","alias":"pocket-kings-fold-preflop-yes-he-showed","excerpt":"We have two all in pre flop with Aaron to make a decision he states he has kings?! ￼￼ He shows the kings and folds! He is correct he was up against pocket aces and pocket queens. ￼￼ The boards run out and aces win! Patti scoops the pot! ￼","content":"We have two all in pre flop with Aaron to make a decision he states he has kings?! ￼￼ He shows the kings and folds! He is correct he was up against pocket aces and pocket queens. ￼￼ The boards run out and aces win! Patti scoops the pot! ￼","publishedAt":"2023-04-15 15:27:00","featured":false,"logo":"908FF7FE-2E51-4853-A104-D9AB2EC37C20-ABkZfl8W.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/908FF7FE-2E51-4853-A104-D9AB2EC37C20-ABkZfl8W.jpg","bannerUrl":"","tournament":{"id":203,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023"}}'::jsonb),
  (145, 'cards-in-the-air-3', 'Cards in the air!', 'Today DPT is in Jamestown at the Buff Bar. 7 tables lots of familiar face and some new ones! Still lots of time to get here, late registration open until approximately 5pm. $175 gets you a 20k stack and for every additional $50 you get anot…', '2023-04-15 14:00:00', null, 'dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023', 'https://dakotapokertour.com/storage/article/thumb/14D65D73-8A7F-41E7-B265-55E5D60BB7E7-uju3fKto.jpg', '/media/dpt/article/14D65D73-8A7F-41E7-B265-55E5D60BB7E7-uju3fKto.jpg', null, '{"id":145,"title":"Cards in the air!","alias":"cards-in-the-air-3","excerpt":"Today DPT is in Jamestown at the Buff Bar. 7 tables lots of familiar face and some new ones! Still lots of time to get here, late registration open until approximately 5pm. $175 gets you a 20k stack and for every additional $50 you get anot…","content":"Today DPT is in Jamestown at the Buff Bar. 7 tables lots of familiar face and some new ones! Still lots of time to get here, late registration open until approximately 5pm. $175 gets you a 20k stack and for every additional $50 you get another 10k. Max buyin $325 and you’ll start with 50k in chips!","publishedAt":"2023-04-15 14:00:00","featured":false,"logo":"14D65D73-8A7F-41E7-B265-55E5D60BB7E7-uju3fKto.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/14D65D73-8A7F-41E7-B265-55E5D60BB7E7-uju3fKto.jpg","bannerUrl":"","tournament":{"id":203,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-2022-23-baffalo-city-showdown-buffalo-city-showdown-03-05-2023"}}'::jsonb),
  (144, 'joel-klipping-joins-the-2022-2023-champions', 'Joel Klipping Joins the 2022-2023 Champions', 'Welcome Joel Klipping to our Season 2022-2023 Champions! Joel took home $5255 and a seat into our Tournament of Champions. 78 players came out today. Congratulations to the players that cashed today. Thank you to all the players that came o…', '2023-04-02 23:26:00', null, 'dakota-poker-tour-2022-23-eagle-eye-eagle-eye-04-02-2023', 'https://dakotapokertour.com/storage/article/thumb/4645C4B0-204A-40AE-BE5E-FFADA924F93D-JNYAFiDc.jpg', '/media/dpt/article/4645C4B0-204A-40AE-BE5E-FFADA924F93D-JNYAFiDc.jpg', null, '{"id":144,"title":"Joel Klipping Joins the 2022-2023 Champions","alias":"joel-klipping-joins-the-2022-2023-champions","excerpt":"Welcome Joel Klipping to our Season 2022-2023 Champions! Joel took home $5255 and a seat into our Tournament of Champions. 78 players came out today. Congratulations to the players that cashed today. Thank you to all the players that came o…","content":"Welcome Joel Klipping to our Season 2022-2023 Champions! Joel took home $5255 and a seat into our Tournament of Champions. 78 players came out today. Congratulations to the players that cashed today. Thank you to all the players that came out today to play, and for your continued support! $5255 Joel Klipping Red Lakes Fall MN $3740 Mike Headland Jamestown ND $2660 Dennis Seeb Fargo ND￼ $1900 Mark Alinder Fargo ND $1500 Craig Thompson $1300 Nathan Kiefert W.Fargo ND $1000 Jasen Mcgouh Valley City ND $700 Shawn Pettigrew Grandforks ND $600 Tim Scott Fargo ND","publishedAt":"2023-04-02 23:26:00","featured":false,"logo":"4645C4B0-204A-40AE-BE5E-FFADA924F93D-JNYAFiDc.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/4645C4B0-204A-40AE-BE5E-FFADA924F93D-JNYAFiDc.jpg","bannerUrl":"","tournament":{"id":227,"name":"Eagle Eye","alias":"dakota-poker-tour-2022-23-eagle-eye-eagle-eye-04-02-2023"}}'::jsonb),
  (143, 'final-table', 'Final Table!', 'Congratulations to the final table all in the money!! 78 players quickly dwindled to the final 9! We had a prize pool of 18,000! Thank you everyone for coming out and supporting the DPT!', '2023-04-02 21:15:00', null, 'dakota-poker-tour-2022-23-eagle-eye-eagle-eye-04-02-2023', 'https://dakotapokertour.com/storage/article/thumb/B8BF4EDE-381E-4F50-9972-56A3258739A6-tLmnrL7U.jpg', '/media/dpt/article/B8BF4EDE-381E-4F50-9972-56A3258739A6-tLmnrL7U.jpg', null, '{"id":143,"title":"Final Table!","alias":"final-table","excerpt":"Congratulations to the final table all in the money!! 78 players quickly dwindled to the final 9! We had a prize pool of 18,000! Thank you everyone for coming out and supporting the DPT!","content":"Congratulations to the final table all in the money!! 78 players quickly dwindled to the final 9! We had a prize pool of 18,000! Thank you everyone for coming out and supporting the DPT!","publishedAt":"2023-04-02 21:15:00","featured":false,"logo":"B8BF4EDE-381E-4F50-9972-56A3258739A6-tLmnrL7U.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/B8BF4EDE-381E-4F50-9972-56A3258739A6-tLmnrL7U.jpg","bannerUrl":"","tournament":{"id":227,"name":"Eagle Eye","alias":"dakota-poker-tour-2022-23-eagle-eye-eagle-eye-04-02-2023"}}'::jsonb),
  (142, 'still-time-to-get-here-late-registration-to-5pm', 'Still time to get here! Late registration to 5pm', 'Still a lot of time to get here 2hours (5pm ) 8 tables!!! $150 for 20k in chips. $300 for 50k.', '2023-04-02 15:05:00', null, 'dakota-poker-tour-2022-23-eagle-eye-eagle-eye-04-02-2023', 'https://dakotapokertour.com/storage/article/thumb/6A014B8A-B91E-4F9C-B52E-EFFCDA9A8692-ARCyilU4.jpg', '/media/dpt/article/6A014B8A-B91E-4F9C-B52E-EFFCDA9A8692-ARCyilU4.jpg', null, '{"id":142,"title":"Still time to get here! Late registration to 5pm","alias":"still-time-to-get-here-late-registration-to-5pm","excerpt":"Still a lot of time to get here 2hours (5pm ) 8 tables!!! $150 for 20k in chips. $300 for 50k.","content":"Still a lot of time to get here 2hours (5pm ) 8 tables!!! $150 for 20k in chips. $300 for 50k.","publishedAt":"2023-04-02 15:05:00","featured":false,"logo":"6A014B8A-B91E-4F9C-B52E-EFFCDA9A8692-ARCyilU4.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/6A014B8A-B91E-4F9C-B52E-EFFCDA9A8692-ARCyilU4.jpg","bannerUrl":"","tournament":{"id":227,"name":"Eagle Eye","alias":"dakota-poker-tour-2022-23-eagle-eye-eagle-eye-04-02-2023"}}'::jsonb),
  (141, 'cards-are-in-the-air-3', 'Cards are in the Air!', 'Join us in Valley City 1 day event. Starts at 12, late registration until 4:30! $175 gets you 20k in starting stack. For every additional $50 you get an additional 10k, up to 3.', '2023-04-02 12:03:00', null, 'dakota-poker-tour-2022-23-eagle-eye-eagle-eye-04-02-2023', 'https://dakotapokertour.com/storage/article/thumb/B27D0E9F-10FE-4EF2-86F7-8EBA727B8035-gEKaqJhS.jpg', '/media/dpt/article/B27D0E9F-10FE-4EF2-86F7-8EBA727B8035-gEKaqJhS.jpg', null, '{"id":141,"title":"Cards are in the Air!","alias":"cards-are-in-the-air-3","excerpt":"Join us in Valley City 1 day event. Starts at 12, late registration until 4:30! $175 gets you 20k in starting stack. For every additional $50 you get an additional 10k, up to 3.","content":"Join us in Valley City 1 day event. Starts at 12, late registration until 4:30! $175 gets you 20k in starting stack. For every additional $50 you get an additional 10k, up to 3.","publishedAt":"2023-04-02 12:03:00","featured":false,"logo":"B27D0E9F-10FE-4EF2-86F7-8EBA727B8035-gEKaqJhS.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/B27D0E9F-10FE-4EF2-86F7-8EBA727B8035-gEKaqJhS.jpg","bannerUrl":"","tournament":{"id":227,"name":"Eagle Eye","alias":"dakota-poker-tour-2022-23-eagle-eye-eagle-eye-04-02-2023"}}'::jsonb),
  (140, 'the-eagle-eye-is-back-in-valley-city', 'The Eagle Eye is BACK in Valley City', 'The Eagle Eye Poker Tournament is back with the Dakota Poker Tour! Join us for this 1-day Poker Tournament at the Valley City Eagles starting at NOON. Buy-in $150 plus $25 for dealer appreciation for 20k in chips. Add 10k more chips for $50…', '2023-03-28 16:30:00', null, 'dakota-poker-tour-season-xi-eagle-eye-eagle-eye-04-16-2022', '', '', 'https://youtu.be/wvO1yniB4NA', '{"id":140,"title":"The Eagle Eye is BACK in Valley City","alias":"the-eagle-eye-is-back-in-valley-city","excerpt":"The Eagle Eye Poker Tournament is back with the Dakota Poker Tour! Join us for this 1-day Poker Tournament at the Valley City Eagles starting at NOON. Buy-in $150 plus $25 for dealer appreciation for 20k in chips. Add 10k more chips for $50…","content":"The Eagle Eye Poker Tournament is back with the Dakota Poker Tour! Join us for this 1-day Poker Tournament at the Valley City Eagles starting at NOON. Buy-in $150 plus $25 for dealer appreciation for 20k in chips. Add 10k more chips for $50 (up to 50k total chips, $300 total buy-in). Registration open until 430pm. For complete details, Leaderboard, and more visit: https://dakotapokertour.com","publishedAt":"2023-03-28 16:30:00","featured":false,"logo":"","banner":null,"videoUrl":"https://youtu.be/wvO1yniB4NA","imageUrl":"","bannerUrl":"","tournament":{"id":18,"name":"Eagle Eye","alias":"dakota-poker-tour-season-xi-eagle-eye-eagle-eye-04-16-2022"}}'::jsonb),
  (138, 'mark-dufner-hole-in-one-champion-6-740', 'Mark Dufner Hole In One Champion $6,740', 'Mark Dufner scored a big win in Oakes, ND outlasting Anthony Scarborough from Mansfield ND. Dufner, from Crookston MN took home $6,740 for 1st Place with Anthony Scarborough from Mansfield ND runner up $4,350. Congratulations Mark on an out…', '2023-03-05 10:46:00', null, 'dakota-poker-tour-2022-23-angry-beaver-angry-beaver-main-event-01-28-2023', 'https://dakotapokertour.com/storage/article/thumb/20230305000249_IMG_6756-37eBVKOB.jpg', '/media/dpt/article/20230305000249_IMG_6756-37eBVKOB.jpg', null, '{"id":138,"title":"Mark Dufner Hole In One Champion $6,740","alias":"mark-dufner-hole-in-one-champion-6-740","excerpt":"Mark Dufner scored a big win in Oakes, ND outlasting Anthony Scarborough from Mansfield ND. Dufner, from Crookston MN took home $6,740 for 1st Place with Anthony Scarborough from Mansfield ND runner up $4,350. Congratulations Mark on an out…","content":"Mark Dufner scored a big win in Oakes, ND outlasting Anthony Scarborough from Mansfield ND. Dufner, from Crookston MN took home $6,740 for 1st Place with Anthony Scarborough from Mansfield ND runner up $4,350. Congratulations Mark on an outstanding tournament, and a big thank you to all the players who turned out for today''s event. Full results including updated POY leaderboard. 1st Place - Mark Dufner $6,740 Runner Up - Anthony Scarborough $4,350 3rd Place - Lee Bohling $3,175 4th Place - David McDonald $2,100 5th Place - Jeremy Thury $1,700 6th Place - Paul Johnson $1,350 7th Place - Jeremy Heinze $1,050 8th Place - Thomas Brimhall $820 9th Place - Randy Kleinsasser $640 10th Place - Curt Waldie $525 11th Place - Paul Awender $525 12th Place - Brandon Johnson $525 Big shoutout to our hosts at the Angry Beaver Lodge and the Hole in One Foundation. Thank you guys! Due to the winter storm weather threat, the Buffalo City Showdown was postponed until Saturday April 15th.","publishedAt":"2023-03-05 10:46:00","featured":true,"logo":"20230305000249_IMG_6756-37eBVKOB.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20230305000249_IMG_6756-37eBVKOB.jpg","bannerUrl":"","tournament":{"id":186,"name":"Hole in one Main Event","alias":"dakota-poker-tour-2022-23-angry-beaver-angry-beaver-main-event-01-28-2023"}}'::jsonb),
  (136, 'paul-johnson-grabs-chip-lead-in-oakes', 'Paul Johnson Grabs Chip Lead in Oakes', 'Paul Johnson made the correct call on the river to double up to 740k in chips with 11 players remaining.', '2023-03-04 21:48:00', null, 'dakota-poker-tour-2022-23-angry-beaver-angry-beaver-main-event-01-28-2023', 'https://dakotapokertour.com/storage/article/thumb/20230304_214632-k4WpnW9p.jpg', '/media/dpt/article/20230304_214632-k4WpnW9p.jpg', null, '{"id":136,"title":"Paul Johnson Grabs Chip Lead in Oakes","alias":"paul-johnson-grabs-chip-lead-in-oakes","excerpt":"Paul Johnson made the correct call on the river to double up to 740k in chips with 11 players remaining.","content":"Paul Johnson made the correct call on the river to double up to 740k in chips with 11 players remaining.","publishedAt":"2023-03-04 21:48:00","featured":false,"logo":"20230304_214632-k4WpnW9p.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20230304_214632-k4WpnW9p.jpg","bannerUrl":"","tournament":{"id":186,"name":"Hole in one Main Event","alias":"dakota-poker-tour-2022-23-angry-beaver-angry-beaver-main-event-01-28-2023"}}'::jsonb),
  (135, 'buffalo-city-showdown-postponed', 'Buffalo City Showdown POSTPONED', 'Forecast tomorrow has a Winter Storm Warning from 9am Sunday to Monday noon, with heavy snow and high wind in the forecast. The tournament will be moved to SATURDAY APRIL 15TH. Please spread the word!', '2023-03-04 20:57:00', null, null, '', '', null, '{"id":135,"title":"Buffalo City Showdown POSTPONED","alias":"buffalo-city-showdown-postponed","excerpt":"Forecast tomorrow has a Winter Storm Warning from 9am Sunday to Monday noon, with heavy snow and high wind in the forecast. The tournament will be moved to SATURDAY APRIL 15TH. Please spread the word!","content":"Forecast tomorrow has a Winter Storm Warning from 9am Sunday to Monday noon, with heavy snow and high wind in the forecast. The tournament will be moved to SATURDAY APRIL 15TH. Please spread the word!","publishedAt":"2023-03-04 20:57:00","featured":false,"logo":null,"banner":null,"videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":null,"name":null,"alias":null}}'::jsonb),
  (134, 'still-time-to-get-down-here', 'Still time to get down here', 'Lots of familiar face here at Hole-in-one tournament at the Angry Beaver here in Oaks ND. GET DOWN HERE first will be over 6k! We have 96 entries you still have 1.5 hrs to get here! (5:00)', '2023-03-04 15:28:00', null, 'dakota-poker-tour-2022-23-angry-beaver-angry-beaver-main-event-01-28-2023', 'https://dakotapokertour.com/storage/article/thumb/FD779374-D103-45EB-9C1C-C0BD1EE461ED-9b5wVgWY.jpg', '/media/dpt/article/FD779374-D103-45EB-9C1C-C0BD1EE461ED-9b5wVgWY.jpg', null, '{"id":134,"title":"Still time to get down here","alias":"still-time-to-get-down-here","excerpt":"Lots of familiar face here at Hole-in-one tournament at the Angry Beaver here in Oaks ND. GET DOWN HERE first will be over 6k! We have 96 entries you still have 1.5 hrs to get here! (5:00)","content":"Lots of familiar face here at Hole-in-one tournament at the Angry Beaver here in Oaks ND. GET DOWN HERE first will be over 6k! We have 96 entries you still have 1.5 hrs to get here! (5:00)","publishedAt":"2023-03-04 15:28:00","featured":false,"logo":"FD779374-D103-45EB-9C1C-C0BD1EE461ED-9b5wVgWY.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/FD779374-D103-45EB-9C1C-C0BD1EE461ED-9b5wVgWY.jpg","bannerUrl":"","tournament":{"id":186,"name":"Hole in one Main Event","alias":"dakota-poker-tour-2022-23-angry-beaver-angry-beaver-main-event-01-28-2023"}}'::jsonb),
  (133, 'great-turnout-in-oakes', 'Great Turnout in Oakes', 'Today''s Deepstack tournament in Oakes is underway with 10 tables to start! Currently 91 unique players and counting. Registration is open until approx 5pm. Plenty of time to get into the action.', '2023-03-04 13:35:00', null, 'dakota-poker-tour-2022-23-angry-beaver-angry-beaver-main-event-01-28-2023', 'https://dakotapokertour.com/storage/article/thumb/20230304_125736-xRwdRqUV.jpg', '/media/dpt/article/20230304_125736-xRwdRqUV.jpg', null, '{"id":133,"title":"Great Turnout in Oakes","alias":"great-turnout-in-oakes","excerpt":"Today''s Deepstack tournament in Oakes is underway with 10 tables to start! Currently 91 unique players and counting. Registration is open until approx 5pm. Plenty of time to get into the action.","content":"Today''s Deepstack tournament in Oakes is underway with 10 tables to start! Currently 91 unique players and counting. Registration is open until approx 5pm. Plenty of time to get into the action.","publishedAt":"2023-03-04 13:35:00","featured":true,"logo":"20230304_125736-xRwdRqUV.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20230304_125736-xRwdRqUV.jpg","bannerUrl":"","tournament":{"id":186,"name":"Hole in one Main Event","alias":"dakota-poker-tour-2022-23-angry-beaver-angry-beaver-main-event-01-28-2023"}}'::jsonb),
  (125, 'kyle-ryder-big-win-at-phat-stacks-6-731', 'Kyle Ryder Big Win at Phat Stacks $6,731', 'Kyle Ryder from Dickinson takes down Phat Stacks at the Phat Fish event for $6,731!! Robert Urbatsch runner up for $4,300. 1st Kyle Ryder $6,731 2nd Robert Urbatsch $4,300 3rd Neal Kukla $3,150 4th Beth Clyde $2,100 5th Joe Kessel $1,680 6t…', '2023-02-27 09:53:00', null, 'dakota-poker-tour-2022-23-phat-stacks-at-the-phat-fish-phat-stacks-at-the-phat-fish-02-26-2023', 'https://dakotapokertour.com/storage/article/thumb/333810060_655538176345039_5236354232912136494_n-lWjkgiB1.jpg', '/media/dpt/article/333810060_655538176345039_5236354232912136494_n-lWjkgiB1.jpg', null, '{"id":125,"title":"Kyle Ryder Big Win at Phat Stacks $6,731","alias":"kyle-ryder-big-win-at-phat-stacks-6-731","excerpt":"Kyle Ryder from Dickinson takes down Phat Stacks at the Phat Fish event for $6,731!! Robert Urbatsch runner up for $4,300. 1st Kyle Ryder $6,731 2nd Robert Urbatsch $4,300 3rd Neal Kukla $3,150 4th Beth Clyde $2,100 5th Joe Kessel $1,680 6t…","content":"Kyle Ryder from Dickinson takes down Phat Stacks at the Phat Fish event for $6,731!! Robert Urbatsch runner up for $4,300. 1st Kyle Ryder $6,731 2nd Robert Urbatsch $4,300 3rd Neal Kukla $3,150 4th Beth Clyde $2,100 5th Joe Kessel $1,680 6th Chad Kelsch $1,340 7th Bridget Zillich-Johnson $1,020 8th Dave Ouellette $800 9th Scott LaFond $640 10th Brandon Messer $525 11th Iggy Weigel $525 12th Kevin Clyde $525 This was an awesome event in conjunction with Roughrider Poker Tour , players receive points for each tour towards Player of The Year recognition. Next up for the DPT is Oakes and Jamestown events March 4th & 5th. Full live stream production will be setup in Oakes on Saturday for the Hole in Won Foundation''s Hole In One Tournament !","publishedAt":"2023-02-27 09:53:00","featured":true,"logo":"333810060_655538176345039_5236354232912136494_n-lWjkgiB1.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/artic