  (123, 'big-turnout-at-phat-fish', 'Big Turnout at Phat Fish', '92 unique players with registration still open in Dickinson for today''s deep stack tournament.', '2023-02-26 16:26:00', null, 'dakota-poker-tour-2022-23-phat-stacks-at-the-phat-fish-phat-stacks-at-the-phat-fish-02-26-2023', '', '', null, '{"id":123,"title":"Big Turnout at Phat Fish","alias":"big-turnout-at-phat-fish","excerpt":"92 unique players with registration still open in Dickinson for today''s deep stack tournament.","content":"92 unique players with registration still open in Dickinson for today''s deep stack tournament.","publishedAt":"2023-02-26 16:26:00","featured":true,"logo":null,"banner":null,"videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":193,"name":"Phat Stacks at the Phat Fish","alias":"dakota-poker-tour-2022-23-phat-stacks-at-the-phat-fish-phat-stacks-at-the-phat-fish-02-26-2023"}}'::jsonb),
  (122, 'ken-voight-buckskin-champ', 'Ken Voight Buckskin Champ', 'Ken Voigt is your Buckskin Shootout Main Event Champ $4,150. Congrats to Ken as this is his largest tournament cash. He looks forward to playing more! Todd Edmonson runner up $2,500 Congrats to the top 9 players who cashed and thanks to all…', '2023-02-12 11:56:00', null, 'dakota-poker-tour-2022-23-buckskin-shootout-bucksin-shootout-02-11-2023', 'https://dakotapokertour.com/storage/article/thumb/20230211230629_IMG_6462-Z1orQdxO.jpg', '/media/dpt/article/20230211230629_IMG_6462-Z1orQdxO.jpg', null, '{"id":122,"title":"Ken Voight Buckskin Champ","alias":"ken-voight-buckskin-champ","excerpt":"Ken Voigt is your Buckskin Shootout Main Event Champ $4,150. Congrats to Ken as this is his largest tournament cash. He looks forward to playing more! Todd Edmonson runner up $2,500 Congrats to the top 9 players who cashed and thanks to all…","content":"Ken Voigt is your Buckskin Shootout Main Event Champ $4,150. Congrats to Ken as this is his largest tournament cash. He looks forward to playing more! Todd Edmonson runner up $2,500 Congrats to the top 9 players who cashed and thanks to all the players who participated in this event and our awesome hosts at the Buckskin!","publishedAt":"2023-02-12 11:56:00","featured":true,"logo":"20230211230629_IMG_6462-Z1orQdxO.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20230211230629_IMG_6462-Z1orQdxO.jpg","bannerUrl":"","tournament":{"id":166,"name":"Buckskin Shootout MAIN EVENT","alias":"dakota-poker-tour-2022-23-buckskin-shootout-bucksin-shootout-02-11-2023"}}'::jsonb),
  (121, 'dinner-break', 'Dinner Break', 'We''ve reached the dinner break with 35 players remaining. Ryan Walker from Killdeer leads the way with over 250k in chips.', '2023-02-11 17:46:00', null, 'dakota-poker-tour-2022-23-buckskin-shootout-bucksin-shootout-02-11-2023', 'https://dakotapokertour.com/storage/article/thumb/20230211_164153-x2DJ4czC.jpg', '/media/dpt/article/20230211_164153-x2DJ4czC.jpg', null, '{"id":121,"title":"Dinner Break","alias":"dinner-break","excerpt":"We''ve reached the dinner break with 35 players remaining. Ryan Walker from Killdeer leads the way with over 250k in chips.","content":"We''ve reached the dinner break with 35 players remaining. Ryan Walker from Killdeer leads the way with over 250k in chips.","publishedAt":"2023-02-11 17:46:00","featured":true,"logo":"20230211_164153-x2DJ4czC.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20230211_164153-x2DJ4czC.jpg","bannerUrl":"","tournament":{"id":166,"name":"Buckskin Shootout MAIN EVENT","alias":"dakota-poker-tour-2022-23-buckskin-shootout-bucksin-shootout-02-11-2023"}}'::jsonb),
  (120, 'feature-table-live-stream-underway', 'Feature Table Live Stream Underway', 'Live Stream is available on YouTube. The following players are now seat at the Feature Table: Greg Nordsven-Killdeer Keith Berkner-Billings MT Justin Young Bird-Halliday Deb Gullickson-Hazen Jerry Pachl-Dickinson Nicholas Klatt-Killdeer Tod…', '2023-02-11 15:44:00', null, 'dakota-poker-tour-2022-23-buckskin-shootout-bucksin-shootout-02-11-2023', 'https://dakotapokertour.com/storage/article/thumb/20230211_144301-oePVcpYy.jpg', '/media/dpt/article/20230211_144301-oePVcpYy.jpg', null, '{"id":120,"title":"Feature Table Live Stream Underway","alias":"feature-table-live-stream-underway","excerpt":"Live Stream is available on YouTube. The following players are now seat at the Feature Table: Greg Nordsven-Killdeer Keith Berkner-Billings MT Justin Young Bird-Halliday Deb Gullickson-Hazen Jerry Pachl-Dickinson Nicholas Klatt-Killdeer Tod…","content":"Live Stream is available on YouTube. The following players are now seat at the Feature Table: Greg Nordsven-Killdeer Keith Berkner-Billings MT Justin Young Bird-Halliday Deb Gullickson-Hazen Jerry Pachl-Dickinson Nicholas Klatt-Killdeer Todd Edmondson-Killdeer Stanley Keller-Dodge Feature Table Live on YouTube","publishedAt":"2023-02-11 15:44:00","featured":true,"logo":"20230211_144301-oePVcpYy.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20230211_144301-oePVcpYy.jpg","bannerUrl":"","tournament":{"id":166,"name":"Buckskin Shootout MAIN EVENT","alias":"dakota-poker-tour-2022-23-buckskin-shootout-bucksin-shootout-02-11-2023"}}'::jsonb),
  (119, 'buckskin-shootout-underway', 'Buckskin Shootout Underway', 'Cards are in the air in Killdeer ND for the Buckskin Shootout. 46 players and counting first level. Stay tuned for live stream production later today.', '2023-02-11 13:48:00', null, 'dakota-poker-tour-2022-23-buckskin-shootout-bucksin-shootout-02-11-2023', 'https://dakotapokertour.com/storage/article/thumb/20230211_124554-Q5hDWJC2.jpg', '/media/dpt/article/20230211_124554-Q5hDWJC2.jpg', null, '{"id":119,"title":"Buckskin Shootout Underway","alias":"buckskin-shootout-underway","excerpt":"Cards are in the air in Killdeer ND for the Buckskin Shootout. 46 players and counting first level. Stay tuned for live stream production later today.","content":"Cards are in the air in Killdeer ND for the Buckskin Shootout. 46 players and counting first level. Stay tuned for live stream production later today.","publishedAt":"2023-02-11 13:48:00","featured":true,"logo":"20230211_124554-Q5hDWJC2.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20230211_124554-Q5hDWJC2.jpg","bannerUrl":"","tournament":{"id":166,"name":"Buckskin Shootout MAIN EVENT","alias":"dakota-poker-tour-2022-23-buckskin-shootout-bucksin-shootout-02-11-2023"}}'::jsonb),
  (118, 'mike-arnold-top-field-at-dead-money-winning-7-270', 'Mike Arnold Top Field at Dead Money Winning $7,270', 'Congrats to Mike Arnold from Fargo for taking down the Dead Money Open on Saturday at the M&J Saloon in West Fargo. Mike earned himself the title and $7,270 cash! Brady Zimmerman runner up $5,200 and Chad Stahl $3,100 for 3rd. The Top 18 ca…', '2023-01-29 10:31:00', null, 'dakota-poker-tour-2022-23-dead-money-open-dead-money-open-main-event-01-28-2023', 'https://dakotapokertour.com/storage/article/thumb/dead-money-open-champ-2023-Sk95dQzh.jpg', '/media/dpt/article/dead-money-open-champ-2023-Sk95dQzh.jpg', null, '{"id":118,"title":"Mike Arnold Top Field at Dead Money Winning $7,270","alias":"mike-arnold-top-field-at-dead-money-winning-7-270","excerpt":"Congrats to Mike Arnold from Fargo for taking down the Dead Money Open on Saturday at the M&J Saloon in West Fargo. Mike earned himself the title and $7,270 cash! Brady Zimmerman runner up $5,200 and Chad Stahl $3,100 for 3rd. The Top 18 ca…","content":"Congrats to Mike Arnold from Fargo for taking down the Dead Money Open on Saturday at the M&J Saloon in West Fargo. Mike earned himself the title and $7,270 cash! Brady Zimmerman runner up $5,200 and Chad Stahl $3,100 for 3rd. The Top 18 cashed in this tournament.","publishedAt":"2023-01-29 10:31:00","featured":true,"logo":"dead-money-open-champ-2023-Sk95dQzh.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/dead-money-open-champ-2023-Sk95dQzh.jpg","bannerUrl":"","tournament":{"id":180,"name":"Dead Money Open Main Event","alias":"dakota-poker-tour-2022-23-dead-money-open-dead-money-open-main-event-01-28-2023"}}'::jsonb),
  (117, 'down-to-3-tables', 'Down to 3 tables', 'We are down to 3 tables from the 126 players who started the day. Still lots of familiar faces. Excited to see who will take home $7200!', '2023-01-28 19:36:00', null, 'dakota-poker-tour-2022-23-dead-money-open-dead-money-open-main-event-01-28-2023', 'https://dakotapokertour.com/storage/article/thumb/199E8651-0849-476C-844F-FCA4C60DD9F3-RbZ83G3s.jpg', '/media/dpt/article/199E8651-0849-476C-844F-FCA4C60DD9F3-RbZ83G3s.jpg', null, '{"id":117,"title":"Down to 3 tables","alias":"down-to-3-tables","excerpt":"We are down to 3 tables from the 126 players who started the day. Still lots of familiar faces. Excited to see who will take home $7200!","content":"We are down to 3 tables from the 126 players who started the day. Still lots of familiar faces. Excited to see who will take home $7200!","publishedAt":"2023-01-28 19:36:00","featured":true,"logo":"199E8651-0849-476C-844F-FCA4C60DD9F3-RbZ83G3s.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/199E8651-0849-476C-844F-FCA4C60DD9F3-RbZ83G3s.jpg","bannerUrl":"","tournament":{"id":180,"name":"Dead Money Open Main Event","alias":"dakota-poker-tour-2022-23-dead-money-open-dead-money-open-main-event-01-28-2023"}}'::jsonb),
  (116, 'it-s-a-full-house', 'It’s a full house', 'It’s a full house!! Still plenty of time to join us (4:30pm) at the M&J! 125 players so far! $175 gets you 20k in chips, $325 gets you 50k.', '2023-01-28 15:15:00', null, 'dakota-poker-tour-2022-23-dead-money-open-dead-money-open-main-event-01-28-2023', 'https://dakotapokertour.com/storage/article/thumb/987E783A-51CC-47D7-AC0D-5D6A104EF5BD-cGfXN4ij.jpg', '/media/dpt/article/987E783A-51CC-47D7-AC0D-5D6A104EF5BD-cGfXN4ij.jpg', null, '{"id":116,"title":"It’s a full house","alias":"it-s-a-full-house","excerpt":"It’s a full house!! Still plenty of time to join us (4:30pm) at the M&J! 125 players so far! $175 gets you 20k in chips, $325 gets you 50k.","content":"It’s a full house!! Still plenty of time to join us (4:30pm) at the M&J! 125 players so far! $175 gets you 20k in chips, $325 gets you 50k.","publishedAt":"2023-01-28 15:15:00","featured":false,"logo":"987E783A-51CC-47D7-AC0D-5D6A104EF5BD-cGfXN4ij.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/987E783A-51CC-47D7-AC0D-5D6A104EF5BD-cGfXN4ij.jpg","bannerUrl":"","tournament":{"id":180,"name":"Dead Money Open Main Event","alias":"dakota-poker-tour-2022-23-dead-money-open-dead-money-open-main-event-01-28-2023"}}'::jsonb),
  (115, 'we-have-a-champion', 'Poker Brat Bounty Champ', 'Congratulations. Joshua Lanzdorf, Poker Brat Bounty Champion. Taking home $4180 for 1st place, plus earned $800 bounties along the way. Joshua has also secured his seat in the DPT Tournament of Champions! Congrats to runner up Warren Christ…', '2022-12-11 23:15:00', null, 'dakota-poker-tour-2022-23-poker-brat-bounty-tournament-poker-brat-bounty-tournament-12-11-2022', 'https://dakotapokertour.com/storage/article/thumb/7AF8C8AA-1515-493D-A8D6-5F8158CCE855-aeVIYIro.jpg', '/media/dpt/article/7AF8C8AA-1515-493D-A8D6-5F8158CCE855-aeVIYIro.jpg', null, '{"id":115,"title":"Poker Brat Bounty Champ","alias":"we-have-a-champion","excerpt":"Congratulations. Joshua Lanzdorf, Poker Brat Bounty Champion. Taking home $4180 for 1st place, plus earned $800 bounties along the way. Joshua has also secured his seat in the DPT Tournament of Champions! Congrats to runner up Warren Christ…","content":"Congratulations. Joshua Lanzdorf, Poker Brat Bounty Champion. Taking home $4180 for 1st place, plus earned $800 bounties along the way. Joshua has also secured his seat in the DPT Tournament of Champions! Congrats to runner up Warren Christensen and the rest of the players who cashed in this event: 1st $4180 Joshua Lanzdorf W. Fargo ND 2nd $2650 Warren Christensen Fargo ND 3rd $2000 Nathan Keifert W.Fargo ND 4th $1425 Bradley Craig Casselton ND 5th $1150 Heidi Roggenkamp Fargo ND 6th $1000 Chase Lardy Fargo ND 7th $800 Kevin Meyer Fargo ND 8th $600 Brayden Stoskopf Roesau MN 9th $450 Chris Pierce Fargo ND Thanks to everyone that came out and played today!","publishedAt":"2022-12-11 23:15:00","featured":true,"logo":"7AF8C8AA-1515-493D-A8D6-5F8158CCE855-aeVIYIro.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/7AF8C8AA-1515-493D-A8D6-5F8158CCE855-aeVIYIro.jpg","bannerUrl":"","tournament":{"id":155,"name":"Poker Brat Bounty Tournament","alias":"dakota-poker-tour-2022-23-poker-brat-bounty-tou