  (114, 'cards-are-in-the-air-2', 'Cards are in the air', 'Registration is open (4:30). Cards are in the air, 9 tables for the Black chip Bounty The Windbreak get $100 for every play you send home. Lots of familiar faces. Come have a beverage watch the Vikings and play some poker.', '2022-12-11 13:18:00', null, 'dakota-poker-tour-2022-23-poker-brat-bounty-tournament-poker-brat-bounty-tournament-12-11-2022', 'https://dakotapokertour.com/storage/article/thumb/EDD9DEFE-6962-4919-B14D-9DFFE1F82F2F-OrPLfKaM.jpg', '/media/dpt/article/EDD9DEFE-6962-4919-B14D-9DFFE1F82F2F-OrPLfKaM.jpg', null, '{"id":114,"title":"Cards are in the air","alias":"cards-are-in-the-air-2","excerpt":"Registration is open (4:30). Cards are in the air, 9 tables for the Black chip Bounty The Windbreak get $100 for every play you send home. Lots of familiar faces. Come have a beverage watch the Vikings and play some poker.","content":"Registration is open (4:30). Cards are in the air, 9 tables for the Black chip Bounty The Windbreak get $100 for every play you send home. Lots of familiar faces. Come have a beverage watch the Vikings and play some poker.","publishedAt":"2022-12-11 13:18:00","featured":false,"logo":"EDD9DEFE-6962-4919-B14D-9DFFE1F82F2F-OrPLfKaM.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/EDD9DEFE-6962-4919-B14D-9DFFE1F82F2F-OrPLfKaM.jpg","bannerUrl":"","tournament":{"id":155,"name":"Poker Brat Bounty Tournament","alias":"dakota-poker-tour-2022-23-poker-brat-bounty-tournament-poker-brat-bounty-tournament-12-11-2022"}}'::jsonb),
