  (111, 'there-is-still-time-to-get-down-here-2', 'There is still time to get down here!', 'Cards are in the air here at the Canad Inns Destination Centre Grand Forks Monster Stack! There is still time to get down here. Late registration open until 1:30! You can max buy for a 90k stack currently 51 players remain in the field aver…', '2022-12-04 12:32:00', null, 'dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022', 'https://dakotapokertour.com/storage/article/thumb/8C2119E5-EE30-4A20-8BD1-4E4F3E4AD8AB-p1AD0PJv.jpg', '/media/dpt/article/8C2119E5-EE30-4A20-8BD1-4E4F3E4AD8AB-p1AD0PJv.jpg', null, '{"id":111,"title":"There is still time to get down here!","alias":"there-is-still-time-to-get-down-here-2","excerpt":"Cards are in the air here at the Canad Inns Destination Centre Grand Forks Monster Stack! There is still time to get down here. Late registration open until 1:30! You can max buy for a 90k stack currently 51 players remain in the field aver…","content":"Cards are in the air here at the Canad Inns Destination Centre Grand Forks Monster Stack! There is still time to get down here. Late registration open until 1:30! You can max buy for a 90k stack currently 51 players remain in the field average chip stack is 168k","publishedAt":"2022-12-04 12:32:00","featured":true,"logo":"8C2119E5-EE30-4A20-8BD1-4E4F3E4AD8AB-p1AD0PJv.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/8C2119E5-EE30-4A20-8BD1-4E4F3E4AD8AB-p1AD0PJv.jpg","bannerUrl":"","tournament":{"id":139,"name":"Monster Stack Main Event","alias":"dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022"}}'::jsonb),
  (109, 'table-draw', 'Table Draw', 'Table draw for Sunday 12/4', '2022-12-03 23:34:00', null, 'dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022', 'https://dakotapokertour.com/storage/article/thumb/EB0F32A5-53C0-4167-A34E-0CD48898FC1E-xhYmSjtl.jpg', '/media/dpt/article/EB0F32A5-53C0-4167-A34E-0CD48898FC1E-xhYmSjtl.jpg', null, '{"id":109,"title":"Table Draw","alias":"table-draw","excerpt":"Table draw for Sunday 12/4","content":"Table draw for Sunday 12/4","publishedAt":"2022-12-03 23:34:00","featured":false,"logo":"EB0F32A5-53C0-4167-A34E-0CD48898FC1E-xhYmSjtl.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/EB0F32A5-53C0-4167-A34E-0CD48898FC1E-xhYmSjtl.jpg","bannerUrl":"","tournament":{"id":139,"name":"Monster Stack Main Event","alias":"dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022"}}'::jsonb),
  (108, 'bag-and-tag', 'Bag and tag!', 'After a long day of poker, we have bagged and tagged! 48 players returning tomorrow. Blinds will be 2k/4K ante 4k. Average chip stack 161,200. Still a lot of play. You can still enter until 1:30pm Sunday 12/4. With a full buyin you would ha…', '2022-12-03 23:28:00', null, 'dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022', 'https://dakotapokertour.com/storage/article/thumb/3DF16268-7DDD-4C53-AF5C-B8BF1963AD20-rTjfpTce.jpg', '/media/dpt/article/3DF16268-7DDD-4C53-AF5C-B8BF1963AD20-rTjfpTce.jpg', null, '{"id":108,"title":"Bag and tag!","alias":"bag-and-tag","excerpt":"After a long day of poker, we have bagged and tagged! 48 players returning tomorrow. Blinds will be 2k/4K ante 4k. Average chip stack 161,200. Still a lot of play. You can still enter until 1:30pm Sunday 12/4. With a full buyin you would ha…","content":"After a long day of poker, we have bagged and tagged! 48 players returning tomorrow. Blinds will be 2k/4K ante 4k. Average chip stack 161,200. Still a lot of play. You can still enter until 1:30pm Sunday 12/4. With a full buyin you would have 90k. Leading the pack going into tomorrow your chip leaders are Randy Hjelmstad 374,500 Joel Klipping 367,000 Wade Kyser 316,000","publishedAt":"2022-12-03 23:28:00","featured":false,"logo":"3DF16268-7DDD-4C53-AF5C-B8BF1963AD20-rTjfpTce.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/3DF16268-7DDD-4C53-AF5C-B8BF1963AD20-rTjfpTce.jpg","bannerUrl":"","tournament":{"id":139,"name":"Monster Stack Main Event","alias":"dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022"}}'::jsonb),
  (107, '10-tables', '10 tables!', 'Just after dinner break 10 tables, lots of familiar faces. Playing 13 levels tonight (approximately 9:45pm). Registration is OPEN until 1pm Sunday. We''ll on pace for a nice prize pool for our LIVE STREAM tomorrow!', '2022-12-03 18:18:00', null, 'dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022', 'https://dakotapokertour.com/storage/article/thumb/8E0C1E85-6D83-4876-AB2A-C509C96896D1-MHwz0l3K.jpg', '/media/dpt/article/8E0C1E85-6D83-4876-AB2A-C509C96896D1-MHwz0l3K.jpg', null, '{"id":107,"title":"10 tables!","alias":"10-tables","excerpt":"Just after dinner break 10 tables, lots of familiar faces. Playing 13 levels tonight (approximately 9:45pm). Registration is OPEN until 1pm Sunday. We''ll on pace for a nice prize pool for our LIVE STREAM tomorrow!","content":"Just after dinner break 10 tables, lots of familiar faces. Playing 13 levels tonight (approximately 9:45pm). Registration is OPEN until 1pm Sunday. We''ll on pace for a nice prize pool for our LIVE STREAM tomorrow!","publishedAt":"2022-12-03 18:18:00","featured":true,"logo":"8E0C1E85-6D83-4876-AB2A-C509C96896D1-MHwz0l3K.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/8E0C1E85-6D83-4876-AB2A-C509C96896D1-MHwz0l3K.jpg","bannerUrl":"","tournament":{"id":139,"name":"Monster Stack Main Event","alias":"dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022"}}'::jsonb),
  (106, 'cards-in-the-air-2', 'The Monster Stack is Underway', 'Monster Stack is underway here at the Canad Inn Grand Forks, with a nice starting field of 8 tables. Reigning champ Martin Short is here defending his title. $200 buy-in plus $25 dealer appreciation gets you 60,000 in chips. Add another $10…', '2022-12-03 13:01:00', null, 'dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022', 'https://dakotapokertour.com/storage/article/thumb/542AD094-FC26-4C4E-99F7-72BB93C55FD1-yQDa1xps.jpg', '/media/dpt/article/542AD094-FC26-4C4E-99F7-72BB93C55FD1-yQDa1xps.jpg', null, '{"id":106,"title":"The Monster Stack is Underway","alias":"cards-in-the-air-2","excerpt":"Monster Stack is underway here at the Canad Inn Grand Forks, with a nice starting field of 8 tables. Reigning champ Martin Short is here defending his title. $200 buy-in plus $25 dealer appreciation gets you 60,000 in chips. Add another $10…","content":"Monster Stack is underway here at the Canad Inn Grand Forks, with a nice starting field of 8 tables. Reigning champ Martin Short is here defending his title. $200 buy-in plus $25 dealer appreciation gets you 60,000 in chips. Add another $100 for a full buy-in with 90,000 chips. MONSTER STACK!","publishedAt":"2022-12-03 13:01:00","featured":true,"logo":"542AD094-FC26-4C4E-99F7-72BB93C55FD1-yQDa1xps.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/542AD094-FC26-4C4E-99F7-72BB93C55FD1-yQDa1xps.jpg","bannerUrl":"","tournament":{"id":139,"name":"Monster Stack Main Event","alias":"dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022"}}'::jsonb),
  (105, 'cards-in-the-air', 'Cards in the air', 'The lights are up and the cards in the air at Canad inn. Join us for satellite night $50 gets you 15,000 in chip. Late entry until 9pm. Currently 43 players.', '2022-12-02 19:53:00', null, 'dakota-poker-tour-season-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-super-satellite-12-02-2022', 'https://dakotapokertour.com/storage/article/thumb/55CAF153-F357-4844-AF77-E9EEA1D6961A-hv3CNnro.jpg', '/media/dpt/article/55CAF153-F357-4844-AF77-E9EEA1D6961A-hv3CNnro.jpg', null, '{"id":105,"title":"Cards in the air","alias":"cards-in-the-air","excerpt":"The lights are up and the cards in the air at Canad inn. Join us for satellite night $50 gets you 15,000 in chip. Late entry until 9pm. Currently 43 players.","content":"The lights are up and the cards in the air at Canad inn. Join us for satellite night $50 gets you 15,000 in chip. Late entry until 9pm. Currently 43 players.","publishedAt":"2022-12-02 19:53:00","featured":true,"logo":"55CAF153-F357-4844-AF77-E9EEA1D6961A-hv3CNnro.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/55CAF153-F357-4844-AF77-E9EEA1D6961A-hv3CNnro.jpg","bannerUrl":"","tournament":{"id":138,"name":"Monster Stack Super Satellite","alias":"dakota-poker-tour-season-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-super-satellite-12-02-2022"}}'::jsonb),
  (104, 'announcing-rpt-casino-state-championship', 'Announcing! RPT Casino State Championship', 'The RPT Casino State Championship at Spirit Lake Casino in Devils Lake is now an official event on the DPT Season 2022-2023! The DPT production crew will provide the full production LIVE STREAM, and yes, THIS tournament will COUNT towards D…', '2022-11-20 16:41:00', null, 'dakota-poker-tour-2022-23-rpt-casino-state-championship-rpt-casino-state-championship-main-event-12-30-2022', 'https://dakotapokertour.com/storage/article/thumb/RPT-Casino-State-Championship-1-WrXF7WZc.jpg', '/media/dpt/article/RPT-Casino-State-Championship-1-WrXF7WZc.jpg', null, '{"id":104,"title":"Announcing! RPT Casino State Championship","alias":"announcing-rpt-casino-state-championship","excerpt":"The RPT Casino State Championship at Spirit Lake Casino in Devils Lake is now an official event on the DPT Season 2022-2023! The DPT production crew will provide the full production LIVE STREAM, and yes, THIS tournament will COUNT towards D…","content":"The RPT Casino State Championship at Spirit Lake Casino in Devils Lake is now an official event on the DPT Season 2022-2023! The DPT production crew will provide the full production LIVE STREAM, and yes, THIS tournament will COUNT towards DPT and RPT Player of the Year points/rewards. You''re going to want to play in ND''s biggest field and largest prize pool of the year! Big shout out to Jerry Sorrells and the entire RPT crew for including the DPT in the year''s PREMIERE EVENT!","publishedAt":"2022-11-20 16:41:00","featured":true,"logo":"RPT-Casino-State-Championship-1-WrXF7WZc.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/RPT-Casino-State-Championship-1-WrXF7WZc.jpg","bannerUrl":"","tournament":{"id":174,"name":"RPT Casino State Championship Main Event","alias":"dakota-poker-tour-2022-23-rpt-casino-state-championship-rpt-casino-state-championship-main-event-12-30-2022"}}'::jsonb),
  (103, 'monster-stack-hype-video', 'Monster Stack HYPE Video', 'We''re getting pumped up for a return to the Canad Inn in Grand Forks for the MONSTER STACK. This 2-day structure gives players plenty of play. Last year''s winner Martin Short took home $7,750.', '2022-11-06 11:48:00', null, 'dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022', 'https://dakotapokertour.com/storage/article/thumb/Screenshot-2022-11-06-115404-nPka58fS.jpg', '/media/dpt/article/Screenshot-2022-11-06-115404-nPka58fS.jpg', 'https://youtu.be/HOg_K6pIDDM', '{"id":103,"title":"Monster Stack HYPE Video","alias":"monster-stack-hype-video","excerpt":"We''re getting pumped up for a return to the Canad Inn in Grand Forks for the MONSTER STACK. This 2-day structure gives players plenty of play. Last year''s winner Martin Short took home $7,750.","content":"We''re getting pumped up for a return to the Canad Inn in Grand Forks for the MONSTER STACK. This 2-day structure gives players plenty of play. Last year''s winner Martin Short took home $7,750.","publishedAt":"2022-11-06 11:48:00","featured":true,"logo":"Screenshot-2022-11-06-115404-nPka58fS.jpg","banner":null,"videoUrl":"https://youtu.be/HOg_K6pIDDM","imageUrl":"https://dakotapokertour.com/storage/article/thumb/Screenshot-2022-11-06-115404-nPka58fS.jpg","bannerUrl":"","tournament":{"id":139,"name":"Monster Stack Main Event","alias":"dakota-poker-tour-2022-23-l-i-s-t-e-n-inc-monster-stack-monster-stack-main-event-12-03-2022"}}'::jsonb),
  (102, 'tommy-hill-does-it-again', 'Tommy Hill does it again!', 'Tommy Hill has done it again! Tommy outlasted 88 players to win $5,140 at Casselton Vets Club. With the win, Tommy jumps into contention for the Player of the Year (POY) points race and also qualified for the end of 2022-2023 Season Tournam…', '2022-11-05 23:17:00', null, 'dakota-poker-tour-2022-23-casselton-vets-casselton-vets-deepstack-09-22-2022', 'https://dakotapokertour.com/storage/article/thumb/67BE9756-2F75-4240-9E77-BA4CEB346374-IKDDbuGC.jpg', '/media/dpt/article/67BE9756-2F75-4240-9E77-BA4CEB346374-IKDDbuGC.jpg', null, '{"id":102,"title":"Tommy Hill does it again!","alias":"tommy-hill-does-it-again","excerpt":"Tommy Hill has done it again! Tommy outlasted 88 players to win $5,140 at Casselton Vets Club. With the win, Tommy jumps into contention for the Player of the Year (POY) points race and also qualified for the end of 2022-2023 Season Tournam…","content":"Tommy Hill has done it again! Tommy outlasted 88 players to win $5,140 at Casselton Vets Club. With the win, Tommy jumps into contention for the Player of the Year (POY) points race and also qualified for the end of 2022-2023 Season Tournament of Champions. Congratulations as well to Duff Diseth for placing runner up $3,450 and the rest of the players who cashed: 1st $5140 Tommy Hill - West Fargo ND 2nd $3450 Donavan Diseth - Edmore ND 3rd $2500 Mike Estes - Coralville Iowa 4th $ Mitchel Haman - Fargo ND 5th $1500 Paul Johnson - Fargo ND 6th $1250 Nick Ingolfsland - Fargo ND 7th $950 Margaret Pomrenke - Brainerd MN 8th $750 Eric Beem - Gwinner ND 9th $600 Jeremy Heinze - Lisbon ND 10th $500 Timothy Sprague - Grand forks ND","publishedAt":"2022-11-05 23:17:00","featured":true,"logo":"67BE9756-2F75-4240-9E77-BA4CEB346374-IKDDbuGC.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/67BE9756-2F75-4240-9E77-BA4CEB346374-IKDDbuGC.jpg","bannerUrl":"","tournament":{"id":148,"name":"Casselton Vets Deepstack","alias":"dakota-poker-tour-2022-23-casselton-vets-casselton-vets-deepstack-09-22-2022"}}'::jsonb),
  (101, 'heads-up', 'Heads up', 'We are down to our final 2 players are Tommy Hill and Duff Diseth battling it out for a spot in the TOC!!', '2022-11-05 22:40:00', null, 'dakota-poker-tour-2022-23-casselton-vets-casselton-vets-deepstack-09-22-2022', 'https://dakotapokertour.com/storage/article/thumb/20221105_223932-BifwvchN.jpg', '/media/dpt/article/20221105_223932-BifwvchN.jpg', null, '{"id":101,"title":"Heads up","alias":"heads-up","excerpt":"We are down to our final 2 players are Tommy Hill and Duff Diseth battling it out for a spot in the TOC!!","content":"We are down to our final 2 players are Tommy Hill and Duff Diseth battling it out for a spot in the TOC!!","publishedAt":"2022-11-05 22:40:00","featured":false,"logo":"20221105_223932-BifwvchN.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20221105_223932-BifwvchN.jpg","bannerUrl":"","tournament":{"id":148,"name":"Casselton Vets Deepstack","alias":"dakota-poker-tour-2022-23-casselton-vets-casselton-vets-deepstack-09-22-2022"}}'::jsonb),
  (100, 'chip-leaders', 'Chip leaders', 'We have 11 players remaining our current chip leaders are Paul Johnson and Tommy Hill with 300k + in chips. Stay tuned for our winner list.', '2022-11-05 20:39:00', null, 'dakota-poker-tour-2022-23-casselton-vets-casselton-vets-deepstack-09-22-2022', 'https://dakotapokertour.com/storage/article/thumb/20221105_203546-Wih5ZMXl.jpg', '/media/dpt/article/20221105_203546-Wih5ZMXl.jpg', null, '{"id":100,"title":"Chip leaders","alias":"chip-leaders","excerpt":"We have 11 players remaining our current chip leaders are Paul Johnson and Tommy Hill with 300k + in chips. Stay tuned for our winner list.","content":"We have 11 players remaining our current chip leaders are Paul Johnson and Tommy Hill with 300k + in chips. Stay tuned for our winner list.","publishedAt":"2022-11-05 20:39:00","featured":false,"logo":"20221105_203546-Wih5ZMXl.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20221105_203546-Wih5ZMXl.jpg","bannerUrl":"","tournament":{"id":148,"name":"Casselton Vets Deepstack","alias":"dakota-poker-tour-2022-23-casselton-vets-casselton-vets-deepstack-09-22-2022"}}'::jsonb),
  (99, 'late-registration-still-open', 'Late Registration still open', 'Get down here!!! 9 Tables …. Registration open until 5:10 $175 gets you 20k in tournament chips, a full buy gets you 50k. Blinds are 1k/2k. Come win all the money 🤑', '2022-11-05 16:48:00', null, 'dakota-poker-tour-2022-23-casselton-vets-casselton-vets-deepstack-09-22-2022', 'https://dakotapokertour.com/storage/article/thumb/211C4058-348D-47E2-A785-01AACA7F1A5C-f5wsUnwm.jpg', '/media/dpt/article/211C4058-348D-47E2-A785-01AACA7F1A5C-f5wsUnwm.jpg', null, '{"id":99,"title":"Late Registration still open","alias":"late-registration-still-open","excerpt":"Get down here!!! 9 Tables …. Registration open until 5:10 $175 gets you 20k in tournament chips, a full buy gets you 50k. Blinds are 1k/2k. Come win all the money 🤑","content":"Get down here!!! 9 Tables …. Registration open until 5:10 $175 gets you 20k in tournament chips, a full buy gets you 50k. Blinds are 1k/2k. Come win all the money 🤑","publishedAt":"2022-11-05 16:48:00","featured":false,"logo":"211C4058-348D-47E2-A785-01AACA7F1A5C-f5wsUnwm.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/211C4058-348D-47E2-A785-01AACA7F1A5C-f5wsUnwm.jpg","bannerUrl":"","tournament":{"id":148,"name":"Casselton Vets Deepstack","alias":"dakota-poker-tour-2022-23-casselton-vets-casselton-vets-deepstack-09-22-2022"}}'::jsonb),
  (97, 'action-today', 'Action Today', 'There is action today! Bradley Craig flopped a royal flush and got paid!! Kramer is off to a early chip lead. Still lots of time to register! (5:00pm)', '2022-11-05 16:38:00', null, 'dakota-poker-tour-2022-23-casselton-vets-casselton-vets-deepstack-09-22-2022', 'https://dakotapokertour.com/storage/article/thumb/5DE6CE1A-E683-4A45-B0AA-A0A75566CC95-AYTWprzR.jpg', '/media/dpt/article/5DE6CE1A-E683-4A45-B0AA-A0A75566CC95-AYTWprzR.jpg', null, '{"id":97,"title":"Action Today","alias":"action-today","excerpt":"There is action today! Bradley Craig flopped a royal flush and got paid!! Kramer is off to a early chip lead. Still lots of time to register! (5:00pm)","content":"There is action today! Bradley Craig flopped a royal flush and got paid!! Kramer is off to a early chip lead. Still lots of time to register! (5:00pm)","publishedAt":"2022-11-05 16:38:00","featured":false,"logo":"5DE6CE1A-E683-4A45-B0AA-A0A75566CC95-AYTWprzR.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/5DE6CE1A-E683-4A45-B0AA-A0A75566CC95-AYTWprzR.jpg","bannerUrl":"","tournament":{"id":148,"name":"Casselton Vets Deepstack","alias":"dakota-poker-tour-2022-23-casselton-vets-casselton-vets-deepstack-09-22-2022"}}'::jsonb),
  (96, 'dustyn-huber-earns-win-at-mandan-eagles', 'Dustyn Huber Earns Win at Mandan Eagles', 'Dustyn Huber outlasted Tyson Maxon and Ryan Sorenson to win the tournament and take home $4,000 cash. With the win, Dustyn took home the Trophy and earned a seat in the season ending Tournament of Champions, a freeroll event which awards a…', '2022-10-14 12:15:00', null, 'dakota-poker-tour-2022-23-mandan-eagles-mandan-eagles-dpt-deepstack-10-08-2022', 'https://dakotapokertour.com/storage/article/thumb/Screenshot-2022-10-14-122121-nP7FbVJU.jpg', '/media/dpt/article/Screenshot-2022-10-14-122121-nP7FbVJU.jpg', 'https://youtu.be/O49vN1Rk4fo', '{"id":96,"title":"Dustyn Huber Earns Win at Mandan Eagles","alias":"dustyn-huber-earns-win-at-mandan-eagles","excerpt":"Dustyn Huber outlasted Tyson Maxon and Ryan Sorenson to win the tournament and take home $4,000 cash. With the win, Dustyn took home the Trophy and earned a seat in the season ending Tournament of Champions, a freeroll event which awards a…","content":"Dustyn Huber outlasted Tyson Maxon and Ryan Sorenson to win the tournament and take home $4,000 cash. With the win, Dustyn took home the Trophy and earned a seat in the season ending Tournament of Champions, a freeroll event which awards a $1,500 Poker Package to the winner. Huber earned enough points to jump to 3rd place on the Player of the Year Points Race currently.","publishedAt":"2022-10-14 12:15:00","featured":true,"logo":"Screenshot-2022-10-14-122121-nP7FbVJU.jpg","banner":null,"videoUrl":"https://youtu.be/O49vN1Rk4fo","imageUrl":"https://dakotapokertour.com/storage/article/thumb/Screenshot-2022-10-14-122121-nP7FbVJU.jpg","bannerUrl":"","tournament":{"id":130,"name":"Mandan Eagles DPT Deepstack","alias":"dakota-poker-tour-2022-23-mandan-eagles-mandan-eagles-dpt-deepstack-10-08-2022"}}'::jsonb),
  (95, 'live-stream-follows-after-dinner-break', 'Live Stream Follows After Dinner Break', 'We''ll crank up the live stream following the break.', '2022-10-08 15:42:00', null, 'dakota-poker-tour-2022-23-mandan-eagles-mandan-eagles-dpt-deepstack-10-08-2022', 'https://dakotapokertour.com/storage/article/thumb/fa222f74-345b-46f8-8992-a33c1934d650-RJkuWujp.jpg', '/media/dpt/article/fa222f74-345b-46f8-8992-a33c1934d650-RJkuWujp.jpg', null, '{"id":95,"title":"Live Stream Follows After Dinner Break","alias":"live-stream-follows-after-dinner-break","excerpt":"We''ll crank up the live stream following the break.","content":"We''ll crank up the live stream following the break.","publishedAt":"2022-10-08 15:42:00","featured":true,"logo":"fa222f74-345b-46f8-8992-a33c1934d650-RJkuWujp.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/fa222f74-345b-46f8-8992-a33c1934d650-RJkuWujp.jpg","bannerUrl":"","tournament":{"id":130,"name":"Mandan Eagles DPT Deepstack","alias":"dakota-poker-tour-2022-23-mandan-eagles-mandan-eagles-dpt-deepstack-10-08-2022"}}'::jsonb),
  (94, '50-players-and-counting', '50 Players and Counting', 'Building a prize pool, early on with 50 players. Come on out and get in the action!', '2022-10-08 13:15:00', null, 'dakota-poker-tour-2022-23-mandan-eagles-mandan-eagles-dpt-deepstack-10-08-2022', 'https://dakotapokertour.com/storage/article/thumb/20221008_130402-7vhhF2bh.jpg', '/media/dpt/article/20221008_130402-7vhhF2bh.jpg', null, '{"id":94,"title":"50 Players and Counting","alias":"50-players-and-counting","excerpt":"Building a prize pool, early on with 50 players. Come on out and get in the action!","content":"Building a prize pool, early on with 50 players. Come on out and get in the action!","publishedAt":"2022-10-08 13:15:00","featured":false,"logo":"20221008_130402-7vhhF2bh.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20221008_130402-7vhhF2bh.jpg","bannerUrl":"","tournament":{"id":130,"name":"Mandan Eagles DPT Deepstack","alias":"dakota-poker-tour-2022-23-mandan-eagles-mandan-eagles-dpt-deepstack-10-08-2022"}}'::jsonb),
  (93, 'today-s-dpt-deepstack-is-underway', 'Today''s DPT Deepstack Is Underway', 'Dana has announced "Cards in the air!" We have a deep structure for today''s tournament, Registration open until approx 5pm.', '2022-10-08 12:05:00', null, 'dakota-poker-tour-2022-23-mandan-eagles-mandan-eagles-dpt-deepstack-10-08-2022', 'https://dakotapokertour.com/storage/article/thumb/16652488850273720979211254261633-Bzl9Xxuv.jpg', '/media/dpt/article/16652488850273720979211254261633-Bzl9Xxuv.jpg', null, '{"id":93,"title":"Today''s DPT Deepstack Is Underway","alias":"today-s-dpt-deepstack-is-underway","excerpt":"Dana has announced \"Cards in the air!\" We have a deep structure for today''s tournament, Registration open until approx 5pm.","content":"Dana has announced \"Cards in the air!\" We have a deep structure for today''s tournament, Registration open until approx 5pm.","publishedAt":"2022-10-08 12:05:00","featured":true,"logo":"16652488850273720979211254261633-Bzl9Xxuv.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/16652488850273720979211254261633-Bzl9Xxuv.jpg","bannerUrl":"","tournament":{"id":130,"name":"Mandan Eagles DPT Deepstack","alias":"dakota-poker-tour-2022-23-mandan-eagles-mandan-eagles-dpt-deepstack-10-08-2022"}}'::jsonb),
  (91, 'getting-hyped-for-the-mandan-eagles-event', 'Getting HYPED for the Mandan Eagles Event', 'We''re getting pumped up for some poker action this weekend at the Mandan Eagles. Check out the Hype Video . We warm up the weekend with a Super Satellite on Friday night at 7pm. The Super Satellite is a fun and cheap way to get in to Saturd…', '2022-10-05 14:37:00', null, null, '', '', 'https://youtu.be/ngAeadlFafw', '{"id":91,"title":"Getting HYPED for the Mandan Eagles Event","alias":"getting-hyped-for-the-mandan-eagles-event","excerpt":"We''re getting pumped up for some poker action this weekend at the Mandan Eagles. Check out the Hype Video . We warm up the weekend with a Super Satellite on Friday night at 7pm. The Super Satellite is a fun and cheap way to get in to Saturd…","content":"We''re getting pumped up for some poker action this weekend at the Mandan Eagles. Check out the Hype Video . We warm up the weekend with a Super Satellite on Friday night at 7pm. The Super Satellite is a fun and cheap way to get in to Saturday''s main deepstack tournament starting at Noon. If you want a shot at completely freerolling this event, head on over to the Bismarck Amvets for their FPN poker league at 7pm, take it down and earn a certificate for a Super Satellite seat.","publishedAt":"2022-10-05 14:37:00","featured":true,"logo":null,"banner":null,"videoUrl":"https://youtu.be/ngAeadlFafw","imageUrl":"","bannerUrl":"","tournament":{"id":null,"name":null,"alias":null}}'::jsonb),
  (90, 'hagges-prize-pool-just-shy-of-30-000', 'Hagges Prize Pool Just Shy of $30,000', 'Registration just closed at today''s deepstack tournament at Hagges in Mapelton. 130 unique players generated a prize pool of $29,765. 1st $7735 2nd $4990 3rd. $3280￼ 4th. $2530 5th. $1860 6th. $1490 7th $1190 8th $940 9th $740 10th-12th $64…', '2022-09-17 17:29:00', null, 'dakota-poker-tour-2022-23-season-2022-2023-kickoff-season-2022-23-kickoff-tournament-09-17-2022', 'https://dakotapokertour.com/storage/article/thumb/306326411_587066880087061_4878308994051190655_n-PavSXOnJ.jpg', '/media/dpt/article/306326411_587066880087061_4878308994051190655_n-PavSXOnJ.jpg', null, '{"id":90,"title":"Hagges Prize Pool Just Shy of $30,000","alias":"hagges-prize-pool-just-shy-of-30-000","excerpt":"Registration just closed at today''s deepstack tournament at Hagges in Mapelton. 130 unique players generated a prize pool of $29,765. 1st $7735 2nd $4990 3rd. $3280￼ 4th. $2530 5th. $1860 6th. $1490 7th $1190 8th $940 9th $740 10th-12th $64…","content":"Registration just closed at today''s deepstack tournament at Hagges in Mapelton. 130 unique players generated a prize pool of $29,765. 1st $7735 2nd $4990 3rd. $3280￼ 4th. $2530 5th. $1860 6th. $1490 7th $1190 8th $940 9th $740 10th-12th $640 13th-15th $550 16th-18th $480","publishedAt":"2022-09-17 17:29:00","featured":true,"logo":"306326411_587066880087061_4878308994051190655_n-PavSXOnJ.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/306326411_587066880087061_4878308994051190655_n-PavSXOnJ.jpg","bannerUrl":"","tournament":{"id":112,"name":"Season 2022-23 Kickoff Tournament","alias":"dakota-poker-tour-2022-23-season-2022-2023-kickoff-season-2022-23-kickoff-tournament-09-17-2022"}}'::jsonb),
  (89, 'prize-pool-growing-at-hagges', 'Prize Pool Growing at Hagges', '126 Players and a growing prize pool at Hagges for today''s deepstack event. Still time to get in to the action, registration open until approx 5pm.', '2022-09-17 15:27:00', null, 'dakota-poker-tour-2022-23-season-2022-2023-kickoff-season-2022-23-kickoff-tournament-09-17-2022', 'https://dakotapokertour.com/storage/article/thumb/hagges-9-17-22-345pm-rSpwH7AC.jpg', '/media/dpt/article/hagges-9-17-22-345pm-rSpwH7AC.jpg', null, '{"id":89,"title":"Prize Pool Growing at Hagges","alias":"prize-pool-growing-at-hagges","excerpt":"126 Players and a growing prize pool at Hagges for today''s deepstack event. Still time to get in to the action, registration open until approx 5pm.","content":"126 Players and a growing prize pool at Hagges for today''s deepstack event. Still time to get in to the action, registration open until approx 5pm.","publishedAt":"2022-09-17 15:27:00","featured":true,"logo":"hagges-9-17-22-345pm-rSpwH7AC.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/hagges-9-17-22-345pm-rSpwH7AC.jpg","bannerUrl":"","tournament":{"id":112,"name":"Season 2022-23 Kickoff Tournament","alias":"dakota-poker-tour-2022-23-season-2022-2023-kickoff-season-2022-23-kickoff-tournament-09-17-2022"}}'::jsonb),
  (88, 'registration-open', 'Registration Open', 'We just kicked off our first Main Event for the 2022-23 Kick off. We are currently at 10 tables, late registration is open through Level 8 approximately dinner time. We have plenty of seats avaliable.', '2022-09-17 12:30:00', null, 'dakota-poker-tour-2022-23-season-2022-2023-kickoff-season-2022-23-kickoff-tournament-09-17-2022', 'https://dakotapokertour.com/storage/article/thumb/20220917_121949-eMuOnles.jpg', '/media/dpt/article/20220917_121949-eMuOnles.jpg', null, '{"id":88,"title":"Registration Open","alias":"registration-open","excerpt":"We just kicked off our first Main Event for the 2022-23 Kick off. We are currently at 10 tables, late registration is open through Level 8 approximately dinner time. We have plenty of seats avaliable.","content":"We just kicked off our first Main Event for the 2022-23 Kick off. We are currently at 10 tables, late registration is open through Level 8 approximately dinner time. We have plenty of seats avaliable.","publishedAt":"2022-09-17 12:30:00","featured":false,"logo":"20220917_121949-eMuOnles.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20220917_121949-eMuOnles.jpg","bannerUrl":"","tournament":{"id":112,"name":"Season 2022-23 Kickoff Tournament","alias":"dakota-poker-tour-2022-23-season-2022-2023-kickoff-season-2022-23-kickoff-tournament-09-17-2022"}}'::jsonb),
  (87, 'satellite-qualifier-concluded', 'Satellite Qualifier Concluded', 'Want to thank all the card players that made it out to our first satellite qualifier 2022-23 Kickoff. We had 59 players register and top 15 qualified for Saturdays Main Event. Final 4 $300 Winners Cory Biloki Robert Robley Scott Thomas Joel…', '2022-09-17 03:57:00', null, 'dakota-poker-tour-2022-23-season-2022-2023-kickoff-hagge-s-super-satellite-2022-23-kickoff-event-09-16-2022', 'https://dakotapokertour.com/storage/article/thumb/20220917_010117-knSAj9d0.jpg', '/media/dpt/article/20220917_010117-knSAj9d0.jpg', null, '{"id":87,"title":"Satellite Qualifier Concluded","alias":"satellite-qualifier-concluded","excerpt":"Want to thank all the card players that made it out to our first satellite qualifier 2022-23 Kickoff. We had 59 players register and top 15 qualified for Saturdays Main Event. Final 4 $300 Winners Cory Biloki Robert Robley Scott Thomas Joel…","content":"Want to thank all the card players that made it out to our first satellite qualifier 2022-23 Kickoff. We had 59 players register and top 15 qualified for Saturdays Main Event. Final 4 $300 Winners Cory Biloki Robert Robley Scott Thomas Joel Smith 11 $150 Winners Tom Keeping Thomas Hughey Lester Hauglid Justin Cole Christopher Frank Rod Rusenau Tanner Larson Cody Slusher Paul Johnson Chase Lardy Lio Meza $80 Bubble Winner Everett Mattison","publishedAt":"2022-09-17 03:57:00","featured":true,"logo":"20220917_010117-knSAj9d0.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20220917_010117-knSAj9d0.jpg","bannerUrl":"","tournament":{"id":113,"name":"Hagge''s Super Satellite 2022-23 Kickoff Event","alias":"dakota-poker-tour-2022-23-season-2022-2023-kickoff-hagge-s-super-satellite-2022-23-kickoff-event-09-16-2022"}}'::jsonb),
  (85, 'all-in-action', 'All in action!!!', 'All in action! Flopped a royal flush draw, turned a straight flush draw... but wait the 4 wins on the river', '2022-09-16 23:54:00', null, 'dakota-poker-tour-2022-23-season-2022-2023-kickoff-hagge-s-super-satellite-2022-23-kickoff-event-09-16-2022', 'https://dakotapokertour.com/storage/article/thumb/12AB3E88-DC1D-4BCE-9414-1CD9FCDB4C6E-HMptV7ZT.jpg', '/media/dpt/article/12AB3E88-DC1D-4BCE-9414-1CD9FCDB4C6E-HMptV7ZT.jpg', null, '{"id":85,"title":"All in action!!!","alias":"all-in-action","excerpt":"All in action! Flopped a royal flush draw, turned a straight flush draw... but wait the 4 wins on the river","content":"All in action! Flopped a royal flush draw, turned a straight flush draw... but wait the 4 wins on the river","publishedAt":"2022-09-16 23:54:00","featured":false,"logo":"12AB3E88-DC1D-4BCE-9414-1CD9FCDB4C6E-HMptV7ZT.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/12AB3E88-DC1D-4BCE-9414-1CD9FCDB4C6E-HMptV7ZT.jpg","bannerUrl":"","tournament":{"id":113,"name":"Hagge''s Super Satellite 2022-23 Kickoff Event","alias":"dakota-poker-tour-2022-23-season-2022-2023-kickoff-hagge-s-super-satellite-2022-23-kickoff-event-09-16-2022"}}'::jsonb),
  (84, 'registration-closed-and-payouts-announced', 'Registration Closed and Payouts Announced', 'Top 16 will earn seats in tonight''s Super Satellite. 1st thru 4th - $300 4th thru 15th - $150 16th - $80', '2022-09-16 22:45:00', null, 'dakota-poker-tour-2022-23-season-2022-2023-kickoff-hagge-s-super-satellite-2022-23-kickoff-event-09-16-2022', 'https://dakotapokertour.com/storage/article/thumb/a4bc0fca-d1bc-436a-b9cb-d695fda812fb-XO2B92IZ.jpg', '/media/dpt/article/a4bc0fca-d1bc-436a-b9cb-d695fda812fb-XO2B92IZ.jpg', null, '{"id":84,"title":"Registration Closed and Payouts Announced","alias":"registration-closed-and-payouts-announced","excerpt":"Top 16 will earn seats in tonight''s Super Satellite. 1st thru 4th - $300 4th thru 15th - $150 16th - $80","content":"Top 16 will earn seats in tonight''s Super Satellite. 1st thru 4th - $300 4th thru 15th - $150 16th - $80","publishedAt":"2022-09-16 22:45:00","featured":true,"logo":"a4bc0fca-d1bc-436a-b9cb-d695fda812fb-XO2B92IZ.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/a4bc0fca-d1bc-436a-b9cb-d695fda812fb-XO2B92IZ.jpg","bannerUrl":"","tournament":{"id":113,"name":"Hagge''s Super Satellite 2022-23 Kickoff Event","alias":"dakota-poker-tour-2022-23-season-2022-2023-kickoff-hagge-s-super-satellite-2022-23-kickoff-event-09-16-2022"}}'::jsonb),
  (83, 'the-dpt-returns-officially-tonight-at-hagge-s', 'The DPT Returns Officially TONIGHT at Hagge''s', 'Tonight we kickoff a new season of the DPT at Hagge''s in Mapleton with a Super Satellite tournament $35 plus $5 suggested dealer appreciation, 10,000 starting chips. Play well and you''ll earn either a $300 or $150 DPT Seat. Cards in the air…', '2022-09-16 18:34:00', null, 'dakota-poker-tour-2022-23-season-2022-2023-kickoff-hagge-s-super-satellite-2022-23-kickoff-event-09-16-2022', 'https://dakotapokertour.com/storage/article/thumb/DPT-hagges-9-16-22-tcB0fET4.jpg', '/media/dpt/article/DPT-hagges-9-16-22-tcB0fET4.jpg', null, '{"id":83,"title":"The DPT Returns Officially TONIGHT at Hagge''s","alias":"the-dpt-returns-officially-tonight-at-hagge-s","excerpt":"Tonight we kickoff a new season of the DPT at Hagge''s in Mapleton with a Super Satellite tournament $35 plus $5 suggested dealer appreciation, 10,000 starting chips. Play well and you''ll earn either a $300 or $150 DPT Seat. Cards in the air…","content":"Tonight we kickoff a new season of the DPT at Hagge''s in Mapleton with a Super Satellite tournament $35 plus $5 suggested dealer appreciation, 10,000 starting chips. Play well and you''ll earn either a $300 or $150 DPT Seat. Cards in the air at 7pm, registration open until around 930pm. Let''s go!","publishedAt":"2022-09-16 18:34:00","featured":true,"logo":"DPT-hagges-9-16-22-tcB0fET4.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/DPT-hagges-9-16-22-tcB0fET4.jpg","bannerUrl":"","tournament":{"id":113,"name":"Hagge''s Super Satellite 2022-23 Kickoff Event","alias":"dakota-poker-tour-2022-23-season-2022-2023-kickoff-hagge-s-super-satellite-2022-23-kickoff-event-09-16-2022"}}'::jsonb),
  (82, 'multiple-freeroll-qualifiers-coming-up', 'Multiple Freeroll Qualifiers Coming Up!', 'Click here to browse multiple DPT Freeroll Bonus Seats qualifiers from sponsoring bars in the area. Note, players earn points towards DPT Player of the Year for these freeroll bonus opportunities.', '2022-09-03 11:28:00', null, 'dakota-poker-tour-2022-23-season-2022-2023-kickoff-hagge-s-super-satellite-2022-23-kickoff-event-09-16-2022', 'https://dakotapokertour.com/storage/article/thumb/785A6764-web-fwSfrMT2.jpg', '/media/dpt/article/785A6764-web-fwSfrMT2.jpg', 'https://youtu.be/MEaWfsl8a80', '{"id":82,"title":"Multiple Freeroll Qualifiers Coming Up!","alias":"multiple-freeroll-qualifiers-coming-up","excerpt":"Click here to browse multiple DPT Freeroll Bonus Seats qualifiers from sponsoring bars in the area. Note, players earn points towards DPT Player of the Year for these freeroll bonus opportunities.","content":"Click here to browse multiple DPT Freeroll Bonus Seats qualifiers from sponsoring bars in the area. Note, players earn points towards DPT Player of the Year for these freeroll bonus opportunities.","publishedAt":"2022-09-03 11:28:00","featured":true,"logo":"785A6764-web-fwSfrMT2.jpg","banner":null,"videoUrl":"https://youtu.be/MEaWfsl8a80","imageUrl":"https://dakotapokertour.com/storage/article/thumb/785A6764-web-fwSfrMT2.jpg","bannerUrl":"","tournament":{"id":113,"name":"Hagge''s Super Satellite 2022-23 Kickoff Event","alias":"dakota-poker-tour-2022-23-season-2022-2023-kickoff-hagge-s-super-satellite-2022-23-kickoff-event-09-16-2022"}}'::jsonb),
  (81, 'brian-twete-wins-1-500-poker-package-in-player-appreciation-freeroll', 'Brian Twete Wins $1,500 Poker Package in Player Appreciation Freeroll', 'Brian Twete from Northwood ND earned a DPT title this season by taking down the Eagle Eye tournament in Valley City back in April. He earned a seat in today''s TOC and finished in 5th Place. Twete had things to do back home and announced on…', '2022-05-22 21:46:00', null, 'dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-player-appreciation-freeroll-05-22-2022', 'https://dakotapokertour.com/storage/article/thumb/20220522_204008-NFpWqKa6.jpg', '/media/dpt/article/20220522_204008-NFpWqKa6.jpg', null, '{"id":81,"title":"Brian Twete Wins $1,500 Poker Package in Player Appreciation Freeroll","alias":"brian-twete-wins-1-500-poker-package-in-player-appreciation-freeroll","excerpt":"Brian Twete from Northwood ND earned a DPT title this season by taking down the Eagle Eye tournament in Valley City back in April. He earned a seat in today''s TOC and finished in 5th Place. Twete had things to do back home and announced on…","content":"Brian Twete from Northwood ND earned a DPT title this season by taking down the Eagle Eye tournament in Valley City back in April. He earned a seat in today''s TOC and finished in 5th Place. Twete had things to do back home and announced on the very first hand of his table that he was going all in on the first hand. Go big or go home... Michelle Meza looked down at AK and called Twete''s all in. But Twete ended up knocking out Michelle and doubling up his chips. So he decided at that point he might as well play it out! And that he did. Twete cruised all day with a big stack and went on to defeat Tony Uhlir headsup to capture the $1,500 Poker Package award and another trophy. Twete is excited to use the $1,500 towards an upcoming World Series of Poker event in June. Good luck Brian and congrats!","publishedAt":"2022-05-22 21:46:00","featured":true,"logo":"20220522_204008-NFpWqKa6.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20220522_204008-NFpWqKa6.jpg","bannerUrl":"","tournament":{"id":30,"name":"DPT Season XI Player Appreciation Freeroll","alias":"dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-player-appreciation-freeroll-05-22-2022"}}'::jsonb),
  (80, 'martin-short-captures-toc-title', 'Martin Short Captures TOC Title', 'Martin Short from Grand Forks took down today''s Season XI Bonus TOC, winning a $1500 poker package and ALMOST enough points to reclaim Player of the Year honors. Martin will use his $1,500 poker package towards an event in Las Vegas in earl…', '2022-05-22 19:47:00', null, 'dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-tournament-of-champions-05-22-2022', 'https://dakotapokertour.com/storage/article/thumb/20220522133445_IMG_5149-c6xbzXHB.jpg', '/media/dpt/article/20220522133445_IMG_5149-c6xbzXHB.jpg', null, '{"id":80,"title":"Martin Short Captures TOC Title","alias":"martin-short-captures-toc-title","excerpt":"Martin Short from Grand Forks took down today''s Season XI Bonus TOC, winning a $1500 poker package and ALMOST enough points to reclaim Player of the Year honors. Martin will use his $1,500 poker package towards an event in Las Vegas in earl…","content":"Martin Short from Grand Forks took down today''s Season XI Bonus TOC, winning a $1500 poker package and ALMOST enough points to reclaim Player of the Year honors. Martin will use his $1,500 poker package towards an event in Las Vegas in early June.","publishedAt":"2022-05-22 19:47:00","featured":true,"logo":"20220522133445_IMG_5149-c6xbzXHB.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20220522133445_IMG_5149-c6xbzXHB.jpg","bannerUrl":"","tournament":{"id":29,"name":"DPT Season XI Tournament of Champions","alias":"dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-tournament-of-champions-05-22-2022"}}'::jsonb),
  (79, 'satya-vegi-doubles-up-to-stay-alive', 'Satya Vegi doubles up to stay alive', 'Martin Short wity a big lead when Satya moved in preflop and Martin called.. K-deuce offsuit for Satya vs Ad6d for Martin. Satya flopped a k8ng right away and turned a deuce to double up and stay alive. Martin 650k Satya 150llk Play continu…', '2022-05-22 15:16:00', null, 'dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-tournament-of-champions-05-22-2022', 'https://dakotapokertour.com/storage/article/thumb/20220522_151518-KLb7YYal.jpg', '/media/dpt/article/20220522_151518-KLb7YYal.jpg', null, '{"id":79,"title":"Satya Vegi doubles up to stay alive","alias":"satya-vegi-doubles-up-to-stay-alive","excerpt":"Martin Short wity a big lead when Satya moved in preflop and Martin called.. K-deuce offsuit for Satya vs Ad6d for Martin. Satya flopped a k8ng right away and turned a deuce to double up and stay alive. Martin 650k Satya 150llk Play continu…","content":"Martin Short wity a big lead when Satya moved in preflop and Martin called.. K-deuce offsuit for Satya vs Ad6d for Martin. Satya flopped a k8ng right away and turned a deuce to double up and stay alive. Martin 650k Satya 150llk Play continues..","publishedAt":"2022-05-22 15:16:00","featured":false,"logo":"20220522_151518-KLb7YYal.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20220522_151518-KLb7YYal.jpg","bannerUrl":"","tournament":{"id":29,"name":"DPT Season XI Tournament of Champions","alias":"dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-tournament-of-champions-05-22-2022"}}'::jsonb),
  (78, 'headsup-satya-vegi-and-martin-short', 'Headsup Satya Vegi and  Martin Short', 'Martin Short and Satya Vegi are headsup on tye feature table in our Tournament of Champions. Nick Ing9lfsland took 3rd and received a $150 buyin certificate to use towards a seat in the next season.', '2022-05-22 14:50:00', null, 'dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-tournament-of-champions-05-22-2022', 'https://dakotapokertour.com/storage/article/thumb/20220522_144600-yBkF6eZM.jpg', '/media/dpt/article/20220522_144600-yBkF6eZM.jpg', null, '{"id":78,"title":"Headsup Satya Vegi and  Martin Short","alias":"headsup-satya-vegi-and-martin-short","excerpt":"Martin Short and Satya Vegi are headsup on tye feature table in our Tournament of Champions. Nick Ing9lfsland took 3rd and received a $150 buyin certificate to use towards a seat in the next season.","content":"Martin Short and Satya Vegi are headsup on tye feature table in our Tournament of Champions. Nick Ing9lfsland took 3rd and received a $150 buyin certificate to use towards a seat in the next season.","publishedAt":"2022-05-22 14:50:00","featured":true,"logo":"20220522_144600-yBkF6eZM.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20220522_144600-yBkF6eZM.jpg","bannerUrl":"","tournament":{"id":29,"name":"DPT Season XI Tournament of Champions","alias":"dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-tournament-of-champions-05-22-2022"}}'::jsonb),
  (77, 'john-wendlick-busts', 'John Wendlick Busts', 'Our Phat Fish Champion is first to bust in today''s TOC.', '2022-05-22 12:24:00', null, 'dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-tournament-of-champions-05-22-2022', '', '', null, '{"id":77,"title":"John Wendlick Busts","alias":"john-wendlick-busts","excerpt":"Our Phat Fish Champion is first to bust in today''s TOC.","content":"Our Phat Fish Champion is first to bust in today''s TOC.","publishedAt":"2022-05-22 12:24:00","featured":false,"logo":null,"banner":null,"videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":29,"name":"DPT Season XI Tournament of Champions","alias":"dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-tournament-of-champions-05-22-2022"}}'::jsonb),
  (76, 'toc-underway', 'TOC Underway', 'Cards are in the air at Bar Nine in West Fargo for the Season XI Tournament of Champions. 1st place will earn bragging rights and a $1,500 Poker Package. Runner up will receive a $300 buy in certificates and 3rd place $150 towards entry in…', '2022-05-22 12:12:00', null, 'dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-tournament-of-champions-05-22-2022', 'https://dakotapokertour.com/storage/article/thumb/20220522_120612-g0huYoLL.jpg', '/media/dpt/article/20220522_120612-g0huYoLL.jpg', null, '{"id":76,"title":"TOC Underway","alias":"toc-underway","excerpt":"Cards are in the air at Bar Nine in West Fargo for the Season XI Tournament of Champions. 1st place will earn bragging rights and a $1,500 Poker Package. Runner up will receive a $300 buy in certificates and 3rd place $150 towards entry in…","content":"Cards are in the air at Bar Nine in West Fargo for the Season XI Tournament of Champions. 1st place will earn bragging rights and a $1,500 Poker Package. Runner up will receive a $300 buy in certificates and 3rd place $150 towards entry in any tournament next season. Note, this event also counts toward Player of the Year points. Value of the prize, plus points according to the FPN points system.","publishedAt":"2022-05-22 12:12:00","featured":true,"logo":"20220522_120612-g0huYoLL.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/20220522_120612-g0huYoLL.jpg","bannerUrl":"","tournament":{"id":29,"name":"DPT Season XI Tournament of Champions","alias":"dakota-poker-tour-season-xi-dpt-season-xi-championship-dpt-season-xi-tournament-of-champions-05-22-2022"}}'::jsonb),
  (74, 'keith-tiny-from-hawaii-kemper-bounty-champ', 'Keith \"Tiny from Hawaii\" Kemper Bounty Champ', 'Tiny from Hawaii was the last player to register today, and the last player remaining. Tiny also captured 7 bounties en route to his title and now joins the exclusive list of DPT champs for the upcoming Tournament of Champions. First place…', '2022-05-01 23:12:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-bounty-tournament-05-01-2022', 'https://dakotapokertour.com/storage/article/thumb/qMq2mEa8P9LDBIDCD3QaDW6nVcQcbG6rDhuFgTqN.jpg', '/media/dpt/article/qMq2mEa8P9LDBIDCD3QaDW6nVcQcbG6rDhuFgTqN.jpg', null, '{"id":74,"title":"Keith \\\"Tiny from Hawaii\\\" Kemper Bounty Champ","alias":"keith-tiny-from-hawaii-kemper-bounty-champ","excerpt":"Tiny from Hawaii was the last player to register today, and the last player remaining. Tiny also captured 7 bounties en route to his title and now joins the exclusive list of DPT champs for the upcoming Tournament of Champions. First place…","content":"Tiny from Hawaii was the last player to register today, and the last player remaining. Tiny also captured 7 bounties en route to his title and now joins the exclusive list of DPT champs for the upcoming Tournament of Champions. First place was $4,310 pluls $700 in bounties for over $5,000 payday!!! Bob \"The Professor\" Sylskar was your runner up for $2,700 plus $400 in bounties.","publishedAt":"2022-05-01 23:12:00","featured":true,"logo":"qMq2mEa8P9LDBIDCD3QaDW6nVcQcbG6rDhuFgTqN.jpg","banner":"","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/qMq2mEa8P9LDBIDCD3QaDW6nVcQcbG6rDhuFgTqN.jpg","bannerUrl":"","tournament":{"id":99,"name":"Bounty Tournament","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-bounty-tournament-05-01-2022"}}'::jsonb),
  (73, 'note-bounties-will-be-included-for-points', 'Note! Bounties will be included for points', 'Quick note to let everyone know, the bounty awards are not currently showing up in the points, but will be added later. Bounties will count towards POY points.', '2022-05-01 22:28:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-bounty-tournament-05-01-2022', '', '', null, '{"id":73,"title":"Note! Bounties will be included for points","alias":"note-bounties-will-be-included-for-points","excerpt":"Quick note to let everyone know, the bounty awards are not currently showing up in the points, but will be added later. Bounties will count towards POY points.","content":"Quick note to let everyone know, the bounty awards are not currently showing up in the points, but will be added later. Bounties will count towards POY points.","publishedAt":"2022-05-01 22:28:00","featured":false,"logo":null,"banner":null,"videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":99,"name":"Bounty Tournament","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-bounty-tournament-05-01-2022"}}'::jsonb),
  (71, 'bounty-tourney-registration-closed', 'Bounty Tourney - Registration Closed', 'Back from the dinner, payouts have been finalized. Witu 94 players, After the $9400 in bounties, there is $14,530 remaining prize pool. Alex Knudsen has collected 5 bounties so far.', '2022-05-01 17:53:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-bounty-tournament-05-01-2022', 'https://dakotapokertour.com/storage/article/thumb/Dxf6EkgJNa5qHKBWksyw5qzRYMnO66OXXAvgYmxt.jpg', '/media/dpt/article/Dxf6EkgJNa5qHKBWksyw5qzRYMnO66OXXAvgYmxt.jpg', null, '{"id":71,"title":"Bounty Tourney - Registration Closed","alias":"bounty-tourney-registration-closed","excerpt":"Back from the dinner, payouts have been finalized. Witu 94 players, After the $9400 in bounties, there is $14,530 remaining prize pool. Alex Knudsen has collected 5 bounties so far.","content":"Back from the dinner, payouts have been finalized. Witu 94 players, After the $9400 in bounties, there is $14,530 remaining prize pool. Alex Knudsen has collected 5 bounties so far.","publishedAt":"2022-05-01 17:53:00","featured":true,"logo":"Dxf6EkgJNa5qHKBWksyw5qzRYMnO66OXXAvgYmxt.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Dxf6EkgJNa5qHKBWksyw5qzRYMnO66OXXAvgYmxt.jpg","bannerUrl":"","tournament":{"id":99,"name":"Bounty Tournament","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-bounty-tournament-05-01-2022"}}'::jsonb),
  (70, 'gary-ewald-first-player-to-collect-2-bounties', 'Gary Ewald first player to collect 2 bounties', 'Gary Ewald is tye player to collect a 2nd Bounty!', '2022-05-01 14:02:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-bounty-tournament-05-01-2022', 'https://dakotapokertour.com/storage/article/thumb/TxPHwHVPsvLbm1MyTyR1vWk1ucxfgfr8Jo0xxrvz.jpg', '/media/dpt/article/TxPHwHVPsvLbm1MyTyR1vWk1ucxfgfr8Jo0xxrvz.jpg', null, '{"id":70,"title":"Gary Ewald first player to collect 2 bounties","alias":"gary-ewald-first-player-to-collect-2-bounties","excerpt":"Gary Ewald is tye player to collect a 2nd Bounty!","content":"Gary Ewald is tye player to collect a 2nd Bounty!","publishedAt":"2022-05-01 14:02:00","featured":false,"logo":"TxPHwHVPsvLbm1MyTyR1vWk1ucxfgfr8Jo0xxrvz.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/TxPHwHVPsvLbm1MyTyR1vWk1ucxfgfr8Jo0xxrvz.jpg","bannerUrl":"","tournament":{"id":99,"name":"Bounty Tournament","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-bounty-tournament-05-01-2022"}}'::jsonb),
  (69, 'justin-smith-earns-first-bounty', 'Justin Smith Earns First Bounty', 'Justin Smith knocked out Chase Lardy to capture the first $100 bounty in today''s tournament. We have just under 90 players registered and over $20,000 in the prize pool already. Registration closes around 430-500pm, still plenty of time to…', '2022-05-01 13:39:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-bounty-tournament-05-01-2022', 'https://dakotapokertour.com/storage/article/thumb/fET9OW2LHW0N7CDz6RjtGrrB1crRq8omU3B1NfoG.jpg', '/media/dpt/article/fET9OW2LHW0N7CDz6RjtGrrB1crRq8omU3B1NfoG.jpg', null, '{"id":69,"title":"Justin Smith Earns First Bounty","alias":"justin-smith-earns-first-bounty","excerpt":"Justin Smith knocked out Chase Lardy to capture the first $100 bounty in today''s tournament. We have just under 90 players registered and over $20,000 in the prize pool already. Registration closes around 430-500pm, still plenty of time to…","content":"Justin Smith knocked out Chase Lardy to capture the first $100 bounty in today''s tournament. We have just under 90 players registered and over $20,000 in the prize pool already. Registration closes around 430-500pm, still plenty of time to enter.","publishedAt":"2022-05-01 13:39:00","featured":true,"logo":"fET9OW2LHW0N7CDz6RjtGrrB1crRq8omU3B1NfoG.jpg","banner":"","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/fET9OW2LHW0N7CDz6RjtGrrB1crRq8omU3B1NfoG.jpg","bannerUrl":"","tournament":{"id":99,"name":"Bounty Tournament","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-bounty-tournament-05-01-2022"}}'::jsonb),
  (72, 'nick-ingolfsland-captures-speedway-title-and-11-230', 'Nick Ingolfsland Captures Speedway Title and $11,230', 'Nick Ingolfsland picked a great time to make his first appearance of the season, taking down a DPT-record 170 player single-day tournament field at the Speedway Event Center for $11,230. The final table featured several players in the hunt…', '2022-04-30 23:45:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-speedway-full-throttle-poker-open-main-event-04-30-2022', 'https://dakotapokertour.com/storage/article/thumb/7tZLogByOahmriURAe4DoGTbrsbdE8UAFmyvxoWN.jpg', '/media/dpt/article/7tZLogByOahmriURAe4DoGTbrsbdE8UAFmyvxoWN.jpg', null, '{"id":72,"title":"Nick Ingolfsland Captures Speedway Title and $11,230","alias":"nick-ingolfsland-captures-speedway-title-and-11-230","excerpt":"Nick Ingolfsland picked a great time to make his first appearance of the season, taking down a DPT-record 170 player single-day tournament field at the Speedway Event Center for $11,230. The final table featured several players in the hunt…","content":"When we got headsup it was Nick and Awesome Basim, with Nick flopping a full house to put Basim away. With the big win, Nick catapulted out of nowhere to challenge for Player of the Year status, but Basim''s 2nd place $7,250 cash put him on top. Sunday''s Bounty Tournament now becomes very interesting in terms of the point race. But no matter what happens on Sunday, players should know that the Player Appreciation Freeroll and and Tournament of Champions events will COUNT towards POY status as well. Those freeroll bonus tournaments will award points using the FPN points structure, which awards points to approximately the top 30% of the field.","publishedAt":"2022-04-30 23:45:00","featured":true,"logo":"7tZLogByOahmriURAe4DoGTbrsbdE8UAFmyvxoWN.jpg","banner":"","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/7tZLogByOahmriURAe4DoGTbrsbdE8UAFmyvxoWN.jpg","bannerUrl":"","tournament":{"id":26,"name":"Speedway Full Throttle Poker Open Main Event","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-speedway-full-throttle-poker-open-main-event-04-30-2022"}}'::jsonb),
  (68, 'all-set-for-the-final-table', 'All set for the FINAL TABLE', 'GETTING READY FOR THE FINAL TABLE Nick Ingolfsland Ashly Hafdahl Everett Mattison Wade Kyser Jeremy Holms Awesome Basim Erik Kimble Steve "Fred" Twete Leo Yao', '2022-04-30 22:19:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-speedway-full-throttle-poker-open-main-event-04-30-2022', 'https://dakotapokertour.com/storage/article/thumb/0l1wcBawchyLQju5MsAWlvLp3FExViDUxDSl8aUB.jpg', '/media/dpt/article/0l1wcBawchyLQju5MsAWlvLp3FExViDUxDSl8aUB.jpg', null, '{"id":68,"title":"All set for the FINAL TABLE","alias":"all-set-for-the-final-table","excerpt":"GETTING READY FOR THE FINAL TABLE Nick Ingolfsland Ashly Hafdahl Everett Mattison Wade Kyser Jeremy Holms Awesome Basim Erik Kimble Steve \"Fred\" Twete Leo Yao","content":"GETTING READY FOR THE FINAL TABLE Nick Ingolfsland Ashly Hafdahl Everett Mattison Wade Kyser Jeremy Holms Awesome Basim Erik Kimble Steve \"Fred\" Twete Leo Yao","publishedAt":"2022-04-30 22:19:00","featured":false,"logo":"0l1wcBawchyLQju5MsAWlvLp3FExViDUxDSl8aUB.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/0l1wcBawchyLQju5MsAWlvLp3FExViDUxDSl8aUB.jpg","bannerUrl":"","tournament":{"id":26,"name":"Speedway Full Throttle Poker Open Main Event","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-speedway-full-throttle-poker-open-main-event-04-30-2022"}}'::jsonb),
  (66, 'wade-kyser-takes-chip-lead', 'Wade Kyser Takes Chip Lead', 'Wade Kyser from Erie, ND doubled up to around 800k in a big hand with Kim Rasmussen. Brian Banish from West Fargo has a big staco as well, around 500k. Ashly Hafdahl, winner if the Windbreak event earlier this season is also making a nice r…', '2022-04-30 20:03:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-speedway-full-throttle-poker-open-main-event-04-30-2022', 'https://dakotapokertour.com/storage/article/thumb/Fykg81EM2ZaIcWuaIomy5pLBMmcr94yt5fv5Q3mw.jpg', '/media/dpt/article/Fykg81EM2ZaIcWuaIomy5pLBMmcr94yt5fv5Q3mw.jpg', null, '{"id":66,"title":"Wade Kyser Takes Chip Lead","alias":"wade-kyser-takes-chip-lead","excerpt":"Wade Kyser from Erie, ND doubled up to around 800k in a big hand with Kim Rasmussen. Brian Banish from West Fargo has a big staco as well, around 500k. Ashly Hafdahl, winner if the Windbreak event earlier this season is also making a nice r…","content":"Wade Kyser from Erie, ND doubled up to around 800k in a big hand with Kim Rasmussen. Brian Banish from West Fargo has a big staco as well, around 500k. Ashly Hafdahl, winner if the Windbreak event earlier this season is also making a nice run in this tournament and recently got moved to the feature table with about 167k. Chris Hanson had a nice day going but suffered a collapse and is now out of the tournament. We look forward to his comments...","publishedAt":"2022-04-30 20:03:00","featured":true,"logo":"Fykg81EM2ZaIcWuaIomy5pLBMmcr94yt5fv5Q3mw.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Fykg81EM2ZaIcWuaIomy5pLBMmcr94yt5fv5Q3mw.jpg","bannerUrl":"","tournament":{"id":26,"name":"Speedway Full Throttle Poker Open Main Event","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-speedway-full-throttle-poker-open-main-event-04-30-2022"}}'::jsonb),
  (65, 'prize-pool-climbing-at-speedway', 'Prize Pool Climbing at Speedway', 'We have a great turnout here today for the Full Throttle Poker Open Main Event at the Speedway, with 163 unique players registered and counting. About an hour away from the dinner break, we are expecting to exceed $40,000 prize pool, and a…', '2022-04-30 15:26:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-speedway-full-throttle-poker-open-main-event-04-30-2022', 'https://dakotapokertour.com/storage/article/thumb/P231gS8ab0miLqQFLbFcv5crAUlEYEa4uI9jJBOe.jpg', '/media/dpt/article/P231gS8ab0miLqQFLbFcv5crAUlEYEa4uI9jJBOe.jpg', null, '{"id":65,"title":"Prize Pool Climbing at Speedway","alias":"prize-pool-climbing-at-speedway","excerpt":"We have a great turnout here today for the Full Throttle Poker Open Main Event at the Speedway, with 163 unique players registered and counting. About an hour away from the dinner break, we are expecting to exceed $40,000 prize pool, and a…","content":"We have a great turnout here today for the Full Throttle Poker Open Main Event at the Speedway, with 163 unique players registered and counting. About an hour away from the dinner break, we are expecting to exceed $40,000 prize pool, and a $10,000+ first place prize. Live Stream Feature Table is available on Youtube. Stay tuned for updates!","publishedAt":"2022-04-30 15:26:00","featured":true,"logo":"P231gS8ab0miLqQFLbFcv5crAUlEYEa4uI9jJBOe.jpg","banner":"","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/P231gS8ab0miLqQFLbFcv5crAUlEYEa4uI9jJBOe.jpg","bannerUrl":"","tournament":{"id":26,"name":"Speedway Full Throttle Poker Open Main Event","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-speedway-full-throttle-poker-open-main-event-04-30-2022"}}'::jsonb),
  (64, '28-players-earn-seats', '28 Players Earn Seats', '126 players turned out for Super Satellite night, plus single table satellites brought the total qualifier count up to 31 players for entries to the remaining tournaments this weekend. Visit the tournament results to see the list of winners…', '2022-04-30 00:27:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-full-throttle-poker-open-super-satellite-04-29-2022', 'https://dakotapokertour.com/storage/article/thumb/lLLbeBS6LVk4t9zBc9ixxOSCSgc37ftT0yXymq1D.jpg', '/media/dpt/article/lLLbeBS6LVk4t9zBc9ixxOSCSgc37ftT0yXymq1D.jpg', null, '{"id":64,"title":"28 Players Earn Seats","alias":"28-players-earn-seats","excerpt":"126 players turned out for Super Satellite night, plus single table satellites brought the total qualifier count up to 31 players for entries to the remaining tournaments this weekend. Visit the tournament results to see the list of winners…","content":"126 players turned out for Super Satellite night, plus single table satellites brought the total qualifier count up to 31 players for entries to the remaining tournaments this weekend. Visit the tournament results to see the list of winners!","publishedAt":"2022-04-30 00:27:00","featured":true,"logo":"lLLbeBS6LVk4t9zBc9ixxOSCSgc37ftT0yXymq1D.jpg","banner":"","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/lLLbeBS6LVk4t9zBc9ixxOSCSgc37ftT0yXymq1D.jpg","bannerUrl":"","tournament":{"id":25,"name":"Full Throttle Poker Open *Super Satellite*","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-full-throttle-poker-open-super-satellite-04-29-2022"}}'::jsonb),
  (63, 'satellite-night-underway-with-big-turnout', 'Satellite Night Underway with Big Turnout', 'We have at least 126 players for tonight''s Super Satellite. Registration still open and there will also be Single Table Satellites (9 handed) $40 buy in, 1st $200 seat, 2nd and 3rd Money back.', '2022-04-29 20:35:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-full-throttle-poker-open-super-satellite-04-29-2022', 'https://dakotapokertour.com/storage/article/thumb/dO1nqNfTVyMfGvd9IG8F0PkquBf15tVEv6gH4AA0.jpg', '/media/dpt/article/dO1nqNfTVyMfGvd9IG8F0PkquBf15tVEv6gH4AA0.jpg', null, '{"id":63,"title":"Satellite Night Underway with Big Turnout","alias":"satellite-night-underway-with-big-turnout","excerpt":"We have at least 126 players for tonight''s Super Satellite. Registration still open and there will also be Single Table Satellites (9 handed) $40 buy in, 1st $200 seat, 2nd and 3rd Money back.","content":"We have at least 126 players for tonight''s Super Satellite. Registration still open and there will also be Single Table Satellites (9 handed) $40 buy in, 1st $200 seat, 2nd and 3rd Money back.","publishedAt":"2022-04-29 20:35:00","featured":true,"logo":"dO1nqNfTVyMfGvd9IG8F0PkquBf15tVEv6gH4AA0.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/dO1nqNfTVyMfGvd9IG8F0PkquBf15tVEv6gH4AA0.jpg","bannerUrl":"","tournament":{"id":25,"name":"Full Throttle Poker Open *Super Satellite*","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-full-throttle-poker-open-super-satellite-04-29-2022"}}'::jsonb),
  (62, 'getting-ready-for-tonight-s-super-satellite', 'Getting Ready for Tonight''s Super Satellite', 'We''re ready for a fun weekend of poker! Join us starting tonight at 7pm for Friday Super Satellite night. Buy in is only $35+5 and you can win a $200 DPT Seat for either Saturday or Sunday''s events.', '2022-04-29 13:14:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-full-throttle-poker-open-super-satellite-04-29-2022', 'https://dakotapokertour.com/storage/article/thumb/gfSEvZYvHRFVPrkEhgXbgPqIyHVzQGyLNBEtE8Bq.jpg', '/media/dpt/article/gfSEvZYvHRFVPrkEhgXbgPqIyHVzQGyLNBEtE8Bq.jpg', null, '{"id":62,"title":"Getting Ready for Tonight''s Super Satellite","alias":"getting-ready-for-tonight-s-super-satellite","excerpt":"We''re ready for a fun weekend of poker! Join us starting tonight at 7pm for Friday Super Satellite night. Buy in is only $35+5 and you can win a $200 DPT Seat for either Saturday or Sunday''s events.","content":"We''re ready for a fun weekend of poker! Join us starting tonight at 7pm for Friday Super Satellite night. Buy in is only $35+5 and you can win a $200 DPT Seat for either Saturday or Sunday''s events.","publishedAt":"2022-04-29 13:14:00","featured":true,"logo":"gfSEvZYvHRFVPrkEhgXbgPqIyHVzQGyLNBEtE8Bq.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/gfSEvZYvHRFVPrkEhgXbgPqIyHVzQGyLNBEtE8Bq.jpg","bannerUrl":"","tournament":{"id":25,"name":"Full Throttle Poker Open *Super Satellite*","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-full-throttle-poker-open-super-satellite-04-29-2022"}}'::jsonb),
  (59, 'congrats-to-mick-alm-for-taking-down-the-tournament', 'Congrats to Mick Alm for taking down the tournament', 'Congrats Mick!', '2022-04-21 16:12:00', null, 'dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-freeroll-at-bar-nine-04-07-2022', 'https://dakotapokertour.com/storage/article/thumb/7WnkcQ62tpTrh019PR2hML9EuimJI9tnd7IKd9Pu.jpg', '/media/dpt/article/7WnkcQ62tpTrh019PR2hML9EuimJI9tnd7IKd9Pu.jpg', null, '{"id":59,"title":"Congrats to Mick Alm for taking down the tournament","alias":"congrats-to-mick-alm-for-taking-down-the-tournament","excerpt":"Congrats Mick!","content":"Congrats Mick!","publishedAt":"2022-04-21 16:12:00","featured":false,"logo":"7WnkcQ62tpTrh019PR2hML9EuimJI9tnd7IKd9Pu.jpg","banner":"","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/7WnkcQ62tpTrh019PR2hML9EuimJI9tnd7IKd9Pu.jpg","bannerUrl":"","tournament":{"id":31,"name":"FREEROLL @ Bar Nine","alias":"dakota-poker-tour-season-xi-speedway-full-throttle-poker-open-freeroll-at-bar-nine-04-07-2022"}}'::jsonb),
  (58, 'congratulations-brian-twete-valley-city-eagles', 'Congratulations Brian Twete Valley City Eagles', 'After a 2+ hour heads up battle, congratulations to our winner Brian Twete from Northwood ND taking home $3660. Brian will also be invited to compete in the tournament of champions. 1st $3660 Brian Twete Northwood ND 2nd $2320 John Stearns…', '2022-04-17 00:51:00', null, 'dakota-poker-tour-season-xi-eagle-eye-eagle-eye-04-16-2022', 'https://dakotapokertour.com/storage/article/thumb/AKz7Wr9B3QO4NUxwH7vLLJ6m78gE4xw2vHqdr8UR.jpg', '/media/dpt/article/AKz7Wr9B3QO4NUxwH7vLLJ6m78gE4xw2vHqdr8UR.jpg', null, '{"id":58,"title":"Congratulations Brian Twete Valley City Eagles","alias":"congratulations-brian-twete-valley-city-eagles","excerpt":"After a 2+ hour heads up battle, congratulations to our winner Brian Twete from Northwood ND taking home $3660. Brian will also be invited to compete in the tournament of champions. 1st $3660 Brian Twete Northwood ND 2nd $2320 John Stearns…","content":"After a 2+ hour heads up battle, congratulations to our winner Brian Twete from Northwood ND taking home $3660. Brian will also be invited to compete in the tournament of champions. 1st $3660 Brian Twete Northwood ND 2nd $2320 John Stearns Valley City ND 3rd $1830 Sudipta Das West Fargo ND 4th $1465 Robert Larson Cooperstown ND 5th $1100 Steve Fuglestad Hope ND 6th $970 Chad Weldon Mandan ND 7th $860 Bryan Kriewald Valley City ND","publishedAt":"2022-04-17 00:51:00","featured":true,"logo":"AKz7Wr9B3QO4NUxwH7vLLJ6m78gE4xw2vHqdr8UR.jpg","banner":"","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/AKz7Wr9B3QO4NUxwH7vLLJ6m78gE4xw2vHqdr8UR.jpg","bannerUrl":"","tournament":{"id":18,"name":"Eagle Eye","alias":"dakota-poker-tour-season-xi-eagle-eye-eagle-eye-04-16-2022"}}'::jsonb),
  (57, 'registration-closed-at-valley-city-eagles', 'Registration closed at Valley City Eagles', 'Registration has closed. 56 players generating a prize pool of $12,000. Current chip leaders are Roddy Gentzkow 217K. Tim Gienger 214K and Awesome Basim Habib 163K. 1st $3660 2nd $2320 3rd $1830 4th $1465 5th $1100 6th $970 7th $860', '2022-04-16 18:01:00', null, 'dakota-poker-tour-season-xi-eagle-eye-eagle-eye-04-16-2022', 'https://dakotapokertour.com/storage/article/thumb/URAISobLlvNMwSoXsqDTJax93JDytDMHAoMzPTKu.jpg', '/media/dpt/article/URAISobLlvNMwSoXsqDTJax93JDytDMHAoMzPTKu.jpg', null, '{"id":57,"title":"Registration closed at Valley City Eagles","alias":"registration-closed-at-valley-city-eagles","excerpt":"Registration has closed. 56 players generating a prize pool of $12,000. Current chip leaders are Roddy Gentzkow 217K. Tim Gienger 214K and Awesome Basim Habib 163K. 1st $3660 2nd $2320 3rd $1830 4th $1465 5th $1100 6th $970 7th $860","content":"Registration has closed. 56 players generating a prize pool of $12,000. Current chip leaders are Roddy Gentzkow 217K. Tim Gienger 214K and Awesome Basim Habib 163K. 1st $3660 2nd $2320 3rd $1830 4th $1465 5th $1100 6th $970 7th $860","publishedAt":"2022-04-16 18:01:00","featured":false,"logo":"URAISobLlvNMwSoXsqDTJax93JDytDMHAoMzPTKu.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/URAISobLlvNMwSoXsqDTJax93JDytDMHAoMzPTKu.jpg","bannerUrl":"","tournament":{"id":18,"name":"Eagle Eye","alias":"dakota-poker-tour-season-xi-eagle-eye-eagle-eye-04-16-2022"}}'::jsonb),
  (56, 'cards-are-in-the-air', 'Cards are in the air!', 'Cards are in the air! There is still 2 hours of late registration available. $150 gets you 20k in chips, $300 gets you $50k in chips. Currently 6 tables, 1st place should be close to $4000!', '2022-04-16 14:20:00', null, 'dakota-poker-tour-season-xi-eagle-eye-eagle-eye-04-16-2022', 'https://dakotapokertour.com/storage/article/thumb/jzQb65sdDO1tDY5dQNTKWECeu625Qp8zPGubS1M5.jpg', '/media/dpt/article/jzQb65sdDO1tDY5dQNTKWECeu625Qp8zPGubS1M5.jpg', null, '{"id":56,"title":"Cards are in the air!","alias":"cards-are-in-the-air","excerpt":"Cards are in the air! There is still 2 hours of late registration available. $150 gets you 20k in chips, $300 gets you $50k in chips. Currently 6 tables, 1st place should be close to $4000!","content":"Cards are in the air! There is still 2 hours of late registration available. $150 gets you 20k in chips, $300 gets you $50k in chips. Currently 6 tables, 1st place should be close to $4000!","publishedAt":"2022-04-16 14:20:00","featured":false,"logo":"jzQb65sdDO1tDY5dQNTKWECeu625Qp8zPGubS1M5.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/jzQb65sdDO1tDY5dQNTKWECeu625Qp8zPGubS1M5.jpg","bannerUrl":"","tournament":{"id":18,"name":"Eagle Eye","alias":"dakota-poker-tour-season-xi-eagle-eye-eagle-eye-04-16-2022"}}'::jsonb),
  (55, 'final-table-live-stream-replay', 'Buffalo City Showdown Final Table Live Stream Replay', 'Final Table live stream replay from Buffalo City Showdown in Jamestown, ND.', '2022-04-04 07:13:00', null, 'dakota-poker-tour-season-xi-buffalo-city-showdown-buffalo-city-showdown-04-03-2022', '', '', 'https://youtu.be/XHDU2gmL1jo', '{"id":55,"title":"Buffalo City Showdown Final Table Live Stream Replay","alias":"final-table-live-stream-replay","excerpt":"Final Table live stream replay from Buffalo City Showdown in Jamestown, ND.","content":"Final Table live stream replay from Buffalo City Showdown in Jamestown, ND.","publishedAt":"2022-04-04 07:13:00","featured":false,"logo":"","banner":"","videoUrl":"https://youtu.be/XHDU2gmL1jo","imageUrl":"","bannerUrl":"","tournament":{"id":20,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-season-xi-buffalo-city-showdown-buffalo-city-showdown-04-03-2022"}}'::jsonb),
  (54, 'brandt-jenner-from-harvey-nd-wins-buffalo-city-showdown', 'Brandt Jenner from Harvey ND Wins Buffalo City Showdown', 'Brandt Jenner made the trip down from Harvey to play in his first Dakota Poker Tour event and came out on top with steady play and some timely agression. Jenner took the trophy after 12 grueling hours of poker, grinding his way to a final t…', '2022-04-04 01:13:00', null, 'dakota-poker-tour-season-xi-buffalo-city-showdown-buffalo-city-showdown-04-03-2022', 'https://dakotapokertour.com/storage/article/thumb/9QmVemfzv3pEh7CDC7iFcJLYP1aWLk7MCKqDdY1z.jpg', '/media/dpt/article/9QmVemfzv3pEh7CDC7iFcJLYP1aWLk7MCKqDdY1z.jpg', null, '{"id":54,"title":"Brandt Jenner from Harvey ND Wins Buffalo City Showdown","alias":"brandt-jenner-from-harvey-nd-wins-buffalo-city-showdown","excerpt":"Brandt Jenner made the trip down from Harvey to play in his first Dakota Poker Tour event and came out on top with steady play and some timely agression. Jenner took the trophy after 12 grueling hours of poker, grinding his way to a final t…","content":"Brandt Jenner made the trip down from Harvey to play in his first Dakota Poker Tour event and came out on top with steady play and some timely agression. Jenner took the trophy after 12 grueling hours of poker, grinding his way to a final table appearance and eventually coming out the nights bug winner with $5120 cash and a seat in the DPT Season XI Tournament of Champions.","publishedAt":"2022-04-04 01:13:00","featured":true,"logo":"9QmVemfzv3pEh7CDC7iFcJLYP1aWLk7MCKqDdY1z.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/9QmVemfzv3pEh7CDC7iFcJLYP1aWLk7MCKqDdY1z.jpg","bannerUrl":"","tournament":{"id":20,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-season-xi-buffalo-city-showdown-buffalo-city-showdown-04-03-2022"}}'::jsonb),
  (53, 'awesome-basim-chip-leader-with-12-players-remaining', 'Awesome Basim Chip Leader with 12 Players Remaining', 'Basim "Awesome Basim" Habib has taken 9ver the chip lead in Jamestown.', '2022-04-03 20:41:00', null, 'dakota-poker-tour-season-xi-buffalo-city-showdown-buffalo-city-showdown-04-03-2022', 'https://dakotapokertour.com/storage/article/thumb/y9chsxJ92uIGSPznzDjBvQF2DSPbEBku3ohsEQVK.jpg', '/media/dpt/article/y9chsxJ92uIGSPznzDjBvQF2DSPbEBku3ohsEQVK.jpg', null, '{"id":53,"title":"Awesome Basim Chip Leader with 12 Players Remaining","alias":"awesome-basim-chip-leader-with-12-players-remaining","excerpt":"Basim \"Awesome Basim\" Habib has taken 9ver the chip lead in Jamestown.","content":"Basim \"Awesome Basim\" Habib has taken 9ver the chip lead in Jamestown.","publishedAt":"2022-04-03 20:41:00","featured":false,"logo":"y9chsxJ92uIGSPznzDjBvQF2DSPbEBku3ohsEQVK.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/y9chsxJ92uIGSPznzDjBvQF2DSPbEBku3ohsEQVK.jpg","bannerUrl":"","tournament":{"id":20,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-season-xi-buffalo-city-showdown-buffalo-city-showdown-04-03-2022"}}'::jsonb),
  (52, 'registration-closed-with-16-855-prize-pool', 'Registration Closed with $16,855 Prize Pool', 'Today''s tournament will pay down 9 places, with 1st place $5,120.', '2022-04-03 19:40:00', null, 'dakota-poker-tour-season-xi-buffalo-city-showdown-buffalo-city-showdown-04-03-2022', '', '', null, '{"id":52,"title":"Registration Closed with $16,855 Prize Pool","alias":"registration-closed-with-16-855-prize-pool","excerpt":"Today''s tournament will pay down 9 places, with 1st place $5,120.","content":"Today''s tournament will pay down 9 places, with 1st place $5,120.","publishedAt":"2022-04-03 19:40:00","featured":false,"logo":null,"banner":null,"videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":20,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-season-xi-buffalo-city-showdown-buffalo-city-showdown-04-03-2022"}}'::jsonb),
  (51, 'michelle-meza-and-bryan-thompson-chip-leaders-on-feature-table-at-break', 'Michelle Meza and Bryan Thompson Chip Leaders on Feature Table at Break', 'Dinner break here in Jamestown, we have 79 players registered currently, with Michelle Meza 216k and Bryan Thompson 179k with the big Stacks on the feature table which is about to go live. Brandon Thomas also with a good start with 140k.', '2022-04-03 17:07:00', null, 'dakota-poker-tour-season-xi-buffalo-city-showdown-buffalo-city-showdown-04-03-2022', 'https://dakotapokertour.com/storage/article/thumb/g4hf9tDwdAoe9MUweAqnqEcx9Jg3jiQQ9YagKik6.jpg', '/media/dpt/article/g4hf9tDwdAoe9MUweAqnqEcx9Jg3jiQQ9YagKik6.jpg', null, '{"id":51,"title":"Michelle Meza and Bryan Thompson Chip Leaders on Feature Table at Break","alias":"michelle-meza-and-bryan-thompson-chip-leaders-on-feature-table-at-break","excerpt":"Dinner break here in Jamestown, we have 79 players registered currently, with Michelle Meza 216k and Bryan Thompson 179k with the big Stacks on the feature table which is about to go live. Brandon Thomas also with a good start with 140k.","content":"Dinner break here in Jamestown, we have 79 players registered currently, with Michelle Meza 216k and Bryan Thompson 179k with the big Stacks on the feature table which is about to go live. Brandon Thomas also with a good start with 140k.","publishedAt":"2022-04-03 17:07:00","featured":false,"logo":"g4hf9tDwdAoe9MUweAqnqEcx9Jg3jiQQ9YagKik6.jpg","banner":"","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/g4hf9tDwdAoe9MUweAqnqEcx9Jg3jiQQ9YagKik6.jpg","bannerUrl":"","tournament":{"id":20,"name":"Buffalo City Showdown","alias":"dakota-poker-tour-season-xi-buffalo-city-showdown-buffalo-city-showdown-04-03-2022"}}'::jsonb),
  (50, 'dpt-coming-to-jamestown', 'DPT Coming to Jamestown!', 'We can''t wait for some DPT action in Jamestown Sunday April 3rd. Can you believe it''s already April? Come out and score big in this one-day tourney and make a run at Player of the Year as well as boosting your chips for the Player Appreciat…', '2022-04-02 13:34:00', null, null, 'https://dakotapokertour.com/storage/article/thumb/RrbSjnJMfOJdEEhXCHrFctDPnzT4E44SzVsiMrq5.jpg', '/media/dpt/article/RrbSjnJMfOJdEEhXCHrFctDPnzT4E44SzVsiMrq5.jpg', 'https://youtu.be/7P4SDH4oRs8', '{"id":50,"title":"DPT Coming to Jamestown!","alias":"dpt-coming-to-jamestown","excerpt":"We can''t wait for some DPT action in Jamestown Sunday April 3rd. Can you believe it''s already April? Come out and score big in this one-day tourney and make a run at Player of the Year as well as boosting your chips for the Player Appreciat…","content":"We can''t wait for some DPT action in Jamestown Sunday April 3rd. Can you believe it''s already April? Come out and score big in this one-day tourney and make a run at Player of the Year as well as boosting your chips for the Player Appreciation Freeroll coming up in May.","publishedAt":"2022-04-02 13:34:00","featured":false,"logo":"RrbSjnJMfOJdEEhXCHrFctDPnzT4E44SzVsiMrq5.jpg","banner":"","videoUrl":"https://youtu.be/7P4SDH4oRs8","imageUrl":"https://dakotapokertour.com/storage/article/thumb/RrbSjnJMfOJdEEhXCHrFctDPnzT4E44SzVsiMrq5.jpg","bannerUrl":"","tournament":{"id":null,"name":null,"alias":null}}'::jsonb),
  (49, 'rick-pflug-from-williston-chip-leader-at-break', 'Rick Pflug from Williston Chip Leader at Break', 'Rick Pflug from Williston in seat 8 on table 4 has been crushing the field in the first half of today''s tournament with nearly 300k in chips.', '2022-03-26 16:23:00', null, 'dakota-poker-tour-season-xi-pour-decisions-march-26-pour-decisions-mar-26th-03-26-2022', 'https://dakotapokertour.com/storage/article/thumb/uefVqVGYBjOHxGnOjGXIwC7F6wduWnchNgxkYtnD.jpg', '/media/dpt/article/uefVqVGYBjOHxGnOjGXIwC7F6wduWnchNgxkYtnD.jpg', null, '{"id":49,"title":"Rick Pflug from Williston Chip Leader at Break","alias":"rick-pflug-from-williston-chip-leader-at-break","excerpt":"Rick Pflug from Williston in seat 8 on table 4 has been crushing the field in the first half of today''s tournament with nearly 300k in chips.","content":"Rick Pflug from Williston in seat 8 on table 4 has been crushing the field in the first half of today''s tournament with nearly 300k in chips.","publishedAt":"2022-03-26 16:23:00","featured":false,"logo":"uefVqVGYBjOHxGnOjGXIwC7F6wduWnchNgxkYtnD.jpg","banner":"","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/uefVqVGYBjOHxGnOjGXIwC7F6wduWnchNgxkYtnD.jpg","bannerUrl":"","tournament":{"id":28,"name":"Pour Decisions Mar 26th","alias":"dakota-poker-tour-season-xi-pour-decisions-march-26-pour-decisions-mar-26th-03-26-2022"}}'::jsonb),
  (48, 'notable-players-exit-early', 'Notable Players Exit Early', 'Reigning DPT Player of the Year Cody Slusher has busted as well as Roughrider Champ Ryan Yanick. Joe Holloway doubled up to stay alive in the hand pictured.', '2022-03-26 14:58:00', null, 'dakota-poker-tour-season-xi-pour-decisions-march-26-pour-decisions-mar-26th-03-26-2022', 'https://dakotapokertour.com/storage/article/thumb/OIlN3jjqvnFbZ8YkLMu7BWKI6ccz5r4VG8FQ2NYd.jpg', '/media/dpt/article/OIlN3jjqvnFbZ8YkLMu7BWKI6ccz5r4VG8FQ2NYd.jpg', null, '{"id":48,"title":"Notable Players Exit Early","alias":"notable-players-exit-early","excerpt":"Reigning DPT Player of the Year Cody Slusher has busted as well as Roughrider Champ Ryan Yanick. Joe Holloway doubled up to stay alive in the hand pictured.","content":"Reigning DPT Player of the Year Cody Slusher has busted as well as Roughrider Champ Ryan Yanick. Joe Holloway doubled up to stay alive in the hand pictured.","publishedAt":"2022-03-26 14:58:00","featured":true,"logo":"OIlN3jjqvnFbZ8YkLMu7BWKI6ccz5r4VG8FQ2NYd.jpg","banner":"","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/OIlN3jjqvnFbZ8YkLMu7BWKI6ccz5r4VG8FQ2NYd.jpg","bannerUrl":"","tournament":{"id":28,"name":"Pour Decisions Mar 26th","alias":"dakota-poker-tour-season-xi-pour-decisions-march-26-pour-decisions-mar-26th-03-26-2022"}}'::jsonb),
  (47, 'chips-in-the-air-in-tioga-2', 'Chips in the air in Tioga', 'Up and running here in Tioga with 35 players and counting. Registration open until 5pm. Live stream coming up this afternoon. We have notable players in the field including reigning Player of the Year Cody Slusher and reigning Pour Decision…', '2022-03-26 13:14:00', null, 'dakota-poker-tour-season-xi-pour-decisions-march-26-pour-decisions-mar-26th-03-26-2022', 'https://dakotapokertour.com/storage/article/thumb/Hyyj0GN7nIDe1EkI8eQDRYUngOP9hPW6DiMYTWfS.jpg', '/media/dpt/article/Hyyj0GN7nIDe1EkI8eQDRYUngOP9hPW6DiMYTWfS.jpg', null, '{"id":47,"title":"Chips in the air in Tioga","alias":"chips-in-the-air-in-tioga-2","excerpt":"Up and running here in Tioga with 35 players and counting. Registration open until 5pm. Live stream coming up this afternoon. We have notable players in the field including reigning Player of the Year Cody Slusher and reigning Pour Decision…","content":"Up and running here in Tioga with 35 players and counting. Registration open until 5pm. Live stream coming up this afternoon. We have notable players in the field including reigning Player of the Year Cody Slusher and reigning Pour Decisions Champ Richard Monson.","publishedAt":"2022-03-26 13:14:00","featured":false,"logo":"Hyyj0GN7nIDe1EkI8eQDRYUngOP9hPW6DiMYTWfS.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Hyyj0GN7nIDe1EkI8eQDRYUngOP9hPW6DiMYTWfS.jpg","bannerUrl":"","tournament":{"id":28,"name":"Pour Decisions Mar 26th","alias":"dakota-poker-tour-season-xi-pour-decisions-march-26-pour-decisions-mar-26th-03-26-2022"}}'::jsonb),
  (45, 'dpt-season-xi-impportant-updates', 'DPT Season XI *IMPORTANT UPDATES*', 'Attn Players! Mark this date! SUNDAY MAY 22ND DPT Season XI will be wrapping up in May in time to award three (3) $1,500 poker packages (in time for the upcoming 2022 World Series of Poker at Bally''s on the strip in Las Vegas). The DPT Seas…', '2022-03-05 08:53:00', null, null, 'https://dakotapokertour.com/storage/article/thumb/qh1Sn680GGcOykBwTssZzqJ5x3Ex8O5ar7Iq4wyB.png', '/media/dpt/article/qh1Sn680GGcOykBwTssZzqJ5x3Ex8O5ar7Iq4wyB.png', null, '{"id":45,"title":"DPT Season XI *IMPORTANT UPDATES*","alias":"dpt-season-xi-impportant-updates","excerpt":"Attn Players! Mark this date! SUNDAY MAY 22ND DPT Season XI will be wrapping up in May in time to award three (3) $1,500 poker packages (in time for the upcoming 2022 World Series of Poker at Bally''s on the strip in Las Vegas). The DPT Seas…","content":"Attn Players! Mark this date! SUNDAY MAY 22ND DPT Season XI will be wrapping up in May in time to award three (3) $1,500 poker packages (in time for the upcoming 2022 World Series of Poker at Bally''s on the strip in Las Vegas). The DPT Season XI Tournament of Champions and Player Appreciation Freeroll events are tentatively scheduled for Sunday, May 22nd at Bar Nine in West Fargo. In a new twist, please note that players will receive BONUS points for attending these events, and winners will receive points equivalent to cash value of any prizes won. For example, the winner of the Player Appreciation Freeroll will receive $1,500 Poker Package and that win will COUNT for POINTS in the Player of the Year race. Same goes for the TOC. Starting times for these events will be announced soon. The DPT Season XI Player of the Year will be determined following those events. POY will earn a DPT POY Bracelet, and a seat in a World Series of Poker event.","publishedAt":"2022-03-05 08:53:00","featured":true,"logo":"qh1Sn680GGcOykBwTssZzqJ5x3Ex8O5ar7Iq4wyB.png","banner":"article/Gh7njbwsEsUxpPkgkzxMJEul68FhG1KuKBV4bnn2.png","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/qh1Sn680GGcOykBwTssZzqJ5x3Ex8O5ar7Iq4wyB.png","bannerUrl":"https://dakotapokertour.com/storage/article/Gh7njbwsEsUxpPkgkzxMJEul68FhG1KuKBV4bnn2.png","tournament":{"id":null,"name":null,"alias":null}}'::jsonb),
  (44, 'john-wendlick-takes-it-down-in-dickinson', 'John Wendlick Takes it Down in Dickinson', 'Congrats are in order to John Wendlick for taking down the Phat Stacks at the Phat Fish tournament in Dickinson.. Also congrats to runner up Chance Lang of Dickinson. The following players cashed in this event: John Wendlick $4200 plus TOC…', '2022-02-21 06:12:00', null, 'dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022', 'https://dakotapokertour.com/storage/article/thumb/vJWa0R5zqf1OD7TnysvbtOd52gT7F8Kh0GvhVxmB.jpg', '/media/dpt/article/vJWa0R5zqf1OD7TnysvbtOd52gT7F8Kh0GvhVxmB.jpg', null, '{"id":44,"title":"John Wendlick Takes it Down in Dickinson","alias":"john-wendlick-takes-it-down-in-dickinson","excerpt":"Congrats are in order to John Wendlick for taking down the Phat Stacks at the Phat Fish tournament in Dickinson.. Also congrats to runner up Chance Lang of Dickinson. The following players cashed in this event: John Wendlick $4200 plus TOC…","content":"Congrats are in order to John Wendlick for taking down the Phat Stacks at the Phat Fish tournament in Dickinson.. Also congrats to runner up Chance Lang of Dickinson. The following players cashed in this event: John Wendlick $4200 plus TOC Qualification Dickinson ND Chance Lang Dickinson ND $2625 Jerry Pachl Dickinson ND $1900 Iggy Weigel Dickinson ND $1400 Merrill Pearcy Dickinson ND $1110 Kevin Krohn Dickinson ND $945 Grant Miller Dickinson ND $770 Jacob Mahlen Dickinson ND $600 Joey Kessel Glendive MT $450 Big thanks to our great hosts at the Phat Fish and our Charity Partner Dunn County Fair Association. Thank you everyone for a great tournament and we look forward to coming back!","publishedAt":"2022-02-21 06:12:00","featured":true,"logo":"vJWa0R5zqf1OD7TnysvbtOd52gT7F8Kh0GvhVxmB.jpg","banner":"article/ZfbeGEFaL3elMvNHEmvs5Kmz8Ti1PziX7vb0bhmV.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/vJWa0R5zqf1OD7TnysvbtOd52gT7F8Kh0GvhVxmB.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/ZfbeGEFaL3elMvNHEmvs5Kmz8Ti1PziX7vb0bhmV.jpg","tournament":{"id":17,"name":"Phat Stacks","alias":"dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022"}}'::jsonb),
  (43, 'phat-stacks-final-table', 'Phat Stacks Final Table', 'Joey Kessel and Arnold Davenport busted in the same hand finishing 9th and 10th place respectively, and we have reached our final table here at the Phat Fish. Seats were shuffled and we have restarted the final table.', '2022-02-21 04:36:00', null, 'dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022', 'https://dakotapokertour.com/storage/article/thumb/2p0vVfSCEgdAfDwBd2i25f2RJIMEbCYGEzS4HdGm.jpg', '/media/dpt/article/2p0vVfSCEgdAfDwBd2i25f2RJIMEbCYGEzS4HdGm.jpg', 'https://youtu.be/vshYYjNY-sY', '{"id":43,"title":"Phat Stacks Final Table","alias":"phat-stacks-final-table","excerpt":"Joey Kessel and Arnold Davenport busted in the same hand finishing 9th and 10th place respectively, and we have reached our final table here at the Phat Fish. Seats were shuffled and we have restarted the final table.","content":"Joey Kessel and Arnold Davenport busted in the same hand finishing 9th and 10th place respectively, and we have reached our final table here at the Phat Fish. Seats were shuffled and we have restarted the final table.","publishedAt":"2022-02-21 04:36:00","featured":true,"logo":"2p0vVfSCEgdAfDwBd2i25f2RJIMEbCYGEzS4HdGm.jpg","banner":"article/03MqTehEjXv2udYinlCiVuxwU2ZJ68Ea8d6kba3Z.jpg","videoUrl":"https://youtu.be/vshYYjNY-sY","imageUrl":"https://dakotapokertour.com/storage/article/thumb/2p0vVfSCEgdAfDwBd2i25f2RJIMEbCYGEzS4HdGm.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/03MqTehEjXv2udYinlCiVuxwU2ZJ68Ea8d6kba3Z.jpg","tournament":{"id":17,"name":"Phat Stacks","alias":"dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022"}}'::jsonb),
  (42, 'john-wendlick-takes-the-chip-lead', 'John Wendlick Takes the Chip Lead', 'John Wendlick is on seat 2 of the Feature Table with over 300k in chips. Reigning champ Jeff Gab is making another run and just got moved to the feature table. The field is currently down to 3 tables. Registration is closed and the prize po…', '2022-02-21 02:00:00', null, 'dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022', 'https://dakotapokertour.com/storage/article/thumb/Mq5DiCMKKfRZzj3ZIDxc8hczNfjrhQfYP6O08BxT.jpg', '/media/dpt/article/Mq5DiCMKKfRZzj3ZIDxc8hczNfjrhQfYP6O08BxT.jpg', null, '{"id":42,"title":"John Wendlick Takes the Chip Lead","alias":"john-wendlick-takes-the-chip-lead","excerpt":"John Wendlick is on seat 2 of the Feature Table with over 300k in chips. Reigning champ Jeff Gab is making another run and just got moved to the feature table. The field is currently down to 3 tables. Registration is closed and the prize po…","content":"John Wendlick is on seat 2 of the Feature Table with over 300k in chips. Reigning champ Jeff Gab is making another run and just got moved to the feature table. The field is currently down to 3 tables. Registration is closed and the prize pool reached $14,000 with 1st place paying out $4200. Final table live stream coming soon.","publishedAt":"2022-02-21 02:00:00","featured":true,"logo":"Mq5DiCMKKfRZzj3ZIDxc8hczNfjrhQfYP6O08BxT.jpg","banner":"article/h7vPnBQYFSlud3HRmpPoucmrNx4JPZ19Y0HnSdUA.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Mq5DiCMKKfRZzj3ZIDxc8hczNfjrhQfYP6O08BxT.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/h7vPnBQYFSlud3HRmpPoucmrNx4JPZ19Y0HnSdUA.jpg","tournament":{"id":17,"name":"Phat Stacks","alias":"dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022"}}'::jsonb),
  (41, 'chip-leaders-going-into-dinner-break', 'Chip Leaders going into Dinner Break', 'Top 3 players with chips currently are Michael Biel, Andy Campbell, and Jeff Gab, all from Dickinson. Each have over 100k with the current avg around 52k in chips.', '2022-02-20 23:13:00', null, 'dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022', 'https://dakotapokertour.com/storage/article/thumb/KeBkJP7vR5qtAraRpcTs8OfkVYEZ1ZzM9Hwzg8GA.jpg', '/media/dpt/article/KeBkJP7vR5qtAraRpcTs8OfkVYEZ1ZzM9Hwzg8GA.jpg', null, '{"id":41,"title":"Chip Leaders going into Dinner Break","alias":"chip-leaders-going-into-dinner-break","excerpt":"Top 3 players with chips currently are Michael Biel, Andy Campbell, and Jeff Gab, all from Dickinson. Each have over 100k with the current avg around 52k in chips.","content":"Top 3 players with chips currently are Michael Biel, Andy Campbell, and Jeff Gab, all from Dickinson. Each have over 100k with the current avg around 52k in chips.","publishedAt":"2022-02-20 23:13:00","featured":true,"logo":"KeBkJP7vR5qtAraRpcTs8OfkVYEZ1ZzM9Hwzg8GA.jpg","banner":"article/VAavDQwWLRp7RB5GgAxI37q3PHnNjjRvt5ZWMGoY.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/KeBkJP7vR5qtAraRpcTs8OfkVYEZ1ZzM9Hwzg8GA.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/VAavDQwWLRp7RB5GgAxI37q3PHnNjjRvt5ZWMGoY.jpg","tournament":{"id":17,"name":"Phat Stacks","alias":"dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022"}}'::jsonb),
  (40, 'phat-stacks-feature-table-live', 'Phat Stacks Feature Table LIVE', 'We have started up a live stream (15 minute delay) of the early action on our feature table here at the Phat Fish. Tune in here: https://youtu.be/5bl2LG1HNWA', '2022-02-20 21:45:00', null, 'dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022', 'https://dakotapokertour.com/storage/article/thumb/l6PX7uFBshX4j4FmGPGbN7IPd6aWuHj1kNCXWADN.jpg', '/media/dpt/article/l6PX7uFBshX4j4FmGPGbN7IPd6aWuHj1kNCXWADN.jpg', 'https://youtu.be/5bl2LG1HNWA', '{"id":40,"title":"Phat Stacks Feature Table LIVE","alias":"phat-stacks-feature-table-live","excerpt":"We have started up a live stream (15 minute delay) of the early action on our feature table here at the Phat Fish. Tune in here: https://youtu.be/5bl2LG1HNWA","content":"We have started up a live stream (15 minute delay) of the early action on our feature table here at the Phat Fish. Tune in here: https://youtu.be/5bl2LG1HNWA","publishedAt":"2022-02-20 21:45:00","featured":true,"logo":"l6PX7uFBshX4j4FmGPGbN7IPd6aWuHj1kNCXWADN.jpg","banner":"article/h5x6vBfniNibfeZs3oz9yeWAxxG5a5zvXw7P4JWq.jpg","videoUrl":"https://youtu.be/5bl2LG1HNWA","imageUrl":"https://dakotapokertour.com/storage/article/thumb/l6PX7uFBshX4j4FmGPGbN7IPd6aWuHj1kNCXWADN.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/h5x6vBfniNibfeZs3oz9yeWAxxG5a5zvXw7P4JWq.jpg","tournament":{"id":17,"name":"Phat Stacks","alias":"dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022"}}'::jsonb),
  (39, 'jason-taylor-scoops-a-pot', 'Jason Taylor Scoops a Pot', 'With a board of Q-A-3-J and 3 players in the hand, Jason Taylor from Dickinson led out with a bet of 2000, Clarence Schaible from Mott called on the button and the 3rd player folded. With a 9 on the river, Taylor bet 4000, and Schaible call…', '2022-02-20 20:53:00', null, 'dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022', 'https://dakotapokertour.com/storage/article/thumb/OxtsQxI35vgvEl0lJvdD9PvWSbtHrBrJZz20jtpD.jpg', '/media/dpt/article/OxtsQxI35vgvEl0lJvdD9PvWSbtHrBrJZz20jtpD.jpg', null, '{"id":39,"title":"Jason Taylor Scoops a Pot","alias":"jason-taylor-scoops-a-pot","excerpt":"With a board of Q-A-3-J and 3 players in the hand, Jason Taylor from Dickinson led out with a bet of 2000, Clarence Schaible from Mott called on the button and the 3rd player folded. With a 9 on the river, Taylor bet 4000, and Schaible call…","content":"With a board of Q-A-3-J and 3 players in the hand, Jason Taylor from Dickinson led out with a bet of 2000, Clarence Schaible from Mott called on the button and the 3rd player folded. With a 9 on the river, Taylor bet 4000, and Schaible called. Taylor showed K-10 for a straight and Schaible groaned while showing A-J. After dragging that pot, Taylor sits with 40,000 chips and Scheible 20,000. Taylor won a seat to today''s tournament playing poker league at Champs Paragon Bowl Wednesday night.","publishedAt":"2022-02-20 20:53:00","featured":true,"logo":"OxtsQxI35vgvEl0lJvdD9PvWSbtHrBrJZz20jtpD.jpg","banner":"article/r9a1ocp42ZAJM86jBMzftPcMjD6khz7mrVAeTO0Q.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/OxtsQxI35vgvEl0lJvdD9PvWSbtHrBrJZz20jtpD.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/r9a1ocp42ZAJM86jBMzftPcMjD6khz7mrVAeTO0Q.jpg","tournament":{"id":17,"name":"Phat Stacks","alias":"dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022"}}'::jsonb),
  (38, 'phat-stacks-at-the-phat-fish-underway', 'Phat Stacks at the Phat Fish Underway!', 'Good early turnout for today''s tournament in Dickinson. Jeff Gab is here to defend his title. Last year he took 1st place for $4,000, AND went on to place Runner Up in Season X Tournament of Champions, earning a seat in today''s event!', '2022-02-20 20:16:00', null, 'dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022', 'https://dakotapokertour.com/storage/article/thumb/pxudQhMBPhIZdcqS1eT81txMoGNxVwj8t7mxxV68.jpg', '/media/dpt/article/pxudQhMBPhIZdcqS1eT81txMoGNxVwj8t7mxxV68.jpg', null, '{"id":38,"title":"Phat Stacks at the Phat Fish Underway!","alias":"phat-stacks-at-the-phat-fish-underway","excerpt":"Good early turnout for today''s tournament in Dickinson. Jeff Gab is here to defend his title. Last year he took 1st place for $4,000, AND went on to place Runner Up in Season X Tournament of Champions, earning a seat in today''s event!","content":"Good early turnout for today''s tournament in Dickinson. Jeff Gab is here to defend his title. Last year he took 1st place for $4,000, AND went on to place Runner Up in Season X Tournament of Champions, earning a seat in today''s event!","publishedAt":"2022-02-20 20:16:00","featured":true,"logo":"pxudQhMBPhIZdcqS1eT81txMoGNxVwj8t7mxxV68.jpg","banner":"article/DyjdzQNQMMwWZ27lnPPlPncIRpXEzcQqrrEZZyGi.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/pxudQhMBPhIZdcqS1eT81txMoGNxVwj8t7mxxV68.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/DyjdzQNQMMwWZ27lnPPlPncIRpXEzcQqrrEZZyGi.jpg","tournament":{"id":17,"name":"Phat Stacks","alias":"dakota-poker-tour-season-xi-phat-stacks-at-the-phat-fish-phat-stacks-02-20-2022"}}'::jsonb),
