  (31, 'cards-in-the-air-at-the-dead-money-open', 'Cards in the air at the Dead Money Open', 'Cards are in the air at the Dead Money Open. 94 players have entered and 148 addons generating a prize pool of just over 18,500! There is still time to join us approximately (4:15 pm) $150 will get you 20k in chips and $300 will get you 50k', '2022-02-12 00:00:00', null, 'dakota-poker-tour-season-xi-dead-money-open-dead-money-open-02-12-2022', '', '', null, '{"id":31,"title":"Cards in the air at the Dead Money Open","alias":"cards-in-the-air-at-the-dead-money-open","excerpt":"Cards are in the air at the Dead Money Open. 94 players have entered and 148 addons generating a prize pool of just over 18,500! There is still time to join us approximately (4:15 pm) $150 will get you 20k in chips and $300 will get you 50k","content":"Cards are in the air at the Dead Money Open. 94 players have entered and 148 addons generating a prize pool of just over 18,500! There is still time to join us approximately (4:15 pm) $150 will get you 20k in chips and $300 will get you 50k","publishedAt":"2022-02-12 00:00:00","featured":false,"logo":"","banner":"","videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":12,"name":"Dead Money Open","alias":"dakota-poker-tour-season-xi-dead-money-open-dead-money-open-02-12-2022"}}'::jsonb),
  (25, 'monster-stack-final-table-live-stream', 'Monster Stack Final Table Live Stream', 'Replay of the final table at the DPT Season XI Monster Stack Main Event.', '2022-01-24 08:23:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022', 'https://dakotapokertour.com/storage/article/thumb/k1O3fGS96wrbg6IWhR0D1mniZ4TuWnrmvzr8pgXe.jpg', '/media/dpt/article/k1O3fGS96wrbg6IWhR0D1mniZ4TuWnrmvzr8pgXe.jpg', 'https://youtu.be/cOngeG0-7Y8', '{"id":25,"title":"Monster Stack Final Table Live Stream","alias":"monster-stack-final-table-live-stream","excerpt":"Replay of the final table at the DPT Season XI Monster Stack Main Event.","content":"Replay of the final table at the DPT Season XI Monster Stack Main Event.","publishedAt":"2022-01-24 08:23:00","featured":true,"logo":"k1O3fGS96wrbg6IWhR0D1mniZ4TuWnrmvzr8pgXe.jpg","banner":"article/U9uQQ9NZjF3B77M22H1lBw0GgagDwhB6m5phJe8i.jpg","videoUrl":"https://youtu.be/cOngeG0-7Y8","imageUrl":"https://dakotapokertour.com/storage/article/thumb/k1O3fGS96wrbg6IWhR0D1mniZ4TuWnrmvzr8pgXe.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/U9uQQ9NZjF3B77M22H1lBw0GgagDwhB6m5phJe8i.jpg","tournament":{"id":11,"name":"Monster Stack","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022"}}'::jsonb),
  (24, 'martin-short-from-grand-forks-is-monster-stack-champion', 'Martin Short from Grand Forks is Monster Stack Champion', 'Martin Short and Mark Dufner had a hard fought headsup battle with Martin coming out on top, earning the Title and $7,750 cash, becoming the latest Monster Stack Champion since Cody Slusher took down the same event 2 years ago. The tourname…', '2022-01-24 08:13:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022', 'https://dakotapokertour.com/storage/article/thumb/ZLB8rauoS2e7uxQ7giTyF5OGZxEWec0Jt3nBClvk.jpg', '/media/dpt/article/ZLB8rauoS2e7uxQ7giTyF5OGZxEWec0Jt3nBClvk.jpg', null, '{"id":24,"title":"Martin Short from Grand Forks is Monster Stack Champion","alias":"martin-short-from-grand-forks-is-monster-stack-champion","excerpt":"Martin Short and Mark Dufner had a hard fought headsup battle with Martin coming out on top, earning the Title and $7,750 cash, becoming the latest Monster Stack Champion since Cody Slusher took down the same event 2 years ago. The tourname…","content":"Martin Short and Mark Dufner had a hard fought headsup battle with Martin coming out on top, earning the Title and $7,750 cash, becoming the latest Monster Stack Champion since Cody Slusher took down the same event 2 years ago. The tournament features a stacked field of 122 unique players and a prize pool just shy of $30k, despite the poor weather weekend and stricter border controls in Canada due to the latest Covid spike. The tournament ran smooth, and we ended up with three (3) separate live stream segments of the Feature Table, including action from Day 1 & 2. Visit youtube.com/dakotapokertour for replays. Congrats to the 15 players who cashed in this event and we''ll look forward to seeing everyone for a return at the Dead Money Open at the M&J Saloon on Saturday, February 12th (1-day format). Can win buy-in on Friday''s single table satellite night, or throughout the week at the Free Poker Network League nights around Fargo.","publishedAt":"2022-01-24 08:13:00","featured":true,"logo":"ZLB8rauoS2e7uxQ7giTyF5OGZxEWec0Jt3nBClvk.jpg","banner":"article/JYVaZOx1n319TipXyCJ96omuTYaxPvY1TBiikjhy.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/ZLB8rauoS2e7uxQ7giTyF5OGZxEWec0Jt3nBClvk.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/JYVaZOx1n319TipXyCJ96omuTYaxPvY1TBiikjhy.jpg","tournament":{"id":11,"name":"Monster Stack","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022"}}'::jsonb),
  (23, 'in-the', 'In the $$', 'Kris Bommersbach busted Chris Koon in 14th place. Tyler Kolness busted Jesse Haddeland and Justin Cole with pocket Aces. We are in the money! Mark Dufner, Martin Short, Nikki Smith, and Tiny from Hawaii have some of the bigger stacks. Live…', '2022-01-23 23:30:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022', '', '', null, '{"id":23,"title":"In the $$","alias":"in-the","excerpt":"Kris Bommersbach busted Chris Koon in 14th place. Tyler Kolness busted Jesse Haddeland and Justin Cole with pocket Aces. We are in the money! Mark Dufner, Martin Short, Nikki Smith, and Tiny from Hawaii have some of the bigger stacks. Live…","content":"Kris Bommersbach busted Chris Koon in 14th place. Tyler Kolness busted Jesse Haddeland and Justin Cole with pocket Aces. We are in the money! Mark Dufner, Martin Short, Nikki Smith, and Tiny from Hawaii have some of the bigger stacks. Live stream is available here: https://youtu.be/xRXo6-3kUGY","publishedAt":"2022-01-23 23:30:00","featured":false,"logo":"","banner":"","videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":11,"name":"Monster Stack","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022"}}'::jsonb),
  (22, 'on-the-bubble', 'On the Bubble', 'We are currently on the bubble! Top 15 get paid.', '2022-01-23 23:13:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022', '', '', null, '{"id":22,"title":"On the Bubble","alias":"on-the-bubble","excerpt":"We are currently on the bubble! Top 15 get paid.","content":"We are currently on the bubble! Top 15 get paid.","publishedAt":"2022-01-23 23:13:00","featured":false,"logo":"","banner":"","videoUrl":null,"imageUrl":"","bannerUrl":"","tournament":{"id":11,"name":"Monster Stack","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022"}}'::jsonb),
  (21, 'chip-leaders-at-the-break', 'Chip Leaders at the Break', 'Chip leaders at the break: Mike Marek, East Grand Forks MN 370k Justin Cole, Mapleton ND 630k Chris Koon, Grand Forks ND 333k Jeremy Schultz Fargo ND 397k Mike Columbus Red Lake Falls MN 476k Terry Anenson, Thief River Falls MN 408k', '2022-01-23 19:52:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022', 'https://dakotapokertour.com/storage/article/thumb/RtxnLxbdMuicx4jmUvlK5guIMcE1P3fZTr1DrvIX.jpg', '/media/dpt/article/RtxnLxbdMuicx4jmUvlK5guIMcE1P3fZTr1DrvIX.jpg', null, '{"id":21,"title":"Chip Leaders at the Break","alias":"chip-leaders-at-the-break","excerpt":"Chip leaders at the break: Mike Marek, East Grand Forks MN 370k Justin Cole, Mapleton ND 630k Chris Koon, Grand Forks ND 333k Jeremy Schultz Fargo ND 397k Mike Columbus Red Lake Falls MN 476k Terry Anenson, Thief River Falls MN 408k","content":"Chip leaders at the break: Mike Marek, East Grand Forks MN 370k Justin Cole, Mapleton ND 630k Chris Koon, Grand Forks ND 333k Jeremy Schultz Fargo ND 397k Mike Columbus Red Lake Falls MN 476k Terry Anenson, Thief River Falls MN 408k","publishedAt":"2022-01-23 19:52:00","featured":true,"logo":"RtxnLxbdMuicx4jmUvlK5guIMcE1P3fZTr1DrvIX.jpg","banner":"article/airEAP7d6fupRU51pZjBY4d8ymJlm0N3saQ7GULl.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/RtxnLxbdMuicx4jmUvlK5guIMcE1P3fZTr1DrvIX.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/airEAP7d6fupRU51pZjBY4d8ymJlm0N3saQ7GULl.jpg","tournament":{"id":11,"name":"Monster Stack","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022"}}'::jsonb),
  (20, 'day-2-underway', 'Day 2 Underway', 'We''re underway, at least 11 new entrants today including Paul Johnson, Thane Fliginger, Tiny, Aaron Raap, Lee Cavanaugh, Russel Johnson, Nicholas Michael, and others, to bring the unique player count to 122 and counting. Prize pool approach…', '2022-01-23 18:41:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022', 'https://dakotapokertour.com/storage/article/thumb/JK2pMg7ySM5FqoQgnUHomf6ZP9VKvZgQ7OwGNsvm.jpg', '/media/dpt/article/JK2pMg7ySM5FqoQgnUHomf6ZP9VKvZgQ7OwGNsvm.jpg', null, '{"id":20,"title":"Day 2 Underway","alias":"day-2-underway","excerpt":"We''re underway, at least 11 new entrants today including Paul Johnson, Thane Fliginger, Tiny, Aaron Raap, Lee Cavanaugh, Russel Johnson, Nicholas Michael, and others, to bring the unique player count to 122 and counting. Prize pool approach…","content":"We''re underway, at least 11 new entrants today including Paul Johnson, Thane Fliginger, Tiny, Aaron Raap, Lee Cavanaugh, Russel Johnson, Nicholas Michael, and others, to bring the unique player count to 122 and counting. Prize pool approaching $30,000. Registration is still open until 1pm. Good luck everyone! Stay tuned for Feature Table Live Stream this afternoon: www.youtube.com/dakotapokertour","publishedAt":"2022-01-23 18:41:00","featured":true,"logo":"JK2pMg7ySM5FqoQgnUHomf6ZP9VKvZgQ7OwGNsvm.jpg","banner":"article/yeIurMU9mIOnFV2PcEFwGCDzx3hNr2brSIX5PpqE.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/JK2pMg7ySM5FqoQgnUHomf6ZP9VKvZgQ7OwGNsvm.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/yeIurMU9mIOnFV2PcEFwGCDzx3hNr2brSIX5PpqE.jpg","tournament":{"id":11,"name":"Monster Stack","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022"}}'::jsonb),
  (19, 'day-2-table-draw', 'Day 2 Table Draw', 'Here is the table draw and chip counts for Day 2. Cards in the air at noon', '2022-01-23 05:23:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022', 'https://dakotapokertour.com/storage/article/thumb/Tl3SCdPoZ0utoToSxQIAMeyBJEsM94rCJIKpU2ly.jpg', '/media/dpt/article/Tl3SCdPoZ0utoToSxQIAMeyBJEsM94rCJIKpU2ly.jpg', null, '{"id":19,"title":"Day 2 Table Draw","alias":"day-2-table-draw","excerpt":"Here is the table draw and chip counts for Day 2. Cards in the air at noon","content":"Here is the table draw and chip counts for Day 2. Cards in the air at noon","publishedAt":"2022-01-23 05:23:00","featured":true,"logo":"Tl3SCdPoZ0utoToSxQIAMeyBJEsM94rCJIKpU2ly.jpg","banner":"article/hUJSqZxcz5PElczQYxqilLOAafQtyCWK61iG0kI7.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Tl3SCdPoZ0utoToSxQIAMeyBJEsM94rCJIKpU2ly.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/hUJSqZxcz5PElczQYxqilLOAafQtyCWK61iG0kI7.jpg","tournament":{"id":11,"name":"Monster Stack","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022"}}'::jsonb),
  (18, 'live-stream-coming-up', 'Live Stream Coming Up', 'We''re getting ready to come back from the dinner break. The Feature Table Live Stream is coming up, tune into YouTube - Dakota Poker Tour Channel to view. The Feature Table includes Season X POY Runner Up and former DPT Champ Brandon Dosch,…', '2022-01-23 01:17:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022', 'https://dakotapokertour.com/storage/article/thumb/Y0dBu3M5QkOgXzSlbPsDY40JZjuRjUY4cY0XRW4m.jpg', '/media/dpt/article/Y0dBu3M5QkOgXzSlbPsDY40JZjuRjUY4cY0XRW4m.jpg', null, '{"id":18,"title":"Live Stream Coming Up","alias":"live-stream-coming-up","excerpt":"We''re getting ready to come back from the dinner break. The Feature Table Live Stream is coming up, tune into YouTube - Dakota Poker Tour Channel to view. The Feature Table includes Season X POY Runner Up and former DPT Champ Brandon Dosch,…","content":"We''re getting ready to come back from the dinner break. The Feature Table Live Stream is coming up, tune into YouTube - Dakota Poker Tour Channel to view. The Feature Table includes Season X POY Runner Up and former DPT Champ Brandon Dosch, Season X Player Appreciation Freeroll Winner Eric Dosch, and East Grand Forks veteran Mike Marek. We currently have 108 unique entries.","publishedAt":"2022-01-23 01:17:00","featured":true,"logo":"Y0dBu3M5QkOgXzSlbPsDY40JZjuRjUY4cY0XRW4m.jpg","banner":"article/YSpptsKMBeJjrW309j5pfyJoCPvEzSDsCBNEpJII.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/Y0dBu3M5QkOgXzSlbPsDY40JZjuRjUY4cY0XRW4m.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/YSpptsKMBeJjrW309j5pfyJoCPvEzSDsCBNEpJII.jpg","tournament":{"id":11,"name":"Monster Stack","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022"}}'::jsonb),
  (17, 'monster-stack-underway-with-over-100-players-registered', 'Monster Stack Underway with over 100 players Registered', 'We''ve reached the 100 player mark here in Grand Forks for Day 1 of the L.i.s.t.e.n. Inc Monster Stack at Playmakers Lounge in the Canad Inn. We look forward to building a big prize pool.', '2022-01-22 21:30:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022', 'https://dakotapokertour.com/storage/article/thumb/ZNZHqTKXRTm7hM9KxAF04RMvK6ddGMnSbLQK0UIy.jpg', '/media/dpt/article/ZNZHqTKXRTm7hM9KxAF04RMvK6ddGMnSbLQK0UIy.jpg', null, '{"id":17,"title":"Monster Stack Underway with over 100 players Registered","alias":"monster-stack-underway-with-over-100-players-registered","excerpt":"We''ve reached the 100 player mark here in Grand Forks for Day 1 of the L.i.s.t.e.n. Inc Monster Stack at Playmakers Lounge in the Canad Inn. We look forward to building a big prize pool.","content":"We''ve reached the 100 player mark here in Grand Forks for Day 1 of the L.i.s.t.e.n. Inc Monster Stack at Playmakers Lounge in the Canad Inn. We look forward to building a big prize pool.","publishedAt":"2022-01-22 21:30:00","featured":true,"logo":"ZNZHqTKXRTm7hM9KxAF04RMvK6ddGMnSbLQK0UIy.jpg","banner":"article/ryeO1ovZGFSzKksgAxnpHxtvrnIvdCE7xm20bWtJ.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/ZNZHqTKXRTm7hM9KxAF04RMvK6ddGMnSbLQK0UIy.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/ryeO1ovZGFSzKksgAxnpHxtvrnIvdCE7xm20bWtJ.jpg","tournament":{"id":11,"name":"Monster Stack","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-monster-stack-01-22-2022"}}'::jsonb),
  (16, 'brian-peck-can-t-get-enough-of-the-action', 'Brian Peck can''t get enough of the action', 'Brian has been not killing it at the tables tonight but he is getting plenty of quality time on the felt. We won''t ask how many entries he put in tonight but it''s safe to say the cost of his poker tuition went up. 😂', '2022-01-22 05:04:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-friday-night-super-satellite-01-21-2022', 'https://dakotapokertour.com/storage/article/thumb/OmcI9zyDwW39DWhIQYsrvHKCz8ZAGRpAJfvBvlB8.jpg', '/media/dpt/article/OmcI9zyDwW39DWhIQYsrvHKCz8ZAGRpAJfvBvlB8.jpg', null, '{"id":16,"title":"Brian Peck can''t get enough of the action","alias":"brian-peck-can-t-get-enough-of-the-action","excerpt":"Brian has been not killing it at the tables tonight but he is getting plenty of quality time on the felt. We won''t ask how many entries he put in tonight but it''s safe to say the cost of his poker tuition went up. 😂","content":"Brian has been not killing it at the tables tonight but he is getting plenty of quality time on the felt. We won''t ask how many entries he put in tonight but it''s safe to say the cost of his poker tuition went up. 😂","publishedAt":"2022-01-22 05:04:00","featured":true,"logo":"OmcI9zyDwW39DWhIQYsrvHKCz8ZAGRpAJfvBvlB8.jpg","banner":"article/hZo4ciwHthoBZmquX15A15DxXimlM8JjVES8ulHO.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/OmcI9zyDwW39DWhIQYsrvHKCz8ZAGRpAJfvBvlB8.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/hZo4ciwHthoBZmquX15A15DxXimlM8JjVES8ulHO.jpg","tournament":{"id":10,"name":"Friday Night Super Satellite","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-friday-night-super-satellite-01-21-2022"}}'::jsonb),
  (15, 'registration-closed-with-2320-prize-pool', 'Registration closed with $2320 prize pool', 'Registration is closed, 14 players have busted. Top 10 earn a $200 buyin for tomorrow''s Monster Stack Main Event!', '2022-01-22 03:34:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-friday-night-super-satellite-01-21-2022', 'https://dakotapokertour.com/storage/article/thumb/RKJd3fOhLGZOZOZiJwRRWZmCeJpTESQqoc1zWVAu.jpg', '/media/dpt/article/RKJd3fOhLGZOZOZiJwRRWZmCeJpTESQqoc1zWVAu.jpg', null, '{"id":15,"title":"Registration closed with $2320 prize pool","alias":"registration-closed-with-2320-prize-pool","excerpt":"Registration is closed, 14 players have busted. Top 10 earn a $200 buyin for tomorrow''s Monster Stack Main Event!","content":"Registration is closed, 14 players have busted. Top 10 earn a $200 buyin for tomorrow''s Monster Stack Main Event!","publishedAt":"2022-01-22 03:34:00","featured":false,"logo":"RKJd3fOhLGZOZOZiJwRRWZmCeJpTESQqoc1zWVAu.jpg","banner":"article/LMTylM8R4p5Rgyk278wQUjfucWMjmT5TdwPYQ9Cq.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/RKJd3fOhLGZOZOZiJwRRWZmCeJpTESQqoc1zWVAu.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/LMTylM8R4p5Rgyk278wQUjfucWMjmT5TdwPYQ9Cq.jpg","tournament":{"id":10,"name":"Friday Night Super Satellite","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-friday-night-super-satellite-01-21-2022"}}'::jsonb),
  (14, 'super-satellite-underway', 'Super Satellite Underway', 'Cards are in the air with 32 players to start. Plenty of time to register, 15,000 starting chips. There will be single table satellites as well.', '2022-01-22 00:00:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-friday-night-super-satellite-01-21-2022', 'https://dakotapokertour.com/storage/article/thumb/EmrqhRew1a6qWP0p96B3iFxMFUKCDg2TW5EHlW0Z.jpg', '/media/dpt/article/EmrqhRew1a6qWP0p96B3iFxMFUKCDg2TW5EHlW0Z.jpg', null, '{"id":14,"title":"Super Satellite Underway","alias":"super-satellite-underway","excerpt":"Cards are in the air with 32 players to start. Plenty of time to register, 15,000 starting chips. There will be single table satellites as well.","content":"Cards are in the air with 32 players to start. Plenty of time to register, 15,000 starting chips. There will be single table satellites as well.","publishedAt":"2022-01-22 00:00:00","featured":true,"logo":"EmrqhRew1a6qWP0p96B3iFxMFUKCDg2TW5EHlW0Z.jpg","banner":"article/2DYqzGYMdGdV4md6O6FFJ4XSWqBkVGvQ2iUuyRIf.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/EmrqhRew1a6qWP0p96B3iFxMFUKCDg2TW5EHlW0Z.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/2DYqzGYMdGdV4md6O6FFJ4XSWqBkVGvQ2iUuyRIf.jpg","tournament":{"id":10,"name":"Friday Night Super Satellite","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-friday-night-super-satellite-01-21-2022"}}'::jsonb),
  (13, 'dpt-returns-to-grand-forks-for-the-monster-stack-at-the-canad-inn', 'DPT Returns to Grand Forks for the Monster Stack at the Canad Inn', 'The DPT returns to Grand Forks and the Canad Inn this weekend for the MONSTER STACK! Did you know? You can win a FREE seat to Friday''s Super Satellite by taking down a FPN poker league night this week in Grand Forks. Monday 7pm - Southgate,…', '2022-01-17 15:40:00', null, 'dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-friday-night-super-satellite-01-21-2022', '', '', 'https://youtu.be/CFXjqd0KB0Q', '{"id":13,"title":"DPT Returns to Grand Forks for the Monster Stack at the Canad Inn","alias":"dpt-returns-to-grand-forks-for-the-monster-stack-at-the-canad-inn","excerpt":"The DPT returns to Grand Forks and the Canad Inn this weekend for the MONSTER STACK! Did you know? You can win a FREE seat to Friday''s Super Satellite by taking down a FPN poker league night this week in Grand Forks. Monday 7pm - Southgate,…","content":"The DPT returns to Grand Forks and the Canad Inn this weekend for the MONSTER STACK! Did you know? You can win a FREE seat to Friday''s Super Satellite by taking down a FPN poker league night this week in Grand Forks. Monday 7pm - Southgate, Wednesday 7pm - EGF Legion. Saturday the main tournament kicks off at Noon - $200 buy-in gets you 60,000 in chips. This tournament has a deep stack 2-day structure with 40 minute levels. First place last time was over $7,000.","publishedAt":"2022-01-17 15:40:00","featured":true,"logo":null,"banner":null,"videoUrl":"https://youtu.be/CFXjqd0KB0Q","imageUrl":"","bannerUrl":"","tournament":{"id":10,"name":"Friday Night Super Satellite","alias":"dakota-poker-tour-season-xi-l-i-s-t-e-n-inc-monster-stack-friday-night-super-satellite-01-21-2022"}}'::jsonb),
  (11, 'poker-brat-classic-final-table-live-stream', 'Poker Brat Classic - Final Table Live Stream', 'We have our final table of 9 players set. Please note, the live stream is on a 15 minute delay. John Harms from Columbus, Nebraska remains the chip leader with 2.75 million. Live stream here-> https://youtu.be/lDvJnS8_NEY', '2021-12-06 00:00:00', null, 'dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021', 'https://dakotapokertour.com/storage/article/thumb/m8mkily7eRRH0Z3IgPPK83OVehuBcriSbPb82oLO.jpg', '/media/dpt/article/m8mkily7eRRH0Z3IgPPK83OVehuBcriSbPb82oLO.jpg', 'https://youtu.be/lDvJnS8_NEY', '{"id":11,"title":"Poker Brat Classic - Final Table Live Stream","alias":"poker-brat-classic-final-table-live-stream","excerpt":"We have our final table of 9 players set. Please note, the live stream is on a 15 minute delay. John Harms from Columbus, Nebraska remains the chip leader with 2.75 million. Live stream here-> https://youtu.be/lDvJnS8_NEY","content":"We have our final table of 9 players set. Please note, the live stream is on a 15 minute delay. John Harms from Columbus, Nebraska remains the chip leader with 2.75 million. Live stream here-> https://youtu.be/lDvJnS8_NEY","publishedAt":"2021-12-06 00:00:00","featured":true,"logo":"m8mkily7eRRH0Z3IgPPK83OVehuBcriSbPb82oLO.jpg","banner":"article/7wZD8MmH7pxUdirFizr1T40zc0IXRMOCoOJke7kf.jpg","videoUrl":"https://youtu.be/lDvJnS8_NEY","imageUrl":"https://dakotapokertour.com/storage/article/thumb/m8mkily7eRRH0Z3IgPPK83OVehuBcriSbPb82oLO.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/7wZD8MmH7pxUdirFizr1T40zc0IXRMOCoOJke7kf.jpg","tournament":{"id":3,"name":"Poker Brat Classic","alias":"dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021"}}'::jsonb),
  (12, 'ashly-hafdahl-wins-poker-brat-classic', 'Ashly Hafdahl Wins Poker Brat Classic', 'Congrats to Ashly Hafdahl from Fargo, ND for taking down the Poker Brat Classic and $7,640 cash! John Harms from Columbus, NE runner up, $5,000', '2021-12-06 00:00:00', null, 'dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021', 'https://dakotapokertour.com/storage/article/thumb/iOFONbwi2dBNMWO7T4MjefmHmSL9EjClOF4uZmnK.jpg', '/media/dpt/article/iOFONbwi2dBNMWO7T4MjefmHmSL9EjClOF4uZmnK.jpg', null, '{"id":12,"title":"Ashly Hafdahl Wins Poker Brat Classic","alias":"ashly-hafdahl-wins-poker-brat-classic","excerpt":"Congrats to Ashly Hafdahl from Fargo, ND for taking down the Poker Brat Classic and $7,640 cash! John Harms from Columbus, NE runner up, $5,000","content":"Congrats to Ashly Hafdahl from Fargo, ND for taking down the Poker Brat Classic and $7,640 cash! John Harms from Columbus, NE runner up, $5,000","publishedAt":"2021-12-06 00:00:00","featured":true,"logo":"iOFONbwi2dBNMWO7T4MjefmHmSL9EjClOF4uZmnK.jpg","banner":"article/xc3HoDOEd27TekBLkwP6WePHpFzhPOyTcz7VRNko.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/iOFONbwi2dBNMWO7T4MjefmHmSL9EjClOF4uZmnK.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/xc3HoDOEd27TekBLkwP6WePHpFzhPOyTcz7VRNko.jpg","tournament":{"id":3,"name":"Poker Brat Classic","alias":"dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021"}}'::jsonb),
  (10, 'john-harms-chip-leader-to-start-day-2', 'John Harms Chip Leader to Start Day 2', 'John Harms has the chip lead going into day 2 of the Poker Brat Classic at the Windbreak. The foul weather unfortunately has prevented several players from making it today. Prize pool announcement coming soon, stay tuned.', '2021-12-05 00:00:00', null, 'dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021', 'https://dakotapokertour.com/storage/article/thumb/1DfTtMloSEUTwxhXxaA99LGmXUlk2YmuWJGQqE6d.jpg', '/media/dpt/article/1DfTtMloSEUTwxhXxaA99LGmXUlk2YmuWJGQqE6d.jpg', null, '{"id":10,"title":"John Harms Chip Leader to Start Day 2","alias":"john-harms-chip-leader-to-start-day-2","excerpt":"John Harms has the chip lead going into day 2 of the Poker Brat Classic at the Windbreak. The foul weather unfortunately has prevented several players from making it today. Prize pool announcement coming soon, stay tuned.","content":"John Harms has the chip lead going into day 2 of the Poker Brat Classic at the Windbreak. The foul weather unfortunately has prevented several players from making it today. Prize pool announcement coming soon, stay tuned.","publishedAt":"2021-12-05 00:00:00","featured":true,"logo":"1DfTtMloSEUTwxhXxaA99LGmXUlk2YmuWJGQqE6d.jpg","banner":"article/0P938YrG0lDSFIBidcjjxaaHXv8LZBR8dPnlMffw.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/1DfTtMloSEUTwxhXxaA99LGmXUlk2YmuWJGQqE6d.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/0P938YrG0lDSFIBidcjjxaaHXv8LZBR8dPnlMffw.jpg","tournament":{"id":3,"name":"Poker Brat Classic","alias":"dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021"}}'::jsonb),
  (7, 'player-of-the-year-points-update', 'Player of the Year Points Update', 'Updated for Season XI, the Player of the Year points calculation will now account for ALL buy-ins. Previously, the points calculation included only the initial buy-in. Now, all re-buys/re-entries will be included in the total points calcula…', '2021-12-04 00:00:00', null, 'dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021', 'https://dakotapokertour.com/storage/article/thumb/8i7xKxe1uaysYTBF5REXWEtjRs6liiUpPUVMP4aK.jpg', '/media/dpt/article/8i7xKxe1uaysYTBF5REXWEtjRs6liiUpPUVMP4aK.jpg', null, '{"id":7,"title":"Player of the Year Points Update","alias":"player-of-the-year-points-update","excerpt":"Updated for Season XI, the Player of the Year points calculation will now account for ALL buy-ins. Previously, the points calculation included only the initial buy-in. Now, all re-buys/re-entries will be included in the total points calcula…","content":"Updated for Season XI, the Player of the Year points calculation will now account for ALL buy-ins. Previously, the points calculation included only the initial buy-in. Now, all re-buys/re-entries will be included in the total points calculation. The current leaderboard reflects this change.","publishedAt":"2021-12-04 00:00:00","featured":true,"logo":"8i7xKxe1uaysYTBF5REXWEtjRs6liiUpPUVMP4aK.jpg","banner":"article/twwD99g8JE1vw52MRbsll7fIOXj64AfSLHo0CTs7.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/8i7xKxe1uaysYTBF5REXWEtjRs6liiUpPUVMP4aK.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/twwD99g8JE1vw52MRbsll7fIOXj64AfSLHo0CTs7.jpg","tournament":{"id":3,"name":"Poker Brat Classic","alias":"dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021"}}'::jsonb),
  (9, 'early-chip-leaders', 'Early Chip Leaders', 'Don Drummond, Charlie Paukert, and Tyrone Cromwell are your early chip leaders, each with 225k+. Registration is open until 1pm Sunday, a full buy in gets you 90,000 chips in this deep stack event.', '2021-12-04 00:00:00', null, 'dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021', 'https://dakotapokertour.com/storage/article/thumb/rPIhadWYYusKiSQ0nC5AnJQWPfvU6McOGZyIjZKF.jpg', '/media/dpt/article/rPIhadWYYusKiSQ0nC5AnJQWPfvU6McOGZyIjZKF.jpg', null, '{"id":9,"title":"Early Chip Leaders","alias":"early-chip-leaders","excerpt":"Don Drummond, Charlie Paukert, and Tyrone Cromwell are your early chip leaders, each with 225k+. Registration is open until 1pm Sunday, a full buy in gets you 90,000 chips in this deep stack event.","content":"Don Drummond, Charlie Paukert, and Tyrone Cromwell are your early chip leaders, each with 225k+. Registration is open until 1pm Sunday, a full buy in gets you 90,000 chips in this deep stack event.","publishedAt":"2021-12-04 00:00:00","featured":true,"logo":"rPIhadWYYusKiSQ0nC5AnJQWPfvU6McOGZyIjZKF.jpg","banner":"article/I5WffN3ftF2JyaMjS9tge7MhsuMJY2qiiuvQbTmP.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/rPIhadWYYusKiSQ0nC5AnJQWPfvU6McOGZyIjZKF.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/I5WffN3ftF2JyaMjS9tge7MhsuMJY2qiiuvQbTmP.jpg","tournament":{"id":3,"name":"Poker Brat Classic","alias":"dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021"}}'::jsonb),
  (6, 'dpt-getting-set-for-return-to-the-winbreak', 'DPT Getting Set for Return to the Winbreak', 'Tournament Directory Dana Castaneda is gearing up for a good turnout at the Windbreak this weekend. This 2-day event features a super deep structure.', '2021-12-03 00:00:00', null, 'dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021', 'https://dakotapokertour.com/storage/article/thumb/2oRtbWswyM4NaJm05iex3wbstGID5AZF65OFRIXX.jpg', '/media/dpt/article/2oRtbWswyM4NaJm05iex3wbstGID5AZF65OFRIXX.jpg', null, '{"id":6,"title":"DPT Getting Set for Return to the Winbreak","alias":"dpt-getting-set-for-return-to-the-winbreak","excerpt":"Tournament Directory Dana Castaneda is gearing up for a good turnout at the Windbreak this weekend. This 2-day event features a super deep structure.","content":"Tournament Directory Dana Castaneda is gearing up for a good turnout at the Windbreak this weekend. This 2-day event features a super deep structure.","publishedAt":"2021-12-03 00:00:00","featured":true,"logo":"2oRtbWswyM4NaJm05iex3wbstGID5AZF65OFRIXX.jpg","banner":"article/Nfd0UeBPtENc7nP4hKtpZ3SC7NLTA1qjXkqwjRpx.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/2oRtbWswyM4NaJm05iex3wbstGID5AZF65OFRIXX.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/Nfd0UeBPtENc7nP4hKtpZ3SC7NLTA1qjXkqwjRpx.jpg","tournament":{"id":3,"name":"Poker Brat Classic","alias":"dakota-poker-tour-season-xi-poker-brat-classic-poker-brat-classic-12-04-2021"}}'::jsonb),
  (4, 'richard-monson-takes-down-pour-decisions', 'Richard Monson Takes Down Pour Decisions', 'Congratulations to Richard Monson from Ray, ND for winning the Pour Decisions tournament in Tioga and $2,150 cash. Richard joins the list of DPT Season XI Tournament Champs.', '2021-11-30 00:00:00', null, 'dakota-poker-tour-season-xi-pour-decisions-tioga-nd-pour-decisions-11-27-2021', 'https://dakotapokertour.com/storage/article/QQRkhu5Sc7byHg1MZeqne5Xl0Sj644GkC9iDgFI5.jpg', '', 'https://www.youtube.com/watch?v=DOaFSYDNDsM', '{"id":4,"title":"Richard Monson Takes Down Pour Decisions","alias":"richard-monson-takes-down-pour-decisions","excerpt":"Congratulations to Richard Monson from Ray, ND for winning the Pour Decisions tournament in Tioga and $2,150 cash. Richard joins the list of DPT Season XI Tournament Champs.","content":"Congratulations to Richard Monson from Ray, ND for winning the Pour Decisions tournament in Tioga and $2,150 cash. Richard joins the list of DPT Season XI Tournament Champs.","publishedAt":"2021-11-30 00:00:00","featured":true,"logo":"article/QQRkhu5Sc7byHg1MZeqne5Xl0Sj644GkC9iDgFI5.jpg","banner":"article/m2GvSsAgGv0mAUFhgyAyIndA5h3ln7XnE2T6J24E.jpg","videoUrl":"https://www.youtube.com/watch?v=DOaFSYDNDsM","imageUrl":"https://dakotapokertour.com/storage/article/QQRkhu5Sc7byHg1MZeqne5Xl0Sj644GkC9iDgFI5.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/m2GvSsAgGv0mAUFhgyAyIndA5h3ln7XnE2T6J24E.jpg","tournament":{"id":2,"name":"Pour Decisions","alias":"dakota-poker-tour-season-xi-pour-decisions-tioga-nd-pour-decisions-11-27-2021"}}'::jsonb),
  (2, 'chips-in-the-air-in-tioga', 'Chips in the Air in Tioga', 'We''re underway at Pour Decisions in Tioga with 3 tables. With deep stacks, there is lots of play in this tournament and registration does not close until after the dinner break around 5pm.', '2021-11-27 00:00:00', null, 'dakota-poker-tour-season-xi-pour-decisions-tioga-nd-pour-decisions-11-27-2021', 'https://dakotapokertour.com/storage/article/thumb/A4TJurNyxiaO4PkaHmsA1O5y4kFS92tXbbtZtvwd.jpg', '/media/dpt/article/A4TJurNyxiaO4PkaHmsA1O5y4kFS92tXbbtZtvwd.jpg', null, '{"id":2,"title":"Chips in the Air in Tioga","alias":"chips-in-the-air-in-tioga","excerpt":"We''re underway at Pour Decisions in Tioga with 3 tables. With deep stacks, there is lots of play in this tournament and registration does not close until after the dinner break around 5pm.","content":"We''re underway at Pour Decisions in Tioga with 3 tables. With deep stacks, there is lots of play in this tournament and registration does not close until after the dinner break around 5pm.","publishedAt":"2021-11-27 00:00:00","featured":false,"logo":"A4TJurNyxiaO4PkaHmsA1O5y4kFS92tXbbtZtvwd.jpg","banner":"article/bCSYKOfbNRDTGALtYptTH1VoRdPJNvLCqlRGOK3i.jpg","videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/A4TJurNyxiaO4PkaHmsA1O5y4kFS92tXbbtZtvwd.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/bCSYKOfbNRDTGALtYptTH1VoRdPJNvLCqlRGOK3i.jpg","tournament":{"id":2,"name":"Pour Decisions","alias":"dakota-poker-tour-season-xi-pour-decisions-tioga-nd-pour-decisions-11-27-2021"}}'::jsonb),
  (5, 'tommy-hill-takes-down-season-xi-opener', 'Tommy Hill Takes Down Season XI Opener', 'Tommy Hill outlasted 38 players to win the Season XI Opening Tournament to open up the early lead for DPT Season XI Player of the Year!', '2021-09-26 00:00:00', null, 'dakota-poker-tour-season-xi-season-xi-kickoff-tournament-hagge-s-hagge-s-bar-grill-09-26-2021', 'https://dakotapokertour.com/storage/article/thumb/roP2dixGt8Tmzb7abotLHgyTVFr9bhwohAx5S94j.jpg', '/media/dpt/article/roP2dixGt8Tmzb7abotLHgyTVFr9bhwohAx5S94j.jpg', 'https://youtu.be/0ZJqAZuQjXc', '{"id":5,"title":"Tommy Hill Takes Down Season XI Opener","alias":"tommy-hill-takes-down-season-xi-opener","excerpt":"Tommy Hill outlasted 38 players to win the Season XI Opening Tournament to open up the early lead for DPT Season XI Player of the Year!","content":"Tommy Hill outlasted 38 players to win the Season XI Opening Tournament to open up the early lead for DPT Season XI Player of the Year!","publishedAt":"2021-09-26 00:00:00","featured":true,"logo":"roP2dixGt8Tmzb7abotLHgyTVFr9bhwohAx5S94j.jpg","banner":"article/zkCRFESAkisodyKoezlhuJY16vNFYzyzICBqFE2g.jpg","videoUrl":"https://youtu.be/0ZJqAZuQjXc","imageUrl":"https://dakotapokertour.com/storage/article/thumb/roP2dixGt8Tmzb7abotLHgyTVFr9bhwohAx5S94j.jpg","bannerUrl":"https://dakotapokertour.com/storage/article/zkCRFESAkisodyKoezlhuJY16vNFYzyzICBqFE2g.jpg","tournament":{"id":9,"name":"Hagge''s Bar & Grill","alias":"dakota-poker-tour-season-xi-season-xi-kickoff-tournament-hagge-s-hagge-s-bar-grill-09-26-2021"}}'::jsonb)
